/**
 * Shared payment methods - same source as Product Management > Payment Methods.
 * Used by Sales (POS), PaymentMethodModal, PaymentMethodManagement, and receipt.
 */
export const PAYMENT_METHODS_STORAGE_KEY = 'pos-payment-methods';
const DEFAULTS = [
  { id: 'cash', name: 'Cash', code: 'cash' },
  { id: 'card', name: 'Card', code: 'card' },
  { id: 'digital', name: 'Digital', code: 'digital' },
  { id: 'cheque', name: 'Cheque', code: 'cheque' },
  { id: 'credit', name: 'Credit', code: 'credit' }
];

export function getPaymentMethods() {
  try {
    const s = localStorage.getItem(PAYMENT_METHODS_STORAGE_KEY);
    if (s) {
      const parsed = JSON.parse(s);
      return Array.isArray(parsed) && parsed.length > 0 ? parsed : DEFAULTS;
    }
  } catch (e) {}
  return [...DEFAULTS];
}

export function getDefaultPaymentMethodCode() {
  const methods = getPaymentMethods();
  return (methods[0] && methods[0].code) || 'cash';
}
