import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';

const EditRowModal = ({ isOpen, onClose, item, onUpdate }) => {
  const { t } = useTranslation();
  const [formData, setFormData] = useState({
    quantity: 1,
    price: 0,
    discount: 0,
    discountType: 'fixed' // 'fixed' or 'percentage'
  });
  const quantityInputRef = useRef(null);

  // Initialize form data when item changes
  useEffect(() => {
    if (item) {
      setFormData({
        quantity: item.quantity || 1,
        price: item.price || 0,
        discount: item.discount || 0,
        discountType: 'fixed' // Reset to fixed when opening for a new item, or could infer from props if persisted
      });
    }
  }, [item]);

  // Focus first input when modal opens
  useEffect(() => {
    if (isOpen) {
      quantityInputRef.current?.focus();
    }
  }, [isOpen]);

  // Handle keyboard events in modal
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e) => {
      // Toggle discount type with Alt+D or specific keys
      if (e.key === 'Escape') {
        onClose();
      } else if (e.key === 'Enter') {
        handleUpdate();
      } else if (e.altKey && e.key.toLowerCase() === 'd') {
        e.preventDefault();
        setFormData(prev => ({
          ...prev,
          discountType: prev.discountType === 'fixed' ? 'percentage' : 'fixed',
          discount: 0
        }));
      } else if (e.key === 'p' || e.key === '%') {
        // Only trigger if not typing in a way that would be interrupted
        setFormData(prev => ({ ...prev, discountType: 'percentage', discount: 0 }));
      } else if (e.key === 'f' || e.key === '$') {
        setFormData(prev => ({ ...prev, discountType: 'fixed', discount: 0 }));
      }
    };

    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [isOpen, onClose, formData]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: parseFloat(value) || 0
    }));
  };

  const handleUpdate = () => {
    // Calculate final absolute discount amount
    let finalDiscountAmount = formData.discount;

    if (formData.discountType === 'percentage') {
      const totalValue = formData.quantity * formData.price;
      // Calculate percentage: (Total * Percent) / 100
      finalDiscountAmount = (totalValue * (formData.discount / 100));
    }

    // Create updated item with all fields
    const updatedItem = {
      ...item,
      quantity: formData.quantity,
      price: formData.price,
      discount: Number(finalDiscountAmount.toFixed(2))
    };
    onUpdate(updatedItem);
    onClose();
  };

  if (!isOpen || !item) return null;

  return (
    <div className="modal-overlay" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={onClose}>
      <div className="modal-content" onClick={e => e.stopPropagation()} style={{ background: 'white', width: 480, borderRadius: 12, overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}>
        <div style={{ padding: '14px 16px', borderBottom: '1px solid #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 600 }}>{t('sales.editItem')}</div>
          <button onClick={onClose} style={{ border: 'none', background: 'transparent', fontSize: 22, color: '#888', cursor: 'pointer' }}>×</button>
        </div>

        <div style={{ padding: 16 }}>
          <div className="item-summary" style={{ marginBottom: '15px' }}>
            <h4 className="item-name" style={{ margin: 0 }}>{item.name || 'Unknown Product'}</h4>
            {item.barcode && (
              <p className="item-barcode" style={{ margin: '4px 0 0 0', display: 'flex', alignItems: 'center', gap: '4px' }}>
                <svg className="form-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24" style={{ width: '12px', height: '12px' }}>
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" />
                </svg>
                {t('products.barcode')}: {item.barcode}
              </p>
            )}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {/* Row 1: Quantity & Price */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
              <div className="form-group" style={{ margin: 0 }}>
                <label htmlFor="quantity" className="form-label" style={{ marginBottom: '4px', fontSize: '12px' }}>{t('grn.quantity')}</label>
                <input
                  ref={quantityInputRef}
                  type="number"
                  id="quantity"
                  name="quantity"
                  value={formData.quantity}
                  onChange={handleInputChange}
                  min="1"
                  className="form-input"
                  style={{ padding: '8px' }}
                />
              </div>

              <div className="form-group" style={{ margin: 0 }}>
                <label htmlFor="price" className="form-label" style={{ marginBottom: '4px', fontSize: '12px' }}>
                  {t('sales.unitPrice')} ($) <span style={{ color: '#9ca3af', fontWeight: 'normal' }}>{t('sales.readOnly')}</span>
                </label>
                <input
                  type="number"
                  id="price"
                  name="price"
                  value={formData.price}
                  readOnly
                  disabled
                  className="form-input"
                  style={{ backgroundColor: '#f3f4f6', cursor: 'not-allowed', color: '#6b7280', padding: '8px' }}
                />
              </div>
               <div style={{ marginTop: '6px', fontSize: '11px', color: '#6b7280', display: 'flex', gap: '10px', alignItems: 'center' }}>
                 <span>Shortcuts:</span>
                 <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                   <kbd style={{ padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>F</kbd> Fixed
                 </span>
                 <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                   <kbd style={{ padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>%</kbd> Percent
                 </span>
                 <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                   <kbd style={{ padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Enter</kbd> Update
                 </span>
                 <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                   <kbd style={{ padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Esc</kbd> Close
                 </span>
               </div>
            </div>

            {/* Row 2: Discount & Subtotal */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', alignItems: 'end' }}>
              <div className="form-group" style={{ margin: 0 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
                  <label htmlFor="discount" className="form-label" style={{ fontSize: '12px', margin: 0 }}>{t('products.discount')}</label>
                  <div style={{ display: 'flex', border: '1px solid #e5e7eb', borderRadius: '4px', overflow: 'hidden' }}>
                    <button
                      type="button"
                      title={`${t('products.fixedDisc')} ($)`}
                      onClick={() => setFormData(prev => ({ ...prev, discountType: 'fixed', discount: 0 }))}
                      style={{
                        padding: '2px 8px',
                        fontSize: '10px',
                        fontWeight: '700',
                        backgroundColor: formData.discountType === 'fixed' ? 'var(--primary)' : 'white',
                        color: formData.discountType === 'fixed' ? 'white' : '#6b7280',
                        border: 'none',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '2px'
                      }}
                    >
                      <span>$</span>
                      <span style={{ fontSize: '8px', opacity: 0.7 }}>[F]</span>
                    </button>
                    <button
                      type="button"
                      title={`${t('products.discount')} (%)`}
                      onClick={() => setFormData(prev => ({ ...prev, discountType: 'percentage', discount: 0 }))}
                      style={{
                        padding: '2px 8px',
                        fontSize: '10px',
                        fontWeight: '700',
                        backgroundColor: formData.discountType === 'percentage' ? 'var(--primary)' : 'white',
                        color: formData.discountType === 'percentage' ? 'white' : '#6b7280',
                        border: 'none',
                        borderLeft: '1px solid #e5e7eb',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '2px'
                      }}
                    >
                      <span>%</span>
                      <span style={{ fontSize: '8px', opacity: 0.7 }}>[P]</span>
                    </button>
                  </div>
                </div>
                <input
                  type="number"
                  id="discount"
                  name="discount"
                  value={formData.discount}
                  onChange={handleInputChange}
                  step={formData.discountType === 'percentage' ? "1" : "0.01"}
                  min="0"
                  max={formData.discountType === 'percentage' ? "100" : undefined}
                  className="form-input"
                  style={{ padding: '8px' }}
                  placeholder={formData.discountType === 'percentage' ? "0%" : "0.00"}
                />
              </div>

              <div style={{
                backgroundColor: '#f9fafb',
                padding: '8px 12px',
                borderRadius: '6px',
                border: '1px solid #e5e7eb',
                height: '42px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between'
              }}>
                <span style={{ fontSize: '12px', color: '#6b7280', fontWeight: '600' }}>{t('grn.subtotal')}:</span>
                <span style={{ fontSize: '16px', fontWeight: '700', color: 'var(--primary)' }}>
                  $ {
                    formData.discountType === 'percentage'
                      ? ((Number(formData.quantity || 0) * Number(formData.price || 0)) * (1 - (Number(formData.discount || 0) / 100))).toFixed(2)
                      : ((Number(formData.quantity || 0) * Number(formData.price || 0)) - Number(formData.discount || 0)).toFixed(2)
                  }
                </span>
              </div>
            </div>
          </div>
        </div>

        <div style={{ padding: 16, borderTop: '1px solid #eee', display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
          <button onClick={onClose} className="sales-button sales-button-secondary">{t('common.cancelEsc')}</button>
          <button onClick={handleUpdate} className="sales-button sales-button-success">{t('common.updateEnter')}</button>
        </div>
      </div>
    </div>
  );
};

export default EditRowModal;
