import React from 'react';
import { useTranslation } from 'react-i18next';
import { getPaymentMethods } from '../utils/paymentMethods';

const PaymentMethodModal = ({ isOpen, onClose, onSelect, onConfirm, current }) => {
  const { t } = useTranslation();
  const rootRef = React.useRef(null);
  const methods = React.useMemo(() => getPaymentMethods().map(m => ({ key: m.code, label: m.name })), []);
  React.useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e) => {
      methods.forEach((m, i) => {
        if (e.key === String(i + 1)) {
          e.preventDefault();
          onSelect(m.key);
          if (onConfirm) onConfirm(m.key);
          onClose();
        }
      });
      if (e.key === 'Enter') {
        e.preventDefault();
        if (onConfirm) onConfirm(current);
        onClose();
      }
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
    };
    window.addEventListener('keydown', handleKey, true);
    return () => window.removeEventListener('keydown', handleKey, true);
  }, [current, isOpen, onClose, onConfirm, onSelect, methods]);
  if (!isOpen) return null;
  return (
    <div className="modal-overlay" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ background: 'white', width: 360, borderRadius: 12, overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}>
        <div style={{ padding: '14px 16px', borderBottom: '1px solid #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <h3 style={{ margin: 0 }}>{t('sales.paymentMethod')}</h3>
          <button onClick={onClose} style={{ border: 'none', background: 'transparent', fontSize: 22, color: '#888', cursor: 'pointer' }}>×</button>
        </div>
        <div ref={rootRef} style={{ padding: 16, display: 'flex', flexWrap: 'wrap', gap: 10 }}>
          {methods.map(m => (
            <button
              key={m.key}
              onClick={() => { onSelect(m.key); if (onConfirm) onConfirm(m.key); onClose(); }}
              className={`sales-button ${current === m.key ? 'sales-button-success' : 'sales-button-secondary'}`}
              style={{ width: 'auto', minWidth: 'min-content', justifyContent: 'space-between', display: 'inline-flex' }}
            >
              <span>{m.label}</span>
              {current === m.key && <span style={{ fontWeight: 800 }}>✓</span>}
            </button>
          ))}
          <div style={{ fontSize: 12, color: '#666', marginTop: 6 }}>
            {methods.map((m, i) => (
              <span key={m.key} style={{ marginRight: 8 }}>
                <kbd style={{ fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>{i + 1}</kbd>
                {m.label}
              </span>
            ))}
            <span style={{ marginLeft: 8 }}>·</span>
            <span style={{ marginLeft: 8 }}>{t('sales.completeSale')}:</span>
            <kbd style={{ marginLeft: 6, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Enter</kbd>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PaymentMethodModal;
