import React, { useState, useEffect, useRef, useMemo } from 'react';
import { get, put, post } from '../utils/api';
import { useSettings } from '../context/SettingsContext';
import { useTranslation } from 'react-i18next';
import UOMDropdown from './common/UOMDropdown';

const ProductEditModal = ({ isOpen, onClose, product, onSave }) => {
  const { settings } = useSettings();
  const { t } = useTranslation();
  const [formData, setFormData] = useState({
    name: '',
    sellingPrice: '',
    costPrice: '',
    barcode: '',
    sku: '',
    categoryId: '',
    description: '',
    unit: 'pcs',
    baseUnitId: null,
    warehouseId: '',
    minStockLevel: 0,
    isActive: true,
    quantity: 0,
    discountPercentage: '',
    discountFixedPrice: ''
  });
  const [errors, setErrors] = useState({});
  const [categories, setCategories] = useState([]);
  const [warehouses, setWarehouses] = useState([]);
  const [isPrinting, setIsPrinting] = useState(false);
  const nameInputRef = useRef(null);
  const discountPercentageRef = useRef(null);
  const discountFixedPriceRef = useRef(null);

  // Load categories and warehouses when modal opens
  useEffect(() => {
    const loadData = async () => {
      try {
        const [catResult, whResult] = await Promise.all([
          get('/categories'),
          get('/warehouses')
        ]);
        if (catResult.success) setCategories(catResult.data || []);
        if (whResult.success) setWarehouses(whResult.data || []);
      } catch (error) {
        console.error('Error loading data:', error);
      }
    };

    if (isOpen) {
      loadData();
    }
  }, [isOpen]);

  const flattenedCategories = useMemo(() => {
    const byId = new Map(categories.map(c => [c.id, { ...c, children: [] }]));
    const roots = [];
    byId.forEach(node => {
      if (node.parentId && byId.has(node.parentId)) {
        byId.get(node.parentId).children.push(node);
      } else {
        roots.push(node);
      }
    });
    const sortTree = (nodes) => {
      nodes.sort((a, b) => a.name.localeCompare(b.name));
      nodes.forEach(n => sortTree(n.children));
    };
    sortTree(roots);
    const out = [];
    const walk = (nodes, prefix = []) => {
      nodes.forEach(n => {
        const labelPath = [...prefix, n.name].join(' > ');
        out.push({ id: n.id, label: labelPath });
        if (n.children && n.children.length) walk(n.children, [...prefix, n.name]);
      });
    };
    walk(roots);
    return out;
  }, [categories]);

  // Initialize form data when product changes
  useEffect(() => {
    if (product) {
      setFormData({
        name: product.name || '',
        sellingPrice: product.sellingPrice || '',
        costPrice: product.costPrice || '',
        barcode: product.barcode || '',
        sku: product.sku || '',
        categoryId: product.categoryId || '',  // Empty string for "no category"
        description: product.description || '',
        unit: product.unit || product.baseUnit?.shortName || 'pcs',
        baseUnitId: product.baseUnitId ?? product.baseUnit?.id ?? null,
        warehouseId: product.warehouseId ?? product.warehouse?.id ?? '',
        minStockLevel: product.minStockLevel || 0,
        isActive: product.isActive !== undefined ? product.isActive : true,
        quantity: product.inventory?.quantity || 0,
        discountPercentage: product.discountPercentage || '',
        discountFixedPrice: product.discountFixedPrice || ''
      });
    }
  }, [product]);

  // Focus first input when modal opens
  useEffect(() => {
    if (isOpen) {
      nameInputRef.current?.focus();
    }
  }, [isOpen]);

  // Handle keyboard events in modal
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        onClose();
      } else if (e.key === 'Enter' && e.target.tagName !== 'TEXTAREA') {
        handleSave();
      } else if (e.altKey && e.key.toLowerCase() === 'p') {
        e.preventDefault();
        discountPercentageRef.current?.focus();
      } else if (e.altKey && e.key.toLowerCase() === 'f') {
        e.preventDefault();
        discountFixedPriceRef.current?.focus();
      }
    };

    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [isOpen, onClose, formData]);

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    // Clear error when user types
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const validate = () => {
    const newErrors = {};
    if (!formData.name || !String(formData.name).trim()) {
      newErrors.name = 'products.validation.nameRequired';
    }
    if (!formData.sellingPrice || isNaN(parseFloat(formData.sellingPrice)) || parseFloat(formData.sellingPrice) <= 0) {
      newErrors.sellingPrice = 'products.validation.sellingPriceRequired';
    }
    if (formData.costPrice !== '' && formData.costPrice != null && (isNaN(parseFloat(formData.costPrice)) || parseFloat(formData.costPrice) < 0)) {
      newErrors.costPrice = 'products.validation.costPriceInvalid';
    }
    if (formData.quantity !== '' && formData.quantity != null && (isNaN(parseInt(formData.quantity, 10)) || parseInt(formData.quantity, 10) < 0)) {
      newErrors.quantity = 'products.validation.quantityInvalid';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = async () => {
    if (!validate()) return;

    try {
      // Prepare product data for saving (exclude quantity as it's handled separately for inventory)
      const { quantity, ...productDataWithoutQuantity } = formData;

      // Handle categoryId properly - only include if it's a valid positive integer
      let categoryIdValue = null;
      if (formData.categoryId && formData.categoryId !== '' && !isNaN(parseInt(formData.categoryId))) {
        const parsedCategoryId = parseInt(formData.categoryId);
        if (parsedCategoryId > 0) {
          categoryIdValue = parsedCategoryId;
        }
      }

      let warehouseIdValue = null;
      if (formData.warehouseId && formData.warehouseId !== '' && !isNaN(parseInt(formData.warehouseId))) {
        const parsed = parseInt(formData.warehouseId);
        if (parsed > 0) warehouseIdValue = parsed;
      }

      const productData = {
        ...productDataWithoutQuantity,
        sellingPrice: parseFloat(formData.sellingPrice),
        costPrice: formData.costPrice ? parseFloat(formData.costPrice) : null,
        ...(categoryIdValue ? { categoryId: categoryIdValue } : {}),
        ...(warehouseIdValue ? { warehouseId: warehouseIdValue } : { warehouseId: null }),
        sku: formData.sku ? String(formData.sku).trim() : null,
        unit: formData.unit || 'pcs',
        baseUnitId: formData.baseUnitId || null,
        minStockLevel: formData.minStockLevel ? parseInt(formData.minStockLevel) : 0,
        discountPercentage: formData.discountPercentage ? parseFloat(formData.discountPercentage) : null,
        discountFixedPrice: formData.discountFixedPrice ? parseFloat(formData.discountFixedPrice) : null,
      };

      // First, update the product data (excluding quantity)
      const productResult = await onSave(productData);

      // Then, adjust inventory quantity if it has changed
      if (product && formData.quantity !== (product.inventory?.quantity || 0)) {
        try {
          const adjustment = formData.quantity - (product.inventory?.quantity || 0);
          const adjustmentType = adjustment > 0 ? 'add' : 'subtract';
          const adjustmentAmount = Math.abs(adjustment);

          if (adjustmentAmount > 0) {
            const inventoryResult = await post('/inventory/adjust', {
              productId: product.id,
              adjustment: adjustmentAmount,
              type: adjustmentType
            });

            if (!inventoryResult.success) {
              console.warn('Inventory adjustment warning:', inventoryResult.message);
              // Continue with the operation even if inventory adjustment has issues
            }
          }
        } catch (inventoryError) {
          console.error('Error adjusting inventory:', inventoryError);
          alert(t('products.errors.inventoryUpdateWarning'));
        }
      }

      onClose();
    } catch (error) {
      console.error('Error saving product:', error);
      const msg = error?.message || '';
      const friendly = msg.toLowerCase().includes('network') || error?.name === 'TypeError' ? t('messages.networkError') : t('products.errors.updateFailed');
      alert(friendly);
    }
  };

  const handlePrintBarcode = () => {
    if (!formData.barcode) {
      alert(t('products.noBarcode') || 'This product does not have a barcode to print');
      return;
    }
    const name = (formData.name || product?.name || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    const price = Number(formData.sellingPrice || product?.sellingPrice || 0).toFixed(2);
    const barcode = formData.barcode;
    const storeName = (settings.storeName || '').replace(/</g, '&lt;').replace(/>/g, '&gt;') || 'Store';
    const barcodeImgUrl = `https://barcode.tec-it.com/barcode.ashx?data=${encodeURIComponent(barcode)}&code=Code128&dpi=96`;
    const printHtml = `<!DOCTYPE html><html><head><title>Barcode - ${name}</title><style>@page{margin:0}body{margin:20px;font-family:Inter,sans-serif;text-align:center;-webkit-print-color-adjust:exact;print-color-adjust:exact}</style></head><body>
      <h2 style="margin:0 0 8px 0;font-size:18px;">${name}</h2>
      <p style="margin:0 0 16px 0;font-size:24px;font-weight:bold;">${price}</p>
      <img src="${barcodeImgUrl}" alt="Barcode" style="max-width:100%;height:auto;" onload="try{var w=window.parent;if(w.__barcodePrintReady){w.__barcodePrintReady();w.__barcodePrintReady=null;}}catch(e){}" onerror="try{var w=window.parent;if(w.__barcodePrintReady){w.__barcodePrintReady();w.__barcodePrintReady=null;}}catch(e){}" />
      <p style="margin:12px 0 0 0;font-family:monospace;font-size:14px;">${barcode}</p>
      <p style="margin:20px 0 0 0;font-size:11px;color:#333;">${storeName}</p>
      </body></html>`;

    let printed = false;
    const doPrint = () => {
      if (printed) return;
      printed = true;
      try {
        if (iframe.contentWindow) {
          iframe.contentWindow.focus();
          iframe.contentWindow.print();
        }
      } catch (e) {
        console.warn('Barcode print failed:', e);
      }
      window.__barcodePrintReady = null;
      setTimeout(() => {
        if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
      }, 500);
    };

    window.__barcodePrintReady = doPrint;

    const iframe = document.createElement('iframe');
    iframe.setAttribute('style', 'position:absolute;width:0;height:0;border:0;visibility:hidden;');
    document.body.appendChild(iframe);
    const doc = iframe.contentWindow.document;
    doc.open();
    doc.write(printHtml);
    doc.close();

    iframe.addEventListener('load', () => {
      const img = iframe.contentDocument?.querySelector('img');
      if (img && img.complete && img.naturalWidth > 0) {
        doPrint();
        return;
      }
      if (img) {
        img.addEventListener('load', () => doPrint(), { once: true });
        img.addEventListener('error', () => setTimeout(doPrint, 300), { once: true });
      }
    });
    setTimeout(() => { if (!printed) doPrint(); }, 6000);
  };

  if (!isOpen || !product) return null;

  const finalPrice = (() => {
    const price = parseFloat(formData.sellingPrice) || 0;
    if (formData.discountFixedPrice) return Math.max(0, price - parseFloat(formData.discountFixedPrice)).toFixed(2);
    if (formData.discountPercentage) return Math.max(0, price * (1 - parseFloat(formData.discountPercentage) / 100)).toFixed(2);
    return price.toFixed(2);
  })();

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-container product-edit-modal" onClick={e => e.stopPropagation()}>
        <style>{`
          .product-edit-modal.modal-container { max-width: 1000px; width: 100%; background: white; border-radius: 24px; box-shadow: 0 25px 50px -12px rgba(0,0,0,0.25); overflow: hidden; display: flex; flex-direction: column; max-height: 95vh; animation: productEditSlideUp 0.3s ease-out; }
          .product-edit-modal .modal-header { padding: 1.5rem 2rem; display: flex; justify-content: space-between; align-items: center; background: linear-gradient(135deg, #10b981 0%, #059669 100%); color: white; }
          .product-edit-modal .header-content { display: flex; align-items: center; gap: 12px; }
          .product-edit-modal .header-title { margin: 0; font-weight: 800; font-size: 1.5rem; letter-spacing: -0.5px; }
          .product-edit-modal .close-button { background: rgba(255,255,255,0.2); border: none; color: white; cursor: pointer; padding: 8px; border-radius: 10px; transition: all 0.2s; }
          .product-edit-modal .close-button:hover { background: rgba(255,255,255,0.3); }
          .product-edit-modal .modal-content { padding: 1.5rem; overflow-y: auto; flex: 1; }
          .product-edit-modal .grid-row { display: grid; grid-template-columns: repeat(2, 1fr); gap: 1.5rem; }
          .product-edit-modal .modern-label { display: block; font-size: 13px; font-weight: 700; color: #374151; margin-bottom: 8px; text-transform: uppercase; letter-spacing: 0.5px; }
          .product-edit-modal .modern-input { width: 100%; padding: 12px 16px; border: 2px solid #e5e7eb; border-radius: 12px; font-size: 15px; outline: none; transition: 0.3s; box-sizing: border-box; }
          .product-edit-modal .modern-input:focus { border-color: #3b82f6; background: #f8fafc; box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1); }
          .product-edit-modal .modern-input.error { border-color: #ef4444; background: #fef2f2; }
          .product-edit-modal .error-message { color: #ef4444; font-size: 13px; margin-top: 6px; display: flex; align-items: center; gap: 6px; font-weight: 500; }
          .product-edit-modal .discount-section { padding: 1rem; background: #f8fafc; border-radius: 12px; border: 1px solid #e2e8f0; margin-top: 0.5rem; }
          .product-edit-modal .discount-header { margin: 0 0 0.75rem 0; color: #475569; font-size: 0.85rem; }
          .product-edit-modal .discount-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.75rem; }
          .product-edit-modal .footer-section { display: flex; justify-content: space-between; align-items: center; margin-top: 2rem; gap: 1rem; padding-top: 1rem; border-top: 1px solid #e5e7eb; background: #f9fafb; }
          .product-edit-modal .button-group { display: flex; gap: 0.75rem; }
          .product-edit-modal .modern-button { padding: 12px 24px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; transition: 0.3s; border: none; text-transform: uppercase; letter-spacing: 0.5px; }
          .product-edit-modal .modern-button.primary { background: linear-gradient(135deg, #10b981 0%, #059669 100%); color: white; box-shadow: 0 4px 12px rgba(16, 185, 129, 0.3); }
          .product-edit-modal .modern-button.primary:hover { background: linear-gradient(135deg, #059669 0%, #047857 100%); transform: translateY(-2px); }
          .product-edit-modal .modern-button.secondary { background: #f3f4f6; color: #374151; border: 2px solid #e5e7eb; }
          .product-edit-modal .modern-button.secondary:hover { background: #e5e7eb; border-color: #d1d5db; }
          @keyframes productEditSlideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
          @media (max-width: 768px) { .product-edit-modal .grid-row { grid-template-columns: 1fr; } .product-edit-modal .footer-section { flex-direction: column; align-items: stretch; } .product-edit-modal .button-group { flex-wrap: wrap; } }
        `}</style>

        <div className="modal-header">
          <div className="header-content">
            <svg style={{ width: '28px', height: '28px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
            </svg>
            <h2 className="header-title">{t('products.editProduct')}</h2>
          </div>
          <button onClick={onClose} className="close-button">
            <svg style={{ width: '24px', height: '24px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="modal-content">
          <div className="grid-row">
            <div>
              <label htmlFor="edit-name" className="modern-label">{t('products.productName')} <span style={{ color: '#ef4444' }}>*</span></label>
              <input
                ref={nameInputRef}
                id="edit-name"
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                className={`modern-input ${errors.name ? 'error' : ''}`}
                placeholder="e.g. Organic Soda"
              />
              {errors.name && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  {t(errors.name)}
                </div>
              )}
            </div>
            <div>
              <label className="modern-label">{t('products.skuOptional')}</label>
              <input type="text" name="sku" value={formData.sku} onChange={handleInputChange} className="modern-input" placeholder="e.g. ABC-123" />
            </div>
            <div>
              <label className="modern-label">{t('products.sellingPrice')} <span style={{ color: '#ef4444' }}>*</span></label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '18px', top: '50%', transform: 'translateY(-50%)', fontWeight: '700', color: '#6b7280', fontSize: '16px' }}>{settings.currency || '$'}</span>
                <input
                  type="number"
                  name="sellingPrice"
                  value={formData.sellingPrice}
                  onChange={handleInputChange}
                  step="0.01"
                  min="0.01"
                  className={`modern-input ${errors.sellingPrice ? 'error' : ''}`}
                  style={{ paddingLeft: '42px' }}
                  placeholder="0.00"
                />
              </div>
              {errors.sellingPrice && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  {t(errors.sellingPrice)}
                </div>
              )}
            </div>
            <div>
              <label className="modern-label">{t('products.categoryOptional')}</label>
              <select name="categoryId" value={formData.categoryId} onChange={handleInputChange} className="modern-input">
                <option value="">{t('products.selectCategory')}</option>
                {flattenedCategories.map(cat => (
                  <option key={cat.id} value={cat.id}>{cat.label}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="modern-label">{t('products.quantityOptional')}</label>
              <input
                type="number"
                name="quantity"
                value={formData.quantity}
                onChange={handleInputChange}
                min="0"
                className={`modern-input ${errors.quantity ? 'error' : ''}`}
                placeholder="0"
              />
              {errors.quantity && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  {t(errors.quantity)}
                </div>
              )}
            </div>
            <div>
              <label className="modern-label">{t('warehouse.defaultWarehouse') || 'Default Warehouse'}</label>
              <select name="warehouseId" value={formData.warehouseId} onChange={handleInputChange} className="modern-input">
                <option value="">{t('warehouse.select') || 'Select Warehouse'}</option>
                {warehouses.map(w => (
                  <option key={w.id} value={w.id}>{w.parentId ? '↳ ' : ''}{w.name}{w.location ? ` (${w.location})` : ''}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="modern-label">{t('products.costPriceOptional')}</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '18px', top: '50%', transform: 'translateY(-50%)', fontWeight: '700', color: '#6b7280', fontSize: '16px' }}>{settings.currency || '$'}</span>
                <input
                  type="number"
                  name="costPrice"
                  value={formData.costPrice}
                  onChange={handleInputChange}
                  step="0.01"
                  min="0"
                  className={`modern-input ${errors.costPrice ? 'error' : ''}`}
                  style={{ paddingLeft: '42px' }}
                  placeholder="0.00"
                />
              </div>
              {errors.costPrice && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  {t(errors.costPrice)}
                </div>
              )}
            </div>
            <div>
              <UOMDropdown
                label={t('products.unit') || 'Unit'}
                name="unit"
                value={formData.baseUnitId || formData.unit}
                onChange={(shortName, unit) => setFormData(prev => ({
                  ...prev,
                  unit: shortName || 'pcs',
                  baseUnitId: unit ? unit.id : null
                }))}
                className="modern-input"
              />
            </div>
            <div>
              <label className="modern-label">{t('products.minStock')}</label>
              <input type="number" name="minStockLevel" value={formData.minStockLevel} onChange={handleInputChange} className="modern-input" placeholder="0" min="0" />
            </div>
          </div>

          <div className="discount-section">
            <h4 className="discount-header">{t('products.discountConfig')}</h4>
            <div className="discount-grid">
              <div>
                <label className="modern-label">{t('products.discount')} % <span style={{ fontSize: '9px', color: '#64748b' }}>[ALT+P]</span></label>
                <input
                  ref={discountPercentageRef}
                  type="number"
                  name="discountPercentage"
                  value={formData.discountPercentage}
                  onChange={(e) => { handleInputChange(e); if (e.target.value) setFormData(prev => ({ ...prev, discountFixedPrice: '' })); }}
                  min="0"
                  max="100"
                  className="modern-input"
                  placeholder="0%"
                />
              </div>
              <div>
                <label className="modern-label">{t('products.fixedDisc')} ({settings.currency || '$'}) <span style={{ fontSize: '9px', color: '#64748b' }}>[ALT+F]</span></label>
                <input
                  ref={discountFixedPriceRef}
                  type="number"
                  name="discountFixedPrice"
                  value={formData.discountFixedPrice}
                  onChange={(e) => { handleInputChange(e); if (e.target.value) setFormData(prev => ({ ...prev, discountPercentage: '' })); }}
                  min="0"
                  className="modern-input"
                  placeholder="0.00"
                />
              </div>
              <div style={{ padding: '10px', background: 'white', borderRadius: '10px', border: '1px dashed #cbd5e1', textAlign: 'center' }}>
                <span style={{ fontSize: '0.8rem', color: '#64748b', display: 'block' }}>{t('products.finalPrice')}</span>
                <span style={{ fontWeight: '800', color: '#10b981' }}>{settings.currency || '$'}{finalPrice}</span>
              </div>
            </div>
          </div>

          <div style={{ marginTop: '1rem' }}>
            <label className="modern-label">{t('products.barcodeOptional')}</label>
            <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
              <input
                type="text"
                name="barcode"
                value={formData.barcode}
                onChange={handleInputChange}
                className="modern-input"
                placeholder={t('products.scanBarcodePlaceholder')}
                style={{ flex: 1, background: '#fffef2', borderColor: '#eab30866' }}
              />
              <button type="button" onClick={handlePrintBarcode} disabled={!formData.barcode} className="modern-button secondary" style={{ whiteSpace: 'nowrap' }}>
                {t('common.print') || 'Print'}
              </button>
            </div>
          </div>

          <div style={{ marginTop: '1rem' }}>
            <label className="modern-label">{t('products.description') || 'Description'}</label>
            <textarea name="description" value={formData.description} onChange={handleInputChange} className="modern-input" rows="2" placeholder="Product description..." style={{ resize: 'vertical' }} />
          </div>

          <div style={{ marginTop: '1rem', display: 'flex', alignItems: 'center', gap: '12px' }}>
            <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer', gap: '8px' }}>
              <input type="checkbox" name="isActive" checked={formData.isActive} onChange={handleInputChange} style={{ width: '18px', height: '18px', accentColor: '#10b981' }} />
              <span style={{ fontWeight: '600', color: '#4b5563', fontSize: '0.9rem' }}>{t('products.active')}</span>
            </label>
          </div>

          <div className="footer-section">
            <div className="button-group">
              <button data-pos-action="cancel" onClick={onClose} className="modern-button secondary">{t('common.cancel')} <kbd>Esc</kbd></button>
              <button data-pos-action="save" onClick={handleSave} className="modern-button primary">{t('common.save')} <kbd>F10</kbd></button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductEditModal;
