/**
 * Currency formatting utility
 * Formats numbers as currency based on the currency code
 */

const CURRENCY_SYMBOLS = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    LKR: 'රු',  // Sinhala rupee symbol
    RS: 'Rs.',  // Alternative LKR format
    INR: '₹',
    JPY: '¥',
    CNY: '¥'
};

const CURRENCY_DECIMALS = {
    JPY: 0,
    KRW: 0,
    // Most currencies use 2 decimals
};

/**
 * Format a number as currency
 * @param {number} amount - The amount to format
 * @param {string} currencyCode - Currency code (LKR, USD, etc.)
 * @param {boolean} showSymbol - Whether to show currency symbol (default: true)
 * @returns {string} Formatted currency string
 */
export const formatCurrency = (amount, currencyCode = 'LKR', showSymbol = true) => {
    if (amount === null || amount === undefined || isNaN(amount)) {
        return showSymbol ? `${CURRENCY_SYMBOLS[currencyCode] || currencyCode} 0.00` : '0.00';
    }

    const decimals = CURRENCY_DECIMALS[currencyCode] !== undefined ? CURRENCY_DECIMALS[currencyCode] : 2;
    const formattedAmount = Number(amount).toFixed(decimals);

    if (!showSymbol) {
        return formattedAmount;
    }

    const symbol = CURRENCY_SYMBOLS[currencyCode] || currencyCode;

    // For some currencies, symbol goes after the amount
    if (currencyCode === 'EUR') {
        return `${formattedAmount} ${symbol}`;
    }

    return `${symbol} ${formattedAmount}`;
};

/**
 * Parse currency string back to number
 * @param {string} currencyString - Currency string to parse
 * @returns {number} Parsed number
 */
export const parseCurrency = (currencyString) => {
    if (typeof currencyString === 'number') {
        return currencyString;
    }

    // Remove all non-numeric characters except decimal point and minus
    const cleaned = String(currencyString).replace(/[^0-9.-]/g, '');
    return parseFloat(cleaned) || 0;
};
