import React from 'react';
import '../../styles/antigravity.css'; // Ensure styles are loaded if used in isolation

const GlassCard = ({
    children,
    className = '',
    hoverEffect = false,
    tiltEffect = false,
    style = {},
    ...props
}) => {
    const handleMouseMove = (e) => {
        if (!tiltEffect) return;

        const card = e.currentTarget;
        const rect = card.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;

        const centerX = rect.width / 2;
        const centerY = rect.height / 2;

        const rotateX = ((y - centerY) / centerY) * -4; // Max rotation deg
        const rotateY = ((x - centerX) / centerX) * 4;

        card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.02, 1.02, 1.02)`;
    };

    const handleMouseLeave = (e) => {
        if (!tiltEffect) return;
        e.currentTarget.style.transform = 'perspective(1000px) rotateX(0) rotateY(0) scale3d(1, 1, 1)';
    };

    return (
        <div
            className={`glass-panel ${hoverEffect ? 'float-hover' : ''} ${className}`}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            style={{
                padding: '1.5rem',
                ...style
            }}
            {...props}
        >
            {children}
        </div>
    );
};

export default GlassCard;
