import React, { createContext, useContext, useReducer, useEffect } from 'react';
import { get } from '../utils/api';

// Define default/fallback settings state
const defaultSettings = {
  storeName: 'POS Store',
  storeAddress: '123 Main Street',
  storePhone: '(555) 123-4567',
  currency: 'LKR',
  taxRate: 10,
  receiptPrinter: 'Default Printer',
  /** Optional: URL of local print bridge (Node/Electron) for silent printing. POST receipt HTML to skip browser dialog. */
  silentPrintBridgeUrl: '',
  defaultPaymentMethod: 'cash',
  lowStockThreshold: 5,
  autoSaveInterval: 30,
  enableNotifications: true,
  darkMode: false,
  soundEffects: true,
  themeColor: '245', // Default Indigo
  logoPath: '', // Path to company logo
  receiptPaperSize: 'Thermal', // Thermal, A4, Letter
  language: 'en', // Default language: en, si, ta, singlish
  themeMode: 'light', // Theme mode: light, dark, custom
  customBrandColor: '#6366f1' // Custom brand color for custom theme mode
};

// Initial state should be empty - we'll load from database
const initialSettings = {}; // Empty object to be populated from database

// Actions
const SETTING_UPDATE = 'SETTING_UPDATE';
const SETTINGS_RESET = 'SETTINGS_RESET';
const SETTINGS_LOAD_START = 'SETTINGS_LOAD_START';
const SETTINGS_LOAD_SUCCESS = 'SETTINGS_LOAD_SUCCESS';
const SETTINGS_LOAD_ERROR = 'SETTINGS_LOAD_ERROR';

// Settings Context
const SettingsContext = createContext();

// Settings Provider Component
export const SettingsProvider = ({ children }) => {
  const [settings, dispatch] = useReducer(settingsReducer, {}); // Start with empty object

  // Load settings from API on initialization
  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      dispatch({ type: SETTINGS_LOAD_START });
      const result = await get('/settings');
      console.log('[DEBUG] Settings Sync:', result.success ? 'SUCCESS' : 'FAILED', result.data ? Object.keys(result.data).length + ' keys' : 'no data');
      if (result.success && result.data) {
        dispatch({ type: SETTINGS_LOAD_SUCCESS, payload: result.data });
      } else {
        dispatch({ type: SETTINGS_LOAD_ERROR });
      }
    } catch (error) {
      console.error('Error loading settings:', error);
      dispatch({ type: SETTINGS_LOAD_ERROR });
    }
  };

  function settingsReducer(state, action) {
    switch (action.type) {
      case SETTINGS_LOAD_START:
        return state;
      case SETTINGS_LOAD_SUCCESS:
        // Use database settings completely
        return {
          ...action.payload  // Use all database values directly
        };
      case SETTINGS_LOAD_ERROR:
        // On error, use default fallback settings
        return { ...defaultSettings };
      case SETTING_UPDATE:
        return {
          ...state,
          [action.payload.key]: action.payload.value
        };
      case SETTINGS_RESET:
        return { ...defaultSettings };
      default:
        return state;
    }
  }

  const updateSetting = (key, value) => {
    dispatch({
      type: SETTING_UPDATE,
      payload: { key, value }
    });
  };

  const resetSettings = () => {
    dispatch({ type: SETTINGS_RESET });
  };

  const value = {
    settings,
    updateSetting,
    resetSettings
  };

  return (
    <SettingsContext.Provider value={value}>
      {children}
    </SettingsContext.Provider>
  );
};

// Custom hook to use settings context
export const useSettings = () => {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error('useSettings must be used within a SettingsProvider');
  }
  return context;
};

export default SettingsContext;