import React, { createContext, useContext, useReducer } from 'react';
import { post } from '../utils/api';
import { useAuth } from './AuthContext';

// Initial state
const initialState = {
  mode: 'DUMMY', // 'LIVE' (Screen A) or 'DUMMY' (Screen B) — default Screen B
  liveCart: [],
  dummyCart: [],
  liveDiscount: 0,
  dummyDiscount: 0,
  currentUserId: null,
  selectedWarehouseId: null, // Default warehouse for sales; CASHIER cannot change
};

// Action types
const actionTypes = {
  ADD_ITEM: 'ADD_ITEM',
  REMOVE_ITEM: 'REMOVE_ITEM',
  UPDATE_QUANTITY: 'UPDATE_QUANTITY',
  UPDATE_PRICE: 'UPDATE_PRICE',
  UPDATE_DISCOUNT: 'UPDATE_DISCOUNT',
  UPDATE_GLOBAL_DISCOUNT: 'UPDATE_GLOBAL_DISCOUNT',
  CLEAR_CART: 'CLEAR_CART',
  SET_CURRENT_USER: 'SET_CURRENT_USER',
  COMPLETE_SALE: 'COMPLETE_SALE',
  SET_MODE: 'SET_MODE',
  SET_WAREHOUSE: 'SET_WAREHOUSE',
};

// Reducer function - use single cart for both LIVE and DUMMY so Screen A → Screen B shows same transaction
const salesReducer = (state, action) => {
  const currentCartKey = 'liveCart';
  const currentDiscountKey = 'liveDiscount';
  const currentCart = state[currentCartKey];

  switch (action.type) {
    case actionTypes.SET_MODE:
      return {
        ...state,
        mode: action.payload.mode
      };

    case actionTypes.SET_WAREHOUSE:
      return {
        ...state,
        selectedWarehouseId: action.payload.warehouseId
      };

    case actionTypes.ADD_ITEM:
      // Check if item already exists in cart
      const existingItemIndex = currentCart.findIndex(item => item.id === action.payload.id);

      let updatedCartAdd;
      if (existingItemIndex >= 0) {
        // If item exists, increment by the provided quantity
        updatedCartAdd = [...currentCart];
        updatedCartAdd[existingItemIndex] = {
          ...updatedCartAdd[existingItemIndex],
          quantity: updatedCartAdd[existingItemIndex].quantity + (action.payload.quantity || 1)
        };
      } else {
        // If item doesn't exist, add it with the provided quantity (default 1)
        // Normalize price from sellingPrice if price is missing
        const price = Number(action.payload.price || action.payload.sellingPrice || 0);

        // Calculate initial discount based on product master data if not explicitly provided
        let initialDiscount = Number(action.payload.discount || 0);
        if (initialDiscount === 0) {
          if (action.payload.discountFixedPrice && Number(action.payload.discountFixedPrice) > 0) {
            initialDiscount = Number(action.payload.discountFixedPrice);
          } else if (action.payload.discountPercentage && Number(action.payload.discountPercentage) > 0) {
            initialDiscount = (price * Number(action.payload.discountPercentage)) / 100;
          }
        }

        updatedCartAdd = [
          ...currentCart,
          {
            ...action.payload,
            price: price,
            // Use the quantity from payload, default to 1 if not specified
            quantity: Number(action.payload.quantity || 1),
            discount: initialDiscount
          }
        ];
      }
      return { ...state, [currentCartKey]: updatedCartAdd };

    case actionTypes.REMOVE_ITEM:
      return {
        ...state,
        [currentCartKey]: currentCart.filter(item => item.id !== action.payload.id)
      };

    case actionTypes.UPDATE_QUANTITY:
      return {
        ...state,
        [currentCartKey]: currentCart.map(item =>
          item.id === action.payload.id
            ? { ...item, quantity: action.payload.quantity }
            : item
        )
      };

    case actionTypes.UPDATE_PRICE:
      return {
        ...state,
        [currentCartKey]: currentCart.map(item =>
          item.id === action.payload.id
            ? { ...item, price: action.payload.price }
            : item
        )
      };

    case actionTypes.UPDATE_DISCOUNT:
      return {
        ...state,
        [currentCartKey]: currentCart.map(item =>
          item.id === action.payload.id
            ? { ...item, discount: action.payload.discount }
            : item
        )
      };

    case actionTypes.UPDATE_GLOBAL_DISCOUNT:
      return {
        ...state,
        [currentDiscountKey]: action.payload.discount
      };

    case actionTypes.CLEAR_CART:
      return {
        ...state,
        [currentCartKey]: [],
        [currentDiscountKey]: 0
      };

    case actionTypes.SET_CURRENT_USER:
      return {
        ...state,
        currentUserId: action.payload.userId
      };

    case actionTypes.COMPLETE_SALE:
      // Clear the cart and discount of the current mode
      return {
        ...state,
        [currentCartKey]: [],
        [currentDiscountKey]: 0
      };

    default:
      return state;
  }
};

// Create context
const SalesContext = createContext();

// Provider component
export const SalesProvider = ({ children }) => {
  const [state, dispatch] = useReducer(salesReducer, initialState);
  const { currentUser } = useAuth();

  // Single cart for both modes so current transaction is visible on both Screen A and Screen B
  const currentCart = state.liveCart;
  const currentGlobalDiscount = state.liveDiscount;

  // Calculate totals
  const subtotal = currentCart.reduce((sum, item) => sum + (Number(item.price || 0) * Number(item.quantity || 1)), 0);
  const totalItemDiscount = currentCart.reduce((sum, item) => sum + Number(item.discount || 0), 0);
  const totalDiscount = totalItemDiscount + Number(currentGlobalDiscount || 0);
  const tax = 0; // No tax applied
  const netTotal = subtotal - totalDiscount; // Total without tax

  // Action creators
  const addProduct = (product, quantity = 1) => {
    dispatch({ type: actionTypes.ADD_ITEM, payload: { ...product, quantity } });
  };

  const removeItem = (productId) => {
    dispatch({ type: actionTypes.REMOVE_ITEM, payload: { id: productId } });
  };

  const updateItemQuantity = (productId, quantity) => {
    if (quantity > 0) {
      dispatch({ type: actionTypes.UPDATE_QUANTITY, payload: { id: productId, quantity } });
    } else {
      removeItem(productId); // Remove item if quantity becomes 0 or less
    }
  };

  const updateItemPrice = (productId, price) => {
    dispatch({ type: actionTypes.UPDATE_PRICE, payload: { id: productId, price } });
  };

  const updateItemDiscount = (productId, discount) => {
    dispatch({ type: actionTypes.UPDATE_DISCOUNT, payload: { id: productId, discount } });
  };

  const updateGlobalDiscount = (discount) => {
    dispatch({ type: actionTypes.UPDATE_GLOBAL_DISCOUNT, payload: { discount } });
  };

  const clearCart = () => {
    dispatch({ type: actionTypes.CLEAR_CART });
  };

  const setCurrentUser = (userId) => {
    dispatch({ type: actionTypes.SET_CURRENT_USER, payload: { userId } });
  };

  const setMode = (mode) => {
    if (mode === 'LIVE' || mode === 'DUMMY') {
      dispatch({ type: actionTypes.SET_MODE, payload: { mode } });
    }
  };

  const setSelectedWarehouse = (warehouseId) => {
    dispatch({ type: actionTypes.SET_WAREHOUSE, payload: { warehouseId } });
  };

  const completeSale = async (paymentMethod = 'cash', extraData = {}) => {
    if (currentCart.length === 0) {
      alert('Cannot complete sale: Cart is empty');
      return null;
    }

    try {
      // Prepare sale data with strict number casting
      const saleData = {
        userId: currentUser?.id || state.currentUserId || 1,
        items: currentCart.map(item => {
          const unitPrice = Number(item.price || 0);
          const quantity = Math.max(0, parseInt(item.quantity, 10) || 0);
          const productId = typeof item.id === 'number' ? item.id : parseInt(item.id, 10);
          return {
            productId: Number.isInteger(productId) ? productId : item.id,
            quantity,
            unitPrice,
            totalPrice: Number((quantity * unitPrice).toFixed(2)),
            discountAmount: Number(item.discount || 0),
            name: item.name
          };
        }),
        discountAmount: totalDiscount, // Includes both item discounts and global discount
        subtotal: subtotal,
        netTotal: netTotal,
        taxAmount: 0,
        paymentMethod,
        status: ['cheque', 'credit'].includes(paymentMethod) ? 'pending' : 'completed',
        type: extraData.type || 'sale',
        originalSaleId: extraData.originalSaleId || null,
        notes: state.mode === 'DUMMY' ? (extraData.notes ? `${extraData.notes} | dummy_sales` : 'dummy_sales') : (extraData.notes || null),
        mode: state.mode,
        customerName: extraData.customerName && String(extraData.customerName).trim() ? String(extraData.customerName).trim() : null,
        tenderedAmount: extraData.tenderedAmount || null,
        change: extraData.change || null
      };

      // Returns must always go to /sales so Inventory is updated (stock add back). Dummy endpoint does not update stock.
      const isReturn = (extraData.type || '').toString().toLowerCase() === 'return';
      let result;
      if (state.mode === 'DUMMY' && !isReturn) {
        // Dummy sales only: send to dummy endpoint (no inventory update)
        const dummyPayload = {
          transactionId: `DUMMY-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
          ...saleData
        };
        result = await post('/dummy-transactions', dummyPayload);
      } else {
        // Real sale or return: use /sales so Inventory is updated (decrement on sale, increment on return)
        result = await post('/sales', saleData);
      }

      if (result && (!result.error && result.success !== false)) {
        console.log(`${state.mode} Sale completed successfully:`, result);
        dispatch({ type: actionTypes.COMPLETE_SALE });

        // Return the sale data for receipt printing, ensuring items are included
        // Merge saleData first so result.data (DB record) takes precedence for IDs/dates, but keep items from saleData if missing in result
        return { ...saleData, ...result.data, mode: state.mode };
      } else {
        const errorMessage = result?.message || 'Server Error';
        console.error('Error completing sale:', errorMessage);
        alert('Error completing sale: ' + errorMessage);
        return null;
      }
    } catch (error) {
      console.error('Network error completing sale:', error);
      alert('Network error completing sale: ' + error.message);
      return null;
    }
  };

  const contextValue = {
    ...state,
    selectedWarehouseId: state.selectedWarehouseId,
    setSelectedWarehouse,
    cart: currentCart, // Expose the active cart as 'cart' for compatibility
    globalDiscount: currentGlobalDiscount,
    total: subtotal,
    discount: totalDiscount,
    tax: tax,
    netTotal: netTotal,
    addProduct,
    removeItem,
    updateItemQuantity,
    updateItemPrice,
    updateItemDiscount,
    updateGlobalDiscount,
    clearCart,
    setCurrentUser,
    completeSale,
    setMode
  };

  return (
    <SalesContext.Provider value={contextValue}>
      {children}
    </SalesContext.Provider>
  );
};

// Custom hook to use the sales context
export const useSalesState = () => {
  const context = useContext(SalesContext);
  if (!context) {
    throw new Error('useSalesState must be used within a SalesProvider');
  }
  return context;
};