import React, { useState, useEffect } from 'react';
import { get } from '../../utils/api';
import { useTranslation } from 'react-i18next';

/**
 * Reusable Unit of Measurement (UOM) dropdown
 * Fetches units from /api/units - use when adding/editing products or selling
 * @param {Object} props
 * @param {string|number} props.value - Selected value: unit shortName (e.g. 'pcs') or baseUnitId
 * @param {function} props.onChange - (value, unit) => {} - value is shortName, unit is full object
 * @param {string} props.name - Input name for form
 * @param {string} props.className - CSS class (e.g. 'modern-input')
 * @param {string} props.placeholder - Placeholder text
 * @param {boolean} props.disabled - Disable dropdown
 * @param {string} props.label - Label text
 * @param {string} props.id - Input id
 */
const UOMDropdown = ({
  value,
  onChange,
  name = 'unit',
  className = 'modern-input',
  placeholder,
  disabled = false,
  label,
  id
}) => {
  const { t } = useTranslation();
  const [units, setUnits] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let mounted = true;
    const load = async () => {
      setLoading(true);
      try {
        const res = await get('/units');
        if (res.success && res.data && mounted) {
          setUnits(res.data);
        }
      } catch (e) {
        console.error('Failed to load units:', e);
      } finally {
        if (mounted) setLoading(false);
      }
    };
    load();
    return () => { mounted = false; };
  }, []);

  const displayValue = (() => {
    if (value == null || value === '') return '';
    const byId = units.find(u => u.id === Number(value));
    const byShort = units.find(u => String(u.shortName).toLowerCase() === String(value).toLowerCase());
    const u = byId || byShort;
    return u ? u.shortName : value;
  })();

  const handleChange = (e) => {
    const selected = e.target.value;
    const unit = units.find(u => u.shortName === selected);
    if (onChange) {
      onChange(selected, unit || null);
    }
  };

  return (
    <div>
      {label && (
        <label className="modern-label" htmlFor={id || name}>
          {label}
        </label>
      )}
      <select
        id={id || name}
        name={name}
        value={displayValue}
        onChange={handleChange}
        className={className}
        disabled={disabled || loading}
        placeholder={placeholder}
        style={{ width: '100%' }}
      >
        {placeholder && <option value="">{placeholder}</option>}
        {units.map((u) => (
          <option key={u.id} value={u.shortName}>
            {u.shortName} ({u.unitName})
          </option>
        ))}
        {units.length === 0 && !loading && (
          <option value="pcs">pcs (Piece)</option>
        )}
      </select>
    </div>
  );
};

export default UOMDropdown;
