import React from 'react';
import { useAuth } from './context/AuthContext';
import { BrowserRouter as Router, Routes, Route, Navigate, Link, useLocation, useNavigate } from 'react-router-dom';
import { SalesProvider, useSalesState } from './context/SalesContext';
import { SettingsProvider, useSettings } from './context/SettingsContext';
import { ThemeProvider } from './context/ThemeContext';
import { useTranslation } from 'react-i18next';
import './i18n'; // Initialize i18n
import SalesScreen from './components/SalesScreen';
import ProductManagement from './components/ProductManagement';
import TestScreen from './components/TestScreen';
import StockManagementScreen from './components/StockManagementScreen';
import Dashboard from './components/ABCDashboard';
import TransactionReportScreen from './components/TransactionReportScreen';
import SettingsScreen from './components/SettingsScreen';
import UserManagement from './components/UserManagement';
import ProductCategoryScreen from './components/ProductCategoryScreen';
import ErrorBoundary from './components/common/ErrorBoundary';
import LoginScreen from './components/LoginScreen';
import ProductSearchModal from './components/ProductSearchModal';
import QuickProductModal from './components/QuickProductModal';
import './App.css';
import { registerPOSShortcuts, getPOSKeyboardHandler, initPOSKeyboardHandler } from './utils/keyboardHandler';
import { useGlobalBarcodeListener } from './hooks/useGlobalBarcodeListener';

function AppContent() {
  const { currentUser, logout, isAuthenticated, canAccessSettings, canAccessAdmin } = useAuth();
  const { addProduct, mode, setMode } = useSalesState();
  const { settings } = useSettings();
  const { t, i18n } = useTranslation();
  const [isSearchModalOpen, setIsSearchModalOpen] = React.useState(false);
  const [isQuickProductModalOpen, setIsQuickProductModalOpen] = React.useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  // Global barcode listener: rapid key sequence → navigate to Sales and pass barcode
  useGlobalBarcodeListener(isAuthenticated ? navigate : null);

  // Initialize keyboard shortcuts and global event listeners
  React.useEffect(() => {
    if (isAuthenticated) {
      initPOSKeyboardHandler();
    }
  }, [isAuthenticated]);

  // Listen for global events dispatched from SalesScreen buttons
  React.useEffect(() => {
    const openSearch = () => setIsSearchModalOpen(true);
    const openQuick = () => setIsQuickProductModalOpen(true);
    window.addEventListener('pos-open-search-modal', openSearch);
    window.addEventListener('pos-open-quick-product-modal', openQuick);
    return () => {
      window.removeEventListener('pos-open-search-modal', openSearch);
      window.removeEventListener('pos-open-quick-product-modal', openQuick);
    };
  }, []);

  // Register F2 shortcut (search) globally
  React.useEffect(() => {
    if (!isAuthenticated) return;
    const handler = getPOSKeyboardHandler();
    // Clear any previous to avoid duplicates
    handler.unregisterKey('F2');
    registerPOSShortcuts({
      searchProduct: () => {
        // Avoid opening if a modal is already open
        const isModalOpen = document.querySelector('.modal-overlay');
        if (!isModalOpen) setIsSearchModalOpen(true);
      },
    });
    return () => {
      handler.unregisterKey('F2');
    };
  }, [isAuthenticated]);

  // Standardized global shortcuts: F8 (Add New), F10 (Save), Esc (Cancel) - exclude Sales screen
  React.useEffect(() => {
    if (!isAuthenticated) return;
    const handler = getPOSKeyboardHandler();
    // Always clear before re-register based on route
    handler.unregisterKey('F8');
    handler.unregisterKey('F10');
    handler.unregisterKey('Escape');

    const isSalesScreen = location.pathname === '/sales';
    if (isSalesScreen) {
      return;
    }

    const findVisible = (selector, root = document) => {
      const nodes = Array.from(root.querySelectorAll(selector));
      return nodes.find(el => el.offsetParent !== null);
    };

    // F8: Add New (only when no modal open)
    handler.registerKey('F8', () => {
      const modalOpen = document.querySelector('.modal-overlay');
      if (modalOpen) return;
      const btn = findVisible('[data-pos-action="add-new"]') || null;
      if (btn) btn.click();
      // Product screen fallback: open Quick Product if button not found
      if (!btn && location.pathname.includes('products')) {
        setIsQuickProductModalOpen(true);
      }
    }, { description: 'Add New' });

    // F10: Save inside modal
    handler.registerKey('F10', () => {
      const overlay = document.querySelector('.modal-overlay');
      const modal = overlay?.querySelector('.modal-container') || document.querySelector('.modal-container');
      const saveBtn = modal ? findVisible('[data-pos-action="save"]', modal) : null;
      if (saveBtn) saveBtn.click();
    }, { description: 'Save/Submit' });

    // Esc: Cancel/Close
    handler.registerKey('Escape', () => {
      const overlay = document.querySelector('.modal-overlay');
      const modal = overlay?.querySelector('.modal-container') || document.querySelector('.modal-container');
      const cancelBtn = modal ? findVisible('[data-pos-action="cancel"]', modal) : null;
      if (cancelBtn) {
        cancelBtn.click();
      } else if (overlay) {
        // Fallback: click overlay to close if supported
        overlay.click();
      }
    }, { description: 'Close/Cancel' });

    return () => {
      handler.unregisterKey('F8');
      handler.unregisterKey('F10');
      handler.unregisterKey('Escape');
    };
  }, [isAuthenticated, location.pathname]);

  // Alt+Q: Focus global search bar on any management screen
  React.useEffect(() => {
    if (!isAuthenticated) return;
    const handleAltQ = (e) => {
      if (e.altKey && (e.key === 'q' || e.key === 'Q')) {
        const target = e.target;
        if (target?.tagName === 'INPUT' || target?.tagName === 'TEXTAREA' || target?.tagName === 'SELECT' || target?.isContentEditable) return;
        e.preventDefault();
        const searchInput = document.querySelector('.global-search-input');
        if (searchInput) {
          searchInput.focus();
          searchInput.select?.();
        }
      }
    };
    window.addEventListener('keydown', handleAltQ, { capture: true });
    return () => window.removeEventListener('keydown', handleAltQ, { capture: true });
  }, [isAuthenticated]);

  // Alt+Letter shortcuts for main tabs (J,K,U,I,O,E)
  React.useEffect(() => {
    if (!isAuthenticated) return;
    const altLetterRoutes = {
      j: '/sales',
      k: '/products',
      u: '/stock-management',
      i: '/dashboard',
      o: '/transaction-report',
      e: '/settings',
    };
    const handleAltLetter = (e) => {
      if (!e.altKey) return;
      const key = e.key?.toLowerCase();
      const path = key ? altLetterRoutes[key] : null;
      if (!path) return;
      const target = e.target;
      if (target?.tagName === 'INPUT' || target?.tagName === 'TEXTAREA' || target?.tagName === 'SELECT' || target?.isContentEditable) return;
      e.preventDefault();
      if (location.pathname !== path) navigate(path);
    };
    window.addEventListener('keydown', handleAltLetter, { capture: true });
    return () => window.removeEventListener('keydown', handleAltLetter, { capture: true });
  }, [isAuthenticated, navigate, location.pathname]);

  // Ctrl+Shift+T = Settings > System Test (main tab nav uses Alt+letter only)
  React.useEffect(() => {
    if (!isAuthenticated) return;
    const handleNavShortcut = (e) => {
      if (!e.ctrlKey || !e.shiftKey) return;
      if (e.key.toLowerCase() === 't') {
        const target = e.target;
        if (target?.tagName === 'INPUT' || target?.tagName === 'TEXTAREA' || target?.tagName === 'SELECT' || target?.isContentEditable) return;
        e.preventDefault();
        navigate('/settings?tab=systemTest');
      }
    };
    window.addEventListener('keydown', handleNavShortcut, { capture: true });
    return () => window.removeEventListener('keydown', handleNavShortcut, { capture: true });
  }, [isAuthenticated, navigate]);

  const handleAddProduct = (product, quantity) => {
    const productToAdd = {
      ...product,
      price: product.sellingPrice || product.price,
    };
    addProduct(productToAdd, quantity);
    setIsSearchModalOpen(false);
    setIsQuickProductModalOpen(false);
  };

  // Theme is applied by ThemeContext (light/dark/system + localStorage)

  // Sync language with settings
  React.useEffect(() => {
    if (settings.language && i18n.language !== settings.language) {
      i18n.changeLanguage(settings.language);
    }
  }, [settings.language, i18n]);

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  return (
    <div className="App">
        {/* Common Header with Navigation */}
        <header className="app-header">
          <div className="header-content">
            <h1 className="header-title">
              {settings?.storeName || 'POS'}
            </h1>
            <div className="header-actions">
            <div className="app-navigation">
              <Link to="/sales" className={`nav-button ${location.pathname === '/sales' ? 'active' : ''}`} title={`${t('navigation.sales')} (Alt+J)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg>
                <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.sales')}</span>
                <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>J</kbd>
              </Link>
              <Link to="/products" className={`nav-button ${location.pathname === '/products' || location.pathname === '/categories' ? 'active' : ''}`} title={`${t('navigation.productManagement')} (Alt+K)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.productManagement')}</span>
                <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>K</kbd>
              </Link>

              <Link to="/stock-management" className={`nav-button ${location.pathname === '/stock-management' || location.pathname === '/grn-management' || location.pathname === '/stock-1' || location.pathname === '/warehouse-management' ? 'active' : ''}`} title={`${t('navigation.stockManagement')} (Alt+U)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.stockManagement')}</span>
                <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>U</kbd>
              </Link>
              <Link to="/dashboard" className={`nav-button ${location.pathname === '/dashboard' ? 'active' : ''}`} title={`${t('navigation.dashboard')} (Alt+I)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z" /></svg>
                <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.dashboard')}</span>
                <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>I</kbd>
              </Link>
              <Link to="/transaction-report" className={`nav-button ${location.pathname === '/transaction-report' ? 'active' : ''}`} title={`${t('navigation.transactionReport')} (Alt+O)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
                <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.transactionReport')}</span>
                <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>O</kbd>
              </Link>

              <Link to="/settings" className={`nav-button ${location.pathname === '/settings' || location.pathname === '/users' ? 'active' : ''}`} title={`${t('navigation.settings')} (Alt+E)`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <svg className="nav-icon" style={{ width: '18px', height: '18px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                  <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t('navigation.settings')}</span>
                  <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.85, border: '1px solid currentColor', borderRadius: 3 }}>E</kbd>
                </Link>
              <button
                className="nav-button logout-button"
                onClick={logout}
              >
                <svg style={{ width: '18px', height: '18px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                {currentUser?.username}
              </button>
            </div>
            </div>
          </div>
        </header>

        <div className="app-content">
          <Routes>
            <Route path="/" element={<Navigate to="/sales" replace />} />
            <Route path="/sales" element={<SalesScreen />} />
            <Route path="/products" element={<ErrorBoundary><ProductCategoryScreen /></ErrorBoundary>} />
            <Route path="/categories" element={<ErrorBoundary><ProductCategoryScreen /></ErrorBoundary>} />
            <Route path="/test" element={<TestScreen />} />
            <Route path="/stock-management" element={<StockManagementScreen />} />
            <Route path="/grn-management" element={<Navigate to="/stock-management" replace />} />
            <Route path="/warehouse-management" element={<Navigate to="/stock-management" replace />} />
            <Route path="/stock-1" element={<Navigate to="/stock-management" replace />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/transaction-report" element={<TransactionReportScreen />} />
            <Route path="/settings" element={<SettingsScreen />} />
            <Route path="/users" element={<Navigate to="/settings?tab=users" replace />} />
          </Routes>
        </div>

        <footer className="app-footer" style={{ textAlign: 'center', padding: '10px 16px', fontSize: '12px', color: 'var(--text-muted)', borderTop: '1px solid var(--border-light)', backgroundColor: 'var(--bg-card)' }}>
          © {new Date().getFullYear()} Softimage
        </footer>

        {/* Global Modals */}
        {isSearchModalOpen && (
          <ProductSearchModal
            isOpen={isSearchModalOpen}
            onClose={() => setIsSearchModalOpen(false)}
            onAddProduct={handleAddProduct}
            quantity={1}
          />
        )}

        {isQuickProductModalOpen && (
          <QuickProductModal
            isOpen={isQuickProductModalOpen}
            onClose={() => setIsQuickProductModalOpen(false)}
            onAddProduct={handleAddProduct}
            quantity={1}
          />
        )}
      </div>
  );
}

function App() {
  return (
    <Router basename="/pos-demo">
      <SettingsProvider>
        <ThemeProvider>
          <SalesProvider>
            <Routes>
              <Route path="/login" element={<LoginScreen />} />
              <Route path="/*" element={<AppContent />} />
            </Routes>
          </SalesProvider>
        </ThemeProvider>
      </SettingsProvider>
    </Router>
  );
}

export default App;
