import React, { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import DataActionsShortcutsBar from './common/DataActionsShortcutsBar';
import { getPaymentMethods, PAYMENT_METHODS_STORAGE_KEY } from '../utils/paymentMethods';

const loadMethods = () => getPaymentMethods();

const saveMethods = (arr) => {
  try {
    localStorage.setItem(PAYMENT_METHODS_STORAGE_KEY, JSON.stringify(arr));
  } catch (e) {}
};

const PaymentMethodManagement = () => {
  const { t } = useTranslation();
  const [methods, setMethods] = useState(() => loadMethods());
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [formData, setFormData] = useState({ name: '', code: '' });
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const selected = selectedIndex >= 0 && selectedIndex < methods.length ? methods[selectedIndex] : null;

  const handleOpenModal = (item = null) => {
    setEditingItem(item);
    setFormData(item ? { name: item.name, code: item.code || item.id } : { name: '', code: '' });
    setShowModal(true);
  };

  const handleSave = (e) => {
    e?.preventDefault();
    if (!formData.name?.trim() || !formData.code?.trim()) {
      alert(t('messages.requiredField') || 'Required');
      return;
    }
    const code = formData.code.trim().toLowerCase().replace(/\s+/g, '_');
    const name = formData.name.trim();
    if (editingItem) {
      const next = methods.map(m => m.id === editingItem.id ? { ...m, name, code } : m);
      setMethods(next);
      saveMethods(next);
    } else {
      const id = 'pm_' + Date.now();
      const next = [...methods, { id, name, code }];
      setMethods(next);
      saveMethods(next);
    }
    setShowModal(false);
  };

  const handleDelete = (id) => {
    if (!window.confirm(t('messages.confirmDelete') || 'Delete?')) return;
    const next = methods.filter(m => m.id !== id);
    setMethods(next);
    saveMethods(next);
    setSelectedIndex(-1);
  };

  // Keyboard shortcuts: V view, E edit, Del delete, ArrowUp/ArrowDown navigate
  const handleKeyDown = useCallback((e) => {
    const isInputElement = e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable;
    if (showModal) {
      if (e.key === 'Escape') {
        e.preventDefault();
        setShowModal(false);
        return;
      }
      if (e.key === 'Enter' && e.target.tagName !== 'TEXTAREA') {
        e.preventDefault();
        handleSave(e);
        return;
      }
      return;
    }
    if (isInputElement) return;
    if (e.key === 'v' || e.key === 'e' || e.key === 'Enter') {
      if (selected) {
        e.preventDefault();
        handleOpenModal(selected);
      }
      return;
    }
    if (e.key === 'Delete' && selected) {
      e.preventDefault();
      handleDelete(selected.id);
      return;
    }
    if (e.key === 'ArrowDown' && methods.length > 0) {
      e.preventDefault();
      setSelectedIndex((prev) => Math.min(prev < 0 ? 0 : prev + 1, methods.length - 1));
      return;
    }
    if (e.key === 'ArrowUp' && methods.length > 0) {
      e.preventDefault();
      setSelectedIndex((prev) => Math.max(prev < 0 ? 0 : prev - 1, 0));
      return;
    }
  }, [showModal, methods.length, selected, handleSave, handleDelete]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [handleKeyDown]);

  useEffect(() => {
    if (methods.length === 0) setSelectedIndex(-1);
    else if (selectedIndex >= methods.length) setSelectedIndex(methods.length - 1);
  }, [methods.length, selectedIndex]);

  return (
    <div style={{ padding: '1.5rem' }}>
      <DataActionsShortcutsBar showDelete />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
        <h3 style={{ margin: 0 }}>{t('sales.paymentMethod') || 'Payment Methods'}</h3>
        <button data-pos-action="add-new" className="btn btn-primary" onClick={() => handleOpenModal()}>
          + {t('common.add')}
        </button>
      </div>
      <table className="data-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ borderBottom: '2px solid var(--border-light)' }}>
            <th style={{ padding: 12, textAlign: 'left' }}>Name</th>
            <th style={{ padding: 12, textAlign: 'left' }}>Code</th>
            <th style={{ padding: 12, textAlign: 'center' }}>{t('common.actions')}</th>
          </tr>
        </thead>
        <tbody>
          {methods.map((m, idx) => (
            <tr
              key={m.id}
              tabIndex={idx === 0 ? 0 : -1}
              onClick={() => setSelectedIndex(idx)}
              style={{
                backgroundColor: selectedIndex === idx ? 'var(--primary-subtle)' : 'transparent',
                cursor: 'pointer',
                borderBottom: '1px solid var(--border-light)'
              }}
            >
              <td style={{ padding: 12 }}>{m.name}</td>
              <td style={{ padding: 12 }}>{m.code || m.id}</td>
              <td style={{ padding: 12, display: 'flex', gap: 4 }}>
                <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); handleOpenModal(m); }} title="V/E">{t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd></button>
                <button className="btn btn-sm btn-outline-danger" onClick={(e) => { e.stopPropagation(); handleDelete(m.id); }} title="Del">{t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd></button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div className="modal-container" onClick={e => e.stopPropagation()} style={{ background: 'white', padding: 24, borderRadius: 12, maxWidth: 400 }}>
            <h4 style={{ margin: '0 0 1rem 0' }}>{editingItem ? t('common.edit') : t('common.add')} Payment Method</h4>
            <form onSubmit={handleSave}>
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 14, fontWeight: 600 }}>Name</label>
                <input value={formData.name} onChange={e => setFormData(p => ({ ...p, name: e.target.value }))} className="modern-input" placeholder="e.g. Cash" />
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 14, fontWeight: 600 }}>Code</label>
                <input value={formData.code} onChange={e => setFormData(p => ({ ...p, code: e.target.value }))} className="modern-input" placeholder="e.g. cash" />
              </div>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                <button type="button" data-pos-action="cancel" className="btn btn-secondary" onClick={() => setShowModal(false)}>{t('common.cancel')}</button>
                <button type="submit" data-pos-action="save" className="btn btn-primary">{t('common.save')}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PaymentMethodManagement;
