import React, { useState, useEffect, useCallback, useRef } from 'react';
import { get, del, post } from '../utils/api';
import GlassCard from './common/GlassCard';
import DataActionsShortcutsBar from './common/DataActionsShortcutsBar';
import { formatCurrency } from '../utils/currency';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../context/AuthContext';
import '../styles/antigravity.css';

// Column definitions: id, labelKey, key, align
const COLUMN_DEFS = [
  { id: 'date', labelKey: 'transactionReport.dateTime', key: 'date', align: 'left' },
  { id: 'type', labelKey: 'transactionReport.type', key: 'type', align: 'left' },
  { id: 'reference', labelKey: 'transactionReport.reference', key: 'reference', align: 'left' },
  { id: 'entity', labelKey: 'transactionReport.entity', key: 'entity', align: 'left' },
  { id: 'paymentMethod', labelKey: 'transactionReport.payment', key: 'paymentMethod', align: 'left' },
  { id: 'notes', labelKey: 'transactionReport.notes', key: 'notes', align: 'left' },
  { id: 'discountAmount', labelKey: 'transactionReport.discount', key: 'discountAmount', align: 'right' },
  { id: 'amount', labelKey: 'transactionReport.amount', key: 'amount', align: 'right' },
  { id: 'status', labelKey: 'transactionReport.status', key: 'status', align: 'center' },
];

const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];
const TransactionReportScreen = () => {
  const { t } = useTranslation();
  const { canDelete } = useAuth();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [deletingId, setDeletingId] = useState(null);
  const [viewingTx, setViewingTx] = useState(null);
  const [viewDetailSale, setViewDetailSale] = useState(null); // full sale with items for view popup
  const [viewDetailLoading, setViewDetailLoading] = useState(false);
  const [showColumnPicker, setShowColumnPicker] = useState(false);
  const [error, setError] = useState(null);
  const [selectedForComplete, setSelectedForComplete] = useState(new Set());
  const [showCompleteModal, setShowCompleteModal] = useState(false);
  const [completing, setCompleting] = useState(false);
  const [completeForm, setCompleteForm] = useState({
    chequeNumber: '',
    completedAt: new Date().toISOString().split('T')[0],
    comment: ''
  });

  // Visible columns - default all
  const [visibleColumns, setVisibleColumns] = useState(
    COLUMN_DEFS.reduce((acc, col) => ({ ...acc, [col.id]: true }), {})
  );

  const [filters, setFilters] = useState({
    startDate: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    type: 'all',
    status: 'all',
    paymentMethod: 'all',
    customer: '',
    search: '',
  });

  const fetchTransactions = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const queryParams = new URLSearchParams(filters).toString();
      const response = await get(`/transactions?${queryParams}`);
      if (response && response.success) {
        setTransactions(Array.isArray(response.data) ? response.data : []);
      } else {
        setError(response?.message || t('messages.loadError') || 'Failed to load transactions');
        setTransactions([]);
      }
    } catch (err) {
      console.error('Error fetching transactions:', err);
      setError(err?.message || t('messages.loadError') || 'Failed to load transactions');
      setTransactions([]);
    } finally {
      setLoading(false);
    }
  // Primitives only so we don't refetch on every search keystroke
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filters.startDate, filters.endDate, filters.type, filters.status, filters.paymentMethod, filters.customer, filters.search, t]);

  useEffect(() => {
    fetchTransactions();
  }, [fetchTransactions]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters, transactions.length]);

  // Fetch sale items when viewing a SALE or RETURN transaction
  useEffect(() => {
    if (!viewingTx || (viewingTx.type !== 'SALE' && viewingTx.type !== 'RETURN')) {
      setViewDetailSale(null);
      return;
    }
    const saleId = viewingTx.id || viewingTx.saleId;
    if (!saleId) {
      setViewDetailSale(null);
      return;
    }
    let cancelled = false;
    setViewDetailLoading(true);
    setViewDetailSale(null);
    get(`/sales/${saleId}`)
      .then((res) => {
        if (cancelled || !res?.success) return;
        setViewDetailSale(res.data || null);
      })
      .catch(() => {
        if (!cancelled) setViewDetailSale(null);
      })
      .finally(() => {
        if (!cancelled) setViewDetailLoading(false);
      });
    return () => { cancelled = true; };
  }, [viewingTx?.id, viewingTx?.saleId, viewingTx?.type]);

  const tableBodyRef = useRef(null);
  const selectAllHeaderRef = useRef(null);

  // Keep selectedIndex in range when page/size/data changes; default to first row when data loads
  useEffect(() => {
    const n = paginatedTransactions.length;
    if (n === 0) {
      setSelectedIndex(-1);
      return;
    }
    setSelectedIndex(prev => {
      if (prev < 0) return 0;
      return prev >= n ? n - 1 : prev;
    });
  }, [currentPage, pageSize, transactions.length]);

  // Scroll selected row into view when selection changes
  useEffect(() => {
    if (selectedIndex < 0 || !tableBodyRef.current) return;
    const row = tableBodyRef.current.querySelector(`tr[data-row-index="${selectedIndex}"]`);
    if (row) row.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  }, [selectedIndex]);

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({ ...prev, [name]: value }));
  };

  const handleSearch = (e) => {
    e.preventDefault();
    const form = e.target;
    const fd = new FormData(form);
    const params = {
      startDate: fd.get('startDate') ?? '',
      endDate: fd.get('endDate') ?? '',
      type: fd.get('type') ?? 'all',
      status: fd.get('status') ?? 'all',
      paymentMethod: fd.get('paymentMethod') ?? 'all',
      customer: fd.get('customer') ?? '',
      search: fd.get('search') ?? '',
    };
    setFilters((prev) => ({ ...prev, ...params }));
    setLoading(true);
    setError(null);
    const queryString = new URLSearchParams(params).toString();
    get(`/transactions?${queryString}`)
      .then((response) => {
        if (response && response.success) {
          setTransactions(Array.isArray(response.data) ? response.data : []);
        } else {
          setError(response?.message || t('messages.loadError') || 'Failed to load transactions');
          setTransactions([]);
        }
      })
      .catch((err) => {
        console.error('Error fetching transactions:', err);
        setError(err?.message || t('messages.loadError') || 'Failed to load transactions');
        setTransactions([]);
      })
      .finally(() => setLoading(false));
  };

  const toggleColumn = (colId) => {
    setVisibleColumns(prev => ({ ...prev, [colId]: !prev[colId] }));
  };

  const isPendingSale = (tx) => tx.type === 'SALE' && tx.status === 'pending';
  const toggleSelectForComplete = (saleId, checked) => {
    setSelectedForComplete(prev => {
      const next = new Set(prev);
      if (checked) next.add(saleId); else next.delete(saleId);
      return next;
    });
  };
  const openCompleteModal = (saleIds) => {
    setSelectedForComplete(new Set(saleIds));
    setCompleteForm({
      chequeNumber: '',
      completedAt: new Date().toISOString().split('T')[0],
      comment: ''
    });
    setShowCompleteModal(true);
  };
  const handleCompleteSubmit = async (e) => {
    e.preventDefault();
    const ids = Array.from(selectedForComplete);
    if (ids.length === 0) return;
    try {
      setCompleting(true);
      const res = await post('/sales/complete', {
        saleIds: ids,
        chequeNumber: completeForm.chequeNumber.trim() || undefined,
        completedAt: completeForm.completedAt || new Date().toISOString().split('T')[0],
        comment: completeForm.comment.trim() || undefined
      });
      if (res && res.success) {
        setShowCompleteModal(false);
        setSelectedForComplete(new Set());
        fetchTransactions();
      } else {
        alert(res?.message || t('messages.saveError') || 'Failed to complete');
      }
    } catch (err) {
      console.error(err);
      alert(err?.message || t('messages.saveError') || 'Failed to complete');
    } finally {
      setCompleting(false);
    }
  };

  const visibleCols = COLUMN_DEFS.filter(col => visibleColumns[col.id]);

  const totalPages = Math.max(1, Math.ceil(transactions.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const paginatedTransactions = transactions.slice(startIndex, startIndex + pageSize);
  const pendingOnPage = paginatedTransactions.filter(isPendingSale);
  const pendingInReport = transactions.filter(isPendingSale);
  const pendingIdsOnPage = pendingOnPage.map(tx => tx.id);
  const allOnPageSelected = pendingIdsOnPage.length > 0 && pendingIdsOnPage.every(id => selectedForComplete.has(id));
  const someOnPageSelected = pendingIdsOnPage.some(id => selectedForComplete.has(id));

  // Header "select all" checkbox indeterminate state (after allOnPageSelected/someOnPageSelected are defined)
  useEffect(() => {
    if (!selectAllHeaderRef.current || pendingOnPage.length === 0) return;
    selectAllHeaderRef.current.checked = allOnPageSelected;
    selectAllHeaderRef.current.indeterminate = someOnPageSelected && !allOnPageSelected;
  }, [allOnPageSelected, someOnPageSelected, pendingOnPage.length]);

  const selectAllOnPage = () => {
    if (allOnPageSelected) {
      setSelectedForComplete(prev => {
        const next = new Set(prev);
        pendingIdsOnPage.forEach(id => next.delete(id));
        return next;
      });
    } else {
      setSelectedForComplete(prev => {
        const next = new Set(prev);
        pendingIdsOnPage.forEach(id => next.add(id));
        return next;
      });
    }
  };
  const selectAllPendingInReport = () => {
    const allIds = pendingInReport.map(tx => tx.id);
    setSelectedForComplete(prev => (prev.size === allIds.length ? new Set() : new Set(allIds)));
  };
  const clearSelection = () => setSelectedForComplete(new Set());

  const handleDelete = useCallback(async (tx) => {
    if (!window.confirm(t('transactionReport.confirmDelete'))) return;
    if (!tx.id && !tx.saleId) {
      alert(t('transactionReport.deleteNotSupported'));
      return;
    }
    try {
      setDeletingId(tx.id || tx.saleId);
      const endpoint = tx.type === 'GRN' ? `/grns/${tx.id}` : tx.type === 'DUMMY' ? `/dummy-transactions/${tx.id}` : `/sales/${tx.id || tx.saleId}`;
      const result = await del(endpoint);
      if (result?.success) {
        setTransactions(prev => prev.filter(t => t.reference !== tx.reference));
      } else {
        alert(result?.message || t('messages.deleteError'));
      }
    } catch (err) {
      console.error('Delete failed', err);
      alert(t('messages.deleteError'));
    } finally {
      setDeletingId(null);
    }
  }, [t]);

  // Keyboard shortcuts (like Transaction History)
  useEffect(() => {
    const onKey = (e) => {
      const target = e.target;
      if (target?.tagName === 'INPUT' || target?.tagName === 'TEXTAREA' || target?.tagName === 'SELECT') return;
      if (viewingTx || showCompleteModal) {
        if (e.key === 'Escape') {
          e.preventDefault();
          setViewingTx(null);
          if (!completing) setShowCompleteModal(false);
        }
        return;
      }
      if (e.key === 'Escape') {
        setViewingTx(null);
        setShowColumnPicker(false);
        return;
      }
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex(prev => Math.min(prev + 1, paginatedTransactions.length - 1));
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex(prev => Math.max(prev - 1, 0));
      } else if (e.key === 'Enter' || e.key.toLowerCase() === 'v') {
        e.preventDefault();
        const tx = paginatedTransactions[selectedIndex];
        if (tx) setViewingTx(tx);
      } else if (e.key.toLowerCase() === 'e') {
        e.preventDefault();
        const tx = paginatedTransactions[selectedIndex];
        if (tx) setViewingTx(tx);
      } else if (e.key === 'Delete' && canDelete) {
        e.preventDefault();
        const tx = paginatedTransactions[selectedIndex];
        if (tx) handleDelete(tx);
      }
    };
    window.addEventListener('keydown', onKey, { capture: true });
    return () => window.removeEventListener('keydown', onKey, { capture: true });
  }, [paginatedTransactions, selectedIndex, viewingTx, showCompleteModal, completing, canDelete, handleDelete]);

  const exportReport = () => {
    const dataToExport = transactions.length > 0 ? transactions : [];
    if (dataToExport.length === 0) {
      alert(t('transactionReport.noDataToExport'));
      return;
    }
    const headers = visibleCols.map(c => t(c.labelKey));
    const rows = dataToExport.map(tx => {
      return visibleCols.map(col => {
        let val = tx[col.key];
        if (col.key === 'date') val = new Date(tx.date).toLocaleString();
        if (col.key === 'amount' || col.key === 'discountAmount') val = val ?? '';
        return `"${String(val ?? '').replace(/"/g, '""')}"`;
      }).join(',');
    });
    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `transaction_report_${filters.startDate}_to_${filters.endDate}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'SALE': return 'var(--success)';
      case 'RETURN': return 'var(--warning)';
      case 'GRN': return 'var(--primary)';
      case 'DUMMY': return 'var(--info, #0ea5e9)';
      default: return 'var(--text-muted)';
    }
  };

  const renderCell = (tx, col) => {
    const key = col.key;
    const val = tx[key];
    if (key === 'date') {
      return (
        <>
          <div style={{ fontWeight: 600 }}>{new Date(tx.date).toLocaleDateString()}</div>
          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{new Date(tx.date).toLocaleTimeString()}</div>
        </>
      );
    }
    if (key === 'type') {
      return (
        <span style={{
          padding: '0.25rem 0.6rem',
          borderRadius: 'var(--radius-sm)',
          fontSize: '0.75rem',
          fontWeight: 800,
          backgroundColor: 'var(--bg-main)',
          border: `1px solid ${getTypeColor(val)}`,
          color: getTypeColor(val)
        }}>
          {val}
        </span>
      );
    }
    if (key === 'discountAmount') {
      return val > 0 ? `-${formatCurrency(val)}` : '-';
    }
    if (key === 'amount') return formatCurrency(val ?? 0);
    if (key === 'status') {
      const c = val === 'completed' ? 'var(--success)' : val === 'void' ? 'var(--danger)' : 'var(--warning)';
      return (
        <>
          <span style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: c, display: 'inline-block', marginRight: 6 }} />
          <span style={{ textTransform: 'capitalize' }}>{val}</span>
        </>
      );
    }
    return (val ?? '-').toString();
  };

  return (
    <div className="transaction-report-root animate-fade-in" data-screen="transaction-report" style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0, backgroundColor: 'var(--bg-main)', flex: 1, position: 'relative', overflow: 'hidden' }}>
      <div style={{ flex: 1, padding: '20px', minHeight: 0, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={{ width: '100%', maxWidth: '1200px', margin: '0 auto', flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          {/* Screen header: title left, shortcuts, filters + actions right (like Product) */}
          <div style={{ flexShrink: 0, marginBottom: '12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
            <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '700', color: 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '10px' }}>
              <svg style={{ width: '28px', height: '28px', color: 'var(--primary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              {t('transactionReport.title')}
            </h2>
            <div className="transaction-report-shortcuts" style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem 1rem', alignItems: 'center', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>↑/↓</kbd> {t('dataActions.navigate')}</span>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>Enter</kbd>/<kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>V</kbd> {t('dataActions.view')}</span>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>E</kbd> {t('dataActions.edit')}</span>
              {canDelete && <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>Del</kbd> {t('dataActions.delete')}</span>}
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>Esc</kbd> {t('dataActions.close')}</span>
            </div>
            <form onSubmit={handleSearch} style={{ display: 'flex', flexWrap: 'wrap', gap: '8px 12px', alignItems: 'flex-end' }}>
              <input
                type="text"
                name="search"
                value={filters.search}
                onChange={handleFilterChange}
                placeholder={t('transactionReport.searchPlaceholder')}
                className="modern-input"
                style={{ padding: '8px 12px', width: 140, boxSizing: 'border-box', minWidth: 0 }}
              />
              <input
                type="text"
                name="customer"
                value={filters.customer}
                onChange={handleFilterChange}
                placeholder={t('transactionReport.customerFilterPlaceholder') || 'Customer name'}
                className="modern-input"
                style={{ padding: '8px 12px', width: 130, boxSizing: 'border-box', minWidth: 0 }}
                aria-label="Customer"
              />
              <select name="type" value={filters.type} onChange={handleFilterChange} className="modern-input" style={{ padding: '8px 12px', width: 100, minWidth: 0 }} aria-label="Type">
                <option value="all">{t('transactionReport.allTypes')}</option>
                <option value="sale">{t('transactionReport.salesOnly')}</option>
                <option value="return">{t('transactionReport.returnsOnly')}</option>
                <option value="grn">GRN</option>
                <option value="dummy">Dummy</option>
              </select>
              <select name="status" value={filters.status} onChange={handleFilterChange} className="modern-input" style={{ padding: '8px 12px', width: 110, minWidth: 0 }} aria-label="Status">
                <option value="all">{t('transactionReport.allStatus') || 'All status'}</option>
                <option value="pending">{t('transactionReport.statusPending') || 'Pending'}</option>
                <option value="completed">{t('transactionReport.statusCompleted') || 'Completed'}</option>
                <option value="void">{t('transactionReport.statusVoid') || 'Void'}</option>
              </select>
              <select name="paymentMethod" value={filters.paymentMethod} onChange={handleFilterChange} className="modern-input" style={{ padding: '8px 12px', width: 110, minWidth: 0 }} aria-label="Payment method">
                <option value="all">{t('transactionReport.allPayment') || 'All payment'}</option>
                <option value="cash">{t('sales.cash')}</option>
                <option value="card">{t('sales.card')}</option>
                <option value="digital">{t('sales.digital')}</option>
                <option value="cheque">{t('transactionReport.cheque') || 'Cheque'}</option>
                <option value="credit">{t('transactionReport.credit') || 'Credit'}</option>
              </select>
              <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                <input type="date" name="startDate" value={filters.startDate} onChange={handleFilterChange} className="modern-input" style={{ padding: '8px', width: 130 }} aria-label="Start date" title="Start date" />
                <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>–</span>
                <input type="date" name="endDate" value={filters.endDate} onChange={handleFilterChange} className="modern-input" style={{ padding: '8px', width: 130 }} aria-label="End date" title="End date" />
              </div>
              <button type="submit" className="btn btn-outline-primary" style={{ padding: '8px 14px' }}>{t('transactionReport.filter')}</button>
              <button type="button" onClick={() => setFilters({ startDate: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], endDate: new Date().toISOString().split('T')[0], type: 'all', status: 'all', paymentMethod: 'all', customer: '', search: '' })} className="btn btn-outline-primary" style={{ padding: '8px 12px' }}>{t('transactionReport.clearFilters')}</button>
              <button type="button" onClick={() => setShowColumnPicker(!showColumnPicker)} className="btn btn-outline-primary" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 14px' }}>
                <svg style={{ width: 16, height: 16 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>
                {t('transactionReport.columns')}
              </button>
              <button type="button" onClick={exportReport} className="btn btn-outline-primary" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 14px' }}>
                <svg style={{ width: 16, height: 16 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                {t('transactionReport.exportReport')}
              </button>
              <button type="button" onClick={fetchTransactions} className="btn btn-primary" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 14px' }}>
                <svg style={{ width: 16, height: 16 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                {t('transactionReport.refresh')}
              </button>
            </form>
          </div>

          <DataActionsShortcutsBar showDelete={canDelete} showCopy={false} />

          {/* Column picker dropdown */}
          {showColumnPicker && (
            <GlassCard style={{ position: 'absolute', top: 80, right: 40, zIndex: 100, padding: '1rem', minWidth: 220 }}>
              <h4 style={{ margin: '0 0 0.75rem 0', fontSize: '0.9rem' }}>{t('transactionReport.selectColumns')}</h4>
              {COLUMN_DEFS.map(col => (
                <label key={col.id} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!visibleColumns[col.id]} onChange={() => toggleColumn(col.id)} />
                  <span style={{ fontSize: '0.9rem' }}>{t(col.labelKey)}</span>
                </label>
              ))}
            </GlassCard>
          )}

          {error && (
            <div style={{ marginBottom: '1rem', padding: '1rem', backgroundColor: 'var(--danger)', color: 'white', borderRadius: 'var(--radius-md)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>{error}</span>
              <button onClick={() => setError(null)} style={{ background: 'rgba(255,255,255,0.3)', border: 'none', borderRadius: 4, padding: '4px 8px', cursor: 'pointer', color: 'white' }}>×</button>
            </div>
          )}

          {pendingInReport.length > 0 && (
            <div style={{ marginBottom: '1rem', padding: '0.75rem 1rem', backgroundColor: 'var(--bg-subtle)', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-light)', display: 'flex', alignItems: 'center', gap: '0.75rem', flexWrap: 'wrap' }}>
              <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                {selectedForComplete.size > 0 ? `${selectedForComplete.size} selected` : `${pendingInReport.length} pending — select below to complete`}
              </span>
              <button type="button" onClick={selectAllOnPage} style={{ padding: '0.4rem 0.75rem', fontSize: '0.85rem', border: '1px solid var(--border-light)', background: 'var(--bg-main)', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontWeight: 600 }}>
                {allOnPageSelected ? 'Deselect this page' : 'Select all (this page)'}
              </button>
              <button type="button" onClick={selectAllPendingInReport} style={{ padding: '0.4rem 0.75rem', fontSize: '0.85rem', border: '1px solid var(--border-light)', background: 'var(--bg-main)', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontWeight: 600 }}>
                {selectedForComplete.size === pendingInReport.length ? 'Deselect all' : `Select all (${pendingInReport.length} pending)`}
              </button>
              {selectedForComplete.size > 0 && (
                <button type="button" onClick={clearSelection} style={{ padding: '0.4rem 0.75rem', fontSize: '0.85rem', border: '1px solid var(--border-light)', background: 'var(--bg-main)', borderRadius: 'var(--radius-md)', cursor: 'pointer' }}>
                  Clear selection
                </button>
              )}
              <button
                type="button"
                onClick={() => openCompleteModal(selectedForComplete.size > 0 ? Array.from(selectedForComplete) : pendingIdsOnPage)}
                disabled={selectedForComplete.size === 0 && pendingOnPage.length === 0}
                style={{ padding: '0.5rem 1rem', backgroundColor: (selectedForComplete.size > 0 || pendingOnPage.length > 0) ? 'var(--success)' : 'var(--text-muted)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: (selectedForComplete.size > 0 || pendingOnPage.length > 0) ? 'pointer' : 'not-allowed', fontWeight: 600 }}
              >
                {selectedForComplete.size > 0 ? `Complete ${selectedForComplete.size} selected` : pendingOnPage.length > 0 ? 'Complete all on this page' : 'Complete selected'}
              </button>
            </div>
          )}

          {/* Table card - same structure as Product screen */}
          <GlassCard style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 0 }}>
            <div className="glass-panel" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1rem', borderBottom: '1px solid var(--glass-border)', borderRadius: '16px 16px 0 0', fontWeight: 'bold', color: 'var(--text-muted)' }}>
              <h3 style={{ margin: 0 }}>{t('transactionReport.title')} ({transactions.length})</h3>
            </div>
            {loading ? (
              <div style={{ textAlign: 'center', padding: '40px' }}>
                <p>{t('common.loading')}</p>
              </div>
            ) : transactions.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-muted)' }}>
                <p>{t('transactionReport.noData')}</p>
              </div>
            ) : (
              <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0 }}>
                <div ref={tableBodyRef} tabIndex={0} style={{ overflow: 'auto', overflowX: 'auto', overflowY: 'auto', flex: 1, minHeight: 0, outline: 'none', isolation: 'isolate' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 900 }}>
                    <thead>
                      <tr className="glass-panel" style={{ borderBottom: '1px solid var(--glass-border)', position: 'sticky', top: 0, background: 'var(--glass-bg)', backdropFilter: 'blur(var(--blur-strength))', zIndex: 10, color: 'var(--text-muted)', boxShadow: '0 1px 0 var(--glass-border)' }}>
                        {pendingInReport.length > 0 && (
                          <th style={{ padding: '12px', width: 44, textAlign: 'center', fontSize: '14px', fontWeight: '600', position: 'sticky', left: 0, zIndex: 11, background: 'var(--glass-bg)', boxShadow: '2px 0 0 var(--glass-border)' }} onClick={e => e.stopPropagation()}>
                            {pendingOnPage.length > 0 ? (
                              <input ref={selectAllHeaderRef} type="checkbox" onChange={() => selectAllOnPage()} style={{ cursor: 'pointer', width: 16, height: 16 }} title={allOnPageSelected ? 'Deselect all on this page' : 'Select all on this page'} />
                            ) : (
                              <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }} title="Select">✓</span>
                            )}
                          </th>
                        )}
                        {visibleCols.map((col, cidx) => (
                          <th key={col.id} style={{ padding: '12px', textAlign: col.align, fontSize: '14px', fontWeight: '600', ...(pendingInReport.length > 0 ? (cidx === 0 ? { position: 'sticky', left: 44, zIndex: 11, background: 'var(--glass-bg)', boxShadow: '2px 0 0 var(--glass-border)', minWidth: 120 } : {}) : cidx === 0 ? { position: 'sticky', left: 0, zIndex: 11, background: 'var(--glass-bg)', boxShadow: '2px 0 0 var(--glass-border)', minWidth: 120 } : {}), ...(pendingInReport.length > 0 && cidx > 0 ? {} : {}) }}>
                            {t(col.labelKey)}
                          </th>
                        ))}
                        <th style={{ padding: '12px', textAlign: 'right', fontSize: '14px', fontWeight: '600', background: 'var(--glass-bg)' }}>{t('transactionReport.actions')}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {paginatedTransactions.map((tx, idx) => (
                        <tr
                          key={`${tx.type}-${tx.id || tx.reference}-${idx}`}
                          data-row-index={idx}
                          onClick={() => setSelectedIndex(idx)}
                          className="inventory-row"
                          style={{
                            borderBottom: '1px solid rgba(255,255,255,0.03)',
                            backgroundColor: idx === selectedIndex ? 'var(--primary-subtle)' : 'transparent',
                            borderLeft: idx === selectedIndex ? '4px solid var(--primary)' : '4px solid transparent',
                            cursor: 'pointer',
                            transition: 'background 0.2s',
                            color: 'var(--text-main)'
                          }}
                        >
                      {pendingInReport.length > 0 && (
                        <td style={{ padding: '0.75rem 0.5rem', textAlign: 'center', position: 'sticky', left: 0, zIndex: 1, background: idx === selectedIndex ? 'var(--primary-subtle)' : 'var(--bg-main)', boxShadow: '2px 0 0 var(--glass-border)' }} onClick={e => e.stopPropagation()}>
                          {isPendingSale(tx) ? (
                            <input
                              type="checkbox"
                              checked={selectedForComplete.has(tx.id)}
                              onChange={(e) => toggleSelectForComplete(tx.id, e.target.checked)}
                              title={t('transactionReport.selectToComplete') || 'Select to complete'}
                            />
                          ) : (
                            <span style={{ color: 'var(--text-muted)' }}>–</span>
                          )}
                        </td>
                      )}
                      {visibleCols.map((col, cidx) => (
                        <td key={col.id} style={{ padding: '0.75rem 1rem', textAlign: col.align, fontSize: '0.9rem', ...(cidx === 0 ? { position: 'sticky', left: pendingInReport.length > 0 ? 44 : 0, zIndex: 1, background: idx === selectedIndex ? 'var(--primary-subtle)' : 'var(--bg-main)', boxShadow: '2px 0 0 var(--glass-border)', minWidth: 120 } : {}) }}>
                          {renderCell(tx, col)}
                        </td>
                      ))}
                      <td style={{ padding: '0.75rem 1rem', textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                        {isPendingSale(tx) && (
                          <button
                            onClick={() => openCompleteModal([tx.id])}
                            style={{ padding: '4px 8px', marginRight: 6, fontSize: '0.75rem', border: 'none', background: 'var(--success)', color: 'white', borderRadius: 4, cursor: 'pointer' }}
                          >
                            Complete
                          </button>
                        )}
                        <button
                          onClick={() => setViewingTx(tx)}
                          style={{ padding: '4px 8px', marginRight: 6, fontSize: '0.75rem', border: 'none', background: 'var(--primary)', color: 'white', borderRadius: 4, cursor: 'pointer' }}
                        >
                          {t('common.view')}
                        </button>
                        {canDelete && (
                          <button
                            onClick={() => handleDelete(tx)}
                            disabled={deletingId === (tx.id || tx.saleId)}
                            style={{ padding: '4px 8px', fontSize: '0.75rem', border: 'none', background: 'var(--danger)', color: 'white', borderRadius: 4, cursor: 'pointer' }}
                          >
                            {t('common.delete')}
                          </button>
                        )}
                      </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                {/* Pagination - table footer */}
                <div style={{ padding: '1rem', borderTop: '1px solid var(--border-light)', backgroundColor: 'var(--bg-subtle)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>
                  {t('transactionReport.showing')} {startIndex + 1}–{Math.min(startIndex + pageSize, transactions.length)} {t('transactionReport.of')} {transactions.length}
                </span>
                <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>|</span>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: '0.85rem' }}>
                  <span style={{ color: 'var(--text-muted)' }}>{t('transactionReport.rowsPerPage') || 'Per page'}:</span>
                  <select
                    value={pageSize}
                    onChange={(e) => { setPageSize(Number(e.target.value)); setCurrentPage(1); }}
                    style={{ padding: '4px 8px', borderRadius: 4, border: '1px solid var(--border-light)' }}
                  >
                    {PAGE_SIZE_OPTIONS.map(n => (
                      <option key={n} value={n}>{n}</option>
                    ))}
                  </select>
                </label>
              </div>
              <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                <button
                  onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                  disabled={currentPage <= 1}
                  style={{ padding: '6px 12px', border: '1px solid var(--border-light)', background: 'var(--bg-card)', borderRadius: 4, cursor: 'pointer', fontWeight: 600 }}
                >
                  {t('sales.prev')}
                </button>
                <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--text-main)' }}>{t('sales.page')} {currentPage} / {totalPages}</span>
                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                  let p;
                  if (totalPages <= 5) p = i + 1;
                  else if (currentPage <= 3) p = i + 1;
                  else if (currentPage >= totalPages - 2) p = totalPages - 4 + i;
                  else p = currentPage - 2 + i;
                  return (
                    <button
                      key={p}
                      onClick={() => setCurrentPage(p)}
                      style={{
                        padding: '6px 10px',
                        minWidth: 36,
                        border: '1px solid var(--border-light)',
                        background: currentPage === p ? 'var(--primary)' : 'var(--bg-card)',
                        color: currentPage === p ? 'white' : 'var(--text-main)',
                        borderRadius: 4,
                        cursor: 'pointer',
                        fontWeight: currentPage === p ? 700 : 500,
                        fontSize: '0.85rem'
                      }}
                    >
                      {p}
                    </button>
                  );
                })}
                <button
                  onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                  disabled={currentPage >= totalPages}
                  style={{ padding: '6px 12px', border: '1px solid var(--border-light)', background: 'var(--bg-card)', borderRadius: 4, cursor: 'pointer', fontWeight: 600 }}
                >
                  {t('sales.next')}
                </button>
              </div>
            </div>
              </div>
            )}
          </GlassCard>
        </div>
      </div>

      {/* View detail modal */}
      {viewingTx && (
        <div
          className="modal-overlay"
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', justifyContent: 'center', alignItems: 'center', padding: 20 }}
          onClick={() => { setViewingTx(null); setViewDetailSale(null); }}
        >
          <GlassCard
            style={{ maxWidth: 600, width: '100%', maxHeight: '90vh', overflow: 'auto' }}
            onClick={e => e.stopPropagation()}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3 style={{ margin: 0 }}>{t('transactionReport.detailTitle')}</h3>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                {viewingTx.type === 'SALE' && viewingTx.status === 'pending' && (
                  <button
                    type="button"
                    onClick={() => { setViewingTx(null); setViewDetailSale(null); openCompleteModal([viewingTx.id]); }}
                    style={{ padding: '6px 14px', backgroundColor: 'var(--success)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontWeight: 600, fontSize: '0.9rem' }}
                  >
                    {t('transactionReport.completeThis') || 'Complete this sale'}
                  </button>
                )}
                <button onClick={() => { setViewingTx(null); setViewDetailSale(null); }} style={{ background: 'none', border: 'none', fontSize: 24, cursor: 'pointer', color: 'var(--text-muted)' }}>×</button>
              </div>
            </div>
            <div style={{ display: 'grid', gap: '0.5rem' }}>
              {COLUMN_DEFS.map(col => (
                <div key={col.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid var(--border-light)' }}>
                  <span style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t(col.labelKey)}</span>
                  <span style={{ fontWeight: 600 }}>{renderCell(viewingTx, col)}</span>
                </div>
              ))}
            </div>
            {/* Products sold - for SALE / RETURN */}
            {(viewingTx.type === 'SALE' || viewingTx.type === 'RETURN') && (
              <div style={{ marginTop: '1.25rem', borderTop: '1px solid var(--border-light)', paddingTop: '1rem' }}>
                <h4 style={{ margin: '0 0 0.75rem 0', fontSize: '0.95rem', color: 'var(--text-main)' }}>
                  {t('transactionReport.productsSold') || 'Products in this transaction'}
                </h4>
                {viewDetailLoading ? (
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t('common.loading')}</p>
                ) : viewDetailSale?.items?.length > 0 ? (
                  <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                      <thead>
                        <tr style={{ borderBottom: '1px solid var(--border-light)', color: 'var(--text-muted)' }}>
                          <th style={{ textAlign: 'left', padding: '6px 8px', fontWeight: 600 }}>{t('transactionReport.product') || 'Product'}</th>
                          <th style={{ textAlign: 'right', padding: '6px 8px', fontWeight: 600 }}>{t('sales.quantity') || 'Qty'}</th>
                          <th style={{ textAlign: 'right', padding: '6px 8px', fontWeight: 600 }}>{t('transactionReport.unitPrice') || 'Unit price'}</th>
                          <th style={{ textAlign: 'right', padding: '6px 8px', fontWeight: 600 }}>{t('transactionReport.lineTotal') || 'Total'}</th>
                        </tr>
                      </thead>
                      <tbody>
                        {viewDetailSale.items.map((item, idx) => (
                          <tr key={item.id || idx} style={{ borderBottom: '1px solid var(--border-light)' }}>
                            <td style={{ padding: '6px 8px' }}>{item.product?.name || t('common.product') || 'Product'}</td>
                            <td style={{ padding: '6px 8px', textAlign: 'right' }}>{item.quantity ?? 0}</td>
                            <td style={{ padding: '6px 8px', textAlign: 'right' }}>{formatCurrency(parseFloat(item.unitPrice) || 0)}</td>
                            <td style={{ padding: '6px 8px', textAlign: 'right', fontWeight: 600 }}>{formatCurrency(parseFloat(item.totalPrice) || 0)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                ) : viewDetailSale && (!viewDetailSale.items || viewDetailSale.items.length === 0) ? (
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t('transactionReport.noItems') || 'No line items.'}</p>
                ) : null}
              </div>
            )}
          </GlassCard>
        </div>
      )}

      {/* Complete pending transactions modal */}
      {showCompleteModal && (
        <div
          className="modal-overlay"
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', justifyContent: 'center', alignItems: 'center', padding: 20 }}
          onClick={() => !completing && setShowCompleteModal(false)}
        >
          <GlassCard
            style={{ maxWidth: 420, width: '100%' }}
            onClick={e => e.stopPropagation()}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3 style={{ margin: 0 }}>Complete transaction(s)</h3>
              <button type="button" onClick={() => !completing && setShowCompleteModal(false)} style={{ background: 'none', border: 'none', fontSize: 24, cursor: 'pointer', color: 'var(--text-muted)' }}>×</button>
            </div>
            <p style={{ margin: '0 0 1rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
              {selectedForComplete.size} pending transaction(s) will be marked as completed.
            </p>
            <form onSubmit={handleCompleteSubmit}>
              <div style={{ marginBottom: '1rem' }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: '0.85rem', fontWeight: 600 }}>Cheque No</label>
                <input
                  type="text"
                  value={completeForm.chequeNumber}
                  onChange={e => setCompleteForm(prev => ({ ...prev, chequeNumber: e.target.value }))}
                  placeholder="Optional"
                  className="modern-input"
                  style={{ padding: '0.5rem 0.75rem', width: '100%' }}
                />
              </div>
              <div style={{ marginBottom: '1rem' }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: '0.85rem', fontWeight: 600 }}>Complete date</label>
                <input
                  type="date"
                  value={completeForm.completedAt}
                  onChange={e => setCompleteForm(prev => ({ ...prev, completedAt: e.target.value }))}
                  className="modern-input"
                  style={{ padding: '0.5rem 0.75rem', width: '100%' }}
                />
              </div>
              <div style={{ marginBottom: '1rem' }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: '0.85rem', fontWeight: 600 }}>Comment</label>
                <textarea
                  value={completeForm.comment}
                  onChange={e => setCompleteForm(prev => ({ ...prev, comment: e.target.value }))}
                  placeholder="Optional"
                  rows={3}
                  className="modern-input"
                  style={{ padding: '0.5rem 0.75rem', width: '100%', resize: 'vertical' }}
                />
              </div>
              <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end' }}>
                <button type="button" onClick={() => !completing && setShowCompleteModal(false)} style={{ padding: '0.5rem 1rem', border: '1px solid var(--border-light)', background: 'var(--bg-card)', borderRadius: 'var(--radius-md)', cursor: 'pointer' }}>Cancel</button>
                <button type="submit" disabled={completing} style={{ padding: '0.5rem 1.25rem', backgroundColor: 'var(--success)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: completing ? 'not-allowed' : 'pointer', fontWeight: 600 }}>
                  {completing ? 'Saving...' : 'Complete'}
                </button>
              </div>
            </form>
          </GlassCard>
        </div>
      )}
    </div>
  );
};

export default TransactionReportScreen;
