import { useEffect, useRef } from 'react';

/**
 * Global barcode listener: detects rapid key sequences (hardware scanner behavior)
 * and navigates to Sales with the barcode. Uses a buffer and short timeout (50ms)
 * to distinguish scanner input from human typing. Ignores events when focus is
 * in input/textarea/select/contenteditable.
 */
const BARCODE_KEY_TIMEOUT_MS = 50;
const MIN_BARCODE_LENGTH = 3;
const MAX_BUFFER_AGE_MS = 2000;

export function useGlobalBarcodeListener(navigate) {
  const bufferRef = useRef([]);
  const lastKeyAtRef = useRef(0);
  const processTimerRef = useRef(null);

  useEffect(() => {
    if (!navigate) return;

    const isEditable = (el) => {
      if (!el || !el.tagName) return false;
      const tag = el.tagName.toUpperCase();
      if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
      return el.isContentEditable === true;
    };

    const flushAndProcess = () => {
      processTimerRef.current = null;
      const buffer = bufferRef.current;
      bufferRef.current = [];
      if (buffer.length < MIN_BARCODE_LENGTH + 1) return; // need at least 3 chars + Enter
      const last = buffer[buffer.length - 1];
      const isEnter = last === '\r' || last === '\n' || (typeof last === 'string' && last.charCodeAt?.(0) === 13);
      if (!isEnter) return;
      const barcode = buffer.slice(0, -1).join('').trim();
      if (barcode.length < MIN_BARCODE_LENGTH) return;
      sessionStorage.setItem('pendingBarcode', barcode);
      if (window.location.pathname !== '/sales') {
        navigate('/sales');
      } else {
        window.dispatchEvent(new CustomEvent('pos-barcode-scan', { detail: { barcode } }));
      }
    };

    const onKeyDown = (e) => {
      if (isEditable(e.target)) return;

      const now = Date.now();
      if (now - lastKeyAtRef.current > BARCODE_KEY_TIMEOUT_MS) {
        bufferRef.current = [];
      }
      lastKeyAtRef.current = now;

      const key = e.key;
      if (key === 'Enter') {
        bufferRef.current.push('\r');
        if (processTimerRef.current) clearTimeout(processTimerRef.current);
        processTimerRef.current = setTimeout(flushAndProcess, 60);
        return;
      }
      if (key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
        bufferRef.current.push(key);
        if (bufferRef.current.length > 0 && now - (lastKeyAtRef.current || 0) > MAX_BUFFER_AGE_MS) {
          bufferRef.current = [key];
        }
      }
    };

    window.addEventListener('keydown', onKeyDown, { capture: true });
    return () => {
      window.removeEventListener('keydown', onKeyDown, { capture: true });
      if (processTimerRef.current) clearTimeout(processTimerRef.current);
    };
  }, [navigate]);
}
