import React, { useState, useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useSalesState } from '../context/SalesContext';
import { useAuth } from '../context/AuthContext';
import { formatCurrency } from '../utils/currency';
import { useSettings } from '../context/SettingsContext';
import { get, post } from '../utils/api';
import ManagerAuthorizationModal from './ManagerAuthorizationModal';
import EditRowModal from './EditRowModal';
import ReceiptPrinter from './ReceiptPrinter';
import SalesTransactionHistory from './SalesTransactionHistory';
import PaymentMethodModal from './PaymentMethodModal';
import WarehouseSelectionModal from './WarehouseSelectionModal';
import HelpDemoModal from './HelpDemoModal';
import PaymentModal from './PaymentModal';
import { registerPOSShortcuts, getPOSKeyboardHandler } from '../utils/keyboardHandler';
import { getPaymentMethods, getDefaultPaymentMethodCode } from '../utils/paymentMethods';
import './SalesScreen.css';
import { useTranslation } from 'react-i18next';

const SalesScreen = ({ isOpen, onClose }) => {
  const { cart, addProduct, removeItem, updateItemQuantity, updateItemPrice, updateItemDiscount, clearCart, currentUserId, total, discount, netTotal, globalDiscount, updateGlobalDiscount, completeSale, mode, setMode, selectedWarehouseId, setSelectedWarehouse } = useSalesState();
  const { canChangeWarehouse, currentUser } = useAuth();
  const [suggestedItems, setSuggestedItems] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [scanAutocompleteProducts, setScanAutocompleteProducts] = useState([]);
  const [showScanAutocomplete, setShowScanAutocomplete] = useState(false);
  const [scanAutocompleteQuery, setScanAutocompleteQuery] = useState('');
  const [scanLoading, setScanLoading] = useState(false);
  const [productStockStatus, setProductStockStatus] = useState({}); // Track stock status for visual indicators
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isHelpDemoOpen, setIsHelpDemoOpen] = useState(false);
  const [isPaymentMethodOpen, setIsPaymentMethodOpen] = useState(false);
  const suggestionsRef = useRef(null);
  const scanAutocompleteRef = useRef(null);
  const [barcode, setBarcode] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [showReceipt, setShowReceipt] = useState(false);
  const [receiptData, setReceiptData] = useState(null);
  const [currentUserDetails, setCurrentUserDetails] = useState(null);
  const barcodeInputRef = useRef(null);
  const [focusedRow, setFocusedRow] = useState(-1);
  const [selectedRowIndex, setSelectedRowIndex] = useState(null);
  const [isEditRowModalOpen, setIsEditRowModalOpen] = useState(false);
  const [isReceiptPrinting, setIsReceiptPrinting] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState(getDefaultPaymentMethodCode);
  const [paymentMethodsList, setPaymentMethodsList] = useState(getPaymentMethods);
  const [isProcessing, setIsProcessing] = useState(false);
  const [topSellingProducts, setTopSellingProducts] = useState([]);
  const overallDiscountRef = useRef(null);
  const [discountMode, setDiscountMode] = useState('fixed'); // 'fixed' | 'percentage'
  const [discountInput, setDiscountInput] = useState(0); // UI value reflecting mode
  const [allProducts, setAllProducts] = useState([]);
  const receiptModalRef = useRef(null);
  const receiptPrintRef = useRef(null);

  const [cartPage, setCartPage] = useState(1);
  const itemsPerCartPage = 8;
  const [isReturnMode, setIsReturnMode] = useState(false);
  const [showReturnReasonModal, setShowReturnReasonModal] = useState(false);
  const [returnReason, setReturnReason] = useState('');
  const [returnSubmitLoading, setReturnSubmitLoading] = useState(false);
  const [autocompleteSuggestions, setAutocompleteSuggestions] = useState([]);
  const [showAutocomplete, setShowAutocomplete] = useState(false);
  const [cartItemTimestamps, setCartItemTimestamps] = useState({}); // Track when items were added to cart
  const [barcodeScanTimestamps, setBarcodeScanTimestamps] = useState({}); // Track when barcodes were scanned
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [paymentData, setPaymentData] = useState(null);
  const [warehouses, setWarehouses] = useState([]);
  const [showManagerAuthModal, setShowManagerAuthModal] = useState(false);
  const [pendingWarehouseChange, setPendingWarehouseChange] = useState(null);
  const [isWarehouseModalOpen, setIsWarehouseModalOpen] = useState(false);

  const { settings } = useSettings();
  const DEFAULT_WAREHOUSE_ID = settings?.defaultWarehouseId || null;
  const { t } = useTranslation();
  const businessInfo = {
    name: settings.storeName,
    address: settings.storeAddress,
    phone: settings.storePhone
  };

  // Sync UI discount input with underlying amount and mode
  useEffect(() => {
    if (discountMode === 'fixed') {
      setDiscountInput(Number(globalDiscount || 0));
    } else {
      const baseTotal = Number(total || 0);
      const pct = baseTotal > 0 ? ((Number(globalDiscount || 0) / baseTotal) * 100) : 0;
      setDiscountInput(Number.isFinite(pct) ? Number(pct.toFixed(2)) : 0);
    }
  }, [discountMode, globalDiscount, total]);

  // Load warehouses and set default
  useEffect(() => {
    const loadWarehouses = async () => {
      try {
        const res = await get('/warehouses');
        if (res.success && res.data?.length) {
          setWarehouses(res.data);
          const defaultId = DEFAULT_WAREHOUSE_ID || res.data[0]?.id;
          if (!selectedWarehouseId && defaultId) {
            setSelectedWarehouse(defaultId);
          }
        }
      } catch (err) {
        console.error('Failed to load warehouses:', err);
      }
    };
    loadWarehouses();
  }, []);

  // Sync payment methods from Product Management (Units & Payment Methods tab)
  useEffect(() => {
    const list = getPaymentMethods();
    setPaymentMethodsList(list);
    const codes = list.map(m => m.code);
    if (codes.length && !codes.includes(paymentMethod)) {
      setPaymentMethod(codes[0]);
    }
  }, []);

  const handleWarehouseChange = (newId) => {
    if (canChangeWarehouse) {
      setSelectedWarehouse(newId);
    } else {
      setPendingWarehouseChange(newId);
      setShowManagerAuthModal(true);
    }
  };

  const handleManagerAuthSuccess = () => {
    if (pendingWarehouseChange != null) {
      setSelectedWarehouse(pendingWarehouseChange);
      setPendingWarehouseChange(null);
    }
    setShowManagerAuthModal(false);
    setTimeout(() => warehouseSelectRef.current?.focus?.(), 100);
  };

  // Load product stock status
  useEffect(() => {
    const loadProductStockStatus = async () => {
      try {
        const response = await get('/products');
        const stockStatus = {};
        const products = response.data || [];
        products.forEach(product => {
          const inventory = product.inventory || {};
          const quantity = inventory.quantity || 0;
          const minStockLevel = product.minStockLevel || 0;

          if (quantity <= 0) {
            stockStatus[product.id] = 'out-of-stock';
          } else if (quantity <= minStockLevel) {
            stockStatus[product.id] = 'low-stock';
          } else {
            stockStatus[product.id] = 'in-stock';
          }
        });
        setProductStockStatus(stockStatus);
        setAllProducts(products);
      } catch (error) {
        console.error('Failed to load product stock status:', error);
      }
    };

    loadProductStockStatus();
  }, []);

  // Enhanced barcode scanning with timestamp tracking
  const handleBarcodeAutoSubmit = async (scannedBarcode) => {
    if (!scannedBarcode.trim()) return;

    const scanTime = new Date().toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });

    try {
      setIsProcessing(true);
      // Record the scan time immediately
      setBarcodeScanTimestamps(prev => ({
        ...prev,
        [scannedBarcode]: scanTime
      }));

      const response = await get(`/products/barcode/${scannedBarcode}`);
      const product = response.data;

      if (product) {
        // Check if product is inactive
        if (!product.isActive) {
          alert(`⚠️ Cannot add "${product.name}" - Product is INACTIVE!\n(Scanned at: ${scanTime})`);
          return;
        }

        // Check stock status
        const stockStatus = productStockStatus[product.id];
        if (stockStatus === 'out-of-stock') {
          alert(`⚠️ Cannot add "${product.name}" - Item is out of stock!\n(Scanned at: ${scanTime})`);
          return;
        }

        // Add to cart with timestamp (works on both Screen A and Screen B)
        enhancedAddProduct(product, quantity);

        setBarcode('');
        setQuantity(1);
        setPendingScannedBarcode(null); // clear so manual form is not prefilled with old "not found" barcode

        setTimeout(() => {
          if (mode === 'DUMMY') dummyBarcodeRef.current?.focus();
          else barcodeInputRef.current?.focus();
        }, 100);
      } else {
        // Product not found
        if (mode === 'DUMMY') {
          // Screen B: add as dummy item with this barcode; user enters name & price in form, then can "Save as product" later
          setPendingScannedBarcode(scannedBarcode);
          setDummyName(scannedBarcode);
          setDummyPrice('');
          setDummyQty(1);
          setBarcode('');
          setTimeout(() => dummyNameRef.current?.focus(), 100);
        } else {
          const addToSystem = window.confirm(
            t('sales.barcodeNotFoundAddToSystem') || `Product not found for barcode "${scannedBarcode}". Add this product to the system? You can edit details and save.`
          );
          if (addToSystem) {
            sessionStorage.setItem('pendingBarcodeForQuickAdd', scannedBarcode);
            window.dispatchEvent(new Event('pos-open-quick-product-modal'));
          }
        }
      }
    } catch (error) {
      console.error('Error fetching product by barcode:', error);
      if (mode === 'DUMMY') {
        setPendingScannedBarcode(scannedBarcode);
        setDummyName(scannedBarcode);
        setDummyPrice('');
        setDummyQty(1);
        setBarcode('');
        setTimeout(() => dummyNameRef.current?.focus(), 100);
      } else {
        const addToSystem = window.confirm(
          t('sales.barcodeNotFoundAddToSystem') || `Product not found for barcode "${scannedBarcode}". Add this product to the system? You can edit details and save.`
        );
        if (addToSystem) {
          sessionStorage.setItem('pendingBarcodeForQuickAdd', scannedBarcode);
          window.dispatchEvent(new Event('pos-open-quick-product-modal'));
        }
      }
    }
    finally {
      setIsProcessing(false);
    }
  };

  // Enhanced addProduct to track timestamps
  const enhancedAddProduct = useCallback((product, quantity = 1) => {
    const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });

    // Check if product is inactive
    if (product.isActive === false) {
      alert(`⚠️ Cannot add "${product.name}" - Product is INACTIVE!`);
      return;
    }

    // Check stock status before adding
    const stockStatus = productStockStatus[product.id];
    if (stockStatus === 'out-of-stock') {
      alert(`⚠️ Cannot add "${product.name}" - Item is out of stock!`);
      return;
    }

    // Add timestamp tracking
    setCartItemTimestamps(prev => ({
      ...prev,
      [product.id]: timestamp
    }));

    addProduct(product, quantity);
  }, [addProduct, productStockStatus]);
  useEffect(() => {
    // Check if there's a pending barcode from the global keyboard handler
    const pendingBarcode = sessionStorage.getItem('pendingBarcode');
    if (pendingBarcode) {
      // Process the pending barcode
      setBarcode(pendingBarcode);

      // Clear the pending barcode
      sessionStorage.removeItem('pendingBarcode');

      // Submit the barcode automatically
      handleBarcodeAutoSubmit(pendingBarcode);
    } else {
      // Just focus the barcode input if no pending barcode and no modal is open
      if (!document.querySelector('.modal-overlay')) {
        barcodeInputRef.current?.focus();
      }
    }

    // Listen for custom global barcode events
    const handleGlobalBarcode = (e) => {
      const scannedBarcode = e.detail?.barcode;
      if (scannedBarcode) {
        setBarcode(scannedBarcode);
        handleBarcodeAutoSubmit(scannedBarcode);
      }
    };

    window.addEventListener('pos-barcode-scan', handleGlobalBarcode);

    // ESC closure for History (only if it's the active modal)
    const handleHistoryEscape = (e) => {
      if (e.key === 'Escape' && isHistoryOpen) {
        setIsHistoryOpen(false);
      }
    };

    window.addEventListener('keydown', handleHistoryEscape);

    return () => {
      window.removeEventListener('pos-barcode-scan', handleGlobalBarcode);
      window.removeEventListener('keydown', handleHistoryEscape);
    };
  }, [isHistoryOpen]);

  // Direct Ctrl+R listener for toggling return mode
  const listenerAddedRef = useRef(false);

  useEffect(() => {
    if (listenerAddedRef.current) return; // Prevent duplicate listeners

    const handleToggleReturn = (e) => {
      if (e.ctrlKey && e.key.toLowerCase() === 'r') {
        e.preventDefault();
        e.stopPropagation();

        setIsReturnMode(currentValue => !currentValue);
      }
    };

    window.addEventListener('keydown', handleToggleReturn, { capture: true });
    listenerAddedRef.current = true;

    return () => {
      window.removeEventListener('keydown', handleToggleReturn, { capture: true });
      listenerAddedRef.current = false;
    };
  }, []); // Empty deps is OK since we use functional setState

  // Handle Screen Switching Shortcuts (Alt+A / Alt+B) and Alt+N (Add product popup on Screen B)
  useEffect(() => {
    const handleScreenSwitch = (e) => {
      // Check for Alt+A (Screen A / LIVE)
      if (e.altKey && e.key.toLowerCase() === 'a') {
        e.preventDefault();
        setMode('LIVE');
      }
      // Check for Alt+B (Screen B / DUMMY)
      if (e.altKey && e.key.toLowerCase() === 'b') {
        e.preventDefault();
        setMode('DUMMY');
      }
      // Alt+N: Open add-product popup on Screen B only
      if (e.altKey && e.key.toLowerCase() === 'n') {
        e.preventDefault();
        if (mode === 'DUMMY') {
          setShowAddProductPopup(true);
        }
      }
    };

    window.addEventListener('keydown', handleScreenSwitch);
    return () => window.removeEventListener('keydown', handleScreenSwitch);
  }, [setMode, mode]);

  // Fetch user details
  const fetchUserDetails = async (userId) => {
    try {
      const result = await get(`/users/${userId}`);
      if (result.success) {
        setCurrentUserDetails(result.data);
      }
    } catch (error) {
      console.error('Error fetching user details:', error);
    }
  };

  useEffect(() => {
    if (currentUserId) {
      fetchUserDetails(currentUserId);
    }
  }, [currentUserId]);

  // Fetch top selling products
  const fetchTopSellingProducts = async () => {
    try {
      const result = await get('/products/top-selling?limit=12');
      if (result.success && result.data) {
        console.log('Top selling products loaded:', result.data.length);
        setTopSellingProducts(result.data);
      } else {
        console.warn('No top selling products returned from API');
        setTopSellingProducts([]);
      }
    } catch (error) {
      console.error('Error fetching top selling products:', error);
      setTopSellingProducts([]);
    }
  };

  // Load top selling products on component mount
  useEffect(() => {
    fetchTopSellingProducts();
  }, []);

  // Screen B Redesign: Manual Dummy Entry State
  const [dummyName, setDummyName] = useState('');
  const [dummyQty, setDummyQty] = useState(1);
  const [dummyPrice, setDummyPrice] = useState('');
  const [shakeField, setShakeField] = useState(null); // 'name', 'qty', 'price'

  const dummyNameRef = useRef(null);
  const dummyQtyRef = useRef(null);
  const dummyPriceRef = useRef(null);
  const dummyBarcodeRef = useRef(null);
  const warehouseSelectRef = useRef(null);
  const [pendingScannedBarcode, setPendingScannedBarcode] = useState(null); // Screen B: barcode not found → add as dummy with this barcode

  // Alt+N popup: add product (name, price, qty, discount F/P, barcode) to current transaction
  const [showAddProductPopup, setShowAddProductPopup] = useState(false);
  const [popupName, setPopupName] = useState('');
  const [popupPrice, setPopupPrice] = useState('');
  const [popupQty, setPopupQty] = useState(1);
  const [popupDiscount, setPopupDiscount] = useState('');
  const [popupDiscountMode, setPopupDiscountMode] = useState('fixed'); // 'fixed' | 'percentage'
  const [popupBarcode, setPopupBarcode] = useState('');
  const popupNameRef = useRef(null);

  // Default to Screen B (DUMMY) when Sales screen loads
  useEffect(() => {
    setMode('DUMMY');
  }, []); // eslint-disable-line react-hooks/exhaustive-deps -- run once on mount to set default screen

  // Auto-focus on mode change
  useEffect(() => {
    setTimeout(() => {
      if (mode === 'DUMMY') {
        dummyBarcodeRef.current?.focus();
      } else {
        barcodeInputRef.current?.focus();
      }
    }, 100);
  }, [mode]);

  const handleDummySubmit = (e) => {
    if (e) e.preventDefault();

    // Validation checks
    if (!dummyName.trim()) {
      setShakeField('name');
      setTimeout(() => setShakeField(null), 400);
      dummyNameRef.current?.focus();
      return;
    }

    const qty = parseFloat(dummyQty);
    if (isNaN(qty) || qty <= 0) {
      setShakeField('qty');
      setTimeout(() => setShakeField(null), 400);
      dummyQtyRef.current?.focus();
      return;
    }

    const price = parseFloat(dummyPrice);
    if (isNaN(price) || price <= 0) {
      setShakeField('price');
      setTimeout(() => setShakeField(null), 400);
      dummyPriceRef.current?.focus();
      return;
    }

    // Logic: Append to transaction (Screen B). Use scanned barcode if we came from "barcode not found", else temp id
    const tempSku = `DUM-${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
    const itemBarcode = pendingScannedBarcode || tempSku;
    const manualItem = {
      id: tempSku,
      productId: tempSku,
      name: dummyName,
      price: price,
      quantity: qty,
      barcode: itemBarcode,
      isManualEntry: true
    };

    addProduct(manualItem, qty);

    setDummyName('');
    setDummyQty(1);
    setDummyPrice('');
    setPendingScannedBarcode(null);
    dummyNameRef.current?.focus();
  };

  // Focus popup name input when Alt+N popup opens
  useEffect(() => {
    if (showAddProductPopup) {
      setPopupName('');
      setPopupPrice('');
      setPopupQty(1);
      setPopupDiscount('');
      setPopupDiscountMode('fixed');
      setPopupBarcode('');
      setTimeout(() => popupNameRef.current?.focus(), 50);
    }
  }, [showAddProductPopup]);

  // F = fixed, P = percentage; Esc = close; F10 = Add and Close. Do NOT trigger F/P when focus is in any input.
  const addProductPopupSubmitRef = useRef(null);
  useEffect(() => {
    if (!showAddProductPopup || mode !== 'DUMMY') return;
    const isInputField = (target) => {
      if (!target || !target.tagName) return false;
      const tag = target.tagName.toUpperCase();
      return tag === 'INPUT' || tag === 'TEXTAREA' || target.isContentEditable;
    };
    const handleKey = (e) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        setShowAddProductPopup(false);
      } else if (e.key === 'F10') {
        e.preventDefault();
        e.stopPropagation();
        addProductPopupSubmitRef.current?.(e, true); // Add and Close
      } else if (e.key === 'f' || e.key === 'F') {
        if (isInputField(e.target)) return;
        e.preventDefault();
        setPopupDiscountMode('fixed');
      } else if (e.key === 'p' || e.key === 'P') {
        if (isInputField(e.target)) return;
        e.preventDefault();
        setPopupDiscountMode('percentage');
      }
    };
    window.addEventListener('keydown', handleKey, true);
    return () => window.removeEventListener('keydown', handleKey, true);
  }, [showAddProductPopup, mode]);

  // Reset Add Product popup form for next item (Add and Next)
  const resetAddProductPopupForm = useCallback(() => {
    setPopupName('');
    setPopupPrice('');
    setPopupQty(1);
    setPopupDiscount('');
    setPopupBarcode('');
    setPopupDiscountMode('fixed');
    setTimeout(() => popupNameRef.current?.focus(), 50);
  }, []);

  // Add product from Alt+N popup: closeAfter = false → Add and Next (keep popup open); true → Add and Close
  const handleAddProductPopupSubmit = (e, closeAfter = false) => {
    if (e) e.preventDefault();
    if (!popupName.trim()) {
      popupNameRef.current?.focus();
      return;
    }
    const qty = parseFloat(popupQty);
    if (isNaN(qty) || qty <= 0) {
      return;
    }
    const price = parseFloat(popupPrice);
    if (isNaN(price) || price <= 0) {
      return;
    }
    const lineTotal = price * qty;
    let discountAmount = 0;
    const discountVal = parseFloat(popupDiscount);
    if (!isNaN(discountVal) && discountVal > 0) {
      if (popupDiscountMode === 'percentage') {
        discountAmount = (lineTotal * discountVal) / 100;
      } else {
        discountAmount = Math.min(discountVal, lineTotal);
      }
    }
    const tempSku = `DUM-${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
    const itemBarcode = (popupBarcode && String(popupBarcode).trim()) || tempSku;
    const manualItem = {
      id: tempSku,
      productId: tempSku,
      name: popupName.trim(),
      price: price,
      quantity: qty,
      discount: Number((discountAmount).toFixed(2)),
      barcode: itemBarcode,
      isManualEntry: true
    };
    addProduct(manualItem, qty);
    if (closeAfter) {
      setShowAddProductPopup(false);
    } else {
      resetAddProductPopupForm();
    }
  };
  addProductPopupSubmitRef.current = handleAddProductPopupSubmit;

  // Handle barcode scanning
  const handleBarcodeChange = (e) => {
    const value = e.target.value;
    setBarcode(value);
  };

  const handleBarcodeKeyDown = (e) => {
    if (e.key === 'Enter' && barcode.trim() && !isProcessing) {
      handleBarcodeAutoSubmit(barcode.trim());
      e.preventDefault(); // Prevent any other Enter key handlers from triggering
    }
    // Also support global History close here
    if (e.key === 'Escape' && isHistoryOpen) {
      setIsHistoryOpen(false);
    }
  };

  const handleAddProductFromSearch = (product) => {
    // Check if product is inactive
    if (product.isActive === false) {
      alert(`⚠️ Cannot add "${product.name}" - Product is INACTIVE!`);
      return;
    }

    const productToAdd = {
      ...product,
      price: product.sellingPrice || product.price,
    };
    addProduct(productToAdd, quantity);
  };

  const handleAddQuickProduct = (product) => {
    // Check if product is inactive
    if (product.isActive === false) {
      alert(`⚠️ Cannot add "${product.name}" - Product is INACTIVE!`);
      return;
    }

    const productToAdd = {
      ...product,
      price: product.sellingPrice || product.price,
    };
    addProduct(productToAdd, quantity);
  };

  // Add product directly from top selling list
  const handleAddTopSellingProduct = useCallback((product) => {
    // Check if product is inactive
    if (product.isActive === false) {
      alert(`⚠️ Cannot add "${product.name}" - Product is INACTIVE!`);
      return;
    }

    const productToAdd = {
      ...product,
      price: product.sellingPrice,
    };
    addProduct(productToAdd, quantity);
    // Move to last page when item is added
    const newTotalPages = Math.ceil((cart.length + 1) / itemsPerCartPage);
    setCartPage(newTotalPages);

    // Focus back to barcode input after adding
    setTimeout(() => {
      if (!document.querySelector('.modal-overlay')) {
        barcodeInputRef.current?.focus();
      }
    }, 100);
  }, [addProduct, quantity, cart.length, itemsPerCartPage]);

  const handleCompleteSale = async () => {
    if (cart.length === 0) {
      alert('Cannot complete sale: Cart is empty');
      return;
    }

    // If in return mode, show reason modal first
    if (isReturnMode) {
      setShowReturnReasonModal(true);
      return;
    }

    // Show payment modal to capture customer payment
    setShowPaymentModal(true);
  };

  const handlePaymentConfirm = async (payment) => {
    setPaymentData(payment);
    setShowPaymentModal(false);

    // Optimistic UI: build receipt from current cart + payment and show/print immediately
    const optimisticReceipt = {
      items: cart.map(item => ({
        productId: item.id,
        quantity: Number(item.quantity || 1),
        unitPrice: Number(item.price || 0),
        totalPrice: Number((Number(item.quantity || 1) * Number(item.price || 0)).toFixed(2)),
        discountAmount: Number(item.discount || 0),
        name: item.name,
        product: { name: item.name }
      })),
      discountAmount: Number(discount || 0),
      subtotal: Number(total || 0),
      netTotal: Number(netTotal || 0),
      taxAmount: 0,
      paymentMethod,
      type: isReturnMode ? 'return' : 'sale',
      tenderedAmount: payment.tenderedAmount,
      change: payment.change,
      createdAt: new Date().toISOString(),
      transactionId: `TEMP-${Date.now()}`,
      user: { username: currentUser?.username || 'Cashier' },
      mode
    };
    setReceiptData(optimisticReceipt);
    setShowReceipt(true);

    // Trigger print immediately (no wait for API) – user can also press Enter to print again
    const triggerPrint = () => {
      try {
        receiptPrintRef.current?.print();
      } catch (e) {
        console.warn('Optimistic print failed:', e);
      }
    };
    requestAnimationFrame(() => setTimeout(triggerPrint, 150));

    try {
      const saleResult = await completeSale(paymentMethod, {
        type: isReturnMode ? 'return' : 'sale',
        tenderedAmount: payment.tenderedAmount,
        change: payment.change,
        customerName: payment.customerName || null
      });
      if (saleResult) {
        setReceiptData(saleResult);
      }
      // Save customer name to Settings > Customers if provided and not already there
      const nameToSave = (payment.customerName || '').trim();
      if (nameToSave) {
        try {
          const custRes = await get('/customers');
          if (custRes?.success && Array.isArray(custRes.data)) {
            const exists = custRes.data.some(c => String(c.name || '').trim().toLowerCase() === nameToSave.toLowerCase());
            if (!exists) {
              await post('/customers', { name: nameToSave });
            }
          }
        } catch (e) {
          console.warn('Could not save customer to Settings:', e);
        }
      }
      setTimeout(() => {
        if (!document.querySelector('.modal-overlay')) {
          barcodeInputRef.current?.focus();
        }
        setBarcode('');
      }, 100);
    } catch (error) {
      console.error('Error completing sale:', error);
      alert('Error completing sale');
      // Receipt already shown; user can close or retry
    }
  };

  const handleRowClick = (index) => {
    setFocusedRow(index);
    // Ensure barcode input is cleared when focusing a row to prevent Enter key conflicts
    if (barcode) {
      setBarcode('');
    }
  };

  const handleUpdateCartItem = (updatedItem) => {
    updateItemQuantity(updatedItem.id, updatedItem.quantity);
    updateItemPrice(updatedItem.id, updatedItem.price);
    updateItemDiscount(updatedItem.id, updatedItem.discount);
    setIsEditRowModalOpen(false);
    setSelectedRowIndex(null);
    setTimeout(() => {
      if (!document.querySelector('.modal-overlay')) {
        barcodeInputRef.current?.focus();
      }
    }, 100);
  };

  const handleReceiptPrintComplete = () => {
    setIsReceiptPrinting(false);
    setShowReceipt(false);
    setReceiptData(null);
    setTimeout(() => {
      if (!document.querySelector('.modal-overlay')) {
        barcodeInputRef.current?.focus();
      }
      setBarcode('');
    }, 100);
  };

  useEffect(() => {
    if (showReceipt && receiptModalRef.current) {
      receiptModalRef.current.focus();
    }
  }, [showReceipt]);

  const handleEditSale = (sale) => {
    if (cart.length > 0 && !window.confirm('Editing this sale will clear the current cart. Continue?')) {
      return;
    }

    clearCart(); // Assuming context provides clearCart

    // items in sale are usually from API, might need mapping
    sale.items.forEach(item => {
      const product = {
        id: item.productId,
        name: item.product?.name || item.name,
        price: item.unitPrice,
        barcode: item.product?.barcode || ''
      };
      addProduct(product, item.quantity);
    });

    setIsHistoryOpen(false);
    alert(`Loaded Sale ${sale.transactionId} for editing.`);
  };







  // Function to search for products for scan area autocomplete
  const searchScanProducts = async (query) => {
    if (query.length < 3) {
      setScanAutocompleteProducts([]);
      setShowScanAutocomplete(false);
      return;
    }

    try {
      setScanLoading(true);
      const response = await fetch(`/api/products?search=${encodeURIComponent(query)}&active=true&limit=10`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });

      if (response.ok) {
        const result = await response.json();
        if (result.success && result.data) {
          // Filter out items already in cart
          const filteredProducts = result.data.filter(product =>
            !cart.some(cartItem => cartItem.id === product.id)
          );
          setScanAutocompleteProducts(filteredProducts);
          setShowScanAutocomplete(filteredProducts.length > 0);
        }
      }
    } catch (error) {
      console.error('Error searching products:', error);
      setScanAutocompleteProducts([]);
      setShowScanAutocomplete(false);
    }
    finally {
      setScanLoading(false);
    }
  };

  // Function to add product from scan autocomplete (Screen A or Screen B)
  const handleAddScanProduct = (product) => {
    const productToAdd = {
      ...product,
      price: product.sellingPrice || product.price,
    };
    addProduct(productToAdd, 1);

    // Clear autocomplete
    setScanAutocompleteQuery('');
    setScanAutocompleteProducts([]);
    setShowScanAutocomplete(false);
    setBarcode('');

    // Focus back to scan input (Screen B or Screen A)
    setTimeout(() => {
      if (mode === 'DUMMY') dummyBarcodeRef.current?.focus();
      else barcodeInputRef.current?.focus();
    }, 100);
  };





  // Keyboard navigation for scan autocomplete
  const [selectedScanIndex, setSelectedScanIndex] = useState(-1);

  useEffect(() => {
    if (!showScanAutocomplete) {
      setSelectedScanIndex(-1);
      return;
    }

    const handleKeyDown = (e) => {
      // Only handle keys when scan autocomplete dropdown is visible
      if (!showScanAutocomplete) return;

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedScanIndex(prev =>
          prev < scanAutocompleteProducts.length - 1 ? prev + 1 : 0
        );
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedScanIndex(prev =>
          prev > 0 ? prev - 1 : scanAutocompleteProducts.length - 1
        );
      } else if (e.key === 'Enter' && selectedScanIndex >= 0) {
        e.preventDefault();
        handleAddScanProduct(scanAutocompleteProducts[selectedScanIndex]);
      } else if (e.key === 'Escape') {
        e.preventDefault();
        // Close autocomplete dropdown
        setShowScanAutocomplete(false);
        setScanAutocompleteQuery('');
        setSelectedScanIndex(-1);
        if (mode === 'DUMMY') dummyBarcodeRef.current?.focus();
        else barcodeInputRef.current?.focus();
      }
    };

    window.addEventListener('keydown', handleKeyDown, true);
    return () => window.removeEventListener('keydown', handleKeyDown, true);
  }, [showScanAutocomplete, scanAutocompleteProducts, selectedScanIndex, mode]);

  const handleDeleteRow = () => {
    if (focusedRow >= 0 && focusedRow < cart.length) {
      const item = cart[focusedRow];
      if (item) {
        removeItem(item.id);
        // Adjust focused row if it was the last item
        if (focusedRow >= cart.length - 1) {
          setFocusedRow(Math.max(0, cart.length - 2));
        }
      }
    }
  };

  // Initialize keyboard shortcuts
  useEffect(() => {
    const keyboardHandler = getPOSKeyboardHandler();

    // Clear existing shortcuts to avoid duplicates
    keyboardHandler.unregisterKey('F10');
    keyboardHandler.unregisterKey('Escape');
    keyboardHandler.unregisterKey('ArrowUp');
    keyboardHandler.unregisterKey('ArrowDown');
    keyboardHandler.unregisterKey('Enter');
    keyboardHandler.unregisterKey('Delete');
    keyboardHandler.unregisterKey('+');
    keyboardHandler.unregisterKey('-');
    keyboardHandler.unregisterKey('s');
    keyboardHandler.unregisterKey('p');
    keyboardHandler.unregisterKey('c');
    keyboardHandler.unregisterKey('d');
    keyboardHandler.unregisterKey('k');
    keyboardHandler.unregisterKey('g');

    // Ensure F10 is properly registered with high priority
    keyboardHandler.registerKey('F10', handleCompleteSale, {
      description: 'Complete sale and print receipt',
      preventDefault: true,
      condition: (event) => {
        const isModalOpen = document.querySelector('.modal-overlay');
        return !isModalOpen;
      }
    });

    // Register POS-specific shortcuts with actual component functions
    registerPOSShortcuts({
      editRow: () => {
        if (showPaymentModal) return;
        if (showSuggestions) return;
        if (barcode) return;
        if (focusedRow >= 0 && focusedRow < cart.length) {
          setSelectedRowIndex(focusedRow);
          setIsEditRowModalOpen(true);
        }
      },
      clearTransaction: () => {
        // Clear cart and reset focus
        const isModalOpen = document.querySelector('.modal-overlay');
        if (isModalOpen) return;
        if (cart.length === 0) return;
        if (window.confirm('Are you sure you want to clear the cart?')) {
          clearCart();
          setFocusedRow(-1);
          setSelectedRowIndex(null);
          setTimeout(() => barcodeInputRef.current?.focus(), 50);
        }
      },
      navigateUp: () => {
        // Completely disabled when suggestions modal is open
        if (showSuggestions) return;
        if (cart.length > 0) {
          setFocusedRow(prev => {
            const next = Math.max(0, prev - 1);
            // If the next focused row is on a different page, switch page
            const targetPage = Math.floor(next / itemsPerCartPage) + 1;
            if (targetPage !== cartPage) setCartPage(targetPage);
            return next;
          });
        }
      },
      navigateDown: () => {
        // Completely disabled when suggestions modal is open
        if (showSuggestions) return;
        if (cart.length > 0) {
          setFocusedRow(prev => {
            const next = Math.min(cart.length - 1, prev + 1);
            // If the next focused row is on a different page, switch page
            const targetPage = Math.floor(next / itemsPerCartPage) + 1;
            if (targetPage !== cartPage) setCartPage(targetPage);
            return next;
          });
        }
      },
      confirmSelection: () => {
        if (showPaymentModal) return;
        if (focusedRow >= 0 && focusedRow < cart.length && !barcode) {
          setSelectedRowIndex(focusedRow);
          setIsEditRowModalOpen(true);
        } else if (!barcode) {
          // If no focused row but Enter was pressed, just focus back to barcode input
          setTimeout(() => {
            if (!document.querySelector('.modal-overlay')) {
              barcodeInputRef.current?.focus();
            }
          }, 50);
        }
      },
      deleteRow: handleDeleteRow,
      increaseQuantity: () => {
        if (focusedRow >= 0 && focusedRow < cart.length) {
          const currentItem = cart[focusedRow];
          if (currentItem) {
            updateItemQuantity(currentItem.id, currentItem.quantity + 1);
          }
        }
      },
      decreaseQuantity: () => {
        if (focusedRow >= 0 && focusedRow < cart.length) {
          const currentItem = cart[focusedRow];
          if (currentItem && currentItem.quantity > 1) {
            updateItemQuantity(currentItem.id, currentItem.quantity - 1);
          }
        }
      },
      focusScanner: () => {
        // When transaction history is open, do not enable scan/sales shortcuts
        if (isHistoryOpen) return;
        const isModalOpen = document.querySelector('.modal-overlay') || isEditRowModalOpen || showReceipt;
        if (!isModalOpen) {
          if (mode === 'DUMMY') dummyBarcodeRef.current?.focus();
          else barcodeInputRef.current?.focus();
        }
      },
      focusProductName: () => {
        if (isHistoryOpen) return;
        const isModalOpen = document.querySelector('.modal-overlay');
        if (!isModalOpen && mode === 'DUMMY') dummyNameRef.current?.focus();
      },
      // Add payment method shortcuts
      cyclePaymentMethod: () => {
        const list = getPaymentMethods();
        const codes = list.map(m => m.code);
        const currentIndex = codes.indexOf(paymentMethod);
        const nextIndex = codes.length ? (currentIndex + 1) % codes.length : 0;
        setPaymentMethod(codes[nextIndex] || 'cash');
      },
      setCashPayment: () => {
        const list = getPaymentMethods();
        const cash = list.find(m => m.code === 'cash');
        setPaymentMethod(cash ? cash.code : (list[0]?.code || 'cash'));
      },
      setCardPayment: () => {
        const list = getPaymentMethods();
        const card = list.find(m => m.code === 'card');
        setPaymentMethod(card ? card.code : (list[0]?.code || 'cash'));
      },
      setDigitalPayment: () => {
        const list = getPaymentMethods();
        const digital = list.find(m => m.code === 'digital');
        setPaymentMethod(digital ? digital.code : (list[0]?.code || 'cash'));
      },
      openHistory: () => {
        setIsHistoryOpen(prev => !prev);
      },
      openPaymentMethod: () => {
        const isModalOpen = document.querySelector('.modal-overlay');
        if (isModalOpen) return;
        setIsPaymentMethodOpen(true);
      },
      // Focus Transaction Discount (Alt+T)
      focusTransactionDiscount: () => {
        const isModalOpen = document.querySelector('.modal-overlay');
        if (isModalOpen) return;
        const el = overallDiscountRef.current || document.getElementById('overall-discount');
        if (el) {
          el.focus();
          el.select?.();
        }
      },
      focusWarehouse: () => {
        const isModalOpen = document.querySelector('.modal-overlay');
        if (isModalOpen || showManagerAuthModal || warehouses.length === 0) return;
        setIsWarehouseModalOpen(true);
      },
      addQuickProduct: () => {
        const isModalOpen = document.querySelector('.modal-overlay');
        if (!isModalOpen) {
          window.dispatchEvent(new Event('pos-open-quick-product-modal'));
        }
      }
    });

    // F1: Help/Demo - REMOVED as requested

    // Clear only the F1-F12 handlers that were used for top selling products originally
    for (let i = 1; i <= 12; i++) {
      if (i !== 2 && i !== 4 && i !== 8 && i !== 10) {
        keyboardHandler.unregisterKey(`F${i}`);
      }
    }

    // Register F1 for Help Demo (language enabled)
    keyboardHandler.registerKey('F1', () => {
      const isModalOpen = document.querySelector('.modal-overlay');
      if (isModalOpen) return;
      setIsHelpDemoOpen(true);
    }, { preventDefault: true, description: 'Open Help / Demo' });

    return () => {
      // Unregister shortcuts when leaving Sales screen
      keyboardHandler.unregisterKey('F10');
      keyboardHandler.unregisterKey('F1');
      keyboardHandler.unregisterKey('Escape');
      keyboardHandler.unregisterKey('ArrowUp');
      keyboardHandler.unregisterKey('ArrowDown');
      keyboardHandler.unregisterKey('Enter');
      keyboardHandler.unregisterKey('Delete');
      keyboardHandler.unregisterKey('+');
      keyboardHandler.unregisterKey('-');
      keyboardHandler.unregisterKey('s');
      keyboardHandler.unregisterKey('p');
      keyboardHandler.unregisterKey('c');
      keyboardHandler.unregisterKey('d');
      keyboardHandler.unregisterKey('k');
      keyboardHandler.unregisterKey('g');
      keyboardHandler.unregisterKey('a');
      keyboardHandler.unregisterKey('h');
      keyboardHandler.unregisterKey('n');

      for (let i = 1; i <= 12; i++) {
        if (i !== 2 && i !== 8) {
          keyboardHandler.unregisterKey(`F${i}`);
        }
      }
    };
  }, [cart, focusedRow, handleCompleteSale, paymentMethod, updateItemQuantity, cartPage, isEditRowModalOpen, showReceipt, showSuggestions, showPaymentModal, warehouses.length]);

  // Separate effect for top selling products shortcuts with Ctrl+Letter
  useEffect(() => {
    if (!topSellingProducts || topSellingProducts.length === 0) return;

    const keyboardHandler = getPOSKeyboardHandler();

    // Clear existing Ctrl+Letter handlers
    // Avoid conflicts: Ctrl+S (save), Ctrl+P (print), Ctrl+A (select all), 
    // Ctrl+C (copy), Ctrl+V (paste), Ctrl+X (cut), Ctrl+Z (undo), 
    // Ctrl+F (find), Ctrl+R (return mode), Ctrl+W (close), Ctrl+N (new)
    // Safe letters: B, D, E, G, H, I, J, K, L, M, N, O, Q, T, U, W, X, Y, Z
    const safeLetters = ['B', 'D', 'E', 'G', 'H', 'I', 'J', 'K', 'L', 'M', 'N', 'O', 'Q', 'T', 'U', 'W', 'X', 'Y', 'Z'];

    // Clear all previous Ctrl+Letter handlers
    safeLetters.forEach(letter => {
      keyboardHandler.unregisterCtrlKey(letter);
    });

    // Register Ctrl+Letter handlers for top selling products
    const productsToRegister = topSellingProducts.slice(0, Math.min(12, safeLetters.length));
    productsToRegister.forEach((product, index) => {
      const letter = safeLetters[index];

      keyboardHandler.registerCtrlKey(letter, () => {
        console.log(`Ctrl+${letter} pressed - Adding product:`, product.name);
        enhancedAddProduct(product);
      }, {
        description: `Add ${product.name}`,
        condition: (event) => {
          // When sales transaction history is open, do not enable scan/sales shortcuts
          if (isHistoryOpen) return false;
          const tagName = event.target.tagName;
          const isInput = tagName === 'INPUT' || tagName === 'TEXTAREA';
          const isContentEditable = event.target.isContentEditable;
          const isModalOpen = document.querySelector('.modal-overlay');

          // Check if the focused input is the barcode scanner input (Screen A or Screen B)
          const isBarcodeInput =
            (barcodeInputRef.current && (event.target === barcodeInputRef.current || document.activeElement === barcodeInputRef.current)) ||
            (mode === 'DUMMY' && dummyBarcodeRef.current && (event.target === dummyBarcodeRef.current || document.activeElement === dummyBarcodeRef.current));

          // Allow shortcut if:
          // 1. Not in any input/textarea (normal case), OR
          // 2. In the barcode scanner input (user wants shortcuts to work here)
          // But still block if:
          // - In contentEditable elements
          // - Modal is open
          // - In other input fields (not barcode scanner)

          if (isModalOpen) {
            return false; // Always block when modal is open
          }

          if (isContentEditable) {
            return false; // Block in contentEditable
          }

          // Allow if not in any input, or if in barcode scanner input
          if (!isInput || isBarcodeInput) {
            return true;
          }

          // Block in other input fields
          return false;
        },
        preventDefault: true
      });
    });

    console.log(`Registered ${productsToRegister.length} Ctrl+Letter shortcuts for top selling products`);

    return () => {
      // Unregister top selling product shortcuts when leaving Sales screen
      safeLetters.forEach(letter => {
        keyboardHandler.unregisterCtrlKey(letter);
      });
    };
  }, [topSellingProducts, handleAddTopSellingProduct, isHistoryOpen, mode]);

  // Return Reason modal: F10 = Process Return, Esc = Cancel (capture phase, stop so POS handler doesn't run)
  useEffect(() => {
    if (!showReturnReasonModal) return;
    const handleReturnModalKey = (e) => {
      if (e.key === 'Escape' || e.key === 'Esc') {
        if (returnSubmitLoading) return;
        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();
        setShowReturnReasonModal(false);
        setReturnReason('');
      } else if (e.key === 'F10' || e.key === 'f10') {
        if (returnReason.trim() && !returnSubmitLoading) {
          e.preventDefault();
          e.stopPropagation();
          e.stopImmediatePropagation();
          document.getElementById('return-submit-btn')?.click();
        }
      }
    };
    window.addEventListener('keydown', handleReturnModalKey, true);
    return () => window.removeEventListener('keydown', handleReturnModalKey, true);
  }, [showReturnReasonModal, returnReason, returnSubmitLoading]);

  // Pagination calculations for cart
  const cartTotalPages = Math.ceil(cart.length / itemsPerCartPage);
  const currentCartItems = cart.slice((cartPage - 1) * itemsPerCartPage, cartPage * itemsPerCartPage);

  return (
    <div className="pos-container">
      <div className="pos-content">
        {/* Return Mode Banner */}
        {isReturnMode && (
          <div className="return-mode-banner">
            🔄 RETURN MODE ACTIVE - Click Ctrl+R to Exit
          </div>
        )}
        <div className="sales-screen-container">

          {/* Left Panel - Control Center */}
          <div className={`sales-left-panel ${mode === 'DUMMY' ? 'glass-panel' : ''}`} style={{ padding: '1.5rem', borderRadius: '16px' }}>
            <div style={{ marginBottom: '1.5rem', position: 'relative' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px', flexWrap: 'wrap', gap: '8px' }}>
                <h2 className="sales-heading-2" style={{ margin: 0, color: mode === 'DUMMY' ? 'var(--accent-primary)' : 'inherit' }}>
                  {mode === 'DUMMY' ? (t('sales.screenB') || 'Screen B: Manual & Barcode') : (t('sales.screenA') || 'Screen A: Scan Item')}
                </h2>
                <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
                  {mode === 'DUMMY' ? (
                    <><kbd style={{ padding: '2px 5px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)' }}>Alt+A</kbd> {t('sales.switchToScreenA') || '→ Screen A'}</>
                  ) : (
                    <><kbd style={{ padding: '2px 5px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)' }}>Alt+B</kbd> {t('sales.switchToScreenBComplete') || '→ Screen B (same cart, complete sale)'}</>
                  )}
                </span>
              </div>

              {mode === 'DUMMY' ? (
                /* Screen B: Manual + Barcode (with suggestions like Screen A) */
                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', position: 'relative' }}>
                  {/* Barcode Scanner Input with autocomplete */}
                  <div style={{ position: 'relative' }}>
                    <input
                      ref={dummyBarcodeRef}
                      type="text"
                      value={barcode}
                      onChange={(e) => {
                        const value = e.target.value;
                        setBarcode(value);
                        if (value.length >= 3) {
                          searchScanProducts(value);
                        } else {
                          setShowScanAutocomplete(false);
                          setScanAutocompleteQuery(value);
                        }
                      }}
                      placeholder={t('sales.scanBarcode') || 'Scan Barcode...'}
                      className="glass-input neon-glow-focus"
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          e.preventDefault();
                          if (showScanAutocomplete && scanAutocompleteProducts.length > 0) {
                            if (selectedScanIndex >= 0) {
                              handleAddScanProduct(scanAutocompleteProducts[selectedScanIndex]);
                            } else {
                              handleAddScanProduct(scanAutocompleteProducts[0]);
                            }
                            return;
                          }
                          if (barcode.trim()) {
                            handleBarcodeAutoSubmit(barcode.trim());
                            setBarcode('');
                          }
                        }
                      }}
                      autoFocus
                    />
                    <div style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)', fontSize: '0.8rem', pointerEvents: 'none' }}>
                      SCAN <kbd style={{ fontSize: 9, padding: '1px 4px', marginLeft: 4 }}>Alt+S</kbd>
                    </div>
                  </div>
                  <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>
                    {t('sales.screenBScanHint') || 'Existing products: scan or type barcode and press Enter to add to cart.'}
                  </div>
                  {/* Screen B scan suggestions dropdown (same as Screen A) */}
                  {(showScanAutocomplete || scanLoading) && (
                    <div style={{
                      position: 'absolute',
                      top: '100%',
                      left: 0,
                      right: 0,
                      backgroundColor: 'white',
                      border: '1px solid #ddd',
                      borderRadius: '4px',
                      maxHeight: '200px',
                      overflowY: 'auto',
                      zIndex: 1000,
                      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
                      marginTop: '2px'
                    }}>
                      {scanLoading && scanAutocompleteProducts.length === 0 && (
                        <div style={{ padding: '10px', color: '#6b7280', fontStyle: 'italic' }}>Searching...</div>
                      )}
                      {scanAutocompleteProducts.map((product, index) => (
                        <div
                          key={product.id}
                          onClick={() => handleAddScanProduct(product)}
                          style={{
                            padding: '10px',
                            cursor: 'pointer',
                            backgroundColor: selectedScanIndex === index ? '#e5e7eb' : 'white',
                            borderBottom: index < scanAutocompleteProducts.length - 1 ? '1px solid #f0f0f0' : 'none',
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center'
                          }}
                          onMouseEnter={() => setSelectedScanIndex(index)}
                        >
                          <div>
                            <div style={{ fontWeight: '600', fontSize: '14px' }}>{product.name}</div>
                            <div style={{ fontSize: '12px', color: '#666' }}>{product.description || 'No description'}</div>
                          </div>
                          <div style={{ textAlign: 'right' }}>
                            <div style={{ fontWeight: '600', color: '#10b981' }}>{formatCurrency(product.sellingPrice, settings.currency || 'USD')}</div>
                            <div style={{ fontSize: '11px', color: '#9ca3af' }}>{product.categoryName || 'Uncategorized'}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}

                  {pendingScannedBarcode && (
                    <div style={{ fontSize: '12px', color: 'var(--primary)', backgroundColor: 'var(--primary-subtle)', padding: '8px 12px', borderRadius: '8px', marginBottom: '4px' }}>
                      {t('sales.barcodeNotFoundAddAsDummy') || `Barcode "${pendingScannedBarcode}" not in system. Enter name & price below to add as dummy; you can "Save as product" from cart later.`}
                    </div>
                  )}
                  <form
                    onSubmit={handleDummySubmit}
                    style={{
                      display: 'grid',
                      gridTemplateColumns: '2fr 1fr 1fr',
                      gap: '12px',
                      alignItems: 'end'
                    }}
                  >
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                      <label style={{ fontSize: '12px', textTransform: 'uppercase', color: 'var(--text-muted)' }}>{t('sales.productName') || 'Product Name'} <kbd style={{ fontSize: 9, padding: '1px 4px', marginLeft: 4 }}>Alt+N</kbd></label>
                      <input
                        ref={dummyNameRef}
                        type="text"
                        placeholder="e.g. Misc Item"
                        value={dummyName}
                        onChange={(e) => setDummyName(e.target.value)}
                        className={`glass-input neon-glow-focus ${shakeField === 'name' ? 'shake-animation' : ''}`}
                      />
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                      <label style={{ fontSize: '12px', textTransform: 'uppercase', color: 'var(--text-muted)' }}>{t('sales.quantity') || 'Qty'}</label>
                      <input
                        ref={dummyQtyRef}
                        type="number"
                        min="1"
                        value={dummyQty}
                        onChange={(e) => setDummyQty(e.target.value)}
                        className={`glass-input neon-glow-focus ${shakeField === 'qty' ? 'shake-animation' : ''}`}
                      />
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                      <label style={{ fontSize: '12px', textTransform: 'uppercase', color: 'var(--text-muted)' }}>{t('sales.price') || 'Price'}</label>
                      <input
                        ref={dummyPriceRef}
                        type="number"
                        step="0.01"
                        placeholder="0.00"
                        value={dummyPrice}
                        onChange={(e) => setDummyPrice(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter') {
                            handleDummySubmit(e);
                          }
                        }}
                        className={`glass-input neon-glow-focus ${shakeField === 'price' ? 'shake-animation' : ''}`}
                      />
                    </div>
                  </form>
                </div>
              ) : (
                /* Screen A: Standard Barcode Listener */
                <form onSubmit={(e) => {
                  e.preventDefault();
                  handleBarcodeAutoSubmit(barcode);
                }} style={{ display: 'flex', flexDirection: 'column', gap: '8px', position: 'relative' }}>
                  <input
                    ref={barcodeInputRef}
                    type="text"
                    value={barcode}
                    onChange={(e) => {
                      const value = e.target.value;
                      handleBarcodeChange(e);

                      // Show product autocomplete when typing 3+ letters
                      if (value.length >= 3) {
                        searchScanProducts(value);
                      } else {
                        setShowScanAutocomplete(false);
                        setScanAutocompleteQuery(value);
                      }
                    }}
                    onKeyDown={(e) => {
                      // Handle Enter key for autocomplete selection
                      if (e.key === 'Enter' && showScanAutocomplete && scanAutocompleteProducts.length > 0) {
                        e.preventDefault();
                        if (selectedScanIndex >= 0) {
                          handleAddScanProduct(scanAutocompleteProducts[selectedScanIndex]);
                        } else {
                          // Add first result if nothing selected
                          handleAddScanProduct(scanAutocompleteProducts[0]);
                        }
                      } else {
                        handleBarcodeKeyDown(e);
                      }
                    }}
                  placeholder={mode === 'DUMMY' ? t('sales.scanDummyPlaceholder') : t('sales.scanPlaceholder')}
                    className="sales-input"
                    autoFocus
                    disabled={isProcessing}
                  />

                  {/* Scan Autocomplete Dropdown */}
                  {(showScanAutocomplete || scanLoading) && (
                    <div style={{
                      position: 'absolute',
                      top: '100%',
                      left: 0,
                      right: 0,
                      backgroundColor: 'white',
                      border: '1px solid #ddd',
                      borderRadius: '4px',
                      maxHeight: '200px',
                      overflowY: 'auto',
                      zIndex: 1000,
                      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
                      marginTop: '2px'
                    }}>
                      {scanLoading && scanAutocompleteProducts.length === 0 && (
                        <div style={{ padding: '10px', color: '#6b7280', fontStyle: 'italic' }}>
                          Searching...
                        </div>
                      )}
                      {scanAutocompleteProducts.map((product, index) => (
                        <div
                          key={product.id}
                          onClick={() => handleAddScanProduct(product)}
                          style={{
                            padding: '10px',
                            cursor: 'pointer',
                            backgroundColor: selectedScanIndex === index ? '#e5e7eb' : 'white',
                            borderBottom: index < scanAutocompleteProducts.length - 1 ? '1px solid #f0f0f0' : 'none',
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center'
                          }}
                          onMouseEnter={() => setSelectedScanIndex(index)}
                        >
                          <div>
                            <div style={{ fontWeight: '600', fontSize: '14px' }}>{product.name}</div>
                            <div style={{ fontSize: '12px', color: '#666' }}>{product.description || 'No description'}</div>
                          </div>
                          <div style={{ textAlign: 'right' }}>
                            <div style={{ fontWeight: '600', color: '#10b981' }}>{formatCurrency(product.sellingPrice, settings.currency || 'USD')}</div>
                            <div style={{ fontSize: '11px', color: '#9ca3af' }}>{product.categoryName || 'Uncategorized'}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}

                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <label htmlFor="qty-input" style={{ fontSize: '14px', fontWeight: '500' }}>Qty:</label>
                    <input
                      id="qty-input"
                      type="number"
                      min="1"
                      value={quantity}
                      onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                      style={{ padding: '6px', border: '1px solid #ccc', borderRadius: '4px', fontSize: '14px', width: '60px' }}
                      disabled={isProcessing}
                    />
                    <button
                      type="button"
                      onClick={() => handleBarcodeAutoSubmit(barcode)}
                      className="sales-button sales-button-primary"
                      disabled={isProcessing}
                    >
                      {isProcessing ? 'Adding...' : 'Add Item'}
                    </button>
                  </div>
                </form>
              )}
            </div>

            {/* Quick Actions */}
            <div>
              <h2 className="sales-heading-2" style={{ marginBottom: 'clamp(8px, 1.5vw, 12px)' }}>{t('sales.quickActions')}</h2>
              <div className="quick-actions-grid" style={{ marginBottom: 'clamp(12px, 2vw, 16px)', display: 'grid', gridTemplateColumns: '1fr', gap: '8px' }}>
                <button onClick={() => setIsHistoryOpen(true)} className="sales-button" style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '6px' }}>
                  <span>{t('sales.history')}</span>
                  <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.9, border: '1px solid currentColor', borderRadius: 3 }}>Alt+H</kbd>
                </button>
                <button onClick={() => setIsHelpDemoOpen(true)} className="sales-button sales-button-secondary" style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '6px' }}>
                  <span>{t('helpDemo.button')}</span>
                  <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.9, border: '1px solid currentColor', borderRadius: 3 }}>F1</kbd>
                </button>
                <button onClick={() => window.dispatchEvent(new Event('pos-open-search-modal'))} className="sales-button sales-button-secondary" style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}>
                  {t('sales.searchProductF2')}
                </button>
                <button onClick={() => window.dispatchEvent(new Event('pos-open-quick-product-modal'))} className="sales-button sales-button-success" style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}>
                  {t('sales.quickItemF8')}
                </button>
                <button
                  onClick={() => setIsReturnMode(!isReturnMode)}
                  className={`sales-button ${isReturnMode ? 'sales-button-danger' : 'sales-button-gray'}`}
                  style={{ gridColumn: 'span 2', padding: '0.4rem 0.8rem', fontSize: '0.85rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '6px' }}
                >
                  <span>{isReturnMode ? t('sales.exitReturnMode') : t('sales.returnMode')}</span>
                  <kbd style={{ fontSize: 9, padding: '1px 4px', flexShrink: 0, opacity: 0.9, border: '1px solid currentColor', borderRadius: 3 }}>Ctrl+R</kbd>
                </button>
              </div>

              {/* Top Selling Products */}
              <div>
                <h3 className="sales-heading-3" style={{ marginBottom: 'clamp(8px, 1.5vw, 12px)', color: '#4b5563' }}>Top Selling Products</h3>
                <div className="top-selling-grid">
                  {topSellingProducts.filter(p => productStockStatus[p.id] !== 'out-of-stock').length === 0 ? (
                    <div style={{ gridColumn: 'span 2', textAlign: 'center', padding: 'clamp(16px, 3vw, 20px)', color: '#9ca3af' }} className="sales-text-small">
                      No top selling products available (or all out of stock)
                    </div>
                  ) : (
                    topSellingProducts.filter(p => productStockStatus[p.id] !== 'out-of-stock').slice(0, 12).map((product, index) => {
                      // Safe letters avoiding browser shortcuts
                      const safeLetters = ['B', 'D', 'E', 'G', 'H', 'I', 'J', 'K', 'L', 'M', 'N', 'O', 'Q', 'T', 'U', 'W', 'X', 'Y', 'Z'];
                      const shortcutKey = index < safeLetters.length ? safeLetters[index] : null;
                      return (
                        <button
                          key={product.id || `product-${index}`}
                          onClick={() => enhancedAddProduct(product)}
                          className="top-selling-button"
                          title={shortcutKey ? `Press Ctrl+${shortcutKey} to add quickly` : 'Click to add'}
                          disabled={productStockStatus[product.id] === 'out-of-stock'}
                          style={{
                            opacity: productStockStatus[product.id] === 'out-of-stock' ? 0.6 : 1,
                            cursor: productStockStatus[product.id] === 'out-of-stock' ? 'not-allowed' : 'pointer'
                          }}
                        >
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 'clamp(4px, 0.8vw, 6px)' }}>
                            <span className="sales-text-small" style={{
                              fontWeight: '600',
                              color: productStockStatus[product.id] === 'out-of-stock' ? '#9ca3af' : '#1f2937',
                              flex: 1,
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap',
                              lineHeight: '1.3'
                            }}>
                              {product.name || 'Unnamed Product'}
                            </span>
                            {shortcutKey && (
                              <kbd className="shortcut-badge">
                                Ctrl+{shortcutKey}
                              </kbd>
                            )}
                          </div>
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '2px' }}>
                            <span className="sales-text-small" style={{ color: '#6b7280', fontWeight: '500' }}>
                              {settings.currency === 'RS' ? 'Rs' : settings.currency || '$'}{Number(product.sellingPrice || 0).toFixed(2)}
                            </span>
                            <div className="product-stock-info">
                              <span className={`stock-indicator ${productStockStatus[product.id] || 'unknown'}`}>
                                {productStockStatus[product.id] === 'out-of-stock' && 'Out of Stock'}
                                {productStockStatus[product.id] === 'low-stock' && `Low (${product.inventory?.quantity || 0})`}
                                {productStockStatus[product.id] === 'in-stock' && `In Stock (${product.inventory?.quantity || 0})`}
                                {productStockStatus[product.id] === 'unknown' && 'Checking...'}
                              </span>
                            </div>
                          </div>
                        </button>
                      );
                    })
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Center Panel - Current Transaction */}
          <div className="sales-center-panel">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '8px', marginBottom: 'clamp(12px, 2vw, 16px)', flexShrink: 0 }}>
              <h2 className="sales-heading-2">{t('sales.currentTransaction')}</h2>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                {warehouses.length > 0 && (
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <label className="sales-text" style={{ whiteSpace: 'nowrap' }}>
                      {t('warehouse.selectWarehouse')}
                      <kbd style={{ marginLeft: 6, fontSize: 11, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Alt+W</kbd>:
                    </label>
                    <div style={{ display: 'inline-flex', alignItems: 'center', background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: 6, padding: '2px' }}>
                      <select
                        ref={warehouseSelectRef}
                        value={selectedWarehouseId || ''}
                        onChange={(e) => handleWarehouseChange(e.target.value)}
                        style={{
                          padding: '6px 10px',
                          borderRadius: 4,
                          border: 'none',
                          background: 'transparent',
                          fontSize: '0.875rem',
                          minWidth: '140px',
                          outline: 'none'
                        }}
                        title={t('rbac.checkOtherWarehouses')}
                      >
                        {warehouses.map((wh) => (
                          <option key={wh.id} value={wh.id}>{wh.name || wh.code || wh.id}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                )}
                <span className="sales-text" style={{ color: '#6b7280' }}>{cart.length} items in cart</span>
              </div>
            </div>

            <div className="cart-table-container">
              {cart.length === 0 ? (
                <div style={{ textAlign: 'center', padding: 'clamp(30px, 6vw, 40px) 0', color: '#9ca3af' }} className="sales-text">No items in cart</div>
              ) : (
                <table className="cart-table">
                  <thead>
                    <tr>
                      <th>{t('sales.productName')}</th>
                      <th style={{ textAlign: 'right' }}>{t('sales.price')}</th>
                      <th style={{ textAlign: 'right' }}>{t('sales.discount')}</th>
                      <th style={{ textAlign: 'center' }}>{t('sales.quantity')}</th>
                      <th style={{ textAlign: 'center' }}>{t('sales.actions') || 'Actions'}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {currentCartItems.map((item, index) => {
                      const absoluteIndex = (cartPage - 1) * itemsPerCartPage + index;
                      const isFocused = focusedRow === absoluteIndex;
                      return (
                        <tr
                          key={`${item.id}-${absoluteIndex}`}
                          style={{
                            borderBottom: '1px solid #f1f5f9',
                            backgroundColor: isFocused ? 'var(--primary-subtle)' : (productStockStatus[item.productId] === 'out-of-stock' ? '#fee2e2' : 'transparent'),
                            borderLeft: isFocused ? '4px solid var(--primary)' : (productStockStatus[item.productId] === 'out-of-stock' ? '4px solid #dc2626' : '4px solid transparent'),
                            cursor: 'pointer',
                            transition: 'background-color 0.2s',
                            opacity: productStockStatus[item.productId] === 'out-of-stock' ? 0.8 : 1
                          }}
                          onClick={() => handleRowClick(absoluteIndex)}
                        >
                          <td>
                            <div className="sales-text" style={{
                              fontWeight: '600',
                              color: isFocused ? 'var(--primary)' : (productStockStatus[item.productId] === 'out-of-stock' ? '#991b1b' : 'var(--text-main)')
                            }}>
                              {item.name || 'Unknown'}
                              {productStockStatus[item.productId] === 'out-of-stock' && (
                                <span style={{
                                  marginLeft: '8px',
                                  fontSize: '0.75rem',
                                  color: '#dc2626',
                                  fontWeight: '700',
                                  backgroundColor: '#fecaca',
                                  padding: '2px 6px',
                                  borderRadius: '4px'
                                }}>
                                  OUT OF STOCK
                                </span>
                              )}
                            </div>
                            <div className="sales-text-small" style={{ color: 'var(--text-muted)' }}>
                              {item.barcode}
                              {cartItemTimestamps[item.productId] && (
                                <div style={{
                                  fontSize: '0.7rem',
                                  color: '#6b7280',
                                  marginTop: '2px',
                                  fontStyle: 'italic'
                                }}>
                                  Added: {cartItemTimestamps[item.productId]}
                                </div>
                              )}
                              {barcodeScanTimestamps[item.barcode] && (
                                <div style={{
                                  fontSize: '0.7rem',
                                  color: '#4f46e5',
                                  marginTop: '1px',
                                  fontWeight: '500'
                                }}>
                                  Scanned: {barcodeScanTimestamps[item.barcode]}
                                </div>
                              )}
                              {productStockStatus[item.productId] === 'low-stock' && (
                                <div style={{
                                  fontSize: '0.7rem',
                                  color: '#d97706',
                                  marginTop: '4px',
                                  fontWeight: '500'
                                }}>
                                  {t('rbac.checkOtherWarehouses')}
                                </div>
                              )}
                            </div>
                          </td>
                          <td style={{ textAlign: 'right', fontWeight: '600' }} className="sales-text">{settings.currency === 'RS' ? 'Rs' : settings.currency}{Number(item.price || 0).toFixed(2)}</td>
                          <td style={{ textAlign: 'right', fontWeight: '600' }} className="sales-text">
                            {formatCurrency(Number(item.discount || 0), settings.currency || 'USD')}
                          </td>
                          <td style={{ textAlign: 'center' }}>
                            <span className="sales-text-small" style={{
                              padding: 'clamp(2px, 0.4vw, 4px) clamp(6px, 1.2vw, 8px)',
                              backgroundColor: isFocused ? 'white' : '#f3f4f6',
                              borderRadius: 'clamp(4px, 0.8vw, 6px)',
                              fontWeight: '700',
                              display: 'inline-block'
                            }}>
                              {item.quantity}
                            </span>
                          </td>
                          <td style={{ textAlign: 'center' }}>
                            {item.isManualEntry && item.barcode && !String(item.barcode).startsWith('DUM-') && (
                              <button
                                type="button"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  sessionStorage.setItem('quickAddInitialData', JSON.stringify({
                                    barcode: item.barcode,
                                    name: item.name,
                                    sellingPrice: String(item.price || 0)
                                  }));
                                  sessionStorage.setItem('quickAddSaveOnly', '1');
                                  window.dispatchEvent(new Event('pos-open-quick-product-modal'));
                                }}
                                className="sales-button"
                                style={{
                                  padding: 'clamp(4px, 0.8vw, 6px) clamp(8px, 1.5vw, 12px)',
                                  marginRight: '6px',
                                  backgroundColor: isFocused ? '#10b981' : '#d1fae5',
                                  color: isFocused ? 'white' : '#065f46',
                                  minWidth: 'auto',
                                  fontSize: '11px'
                                }}
                                title={t('sales.saveAsProduct') || 'Save as product (appears in Products tab)'}
                              >
                                {t('sales.saveAsProduct') || 'Save as product'}
                              </button>
                            )}
                            <button
                              onClick={(e) => { e.stopPropagation(); removeItem(item.id); }}
                              className="sales-button sales-button-danger"
                              style={{
                                padding: 'clamp(4px, 0.8vw, 6px) clamp(8px, 1.5vw, 12px)',
                                backgroundColor: isFocused ? 'var(--danger)' : '#fee2e2',
                                color: isFocused ? 'white' : 'var(--danger)',
                                minWidth: 'auto',
                                width: 'auto'
                              }}
                            >
                              {t('sales.remove')}
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              )}
            </div>

            {/* Cart Pagination */}
            {cartTotalPages > 1 && (
              <div style={{ padding: '8px 12px', borderTop: '1px solid #eee', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '10px', backgroundColor: '#f9fafb', flexShrink: 0 }}>
                <button disabled={cartPage === 1} onClick={() => setCartPage(p => Math.max(1, p - 1))} style={{ padding: '4px 10px', border: '1px solid #ddd', borderRadius: '4px', background: 'white', cursor: cartPage === 1 ? 'not-allowed' : 'pointer' }}>PREV</button>
                <span style={{ fontSize: '12px', fontWeight: '700' }}>PAGE {cartPage} / {cartTotalPages}</span>
                <button disabled={cartPage >= cartTotalPages} onClick={() => setCartPage(p => Math.min(cartTotalPages, p + 1))} style={{ padding: '4px 10px', border: '1px solid #ddd', borderRadius: '4px', background: 'white', cursor: cartPage >= cartTotalPages ? 'not-allowed' : 'pointer' }}>NEXT</button>
              </div>
            )}
          </div>

          {/* Right Panel - Summary */}
          <div className="sales-right-panel">
              <h2 className="sales-heading-2" style={{ marginBottom: 'clamp(8px, 1.5vw, 12px)' }}>{t('sales.summary')}</h2>
            <div className="summary-section" style={{ marginTop: 'clamp(4px, 0.8vw, 8px)', marginBottom: 'clamp(4px, 0.8vw, 8px)' }}>
              <div className="summary-row" style={{ marginBottom: 'clamp(2px, 0.4vw, 4px)' }}>
                <span className="sales-text">{t('sales.itemsInCart')}:</span>
                <span className="sales-text">{cart.reduce((sum, item) => sum + item.quantity, 0)}</span>
              </div>
              <div className="summary-row summary-total" style={{ marginBottom: 'clamp(6px, 1.2vw, 10px)', paddingBottom: 'clamp(4px, 0.8vw, 6px)', borderBottom: '1px solid var(--border-color)' }}>
                <span>{t('sales.total')}:</span>
                <span>{formatCurrency(netTotal || 0, settings.currency || 'USD')}</span>
              </div>
              <div className="summary-row" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <label htmlFor="overall-discount" className="sales-text">
                  {t('sales.transactionDiscount')}
                  <kbd style={{ marginLeft: 6, fontSize: 11, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Alt+T</kbd>:
                </label>
                <div style={{ display: 'inline-flex', alignItems: 'center', gap: 6, background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: 6, padding: '2px' }}>
                  <button
                    type="button"
                    onClick={() => setDiscountMode('fixed')}
                    title="Fixed amount (F)"
                    style={{
                      padding: '2px 8px',
                      borderRadius: 4,
                      border: 'none',
                      background: discountMode === 'fixed' ? '#e5e7eb' : 'transparent',
                      cursor: 'pointer'
                    }}
                  >
                    $
                    <kbd style={{ marginLeft: 4, fontSize: 10, padding: '0 4px', border: '1px solid #e5e7eb', borderRadius: 3, background: '#fff' }}>F</kbd>
                  </button>
                  <button
                    type="button"
                    onClick={() => setDiscountMode('percentage')}
                    title="Percentage (P)"
                    style={{
                      padding: '2px 8px',
                      borderRadius: 4,
                      border: 'none',
                      background: discountMode === 'percentage' ? '#e5e7eb' : 'transparent',
                      cursor: 'pointer'
                    }}
                  >
                    %
                    <kbd style={{ marginLeft: 4, fontSize: 10, padding: '0 4px', border: '1px solid #e5e7eb', borderRadius: 3, background: '#fff' }}>P</kbd>
                  </button>
                </div>
                <input
                  id="overall-discount"
                  type="number"
                  min="0"
                  step="0.01"
                  value={Number(discountInput) || 0}
                  onChange={(e) => {
                    const v = parseFloat(e.target.value) || 0;
                    setDiscountInput(v);
                    if (discountMode === 'fixed') {
                      updateGlobalDiscount(v);
                    } else {
                      const baseTotal = Number(total || 0);
                      const amount = Math.max(0, Math.min(baseTotal, (v / 100) * baseTotal));
                      updateGlobalDiscount(Number.isFinite(amount) ? amount : 0);
                    }
                  }}
                  onKeyDown={(e) => {
                    const k = (e.key || '').toLowerCase();
                    if (k === 'p') {
                      e.preventDefault();
                      setDiscountMode('percentage');
                    } else if (k === 'f') {
                      e.preventDefault();
                      setDiscountMode('fixed');
                    }
                  }}
                  className="sales-input"
                  style={{ width: 'clamp(100px, 12vw, 200px)', minWidth: 100 }}
                  title={t('sales.transactionDiscount')}
                  ref={overallDiscountRef}
                />
                <span style={{ fontSize: 11, color: '#6b7280' }}>
                  {discountMode === 'fixed' ? t('sales.amount') : '%'}
                </span>
              </div>
              <div className="summary-row" style={{ marginTop: 'clamp(6px, 1.2vw, 10px)', display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span className="sales-text">
                  {t('sales.paymentMethod')}
                  <kbd title="Open selector" style={{ marginLeft: 6, fontSize: 11, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Alt+D</kbd>:
                </span>
                <select value={paymentMethod} onChange={(e) => setPaymentMethod(e.target.value)} className="sales-input" style={{ width: 'auto', minWidth: 'clamp(80px, 15vw, 120px)', padding: 'clamp(4px, 0.8vw, 6px)' }}>
                  {paymentMethodsList.map((m) => (
                    <option key={m.id} value={m.code}>{m.name}</option>
                  ))}
                </select>
              </div>
            </div>
            <button
              onClick={handleCompleteSale}
              disabled={cart.length === 0}
              className={`complete-sale-button ${isReturnMode ? 'sales-button-danger' : ''}`}
              style={{ backgroundColor: isReturnMode ? '#ef4444' : (cart.length > 0 ? '#10b981' : '#ccc') }}
            >
              {isReturnMode ? 'Process Return' : 'Complete Sale (F10)'}
            </button>
          </div>
        </div>
      </div>

      {/* Modals */}
      {isEditRowModalOpen && selectedRowIndex !== null && (
        <EditRowModal isOpen={isEditRowModalOpen} onClose={() => { setIsEditRowModalOpen(false); setSelectedRowIndex(null); }} item={cart[selectedRowIndex]} onUpdate={handleUpdateCartItem} />
      )}

      {/* Alt+N: Add Product To Sales popup (Screen B) - Payment Method style; F/P discount shortcuts; Esc close */}
      {showAddProductPopup && mode === 'DUMMY' && (
        <div
          className="modal-overlay"
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          onClick={() => setShowAddProductPopup(false)}
          onKeyDown={(e) => {
            if (e.key === 'Escape') {
              e.preventDefault();
              setShowAddProductPopup(false);
            }
          }}
          tabIndex={-1}
          role="dialog"
          aria-label="Add Product To Sales"
        >
          <div
            className="modal-content add-product-popup"
            style={{ background: 'white', width: 'min(480px, 92vw)', borderRadius: 12, overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}
            onClick={e => e.stopPropagation()}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleAddProductPopupSubmit(e, false); // Add and Next
              }
            }}
          >
            <div style={{ padding: '14px 16px', borderBottom: '1px solid #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <h3 style={{ margin: 0 }}>Add Product To Sales</h3>
              <button type="button" onClick={() => setShowAddProductPopup(false)} style={{ border: 'none', background: 'transparent', fontSize: 22, color: '#888', cursor: 'pointer' }}>×</button>
            </div>
            <form onSubmit={(e) => { e.preventDefault(); handleAddProductPopupSubmit(e, false); }} style={{ padding: 16, display: 'flex', flexDirection: 'column', gap: 10 }}>
              <div>
                <label style={{ display: 'block', fontSize: 14, fontWeight: 500, color: '#1f2937', marginBottom: 6 }}>{t('sales.productName') || 'Product name'}</label>
                <input
                  ref={popupNameRef}
                  type="text"
                  value={popupName}
                  onChange={e => setPopupName(e.target.value)}
                  placeholder="e.g. Misc Item"
                  style={{ width: '100%', padding: '8px 12px', boxSizing: 'border-box', border: '1px solid #e5e7eb', borderRadius: 6 }}
                />
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                <div>
                  <label style={{ display: 'block', fontSize: 14, fontWeight: 500, color: '#1f2937', marginBottom: 6 }}>{t('sales.price') || 'Price'}</label>
                  <input
                    type="number"
                    step="0.01"
                    min="0"
                    value={popupPrice}
                    onChange={e => setPopupPrice(e.target.value)}
                    placeholder="0.00"
                    style={{ width: '100%', padding: '8px 12px', boxSizing: 'border-box', border: '1px solid #e5e7eb', borderRadius: 6 }}
                  />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: 14, fontWeight: 500, color: '#1f2937', marginBottom: 6 }}>{t('sales.quantity') || 'Qty'}</label>
                  <input
                    type="number"
                    min="1"
                    step="1"
                    value={popupQty}
                    onChange={e => setPopupQty(e.target.value)}
                    style={{ width: '100%', padding: '8px 12px', boxSizing: 'border-box', border: '1px solid #e5e7eb', borderRadius: 6 }}
                  />
                </div>
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 14, fontWeight: 500, color: '#1f2937', marginBottom: 6 }}>
                  {t('sales.discount') || 'Discount'} — <kbd style={{ fontSize: 12, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>F</kbd> value &nbsp; <kbd style={{ fontSize: 12, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>P</kbd> percentage
                </label>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <input
                    type="number"
                    step="0.01"
                    min="0"
                    value={popupDiscount}
                    onChange={e => setPopupDiscount(e.target.value)}
                    placeholder={popupDiscountMode === 'percentage' ? 'e.g. 10' : '0.00'}
                    style={{ flex: 1, padding: '8px 12px', boxSizing: 'border-box', border: '1px solid #e5e7eb', borderRadius: 6 }}
                  />
                  <div style={{ display: 'flex', gap: 4 }}>
                    <button
                      type="button"
                      onClick={() => setPopupDiscountMode('fixed')}
                      style={{
                        padding: '6px 12px',
                        fontSize: 12,
                        fontWeight: popupDiscountMode === 'fixed' ? 600 : 400,
                        border: '1px solid #e5e7eb',
                        borderRadius: 6,
                        background: popupDiscountMode === 'fixed' ? '#4f46e5' : '#f9fafb',
                        color: popupDiscountMode === 'fixed' ? 'white' : '#374151',
                        cursor: 'pointer'
                      }}
                    >
                      F
                    </button>
                    <button
                      type="button"
                      onClick={() => setPopupDiscountMode('percentage')}
                      style={{
                        padding: '6px 12px',
                        fontSize: 12,
                        fontWeight: popupDiscountMode === 'percentage' ? 600 : 400,
                        border: '1px solid #e5e7eb',
                        borderRadius: 6,
                        background: popupDiscountMode === 'percentage' ? '#4f46e5' : '#f9fafb',
                        color: popupDiscountMode === 'percentage' ? 'white' : '#374151',
                        cursor: 'pointer'
                      }}
                    >
                      P
                    </button>
                  </div>
                </div>
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 14, fontWeight: 500, color: '#1f2937', marginBottom: 6 }}>{t('sales.barcode') || 'Barcode'}</label>
                <input
                  type="text"
                  value={popupBarcode}
                  onChange={e => setPopupBarcode(e.target.value)}
                  placeholder={t('sales.optional') || 'Optional'}
                  style={{ width: '100%', padding: '8px 12px', boxSizing: 'border-box', border: '1px solid #e5e7eb', borderRadius: 6 }}
                />
              </div>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 4, flexWrap: 'wrap' }}>
                <button type="button" onClick={() => setShowAddProductPopup(false)} style={{ padding: '8px 16px', border: '1px solid #e5e7eb', borderRadius: 6, background: '#f9fafb', cursor: 'pointer' }}>
                  {t('common.cancel') || 'Cancel'}
                </button>
                <button type="submit" style={{ padding: '8px 16px', borderRadius: 6, background: '#4f46e5', color: 'white', border: 'none', cursor: 'pointer', fontWeight: 600 }}>
                  Add and Next (Enter)
                </button>
                <button type="button" onClick={() => handleAddProductPopupSubmit(null, true)} style={{ padding: '8px 16px', borderRadius: 6, background: '#059669', color: 'white', border: 'none', cursor: 'pointer', fontWeight: 600 }}>
                  Add and Close (F10)
                </button>
              </div>
              <div style={{ fontSize: 12, color: '#666', marginTop: 6 }}>
                <kbd style={{ fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>F</kbd> value
                <span style={{ marginLeft: 8 }}>·</span>
                <kbd style={{ marginLeft: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>P</kbd> percentage
                <span style={{ marginLeft: 8 }}>·</span>
                <kbd style={{ marginLeft: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>Enter</kbd> Add and Next
                <span style={{ marginLeft: 8 }}>·</span>
                <kbd style={{ marginLeft: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', marginRight: 4 }}>F10</kbd> Add and Close
                <span style={{ marginLeft: 8 }}>·</span>
                <kbd style={{ marginLeft: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Esc</kbd> Close
              </div>
            </form>
          </div>
        </div>
      )}

      <ManagerAuthorizationModal
        isOpen={showManagerAuthModal}
        onClose={() => { setShowManagerAuthModal(false); setPendingWarehouseChange(null); }}
        onAuthorized={handleManagerAuthSuccess}
        title={t('rbac.authorizationRequired')}
        message={t('rbac.managerAuthMessage')}
      />

      {showReceipt && receiptData && (
        <div className="modal-overlay" style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <div
            ref={receiptModalRef}
            className="receipt-modal"
            role="dialog"
            tabIndex={0}
            style={{ backgroundColor: 'white', padding: '20px', borderRadius: '8px', maxWidth: '420px', width: '90%', maxHeight: '90vh', overflowY: 'auto', outline: 'none' }}
            onClick={e => e.stopPropagation()}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                receiptPrintRef.current?.print();
              } else if (e.key === 'Escape') {
                e.preventDefault();
                handleReceiptPrintComplete();
              }
            }}
          >
            <ReceiptPrinter ref={receiptPrintRef} saleData={receiptData} businessInfo={businessInfo} currency={settings.currency} onAfterPrint={handleReceiptPrintComplete} />
            <button onClick={() => handleReceiptPrintComplete()} style={{ width: '100%', padding: '8px', marginTop: '10px' }}>{t('common.close') || 'Close'} (Esc)</button>
          </div>
        </div>
      )}

      {/* Help Demo Modal */}
      {isHelpDemoOpen && (
        <HelpDemoModal isOpen={isHelpDemoOpen} onClose={() => setIsHelpDemoOpen(false)} />
      )}



      {/* Return Reason Modal - F10 = Process Return, Esc = Cancel */}
      {showReturnReasonModal && createPortal(
        <div
          className="modal-overlay"
          role="dialog"
          aria-modal="true"
          aria-labelledby="return-reason-title"
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            backgroundColor: 'rgba(0,0,0,0.5)',
            zIndex: 99999,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
          onClick={(e) => {
            if (e.target === e.currentTarget && !returnSubmitLoading) {
              setShowReturnReasonModal(false);
              setReturnReason('');
            }
          }}
          onKeyDown={(e) => {
            if (e.key === 'Escape' && !returnSubmitLoading) {
              e.preventDefault();
              setShowReturnReasonModal(false);
              setReturnReason('');
            }
          }}
          tabIndex={-1}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              backgroundColor: 'white',
              padding: '24px',
              borderRadius: '8px',
              maxWidth: '500px',
              width: '90%',
              boxShadow: '0 4px 20px rgba(0,0,0,0.15)',
            }}
          >
            <h3 id="return-reason-title" style={{ marginBottom: '8px', fontSize: '18px' }}>
              {t('sales.returnReason') || 'Return Reason'}
            </h3>
            <p style={{ marginBottom: '8px', fontSize: '13px', color: '#555', display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
              <span>
                <kbd style={{ padding: '3px 8px', background: '#e5e7eb', border: '1px solid #d1d5db', borderRadius: '4px', fontWeight: 600, fontSize: '12px' }}>F10</kbd>
                <span style={{ marginLeft: '4px' }}>{t('sales.processReturn') || 'Process Return'}</span>
              </span>
              <span style={{ color: '#ccc' }}>|</span>
              <span>
                <kbd style={{ padding: '3px 8px', background: '#e5e7eb', border: '1px solid #d1d5db', borderRadius: '4px', fontWeight: 600, fontSize: '12px' }}>Esc</kbd>
                <span style={{ marginLeft: '4px' }}>{t('common.cancel') || 'Cancel'}</span>
              </span>
            </p>
            <p style={{ marginBottom: '12px', fontSize: '14px', color: '#666' }}>
              {t('sales.returnReasonPrompt') || 'Please provide a reason for this return:'}
            </p>
            <textarea
              value={returnReason}
              onChange={(e) => setReturnReason(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && e.ctrlKey && returnReason.trim() && !returnSubmitLoading) {
                  e.preventDefault();
                  document.getElementById('return-submit-btn')?.click();
                } else if (e.key === 'Escape' && !returnSubmitLoading) {
                  e.preventDefault();
                  setShowReturnReasonModal(false);
                  setReturnReason('');
                }
              }}
              placeholder={t('sales.returnReasonPlaceholder') || 'e.g., Item damaged, Wrong product, Customer request...'}
              style={{ width: '100%', minHeight: '100px', padding: '12px', border: '1px solid #ddd', borderRadius: '4px', fontSize: '14px', marginBottom: '16px', boxSizing: 'border-box' }}
              autoFocus
              disabled={returnSubmitLoading}
            />
            <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end' }}>
              <button
                type="button"
                onClick={() => {
                  if (returnSubmitLoading) return;
                  setShowReturnReasonModal(false);
                  setReturnReason('');
                }}
                disabled={returnSubmitLoading}
                style={{ padding: '10px 20px', backgroundColor: '#e5e7eb', border: 'none', borderRadius: '4px', cursor: returnSubmitLoading ? 'not-allowed' : 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}
              >
                <span>{t('common.cancel') || 'Cancel'}</span>
                <kbd style={{ fontSize: 10, padding: '2px 5px', opacity: 0.9, border: '1px solid #9ca3af', borderRadius: 3, background: '#f9fafb' }}>Esc</kbd>
              </button>
              <button
                id="return-submit-btn"
                type="button"
                onClick={async () => {
                  if (!returnReason.trim() || returnSubmitLoading) return;
                  setReturnSubmitLoading(true);
                  try {
                    const saleResult = await completeSale(paymentMethod, {
                      type: 'return',
                      notes: returnReason.trim() || (t('sales.noReasonProvided') || 'No reason provided'),
                    });
                    if (saleResult) {
                      setShowReturnReasonModal(false);
                      setReturnReason('');
                      setReceiptData(saleResult);
                      setShowReceipt(true);
                      setIsReceiptPrinting(true);
                      setIsReturnMode(false);
                      requestAnimationFrame(() => {
                        setTimeout(() => {
                          try {
                            receiptPrintRef.current?.print();
                          } catch (err) {
                            console.warn('Return receipt print failed:', err);
                          }
                        }, 150);
                      });
                    }
                  } catch (error) {
                    console.error('Error processing return:', error);
                    alert(t('sales.returnError') || 'Error processing return. Please try again.');
                  } finally {
                    setReturnSubmitLoading(false);
                  }
                }}
                disabled={!returnReason.trim() || returnSubmitLoading}
                style={{
                  padding: '10px 20px',
                  backgroundColor: returnReason.trim() && !returnSubmitLoading ? '#ef4444' : '#ccc',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: returnReason.trim() && !returnSubmitLoading ? 'pointer' : 'not-allowed',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                }}
              >
                <span>{returnSubmitLoading ? (t('sales.processing') || 'Processing...') : (t('sales.processReturn') || 'Process Return')}</span>
                {!returnSubmitLoading && <kbd style={{ fontSize: 10, padding: '2px 5px', opacity: 0.95, border: '1px solid rgba(255,255,255,0.6)', borderRadius: 3, background: 'rgba(255,255,255,0.2)' }}>F10</kbd>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* Payment Modal */}
      <PaymentModal
        isOpen={showPaymentModal}
        onClose={() => setShowPaymentModal(false)}
        onConfirm={handlePaymentConfirm}
        totalAmount={netTotal}
        currency={settings.currency || 'USD'}
        paymentMethod={paymentMethod}
      />
      {/* Sales Transaction History Modal */}
      {isHistoryOpen && (
        <SalesTransactionHistory
          isOpen={isHistoryOpen}
          onClose={() => setIsHistoryOpen(false)}
          onEditSale={handleEditSale}
        />
      )}
      {isPaymentMethodOpen && (
        <PaymentMethodModal
          isOpen={isPaymentMethodOpen}
          onClose={() => setIsPaymentMethodOpen(false)}
          onSelect={(m) => setPaymentMethod(m)}
          onConfirm={() => handleCompleteSale()}
          current={paymentMethod}
        />
      )}
      {isWarehouseModalOpen && warehouses.length > 0 && (
        <WarehouseSelectionModal
          isOpen={isWarehouseModalOpen}
          onClose={() => setIsWarehouseModalOpen(false)}
          onSelect={(id) => handleWarehouseChange(id)}
          warehouses={warehouses}
          current={selectedWarehouseId}
        />
      )}
    </div>
  );
};

export default SalesScreen;
