import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { post } from '../utils/api';
import UOMDropdown from './common/UOMDropdown';

const getValidationErrors = (product) => {
  const newErrors = {};
  if (!product.name || !String(product.name).trim()) {
    newErrors.name = 'products.validation.nameRequired';
  }
  if (!product.sellingPrice || isNaN(parseFloat(product.sellingPrice)) || parseFloat(product.sellingPrice) <= 0) {
    newErrors.sellingPrice = 'products.validation.sellingPriceRequired';
  }
  if (product.costPrice !== '' && product.costPrice != null && (isNaN(parseFloat(product.costPrice)) || parseFloat(product.costPrice) < 0)) {
    newErrors.costPrice = 'products.validation.costPriceInvalid';
  }
  if (product.quantity !== '' && product.quantity != null && (isNaN(parseInt(product.quantity, 10)) || parseInt(product.quantity, 10) < 0)) {
    newErrors.quantity = 'products.validation.quantityInvalid';
  }
  return newErrors;
};

const QuickProductModal = ({ isOpen, onClose, onAddProduct, quantity = 1, initialData = null }) => {
  const { t } = useTranslation();
  const [settings, setSettings] = useState({ currency: '$' }); // Default currency
  const [product, setProduct] = useState({
    name: '',
    sellingPrice: '',
    costPrice: '',
    barcode: '',
    categoryId: '',
    quantity: '',
    warehouseId: '',
    minStockLevel: 0,
    unit: 'pcs',
    baseUnitId: null,
    discountPercentage: '',
    discountFixedPrice: '',
    sku: ''
  });
  const [errors, setErrors] = useState({});
  const nameInputRef = useRef(null);
  const discountPercentageRef = useRef(null);
  const discountFixedPriceRef = useRef(null);

  const [categories, setCategories] = useState([]);
  const [warehouses, setWarehouses] = useState([]);
  const [isPrinting, setIsPrinting] = useState(false); // State for print status
  const [saveAndNext, setSaveAndNext] = useState(false); // State for Save & Next functionality

  // Load categories and settings when modal opens
  useEffect(() => {
    const loadData = async () => {
      try {
        // Load categories
        const categoriesResponse = await fetch('/api/categories', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });
        const categoriesResult = await categoriesResponse.json();
        if (categoriesResult.success) {
          setCategories(categoriesResult.data || []);
        }

        // Load settings
        const settingsResponse = await fetch('/api/settings', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });
        const settingsResult = await settingsResponse.json();
        if (settingsResult.success) {
          setSettings(settingsResult.data);
        }

        // Load warehouses for default warehouse dropdown
        const warehousesResponse = await fetch('/api/warehouses', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });
        const warehousesResult = await warehousesResponse.json();
        if (warehousesResult.success) {
          setWarehouses(warehousesResult.data || []);
        }
      } catch (error) {
        console.error('Error loading data:', error);
      }
    };

    if (isOpen) {
      loadData();
    }
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) {
      sessionStorage.removeItem('quickAddInitialData');
      sessionStorage.removeItem('quickAddSaveOnly');
    }
  }, [isOpen]);

  // Focus first input when modal opens and check for pending barcode or initial data
  useEffect(() => {
    if (isOpen) {
      const quickAddData = sessionStorage.getItem('quickAddInitialData');
      if (quickAddData) {
        try {
          const data = JSON.parse(quickAddData);
          setProduct(prev => ({ ...prev, ...data }));
          // Keep quickAddInitialData so we can set default warehouse when warehouses load
        } catch (e) {}
      } else {
        const pendingBarcode = sessionStorage.getItem('pendingBarcodeForQuickAdd');
        if (pendingBarcode) {
          setProduct(prev => ({ ...prev, barcode: pendingBarcode }));
          sessionStorage.removeItem('pendingBarcodeForQuickAdd');
        } else if (initialData) {
          setProduct(prev => ({ ...prev, ...initialData }));
        }
      }
      nameInputRef.current?.focus();
    }
  }, [isOpen, initialData]);

  // When opening from "Save as product", set default warehouse once warehouses are loaded
  useEffect(() => {
    if (!isOpen || warehouses.length === 0) return;
    const quickAddData = sessionStorage.getItem('quickAddInitialData');
    if (quickAddData && warehouses[0]) {
      setProduct(prev => ({ ...prev, warehouseId: String(warehouses[0].id) }));
      sessionStorage.removeItem('quickAddInitialData');
    }
  }, [isOpen, warehouses]);

  // Handle keyboard events in modal
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      } else if (e.key === 'F10') {
        e.preventDefault();
        handleAddProduct();
      } else if (e.altKey && e.key.toLowerCase() === 'p') {
        e.preventDefault();
        discountPercentageRef.current?.focus();
      } else if (e.altKey && e.key.toLowerCase() === 'f') {
        e.preventDefault();
        discountFixedPriceRef.current?.focus();
      }
    };

    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [isOpen, onClose, product]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setProduct(prev => ({
      ...prev,
      [name]: value
    }));

    // Clear error when user types
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  // Log product state for debugging
  useEffect(() => {
    console.log('Product state:', product);
    console.log('Validation errors:', errors);
  }, [product, errors]);

  const flattenedCategories = useMemo(() => {
    const byId = new Map(categories.map(c => [c.id, { ...c, children: [] }]));
    const roots = [];
    byId.forEach(node => {
      if (node.parentId && byId.has(node.parentId)) {
        byId.get(node.parentId).children.push(node);
      } else {
        roots.push(node);
      }
    });
    const sortTree = (nodes) => {
      nodes.sort((a, b) => a.name.localeCompare(b.name));
      nodes.forEach(n => sortTree(n.children));
    };
    sortTree(roots);
    const out = [];
    const walk = (nodes, prefix = []) => {
      nodes.forEach(n => {
        const labelPath = [...prefix, n.name].join(' > ');
        out.push({ id: n.id, label: labelPath });
        if (n.children && n.children.length) walk(n.children, [...prefix, n.name]);
      });
    };
    walk(roots);
    return out;
  }, [categories]);

  const handleAddProduct = useCallback(async () => {
    const validationErrors = getValidationErrors(product);
    if (Object.keys(validationErrors).length) {
      setErrors(validationErrors);
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        alert(t('products.errors.authRequired'));
        return;
      }

      let categoryIdValue = null;
      if (product.categoryId && product.categoryId !== '' && !isNaN(parseInt(product.categoryId))) {
        const parsedCategoryId = parseInt(product.categoryId);
        if (parsedCategoryId > 0) {
          categoryIdValue = parsedCategoryId;
        }
      }

      const safeFloat = (value) => {
        if (!value || value === '' || isNaN(parseFloat(value))) return null;
        return parseFloat(value);
      };
      const safeInt = (value) => {
        if (!value || value === '' || isNaN(parseInt(value))) return 0;
        return parseInt(value);
      };

      const warehouseIdValue = product.warehouseId && product.warehouseId !== '' && !isNaN(parseInt(product.warehouseId))
        ? parseInt(product.warehouseId) : null;

      const productData = {
        ...product,
        ...(categoryIdValue ? { categoryId: categoryIdValue } : {}),
        ...(warehouseIdValue ? { warehouseId: warehouseIdValue } : {}),
        sellingPrice: safeFloat(product.sellingPrice),
        costPrice: safeFloat(product.costPrice),
        quantity: safeInt(product.quantity),
        minStockLevel: safeInt(product.minStockLevel) || 0,
        unit: product.unit || 'pcs',
        baseUnitId: product.baseUnitId || null,
        discountPercentage: safeFloat(product.discountPercentage),
        discountFixedPrice: safeFloat(product.discountFixedPrice),
        ...(product.sku && product.sku.trim() !== '' ? { sku: product.sku.trim() } : {})
      };

      if (!productData.name || productData.name.trim() === '') {
        setErrors({ name: 'products.validation.nameRequired' });
        return;
      }
      if (productData.sellingPrice === null || productData.sellingPrice <= 0) {
        setErrors({ sellingPrice: 'products.validation.sellingPriceRequired' });
        return;
      }

      let result;
      if (isPrinting) {
        result = await post('/products/create-with-barcode-and-print', productData);
      } else {
        result = await post('/products/create-with-barcode', productData);
      }

      if (!result.success) {
        const rawMsg = (result.errors?.map(e => e.msg).join(' ') || result.message || '').toLowerCase();
        const friendlyMessage = rawMsg.includes('barcode') && (rawMsg.includes('unique') || rawMsg.includes('exists') || rawMsg.includes('duplicate'))
          ? t('products.errors.barcodeExists')
          : (result.message ? result.message : t('products.errors.createFailed'));
        alert(friendlyMessage);
        return;
      }

      const saveOnly = sessionStorage.getItem('quickAddSaveOnly');
      if (saveOnly) {
        sessionStorage.removeItem('quickAddSaveOnly');
        alert(t('products.success.createdAndInProducts') || 'Product created. It will appear in the Products tab.');
        onClose();
        setProduct({ name: '', sellingPrice: '', costPrice: '', barcode: '', categoryId: '', quantity: '', warehouseId: '', minStockLevel: 0, unit: 'pcs', baseUnitId: null, discountPercentage: '', discountFixedPrice: '', sku: '' });
        return;
      }

      onAddProduct({
        ...result.data,
        quantity: quantity
      });

      if (isPrinting && result.printSuccess) {
        alert(t('products.success.createdPrinted'));
      } else if (isPrinting) {
        alert(t('products.success.createdPrintFailed'));
      } else {
        alert(t('products.success.created'));
      }

      if (saveAndNext) {
        setProduct({ name: '', sellingPrice: '', costPrice: '', barcode: '', categoryId: '', quantity: '', warehouseId: '', minStockLevel: 0, unit: 'pcs', baseUnitId: null, discountPercentage: '', discountFixedPrice: '', sku: '' });
        setIsPrinting(false);
        setSaveAndNext(false);
        setTimeout(() => {
          nameInputRef.current?.focus();
        }, 100);
      } else {
        setProduct({ name: '', sellingPrice: '', costPrice: '', barcode: '', categoryId: '', quantity: '', warehouseId: '', minStockLevel: 0, unit: 'pcs', baseUnitId: null, discountPercentage: '', discountFixedPrice: '', sku: '' });
        setIsPrinting(false);
        onClose();
      }
    } catch (error) {
      console.error('Error creating product:', error);
      const msg = error?.message || '';
      const friendly = msg.toLowerCase().includes('network') || error?.name === 'TypeError'
        ? t('messages.networkError')
        : t('products.errors.createFailed');
      alert(friendly);
    }
  }, [product, onAddProduct, quantity, onClose, isPrinting, saveAndNext, t]);

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-container" onClick={(e) => e.stopPropagation()}>
        <style>{`
          /* Reset & Base Styles */
          .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.5);
            backdrop-filter: blur(8px);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 2000;
            padding: 20px;
            animation: fadeIn 0.3s ease-out;
          }

          .modal-container {
            max-width: 1000px;
            width: 100%;
            background: white;
            border-radius: 24px;
            box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
            overflow: hidden;
            display: flex;
            flex-direction: column;
            max-height: 95vh;
            animation: slideUp 0.3s ease-out;
            font-family: -apple-system, system-ui, sans-serif;
          }

          /* Header Styles */
          .modal-header {
            padding: 1.5rem 2rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            background: linear-gradient(135deg, #10b981 0%, #059669 100%);
            color: white;
          }

          .header-content {
            display: flex;
            align-items: center;
            gap: 12px;
          }

          .header-title {
            margin: 0;
            font-weight: 800;
            font-size: 1.5rem;
            letter-spacing: -0.5px;
          }

          .close-button {
            background: rgba(255,255,255,0.2);
            border: none;
            color: white;
            cursor: pointer;
            padding: 8px;
            border-radius: 10px;
            transition: all 0.2s;
          }

          .close-button:hover {
            background: rgba(255,255,255,0.3);
          }

          /* Content Styles */
          .modal-content {
            padding: 1.5rem;
            overflow-y: auto;
            flex: 1;
          }

          /* Responsive Grid System */
          .grid-row {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 1.5rem;
          }

          /* Input Styles */
          .modern-label { display: block; font-size: 13px; font-weight: 700; color: #374151; margin-bottom: 8px; text-transform: uppercase; letter-spacing: 0.5px; }
          .modern-input { width: 100%; padding: 12px 16px; border: 2px solid #e5e7eb; border-radius: 12px; font-size: 15px; outline: none; transition: 0.3s; box-sizing: border-box; }
          .modern-input:focus { border-color: #3b82f6; background: #f8fafc; box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1); }
          .error { border-color: #ef4444 !important; background: #fef2f2 !important; }
          .error-message { color: #ef4444; font-size: 13px; margin-top: 6px; display: flex; align-items: center; gap: 6px; font-weight: 500; }
          
          /* Button Styles */
          .modern-button { padding: 12px 24px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; transition: 0.3s; border: none; text-transform: uppercase; letter-spacing: 0.5px; }
          .primary { background: linear-gradient(135deg, #10b981 0%, #059669 100%); color: white; box-shadow: 0 4px 12px rgba(16, 185, 129, 0.3); }
          .primary:hover { background: linear-gradient(135deg, #059669 0%, #047857 100%); box-shadow: 0 6px 16px rgba(16, 185, 129, 0.4); transform: translateY(-2px); }
          .secondary { background: #f3f4f6; color: #374151; border: 2px solid #e5e7eb; }
          .secondary:hover { background: #e5e7eb; border-color: #d1d5db; transform: translateY(-1px); }
          
          /* Discount Section */
          .discount-section {
            padding: 1rem;
            background: #f8fafc;
            border-radius: 12px;
            border: 1px solid #e2e8f0;
          }
          
          .discount-header {
            margin: 0 0 0.75rem 0;
            color: #475569;
            font-size: 0.85rem;
          }
          
          .discount-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 0.75rem;
            margin-bottom: 0.75rem;
          }
          
          .final-price-display {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 0.5rem 0.75rem;
            background: white;
            border-radius: 6px;
            border: 1px solid #cbd5e1;
            font-size: 0.85rem;
          }
          
          /* Footer Section */
          .footer-section {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-top: 2rem;
            gap: 1rem;
            padding-top: 1rem;
            border-top: 1px solid #e5e7eb;
            background: #f9fafb;
          }
          
          .button-group {
            display: flex;
            gap: 0.75rem;
          }
          
          /* Responsive Adjustments */
          @media (max-width: 768px) {
            .modal-overlay { padding: 10px; }
            .modal-container { border-radius: 16px; max-height: 98vh; }
            .grid-row { grid-template-columns: 1fr; gap: 1rem; }
            .header-title { font-size: 1.2rem !important; }
            .modal-content { padding: 1rem !important; }
            .footer-section { flex-direction: column !important; align-items: stretch !important; }
            .button-group { width: 100%; }
            .modern-button { width: 100%; }
          }
          
          @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
          @keyframes slideUp { 
            from { transform: translateY(20px) scale(0.98); opacity: 0; }
            to { transform: translateY(0) scale(1); opacity: 1; }
          }
        `}</style>
        <style>{`
          @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
          }
          @keyframes slideUp {
            from { 
              transform: translateY(20px) scale(0.98);
              opacity: 0;
            }
            to { 
              transform: translateY(0) scale(1);
              opacity: 1;
            }
          }
          @media (max-width: 640px) {
            .modal-container {
              max-width: 100% !important;
              border-radius: 16px !important;
              max-height: 95vh !important;
            }
            .modal-header {
              padding: 1.5rem !important;
            }
            .modal-body {
              padding: 1.5rem !important;
              gap: 1.25rem !important;
            }
            .modal-footer {
              padding: 1.25rem 1.5rem !important;
              flex-direction: column-reverse !important;
            }
            .modern-button {
              width: 100% !important;
            }
          }
          .modern-input {
            width: 100%;
            padding: 14px 18px;
            border: 2px solid #e5e7eb;
            border-radius: 12px;
            font-size: 15px;
            font-weight: 500;
            color: #1f2937;
            background: #ffffff;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            outline: none;
          }
          .modern-input:focus {
            border-color: #3b82f6;
            background: #f8fafc;
            box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1), 0 0 0 1px rgba(59, 130, 246, 0.2);
            transform: translateY(-1px);
          }
          .modern-input:hover:not(:focus) {
            border-color: #d1d5db;
          }
          .modern-input.error {
            border-color: #ef4444;
            background: #fef2f2;
          }
          .modern-input.error:focus {
            border-color: #ef4444;
            box-shadow: 0 0 0 4px rgba(239, 68, 68, 0.1), 0 0 0 1px rgba(239, 68, 68, 0.2);
          }
          .error-message {
            color: #ef4444;
            font-size: 13px;
            margin-top: 6px;
            display: flex;
            align-items: center;
            gap: 6px;
            font-weight: 500;
          }
          .modern-label {
            display: block;
            font-size: 13px;
            font-weight: 700;
            color: #374151;
            margin-bottom: 8px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
          }
          .modern-button {
            padding: 14px 28px;
            border-radius: 12px;
            font-size: 14px;
            font-weight: 700;
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            border: none;
            text-transform: uppercase;
            letter-spacing: 0.5px;
          }
          .modern-button.primary {
            background: linear-gradient(135deg, #10b981 0%, #059669 100%);
            color: white;
            box-shadow: 0 4px 12px rgba(16, 185, 129, 0.3);
          }
          .modern-button.primary:hover {
            background: linear-gradient(135deg, #059669 0%, #047857 100%);
            box-shadow: 0 6px 16px rgba(16, 185, 129, 0.4);
            transform: translateY(-2px);
          }
          .modern-button.primary:active {
            transform: translateY(0);
          }
          .modern-button.secondary {
            background: #f3f4f6;
            color: #374151;
            border: 2px solid #e5e7eb;
          }
          .modern-button.secondary:hover {
            background: #e5e7eb;
            border-color: #d1d5db;
            transform: translateY(-1px);
          }
        `}</style>

        <div className="modal-header">
          <div className="header-content">
            <svg style={{ width: '28px', height: '28px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            <h2 className="header-title">
              {t('products.quickAddTitle')}
            </h2>
          </div>
          <button onClick={onClose} className="close-button">
            <svg style={{ width: '24px', height: '24px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="modal-content">
          <div className="grid-row">

            <div>
              <label htmlFor="name" className="modern-label">
                {t('products.productName')} <span style={{ color: '#ef4444' }}>*</span>
              </label>
              <input
                ref={nameInputRef}
                type="text"
                id="name"
                name="name"
                value={product.name}
                onChange={handleInputChange}
                className={`modern-input ${errors.name ? 'error' : ''}`}
                placeholder="e.g. Organic Soda"
              />
              {errors.name && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  {t(errors.name)}
                </div>
              )}
            </div>

            <div>
              <label className="modern-label">
                {t('products.skuOptional')}
              </label>
              <input
                type="text"
                name="sku"
                value={product.sku}
                onChange={handleInputChange}
                className="modern-input"
                placeholder="e.g. ABC-123"
              />
            </div>

            <div>
              <label className="modern-label">
                {t('products.sellingPrice')} <span style={{ color: '#ef4444' }}>*</span>
              </label>
              <div style={{ position: 'relative' }}>
                <span style={{
                  position: 'absolute',
                  left: '18px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  fontWeight: '700',
                  color: '#6b7280',
                  fontSize: '16px'
                }}>{settings.currency || '$'}</span>
                <input
                  type="number"
                  name="sellingPrice"
                  value={product.sellingPrice}
                  onChange={handleInputChange}
                  step="0.01"
                  min="0.01"
                  className={`modern-input ${errors.sellingPrice ? 'error' : ''}`}
                  style={{ paddingLeft: '42px' }}
                  placeholder="0.00"
                />
              </div>
              {errors.sellingPrice && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  {t(errors.sellingPrice)}
                </div>
              )}
            </div>

            <div>
              <label className="modern-label">{t('products.categoryOptional')}</label>
              <select
                name="categoryId"
                value={product.categoryId}
                onChange={handleInputChange}
                className="modern-input"
                onKeyDown={(e) => {
                  // Allow arrow key navigation in the select dropdown
                  if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
                    // Let the default behavior handle the selection
                    return;
                  }
                }}
              >
                <option value="">{t('products.selectCategory')}</option>
                {flattenedCategories.map(category => (
                  <option key={category.id} value={category.id}>
                    {category.label}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="modern-label">{t('products.quantityOptional')}</label>
              <div style={{ position: 'relative' }}>
                <input
                  type="number"
                  name="quantity"
                  value={product.quantity}
                  onChange={handleInputChange}
                  min="0"
                  className={`modern-input ${errors.quantity ? 'error' : ''}`}
                  placeholder="0"
                />
              </div>
              {errors.quantity && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  {t(errors.quantity)}
                </div>
              )}
            </div>

            <div>
              <label className="modern-label">{t('warehouse.defaultWarehouse') || 'Default Warehouse'}</label>
              <select
                name="warehouseId"
                value={product.warehouseId}
                onChange={handleInputChange}
                className="modern-input"
              >
                <option value="">{t('warehouse.select') || 'Select Warehouse'}</option>
                {warehouses.map(w => (
                  <option key={w.id} value={w.id}>{w.name} {w.location ? `(${w.location})` : ''}</option>
                ))}
              </select>
              <small style={{ color: '#6b7280', fontSize: '11px', marginTop: '4px', display: 'block' }}>
                {t('warehouse.defaultWarehouseHint') || 'Initial stock will be mapped to this warehouse'}
              </small>
            </div>

            <div>
              <label className="modern-label">{t('products.costPriceOptional')}</label>
              <div style={{ position: 'relative' }}>
                <span style={{
                  position: 'absolute',
                  left: '18px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  fontWeight: '700',
                  color: '#6b7280',
                  fontSize: '16px'
                }}>{settings.currency || '$'}</span>
                <input
                  type="number"
                  name="costPrice"
                  value={product.costPrice}
                  onChange={handleInputChange}
                  step="0.01"
                  min="0"
                  className={`modern-input ${errors.costPrice ? 'error' : ''}`}
                  style={{ paddingLeft: '42px' }}
                  placeholder="0.00"
                />
              </div>
              {errors.costPrice && (
                <div className="error-message">
                  <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  {t(errors.costPrice)}
                </div>
              )}
            </div>

            <div>
              <UOMDropdown
                label={t('products.unit') || 'Unit'}
                name="unit"
                value={product.baseUnitId || product.unit}
                onChange={(shortName, unit) => setProduct(prev => ({
                  ...prev,
                  unit: shortName || 'pcs',
                  baseUnitId: unit ? unit.id : null
                }))}
                className="modern-input"
              />
            </div>

            <div>
              <label className="modern-label">{t('products.minStock')} / {t('warehouse.lowStockAlerts') || 'Low Stock Alert'}</label>
              <input
                type="number"
                name="minStockLevel"
                value={product.minStockLevel ?? ''}
                onChange={handleInputChange}
                min="0"
                className="modern-input"
                placeholder="0"
              />
              <small style={{ color: '#6b7280', fontSize: '11px', marginTop: '4px', display: 'block' }}>
                {t('products.minStock')} {t('warehouse.lowStockAlerts')}
              </small>
            </div>

          </div> {/* End of grid container */}

          <div className="discount-section">
            <h4 className="discount-header">{t('products.discountConfig')}</h4>
            <div className="discount-grid">
              <div>
                <label className="modern-label">{t('products.discount')} % <span style={{ fontSize: '9px', color: '#64748b' }}>[ALT+P]</span></label>
                <input
                  ref={discountPercentageRef}
                  type="number"
                  name="discountPercentage"
                  value={product.discountPercentage}
                  onChange={(e) => {
                    handleInputChange(e);
                    if (e.target.value) setProduct(prev => ({ ...prev, discountFixedPrice: '' }));
                  }}
                  min="0"
                  max="100"
                  className="modern-input"
                  placeholder="0%"
                />
              </div>
              <div>
                <label className="modern-label">{t('products.fixedDisc')} ({settings.currency || '$'}) <span style={{ fontSize: '9px', color: '#64748b' }}>[ALT+F]</span></label>
                <input
                  ref={discountFixedPriceRef}
                  type="number"
                  name="discountFixedPrice"
                  value={product.discountFixedPrice}
                  onChange={(e) => {
                    handleInputChange(e);
                    if (e.target.value) setProduct(prev => ({ ...prev, discountPercentage: '' }));
                  }}
                  min="0"
                  className="modern-input"
                  placeholder="0.00"
                />
              </div>
              <div style={{ padding: '10px', background: 'white', borderRadius: '10px', border: '1px dashed #cbd5e1', textAlign: 'center' }}>
                <span style={{ fontSize: '0.8rem', color: '#64748b', display: 'block' }}>{t('products.finalPrice')}</span>
                <span style={{ fontWeight: '800', color: '#10b981' }}>
                  {settings.currency || '$'}{(() => {
                    const price = parseFloat(product.sellingPrice) || 0;
                    if (product.discountFixedPrice) {
                      return Math.max(0, price - parseFloat(product.discountFixedPrice)).toFixed(2);
                    }
                    if (product.discountPercentage) {
                      return Math.max(0, price * (1 - parseFloat(product.discountPercentage) / 100)).toFixed(2);
                    }
                    return price.toFixed(2);
                  })()}
                </span>
              </div>
            </div>
          </div>

          <div>
            <label className="modern-label">{t('products.barcodeOptional')}</label>
            <div style={{ position: 'relative' }}>
              <input
                type="text"
                name="barcode"
                value={product.barcode}
                onChange={handleInputChange}
                className="modern-input"
                placeholder={t('products.scanBarcodePlaceholder')}
                style={{ background: '#fffef2', borderColor: '#eab30866' }}
              />
              <svg fill="none" stroke="currentColor" viewBox="0 0 24 24" style={{ position: 'absolute', right: '15px', top: '50%', transform: 'translateY(-50%)', width: '20px', color: '#94a3b8' }}>
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z"></path>
              </svg>
            </div>
          </div>

          {/* Action buttons at the bottom */}
          <div className="footer-section">
            <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer', gap: '8px' }}>
              <input
                type="checkbox"
                checked={isPrinting}
                onChange={() => setIsPrinting(!isPrinting)}
                style={{
                  width: '18px',
                  height: '18px',
                  accentColor: '#10b981'
                }}
              />
              <span style={{ fontWeight: '600', color: '#4b5563', fontSize: '0.9rem' }}>{t('products.printBarcodeAfterSave')}</span>
            </label>
            <div className="button-group">
              <button data-pos-action="cancel" onClick={onClose} className="modern-button secondary">
                {t('common.cancel')} <kbd>Esc</kbd>
              </button>
              <button
                onClick={() => {
                  setSaveAndNext(true);
                  handleAddProduct();
                }}
                className="modern-button"
                style={{
                  backgroundColor: '#f59e0b',
                  color: 'white',
                  border: 'none',
                  padding: '12px 24px',
                  borderRadius: '12px',
                  fontSize: '14px',
                  fontWeight: '700',
                  cursor: 'pointer',
                  transition: '0.3s',
                  textTransform: 'uppercase',
                  letterSpacing: '0.5px'
                }}
              >
                {t('products.saveAndNext')}
              </button>
              <button
                data-pos-action="save"
                onClick={handleAddProduct}
                className="modern-button primary"
              >
                {t('common.save')} <kbd>F10</kbd>
              </button>
            </div>
          </div>





        </div>
      </div>


    </div>
  );
};

export default QuickProductModal;
