import React from 'react';

/**
 * Catches render errors in children and shows a fallback instead of a white screen.
 */
class ErrorBoundary extends React.Component {
  state = { hasError: false, error: null };

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    console.error('ErrorBoundary caught:', error, errorInfo);
  }

  render() {
    if (this.state.hasError && this.state.error) {
      return (
        <div style={{
          padding: '2rem',
          maxWidth: '600px',
          margin: '2rem auto',
          backgroundColor: 'var(--bg-card)',
          border: '1px solid var(--border-light)',
          borderRadius: 'var(--radius-md)',
          color: 'var(--text-main)'
        }}>
          <h3 style={{ marginTop: 0, color: 'var(--danger)' }}>Something went wrong</h3>
          <p style={{ marginBottom: '1rem' }}>This screen could not load. Try refreshing the page.</p>
          <pre style={{
            fontSize: '12px',
            overflow: 'auto',
            padding: '1rem',
            background: 'var(--bg-main)',
            borderRadius: '4px',
            border: '1px solid var(--border-light)'
          }}>
            {this.state.error?.message || String(this.state.error)}
          </pre>
          <button
            type="button"
            className="btn btn-primary"
            style={{ marginTop: '1rem' }}
            onClick={() => this.setState({ hasError: false, error: null })}
          >
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

export default ErrorBoundary;
