import React from 'react';
import { useTranslation } from 'react-i18next';

/**
 * Shortcuts bar like Transaction History - shows ↑/↓ Navigate, Enter/V View, E Edit, Del Delete, Esc Close
 */
const DataActionsShortcutsBar = ({ showDelete = true, showCopy = false }) => {
  const { t } = useTranslation();
  return (
    <div style={{
      marginBottom: '1rem',
      padding: '0.5rem 1rem',
      backgroundColor: 'var(--bg-card)',
      borderRadius: 'var(--radius-md)',
      border: '1px solid var(--border-light)',
      display: 'flex',
      gap: '1rem',
      flexWrap: 'wrap',
      fontSize: '0.8rem',
      color: 'var(--text-muted)'
    }}>
      <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>↑/↓</kbd> {t('dataActions.navigate')}</span>
      <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Enter</kbd>/<kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>V</kbd> {t('dataActions.view')}</span>
      <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd> {t('dataActions.edit')}</span>
      {showCopy && <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Alt+C</kbd> {t('dataActions.copy')}</span>}
      {showDelete && <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd> {t('dataActions.delete')}</span>}
      <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Esc</kbd> {t('dataActions.close')}</span>
    </div>
  );
};

export default DataActionsShortcutsBar;
