import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';

const DEBOUNCE_MS = 300;

/**
 * GlobalSearchBar - Reusable search bar for management tables.
 * @param {string} value - Controlled value
 * @param {function} onChange - Called on change (debounced)
 * @param {function} onClear - Called when Esc is pressed
 * @param {function} onArrowDown - Called when Arrow Down is pressed (move focus to table)
 * @param {React.Ref} inputRef - Ref for the input (for Alt+Q focus)
 * @param {string} placeholder - Override placeholder
 * @param {string} className - Additional class names
 * @param {object} style - Additional styles
 */
const GlobalSearchBar = ({
  value,
  onChange,
  onClear,
  onArrowDown,
  inputRef: externalRef,
  placeholder,
  className = '',
  style = {},
}) => {
  const { t } = useTranslation();
  const [localValue, setLocalValue] = useState(value ?? '');
  const internalRef = useRef(null);
  const ref = externalRef || internalRef;
  const debounceTimer = useRef(null);

  const placeholderText = placeholder ?? t('search.placeholder');

  // Sync external value to local
  useEffect(() => {
    setLocalValue(value ?? '');
  }, [value]);

  // Debounced onChange - sync to parent after typing pauses
  useEffect(() => {
    if (debounceTimer.current) clearTimeout(debounceTimer.current);
    debounceTimer.current = setTimeout(() => {
      if (onChange) onChange(localValue);
      debounceTimer.current = null;
    }, DEBOUNCE_MS);
    return () => {
      if (debounceTimer.current) clearTimeout(debounceTimer.current);
    };
  }, [localValue]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleChange = useCallback((e) => {
    setLocalValue(e.target.value);
  }, []);

  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Escape') {
      e.preventDefault();
      if (debounceTimer.current) clearTimeout(debounceTimer.current);
      debounceTimer.current = null;
      setLocalValue('');
      if (onChange) onChange('');
      if (onClear) onClear();
      ref.current?.blur();
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (onArrowDown) onArrowDown();
    }
  }, [onChange, onClear, onArrowDown, ref]);

  const handleClearClick = useCallback(() => {
    if (debounceTimer.current) clearTimeout(debounceTimer.current);
    debounceTimer.current = null;
    setLocalValue('');
    if (onChange) onChange('');
    if (onClear) onClear();
    ref.current?.focus();
  }, [onChange, onClear, ref]);

  return (
    <div
      className={`global-search-bar ${className}`}
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        minWidth: '220px',
        maxWidth: '320px',
        ...style
      }}
    >
      <svg style={{ width: '18px', height: '18px', color: 'var(--text-muted)', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
      </svg>
      <input
        ref={ref}
        type="text"
        className="global-search-input"
        value={localValue}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        placeholder={placeholderText}
        style={{
          flex: 1,
          padding: '8px 12px',
          border: '1px solid var(--border-light)',
          borderRadius: '6px',
          fontSize: '14px',
          background: 'var(--bg-main)',
          color: 'var(--text-main)'
        }}
        data-search-focus="true"
      />
      {localValue && (
        <button
          type="button"
          onClick={handleClearClick}
          className="btn btn-sm"
          style={{ padding: '4px 8px', minWidth: 'auto' }}
          title={t('common.close')}
          aria-label="Clear search"
        >
          ×
        </button>
      )}
    </div>
  );
};

export default GlobalSearchBar;
