import React, { useState, useEffect } from 'react';
import { get, post } from '../utils/api';
import GlassCard from './common/GlassCard';
import ProductSearchModal from './ProductSearchModal';

const StockAdjustment = ({ onAdjustmentSuccess }) => {
  const [formData, setFormData] = useState({
    productId: '',
    productName: '',
    adjustmentType: 'deduction',
    reason: 'damage',
    quantity: 1,
    notes: ''
  });

  const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [currentStock, setCurrentStock] = useState(null);

  const reasons = [
    { value: 'damage', label: 'Damage' },
    { value: 'theft', label: 'Theft' },
    { value: 'expiry', label: 'Expiry' },
    { value: 'barcode_error', label: 'Barcode Error' },
    { value: 'supplier_return', label: 'Supplier Return' },
    { value: 'customer_return', label: 'Customer Return' },
    { value: 'physical_count', label: 'Physical Count' },
    { value: 'promotion', label: 'Promotion' },
    { value: 'write_off', label: 'Write Off' },
    { value: 'other', label: 'Other' }
  ];

  const handleProductSelect = (product) => {
    setFormData(prev => ({
      ...prev,
      productId: product.id,
      productName: product.name
    }));
    setCurrentStock(product.inventory?.quantity || 0);
    setIsSearchModalOpen(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.productId) {
      setMessage({ type: 'error', text: 'Please select a product' });
      return;
    }

    try {
      setLoading(true);
      setMessage({ type: '', text: '' });

      const response = await post('/stock-adjustments', {
        productId: formData.productId,
        adjustmentType: formData.adjustmentType,
        reason: formData.reason,
        quantity: parseInt(formData.quantity),
        notes: formData.notes
      });

      if (response.success) {
        setMessage({ type: 'success', text: 'Stock adjustment submitted successfully and pending approval.' });
        setFormData({
          productId: '',
          productName: '',
          adjustmentType: 'deduction',
          reason: 'damage',
          quantity: 1,
          notes: ''
        });
        if (onAdjustmentSuccess) onAdjustmentSuccess();
      } else {
        setMessage({ type: 'error', text: response.message || 'Failed to submit adjustment' });
      }
    } catch (err) {
      console.error('Error submitting stock adjustment:', err);
      setMessage({ type: 'error', text: 'Server error' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="stock-adjustment-container">
      <GlassCard style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
        <h2 style={{ margin: '0 0 1.5rem 0', color: 'var(--text-main)' }}>Create Stock Adjustment</h2>

        {message.text && (
          <div style={{
            padding: '1rem',
            borderRadius: 'var(--radius-md)',
            marginBottom: '1.5rem',
            backgroundColor: message.type === 'success' ? 'var(--success-subtle)' : 'var(--danger-subtle)',
            color: message.type === 'success' ? 'var(--success)' : 'var(--danger)',
            border: `1px solid ${message.type === 'success' ? 'var(--success)' : 'var(--danger)'}`
          }}>
            {message.text}
          </div>
        )}

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            <label style={{ fontWeight: '600', color: 'var(--text-muted)' }}>Product</label>
            <div style={{ display: 'flex', gap: '1rem' }}>
              <input
                type="text"
                readOnly
                placeholder="Select a product..."
                value={formData.productName}
                style={{
                  flex: 1,
                  padding: '0.75rem 1rem',
                  borderRadius: 'var(--radius-md)',
                  border: '1px solid var(--border-light)',
                  backgroundColor: 'var(--bg-main)',
                  color: 'var(--text-main)'
                }}
              />
              <button
                type="button"
                onClick={() => setIsSearchModalOpen(true)}
                style={{
                  padding: '0.75rem 1.5rem',
                  backgroundColor: 'var(--primary)',
                  color: 'white',
                  border: 'none',
                  borderRadius: 'var(--radius-md)',
                  cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                Search
              </button>
            </div>
            {currentStock !== null && (
              <div style={{ fontSize: '0.9rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>
                Current Stock: <strong style={{ color: currentStock > 0 ? 'var(--success)' : 'var(--danger)' }}>{currentStock}</strong>
              </div>
            )}
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
              <label style={{ fontWeight: '600', color: 'var(--text-muted)' }}>Adjustment Type</label>
              <select
                value={formData.adjustmentType}
                onChange={(e) => setFormData({ ...formData, adjustmentType: e.target.value })}
                style={{
                  padding: '0.75rem 1rem',
                  borderRadius: 'var(--radius-md)',
                  border: '1px solid var(--border-light)',
                  backgroundColor: 'var(--bg-main)',
                  color: 'var(--text-main)'
                }}
              >
                <option value="addition">Addition (+)</option>
                <option value="deduction">Deduction (-)</option>
              </select>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
              <label style={{ fontWeight: '600', color: 'var(--text-muted)' }}>Reason</label>
              <select
                value={formData.reason}
                onChange={(e) => setFormData({ ...formData, reason: e.target.value })}
                style={{
                  padding: '0.75rem 1rem',
                  borderRadius: 'var(--radius-md)',
                  border: '1px solid var(--border-light)',
                  backgroundColor: 'var(--bg-main)',
                  color: 'var(--text-main)'
                }}
              >
                {reasons.map(r => (
                  <option key={r.value} value={r.value}>{r.label}</option>
                ))}
              </select>
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            <label style={{ fontWeight: '600', color: 'var(--text-muted)' }}>Quantity</label>
            <input
              type="number"
              min="1"
              value={formData.quantity}
              onChange={(e) => setFormData({ ...formData, quantity: e.target.value })}
              style={{
                padding: '0.75rem 1rem',
                borderRadius: 'var(--radius-md)',
                border: '1px solid var(--border-light)',
                backgroundColor: 'var(--bg-main)',
                color: 'var(--text-main)'
              }}
            />
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            <label style={{ fontWeight: '600', color: 'var(--text-muted)' }}>Notes</label>
            <textarea
              rows="3"
              value={formData.notes}
              onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
              placeholder="Internal notes about this adjustment..."
              style={{
                padding: '0.75rem 1rem',
                borderRadius: 'var(--radius-md)',
                border: '1px solid var(--border-light)',
                backgroundColor: 'var(--bg-main)',
                color: 'var(--text-main)',
                resize: 'none'
              }}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            style={{
              marginTop: '1rem',
              padding: '1rem',
              backgroundColor: 'var(--accent-secondary)',
              color: 'white',
              border: 'none',
              borderRadius: 'var(--radius-md)',
              cursor: loading ? 'not-allowed' : 'pointer',
              fontWeight: '700',
              fontSize: '1rem',
              opacity: loading ? 0.7 : 1,
              transition: 'all var(--transition-fast)'
            }}
          >
            {loading ? 'Submitting...' : 'Submit Adjustment'}
          </button>
        </form>
      </GlassCard>

      {isSearchModalOpen && (
        <ProductSearchModal
          isOpen={isSearchModalOpen}
          onClose={() => setIsSearchModalOpen(false)}
          onAddProduct={(product) => handleProductSelect(product)}
          quantity={1}
        />
      )}
    </div>
  );
};

export default StockAdjustment;