import { useEffect, useCallback } from 'react';

const useProductKeyboard = (dependencies = {}) => {
  const {
    selectedProduct,
    focusedRow,
    filteredProducts = [],
    currentItems = [],
    handleDeleteProduct,
    handleViewProduct,
    handleEditProduct,
    loadProducts,
    setShowSearchModal,
    setShowQuickProductModal
  } = dependencies;

  const handleKeyDown = useCallback((e) => {
    // Check if we're in a modal or input field
    const isModalOpen = document.querySelector('.modal-overlay');
    const isInputElement = e.target.tagName === 'INPUT' || 
                          e.target.tagName === 'TEXTAREA' || 
                          e.target.isContentEditable;
    
    // Skip if in modal or input field
    if (isModalOpen || isInputElement) {
      return;
    }

    // Additional check: make sure we're on the product management screen
    const isOnProductScreen = window.location.hash === '#/products' || 
                             window.location.pathname.includes('products') ||
                             document.querySelector('[data-screen="product-management"]');
    
    if (!isOnProductScreen) {
      return;
    }

    // F2 - Open search modal
    if (e.key === 'F2') {
      e.preventDefault();
      setShowSearchModal(true);
    }
    // F5 - Refresh products
    else if (e.key === 'F5') {
      e.preventDefault();
      loadProducts();
    }
    // F8 - Add new product
    else if (e.key === 'F8') {
      e.preventDefault();
      e.stopPropagation();
      setShowQuickProductModal(true);
    }
    // Ctrl+E - Edit selected product
    else if (e.ctrlKey && e.key.toLowerCase() === 'e' && selectedProduct) {
      e.preventDefault();
      e.stopPropagation();
      handleEditProduct(selectedProduct);
    }
    // Delete - Delete selected product
    else if (e.key === 'Delete' && selectedProduct) {
      e.preventDefault();
      handleDeleteProduct(selectedProduct.id);
    }
    // Escape - Clear selection/close modals
    else if (e.key === 'Escape') {
      e.preventDefault();
      // These functions should be passed as dependencies
    }
    // Arrow navigation
    else if ((e.key === 'ArrowDown' || e.key === 'ArrowUp') && (filteredProducts?.length ?? 0) > 0) {
      e.preventDefault();
      const items = currentItems ?? [];
      let newIndex = typeof focusedRow === 'number' ? focusedRow : -1;
      
      if (e.key === 'ArrowDown') {
        newIndex = Math.min(newIndex + 1, items.length - 1);
      } else {
        newIndex = Math.max(newIndex - 1, 0);
      }
      
      // Update the focused row and selected product based on the new index
      if (typeof dependencies.setFocusedRow === 'function') {
        dependencies.setFocusedRow(newIndex);
      }
      if (newIndex >= 0 && items[newIndex]) {
        if (typeof dependencies.setSelectedProduct === 'function') {
          dependencies.setSelectedProduct(items[newIndex]);
        }
      }
    }
    // Enter or V - View selected product
    else if ((e.key === 'Enter' || e.key.toLowerCase() === 'v') && selectedProduct) {
      e.preventDefault();
      e.stopPropagation();
      if (handleViewProduct) handleViewProduct(selectedProduct);
      else handleEditProduct(selectedProduct);
    }
    // E - Edit selected product
    else if (e.key.toLowerCase() === 'e' && selectedProduct) {
      e.preventDefault();
      e.stopPropagation();
      handleEditProduct(selectedProduct);
    }
    // Alt+C - Duplicate selected product
    else if (e.altKey && e.key.toLowerCase() === 'c' && selectedProduct) {
      e.preventDefault();
      e.stopPropagation();
      if (typeof dependencies.handleDuplicateProduct === 'function') {
        dependencies.handleDuplicateProduct(selectedProduct);
      }
    }
    // Alt+P - Print barcode for selected product
    else if (e.altKey && e.key.toLowerCase() === 'p' && selectedProduct) {
      e.preventDefault();
      e.stopPropagation();
      if (typeof dependencies.handlePrintBarcode === 'function') {
        dependencies.handlePrintBarcode(selectedProduct);
      }
    }
  }, [
    selectedProduct,
    focusedRow,
    filteredProducts,
    currentItems,
    handleDeleteProduct,
    handleViewProduct,
    handleEditProduct,
    loadProducts,
    setShowSearchModal,
    setShowQuickProductModal
  ]);

  useEffect(() => {
    // Use capture phase to ensure we get the event before other handlers
    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [handleKeyDown]);

  // Return a function to manually re-enable the keyboard handler
  const reEnableKeyboard = useCallback(() => {
    console.log('Re-enabling product keyboard shortcuts');
    // Remove and re-add the event listener
    window.removeEventListener('keydown', handleKeyDown, { capture: true });
    window.addEventListener('keydown', handleKeyDown, { capture: true });
  }, [handleKeyDown]);

  return { reEnableKeyboard };
};

export default useProductKeyboard;