import React, { useState, useEffect, useRef } from 'react';
import { formatCurrency } from '../utils/currency';
import { get } from '../utils/api';

const PaymentModal = ({ isOpen, onClose, onConfirm, totalAmount, currency = 'USD', paymentMethod = 'cash' }) => {
    const [tenderedAmount, setTenderedAmount] = useState('');
    const [change, setChange] = useState(0);
    const [customerName, setCustomerName] = useState('');
    const [customerSuggestions, setCustomerSuggestions] = useState([]);
    const [showSuggestions, setShowSuggestions] = useState(false);
    const [suggestionIndex, setSuggestionIndex] = useState(-1);
    const inputRef = useRef(null);
    const customerInputRef = useRef(null);
    const suggestionsRef = useRef(null);

    // Calculate change whenever tendered amount changes
    useEffect(() => {
        const tendered = parseFloat(tenderedAmount) || 0;
        const changeAmount = tendered - totalAmount;
        setChange(changeAmount);
    }, [tenderedAmount, totalAmount]);

    // Auto-focus and reset when modal opens
    useEffect(() => {
        if (isOpen) {
            setTenderedAmount(totalAmount.toString());
            setCustomerName('');
            setCustomerSuggestions([]);
            setShowSuggestions(false);
            setSuggestionIndex(-1);
            setTimeout(() => customerInputRef.current?.focus(), 80);
            setTimeout(() => inputRef.current?.focus(), 120);
            setTimeout(() => inputRef.current?.select(), 180);
        }
    }, [isOpen, totalAmount]);

    // Fetch customer name suggestions (debounced)
    useEffect(() => {
        if (!isOpen) return;
        const q = customerName.trim();
        const timer = setTimeout(async () => {
            try {
                const res = await get(`/customers/names?q=${encodeURIComponent(q)}`);
                if (res && res.success && Array.isArray(res.data)) {
                    setCustomerSuggestions(res.data);
                    setShowSuggestions(res.data.length > 0);
                    setSuggestionIndex(-1);
                } else {
                    setCustomerSuggestions([]);
                    setShowSuggestions(false);
                }
            } catch (e) {
                setCustomerSuggestions([]);
                setShowSuggestions(false);
            }
        }, 250);
        return () => clearTimeout(timer);
    }, [isOpen, customerName]);

    const handleConfirm = () => {
        const tendered = parseFloat(tenderedAmount) || 0;

        if (paymentMethod === 'cash' && tendered < totalAmount) {
            alert(`Insufficient payment! Customer must pay at least ${formatCurrency(totalAmount, currency)}`);
            return;
        }

        onConfirm({
            tenderedAmount: tendered,
            change: Math.max(0, tendered - totalAmount),
            customerName: customerName.trim() || null
        });
    };

    const handleCustomerKeyDown = (e) => {
        if (!showSuggestions || customerSuggestions.length === 0) return;
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setSuggestionIndex(i => (i < customerSuggestions.length - 1 ? i + 1 : i));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setSuggestionIndex(i => (i <= 0 ? -1 : i - 1));
        } else if (e.key === 'Enter' && suggestionIndex >= 0 && customerSuggestions[suggestionIndex]) {
            e.preventDefault();
            setCustomerName(customerSuggestions[suggestionIndex]);
            setShowSuggestions(false);
            setSuggestionIndex(-1);
        }
    };

    const handleKeyDown = (e) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            handleConfirm();
        } else if (e.key === 'Escape') {
            e.preventDefault();
            onClose();
        }
    };

    if (!isOpen) return null;

    return (
        <div className="modal-overlay" style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.7)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999
        }}>
            <div className="modal-content" style={{
                backgroundColor: 'white',
                borderRadius: '12px',
                padding: '32px',
                maxWidth: '500px',
                width: '90%',
                boxShadow: '0 20px 60px rgba(0, 0, 0, 0.3)',
                position: 'relative'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px' }}>
                    <h2 style={{
                        margin: 0,
                        fontSize: '24px',
                        fontWeight: '800',
                        color: '#1f2937'
                    }}>
                        💰 PAYMENT
                    </h2>
                    <button
                        type="button"
                        onClick={onClose}
                        aria-label="Close"
                        style={{
                            background: '#f3f4f6',
                            border: 'none',
                            width: '40px',
                            height: '40px',
                            borderRadius: '10px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: '#374151',
                            fontSize: '20px',
                            lineHeight: 1,
                            padding: 0
                        }}
                    >
                        ×
                    </button>
                </div>

                {/* Total Amount Due */}
                <div style={{
                    backgroundColor: '#f3f4f6',
                    padding: '20px',
                    borderRadius: '8px',
                    marginBottom: '24px',
                    textAlign: 'center'
                }}>
                    <div style={{ fontSize: '14px', color: '#6b7280', marginBottom: '8px', fontWeight: '600' }}>
                        TOTAL AMOUNT DUE
                    </div>
                    <div style={{ fontSize: '36px', fontWeight: '800', color: '#1f2937' }}>
                        {formatCurrency(totalAmount, currency)}
                    </div>
                </div>

                {/* Payment Method */}
                <div style={{
                    marginBottom: '20px',
                    padding: '12px',
                    backgroundColor: '#eff6ff',
                    borderRadius: '6px',
                    textAlign: 'center'
                }}>
                    <span style={{ fontSize: '14px', color: '#1e40af', fontWeight: '700' }}>
                        PAYMENT METHOD: {paymentMethod.toUpperCase()}
                    </span>
                </div>

                {/* Customer Name (saved with transaction) */}
                <div style={{ marginBottom: '20px', position: 'relative' }}>
                    <label style={{
                        display: 'block',
                        marginBottom: '8px',
                        fontSize: '14px',
                        fontWeight: '700',
                        color: '#374151'
                    }}>
                        Customer Name
                    </label>
                    <input
                        ref={customerInputRef}
                        type="text"
                        value={customerName}
                        onChange={(e) => setCustomerName(e.target.value)}
                        onFocus={() => customerSuggestions.length > 0 && setShowSuggestions(true)}
                        onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                        onKeyDown={handleCustomerKeyDown}
                        placeholder="Optional – type to see customers from Settings"
                        style={{
                            width: '100%',
                            padding: '12px 14px',
                            fontSize: '16px',
                            border: '2px solid #d1d5db',
                            borderRadius: '8px',
                            boxSizing: 'border-box'
                        }}
                    />
                    {showSuggestions && customerSuggestions.length > 0 && (
                        <ul
                            ref={suggestionsRef}
                            style={{
                                position: 'absolute',
                                left: 0,
                                right: 0,
                                top: '100%',
                                margin: 0,
                                padding: 0,
                                listStyle: 'none',
                                backgroundColor: 'white',
                                border: '1px solid #e5e7eb',
                                borderRadius: '8px',
                                boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                                maxHeight: 200,
                                overflowY: 'auto',
                                zIndex: 10
                            }}
                        >
                            {customerSuggestions.map((name, i) => (
                                <li
                                    key={name}
                                    onClick={() => {
                                        setCustomerName(name);
                                        setShowSuggestions(false);
                                        setSuggestionIndex(-1);
                                    }}
                                    style={{
                                        padding: '10px 14px',
                                        cursor: 'pointer',
                                        backgroundColor: suggestionIndex === i ? '#eff6ff' : 'transparent',
                                        borderBottom: i < customerSuggestions.length - 1 ? '1px solid #f3f4f6' : 'none'
                                    }}
                                >
                                    {name}
                                </li>
                            ))}
                        </ul>
                    )}
                </div>

                {/* Amount Tendered Input */}
                <div style={{ marginBottom: '24px' }}>
                    <label style={{
                        display: 'block',
                        marginBottom: '8px',
                        fontSize: '14px',
                        fontWeight: '700',
                        color: '#374151'
                    }}>
                        Amount Tendered (Customer Paid)
                    </label>
                    <input
                        ref={inputRef}
                        type="number"
                        step="0.01"
                        min={paymentMethod === 'cash' ? totalAmount : 0}
                        value={tenderedAmount}
                        onChange={(e) => setTenderedAmount(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder="Enter amount"
                        style={{
                            width: '100%',
                            padding: '16px',
                            fontSize: '24px',
                            fontWeight: '700',
                            border: '2px solid #d1d5db',
                            borderRadius: '8px',
                            textAlign: 'right',
                            boxSizing: 'border-box'
                        }}
                    />
                </div>

                {/* Change Display */}
                <div style={{
                    backgroundColor: change >= 0 ? '#d1fae5' : '#fee2e2',
                    padding: '20px',
                    borderRadius: '8px',
                    marginBottom: '24px',
                    textAlign: 'center'
                }}>
                    <div style={{
                        fontSize: '14px',
                        color: change >= 0 ? '#065f46' : '#991b1b',
                        marginBottom: '8px',
                        fontWeight: '600'
                    }}>
                        {change >= 0 ? 'CHANGE TO RETURN' : 'INSUFFICIENT PAYMENT'}
                    </div>
                    <div style={{
                        fontSize: '32px',
                        fontWeight: '800',
                        color: change >= 0 ? '#059669' : '#dc2626'
                    }}>
                        {formatCurrency(Math.abs(change), currency)}
                    </div>
                </div>

                {/* Action Buttons - width fits text */}
                <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end', flexWrap: 'wrap' }}>
                    <button
                        onClick={onClose}
                        style={{
                            padding: '14px 20px',
                            fontSize: '16px',
                            fontWeight: '700',
                            backgroundColor: '#f3f4f6',
                            color: '#374151',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            width: 'auto',
                            minWidth: 'min-content'
                        }}
                    >
                        Cancel (Esc)
                    </button>
                    <button
                        onClick={handleConfirm}
                        style={{
                            padding: '14px 20px',
                            fontSize: '16px',
                            fontWeight: '700',
                            backgroundColor: '#10b981',
                            color: 'white',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            width: 'auto',
                            minWidth: 'min-content'
                        }}
                    >
                        ✓ Confirm Payment (Enter)
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PaymentModal;
