import React, { useState, useEffect, useCallback } from 'react';
import { get, post, put, del } from '../utils/api';
import { useTranslation } from 'react-i18next';
import DataActionsShortcutsBar from './common/DataActionsShortcutsBar';

const UnitsManagement = () => {
  const { t } = useTranslation();
  const [units, setUnits] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingUnit, setEditingUnit] = useState(null);
  const [formData, setFormData] = useState({ unitName: '', shortName: '' });
  const [selectedIndex, setSelectedIndex] = useState(-1);

  useEffect(() => {
    loadUnits();
  }, []);

  const loadUnits = async () => {
    try {
      setLoading(true);
      const result = await get('/units');
      if (result.success && result.data) setUnits(result.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const selectedUnit = selectedIndex >= 0 && selectedIndex < units.length ? units[selectedIndex] : null;

  const handleOpenModal = (unit) => {
    setEditingUnit(unit);
    setFormData(unit ? { unitName: unit.unitName, shortName: unit.shortName } : { unitName: '', shortName: '' });
    setShowModal(true);
  };

  const handleSave = async (e) => {
    if (e) e.preventDefault();
    if (!formData.unitName || !formData.shortName) {
      alert(t('messages.requiredField') || 'Required');
      return;
    }
    try {
      if (editingUnit) {
        const result = await put('/units/' + editingUnit.id, formData);
        if (result.success) {
          loadUnits();
          setShowModal(false);
        } else alert(result.message || 'Failed');
      } else {
        const result = await post('/units', formData);
        if (result.success) {
          loadUnits();
          setShowModal(false);
        } else alert(result.message || 'Failed');
      }
    } catch (err) {
      alert(err.message || 'Error');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(t('messages.confirmDelete') || 'Delete?')) return;
    try {
      const result = await del('/units/' + id);
      if (result.success) {
        loadUnits();
        setSelectedIndex(-1);
      } else alert(result.message || 'Failed');
    } catch (err) {
      alert(err.message || 'Error');
    }
  };

  // Keyboard shortcuts: V view, E edit, Del delete, ArrowUp/ArrowDown navigate
  const handleKeyDown = useCallback((e) => {
    const isInputElement = e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable;
    if (showModal) {
      if (e.key === 'Escape') {
        e.preventDefault();
        setShowModal(false);
        return;
      }
      if (e.key === 'Enter' && e.target.tagName !== 'TEXTAREA') {
        e.preventDefault();
        handleSave(e);
        return;
      }
      return;
    }
    if (isInputElement) return;
    // View/Edit: V, E, Enter
    if (e.key === 'v' || e.key === 'e' || e.key === 'Enter') {
      if (selectedUnit) {
        e.preventDefault();
        handleOpenModal(selectedUnit);
      }
      return;
    }
    if (e.key === 'Delete' && selectedUnit) {
      e.preventDefault();
      handleDelete(selectedUnit.id);
      return;
    }
    if (e.key === 'ArrowDown' && units.length > 0) {
      e.preventDefault();
      setSelectedIndex((prev) => Math.min(prev < 0 ? 0 : prev + 1, units.length - 1));
      return;
    }
    if (e.key === 'ArrowUp' && units.length > 0) {
      e.preventDefault();
      setSelectedIndex((prev) => Math.max(prev < 0 ? 0 : prev - 1, 0));
      return;
    }
  }, [showModal, units.length, selectedUnit, handleSave, handleDelete]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [handleKeyDown]);

  useEffect(() => {
    if (units.length === 0) setSelectedIndex(-1);
    else if (selectedIndex >= units.length) setSelectedIndex(units.length - 1);
  }, [units.length, selectedIndex]);

  return (
    <div style={{ padding: '1.5rem' }}>
      <DataActionsShortcutsBar showDelete />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
        <h3 style={{ margin: 0 }}>{t('products.unit') || 'Units'}</h3>
        <button data-pos-action="add-new" className="btn btn-primary" onClick={() => handleOpenModal(null)}>+ Add Unit</button>
      </div>
      {loading ? (
        <p>{t('common.loading')}</p>
      ) : (
        <table className="data-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '2px solid var(--border-light)' }}>
              <th style={{ padding: 12, textAlign: 'left' }}>Unit Name</th>
              <th style={{ padding: 12, textAlign: 'left' }}>Short</th>
              <th style={{ padding: 12, textAlign: 'center' }}>{t('common.actions')}</th>
            </tr>
          </thead>
          <tbody>
            {units.map((u, idx) => (
              <tr
                key={u.id}
                tabIndex={idx === 0 ? 0 : -1}
                onClick={() => setSelectedIndex(idx)}
                style={{ backgroundColor: selectedIndex === idx ? 'var(--primary-subtle)' : 'transparent', cursor: 'pointer', borderBottom: '1px solid var(--border-light)' }}
              >
                <td style={{ padding: 12 }}>{u.unitName}</td>
                <td style={{ padding: 12 }}>{u.shortName}</td>
                <td style={{ padding: 12, display: 'flex', gap: 4 }}>
                  <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); handleOpenModal(u); }} title="V/E">{t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd></button>
                  <button className="btn btn-sm btn-outline-danger" onClick={(e) => { e.stopPropagation(); handleDelete(u.id); }} title="Del">{t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div className="modal-container" onClick={(e) => e.stopPropagation()} style={{ background: 'white', padding: 24, borderRadius: 12, maxWidth: 400 }}>
            <h4 style={{ margin: '0 0 1rem 0' }}>{editingUnit ? t('common.edit') : t('common.add')} Unit</h4>
            <form onSubmit={handleSave}>
              <div style={{ marginBottom: 12 }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 14, fontWeight: 600 }}>Unit Name</label>
                <input value={formData.unitName} onChange={(e) => setFormData((p) => ({ ...p, unitName: e.target.value }))} className="modern-input" placeholder="Kilogram" />
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 14, fontWeight: 600 }}>Short Name</label>
                <input value={formData.shortName} onChange={(e) => setFormData((p) => ({ ...p, shortName: e.target.value }))} className="modern-input" placeholder="kg" />
              </div>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                <button type="button" data-pos-action="cancel" className="btn btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" data-pos-action="save" className="btn btn-primary">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UnitsManagement;
