// API utility functions with authentication

const getAuthToken = () => {
  return localStorage.getItem('token');
};

export const apiRequest = async (endpoint, options = {}) => {
  const token = getAuthToken();

  const defaultOptions = {
    headers: {
      'Content-Type': 'application/json',
      ...(token && { 'Authorization': `Bearer ${token}` })
    }
  };

  const requestOptions = {
    ...defaultOptions,
    ...options,
    headers: {
      ...defaultOptions.headers,
      ...options.headers
    }
  };

  try {
    const response = await fetch(endpoint, requestOptions);

    // If the response is 401 (unauthorized), redirect to login
    if (response.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      // Only redirect if not already on the login page to avoid loops
      if (window.location.pathname !== '/login' && window.location.pathname !== '/') {
        window.location.href = '/';
      }
      return { error: true, status: 401, message: 'Authorization denied' };
    }

    return response;
  } catch (error) {
    console.error('API Request Error:', error);
    return { error: true, message: error.message };
  }
};

const handleResponse = async (response) => {
  if (!response) return { success: false, message: 'No response from server' };
  if (response.error) return { success: false, ...response };

  try {
    const contentType = response.headers.get('content-type');
    if (contentType && contentType.indexOf('application/json') !== -1) {
      const data = await response.json();
      if (data && typeof data.success === 'boolean') {
        return data;
      }
      return { success: response.ok, data };
    } else {
      const text = await response.text();
      return { success: response.ok, message: text };
    }
  } catch (error) {
    return { success: false, message: 'Failed to parse response' };
  }
};

export const get = async (endpoint) => {
  // Map /v1/ endpoints to existing structure if needed
  let finalEndpoint = endpoint;
  if (endpoint.startsWith('/v1/inventory')) {
    finalEndpoint = endpoint.replace('/v1/inventory', '/inventory');
  } else if (endpoint.startsWith('/v1/analytics/aggregate')) {
    // Map to an existing report endpoint that matches the intent, or handled by new logic
    finalEndpoint = endpoint.replace('/v1/analytics/aggregate', '/reports/inventory-summary');
  }

  const response = await apiRequest(`/api${finalEndpoint}`);
  return handleResponse(response);
};

export const post = async (endpoint, data) => {
  const response = await apiRequest(`/api${endpoint}`, {
    method: 'POST',
    body: JSON.stringify(data)
  });
  return handleResponse(response);
};

export const put = async (endpoint, data) => {
  const response = await apiRequest(`/api${endpoint}`, {
    method: 'PUT',
    body: JSON.stringify(data)
  });
  return handleResponse(response);
};

export const del = async (endpoint) => {
  const response = await apiRequest(`/api${endpoint}`, {
    method: 'DELETE'
  });
  return handleResponse(response);
};

export const patch = async (endpoint, data) => {
  const response = await apiRequest(`/api${endpoint}`, {
    method: 'PATCH',
    body: data ? JSON.stringify(data) : undefined
  });
  return handleResponse(response);
};