import React, { forwardRef, useImperativeHandle, useRef } from 'react';
import { useSettings } from '../context/SettingsContext';
import { formatCurrency } from '../utils/currency';
import { useTranslation } from 'react-i18next';

// Receipt component that will be printed
const Receipt = ({ saleData, businessInfo, currency = 'USD', settings = {} }) => {
  const { t } = useTranslation();
  // Calculate totals
  const subtotal = saleData.items?.reduce((sum, item) => sum + (Number(item.unitPrice || item.price || 0) * Number(item.quantity || 0)), 0) || 0;
  const totalDiscount = saleData.discountAmount !== undefined ? Number(saleData.discountAmount) : (saleData.items?.reduce((sum, item) => sum + Number(item.discountAmount || 0), 0) || 0);
  const tax = saleData.taxAmount || 0;
  const netTotal = saleData.netAmount || (subtotal - totalDiscount + tax);

  const formatPrice = (val) => {
    return formatCurrency(val, currency);
  };

  const getPaperWidth = () => {
    switch (settings.receiptPaperSize) {
      case 'A4': return '210mm';
      case 'Letter': return '215.9mm';
      default: return '80mm';
    }
  };

  return (
    <div className="receipt-container" style={{
      fontFamily: "'Inter', 'Segoe UI', Roboto, sans-serif",
      fontSize: settings.receiptPaperSize === 'Thermal' ? '12px' : '14px',
      width: getPaperWidth(),
      margin: settings.receiptPaperSize === 'Thermal' ? '0' : '0 auto',
      padding: settings.receiptPaperSize === 'Thermal' ? '2mm' : '20mm',
      lineHeight: '1.4',
      backgroundColor: '#fff',
      color: '#000',
      boxSizing: 'border-box',
      minHeight: (settings.receiptPaperSize === 'A4' || settings.receiptPaperSize === 'Letter') ? '297mm' : 'auto'
    }}>
      <div className="receipt-inner">
        {/* Logo Section */}
        {(settings.logoPath || settings.receiptLogo) && (
          <div style={{ textAlign: 'center', marginBottom: settings.receiptPaperSize === 'Thermal' ? '2px' : '10px', marginTop: '0' }}>
            <img
              src={settings.receiptLogo || (settings.logoPath.startsWith('http') ? settings.logoPath : `${window.location.origin}/uploads/${settings.logoPath}`)}
              alt="Logo"
              style={{
                maxWidth: '60mm',
                maxHeight: '25mm',
                objectFit: 'contain',
                marginBottom: '5px'
              }}
            />
          </div>
        )}

        {/* Business Info */}
        <div style={{ textAlign: 'center', marginBottom: settings.receiptPaperSize === 'Thermal' ? '5px' : '15px', marginTop: '0' }}>
          <h1 style={{ margin: '0 0 2px 0', fontSize: '18px', fontWeight: '800', textTransform: 'uppercase', letterSpacing: '1px', marginTop: '0' }}>
            {businessInfo.name || 'SOFTIMAGE MRDS'}
          </h1>
          {businessInfo.address && <div style={{ fontSize: '11px', marginBottom: '2px' }}>{businessInfo.address}</div>}
          {businessInfo.phone && <div style={{ fontSize: '11px', marginBottom: '2px' }}>Tel: {businessInfo.phone}</div>}
          {businessInfo.email && <div style={{ fontSize: '11px' }}>{businessInfo.email}</div>}
        </div>

        <div style={{ borderTop: '1px dashed #000', margin: '10px 0' }}></div>

        {/* Transaction Info */}
        <div style={{ marginBottom: '10px' }}>
          <h2 style={{ textAlign: 'center', fontSize: '14px', fontWeight: 'bold', margin: '0 0 8px 0' }}>
            {saleData.type === 'return' ? t('receipt.returnReceipt') : t('receipt.salesReceipt')}
          </h2>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '11px' }}>
            <span>{t('receipt.transactionId')}: {saleData.transactionId || saleData.id || `TXN-${Date.now()}`}</span>
            <span>{t('receipt.date')}: {new Date(saleData.createdAt || Date.now()).toLocaleDateString()}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '11px' }}>
            <span>{t('receipt.cashier')}: {saleData.user?.username || t('receipt.admin')}</span>
            <span>{t('receipt.time')}: {new Date(saleData.createdAt || Date.now()).toLocaleTimeString()}</span>
          </div>
        </div>

        <div style={{ borderTop: '2px solid #000', margin: '8px 0' }}></div>

        {/* Items Table */}
        <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '10px' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid #000' }}>
              <th style={{ textAlign: 'left', padding: '4px 0', fontSize: '11px' }}>{t('receipt.itemDesc')}</th>
              <th style={{ textAlign: 'center', padding: '4px 0', fontSize: '11px' }}>{t('receipt.qty')}</th>
              <th style={{ textAlign: 'right', padding: '4px 0', fontSize: '11px' }}>{t('receipt.disc')}</th>
              <th style={{ textAlign: 'right', padding: '4px 0', fontSize: '11px' }}>{t('receipt.total')}</th>
            </tr>
          </thead>
          <tbody>
            {saleData.items?.map((item, index) => (
              <tr key={index}>
                <td style={{ padding: '6px 0', verticalAlign: 'top' }}>
                  <div style={{ fontWeight: '600', fontSize: '12px' }}>{item.product?.name || item.name}</div>
                  <div style={{ fontSize: '10px', color: '#444' }}>{formatPrice(item.unitPrice || item.price)} / unit</div>
                </td>
                <td style={{ textAlign: 'center', padding: '6px 0', verticalAlign: 'top', fontSize: '12px' }}>{item.quantity}</td>
                <td style={{ textAlign: 'right', padding: '6px 0', verticalAlign: 'top', fontSize: '11px', color: Number(item.discountAmount || item.discount || 0) > 0 ? '#000' : '#444' }}>
                  {formatPrice(item.discountAmount || item.discount || 0)}
                </td>
                <td style={{ textAlign: 'right', padding: '6px 0', verticalAlign: 'top', fontWeight: '600', fontSize: '12px' }}>
                  {formatPrice((item.unitPrice || item.price) * item.quantity - (item.discountAmount || item.discount || 0))}
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        <div style={{ borderTop: '1px dashed #000', margin: '8px 0' }}></div>

        {/* Totals Section */}
        <div style={{ marginLeft: 'auto', width: '100%' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
            <span>{t('receipt.subtotal')}</span>
            <span>{formatPrice(subtotal)}</span>
          </div>
          {totalDiscount > 0 && (
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
              <span>{t('receipt.discount')}</span>
              <span>-{formatPrice(totalDiscount)}</span>
            </div>
          )}
          {tax > 0 && (
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
              <span>{t('receipt.tax')}</span>
              <span>{formatPrice(tax)}</span>
            </div>
          )}
          <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '6px', paddingTop: '6px', borderTop: '2px solid #000', fontWeight: '800', fontSize: '16px' }}>
            <span>{t('receipt.total')}</span>
            <span>{formatPrice(netTotal)}</span>
          </div>
        </div>

        <div style={{ borderTop: '1px dashed #000', margin: '12px 0' }}></div>

        {/* Payment & Change */}
        <div style={{ marginBottom: '15px', fontSize: '11px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>{t('receipt.paymentMethod')}:</span>
            <span style={{ fontWeight: 'bold' }}>{(saleData.paymentMethod || 'CASH').toUpperCase()}</span>
          </div>
          {saleData.tenderedAmount !== undefined && (
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span>{t('receipt.tendered')}:</span>
              <span>{formatPrice(saleData.tenderedAmount)}</span>
            </div>
          )}
          {saleData.change !== undefined && (
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span>{t('receipt.change')}:</span>
              <span style={{ fontWeight: 'bold' }}>{formatPrice(saleData.change)}</span>
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{ textAlign: 'center', marginTop: '20px' }}>
          <div style={{ fontSize: '13px', fontWeight: 'bold', marginBottom: '4px' }}>{t('receipt.thankYou')}</div>
          <div style={{ fontSize: '11px' }}>{t('receipt.keepReceipt')}</div>
          {saleData.notes && (
            <div style={{ marginTop: '10px', padding: '6px', border: '1px solid #000', fontSize: '10px' }}>
              {t('receipt.notes')}: {saleData.notes}
            </div>
          )}
          <div style={{ marginTop: '15px', fontSize: '10px' }}>Softimage System solutions contact 0784355588</div>
        </div>
      </div>
    </div>
  );
};

// Receipt Printer Component - manual print only (Print button or Enter); uses hidden iframe for print dialog
const ReceiptPrinter = forwardRef(({ saleData, businessInfo = {}, currency = 'USD', isPrinting: _isPrinting, onPrintComplete: _onPrintComplete, onAfterPrint }, ref) => {
  const { t } = useTranslation();
  const { settings } = useSettings();
  const hiddenReceiptRef = useRef();
  const printFrameRef = useRef(null);

  const getPageSize = () => {
    switch (settings.receiptPaperSize) {
      case 'A4': return 'A4';
      case 'Letter': return 'letter';
      default: return '80mm auto';
    }
  };

  const getContainerWidth = () => {
    switch (settings.receiptPaperSize) {
      case 'A4': return '210mm';
      case 'Letter': return '215.9mm';
      default: return '80mm';
    }
  };

  const handlePrint = React.useCallback(() => {
    if (!hiddenReceiptRef.current || !saleData) return;

    const receiptHtml = hiddenReceiptRef.current.innerHTML;
    const paperWidth = getContainerWidth();
    const pageSize = getPageSize();
    const fullHtml = `<!DOCTYPE html><html><head>
      <title>Receipt</title>
      <style>
        @page { size: ${pageSize}; margin: 0 !important; }
        html, body { margin: 0 !important; padding: 0 !important; width: ${paperWidth} !important; min-height: 0 !important; background: #fff !important; font-family: 'Inter', 'Segoe UI', Roboto, sans-serif; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        .receipt-wrapper { width: ${paperWidth} !important; margin: 0 !important; padding: 0 !important; }
        .receipt-container { width: 100% !important; padding: ${settings.receiptPaperSize === 'Thermal' ? '2mm' : '10mm'} !important; background: #fff !important; color: #000 !important; box-sizing: border-box !important; }
        table { width: 100%; border-collapse: collapse; }
        img { max-width: 100%; height: auto; }
      </style>
    </head><body><div class="receipt-wrapper">${receiptHtml}</div></body></html>`;

    // Silent printing: send to local bridge (e.g. Node/Electron) to print without browser dialog
    const silentBridgeUrl = settings.silentPrintBridgeUrl || settings.receiptSilentPrintUrl;
    if (silentBridgeUrl && typeof fetch === 'function') {
      fetch(silentBridgeUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'text/html' },
        body: fullHtml
      }).then(() => {}).catch(() => {
        runBrowserPrint();
      });
      if (onAfterPrint) setTimeout(onAfterPrint, 300);
      return;
    }

    runBrowserPrint();
    if (onAfterPrint) setTimeout(onAfterPrint, 300);

    function runBrowserPrint() {
      let iframe = printFrameRef.current;
      if (!iframe) {
        iframe = document.createElement('iframe');
        iframe.setAttribute('style', 'position:absolute;width:0;height:0;border:0;visibility:hidden;');
        document.body.appendChild(iframe);
        printFrameRef.current = iframe;
      }
      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write(fullHtml);
      doc.close();

      let printed = false;
      const printFrame = () => {
        if (printed) return;
        printed = true;
        try {
          iframe.contentWindow.focus();
          iframe.contentWindow.print();
        } catch (e) {
          console.warn('Print failed:', e);
        }
      };
      iframe.contentWindow.addEventListener('load', () => setTimeout(printFrame, 120));
      if (iframe.contentDocument.readyState === 'complete') {
        setTimeout(printFrame, 150);
      }
    }
  }, [settings.receiptPaperSize, settings.silentPrintBridgeUrl, settings.receiptSilentPrintUrl, saleData, onAfterPrint]);

  useImperativeHandle(ref, () => ({
    print: handlePrint
  }), [handlePrint]);

  return (
    <div>
      <div ref={hiddenReceiptRef}>
        <Receipt
          saleData={saleData}
          businessInfo={businessInfo}
          currency={currency}
          settings={settings}
        />
      </div>
      <button
        type="button"
        onClick={handlePrint}
        style={{ width: '100%', marginTop: '12px', padding: '10px', backgroundColor: 'var(--primary)', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600' }}
      >
        {t('receipt.printReceipt', 'Print Receipt')}
      </button>
    </div>
  );
});

ReceiptPrinter.displayName = 'ReceiptPrinter';
export default ReceiptPrinter;