import React, { useState, useEffect, useRef } from 'react';
import { get, del } from '../utils/api';
import { formatCurrency } from '../utils/currency';
import { useSettings } from '../context/SettingsContext';
import { useAuth } from '../context/AuthContext';
import ReceiptPrinter from './ReceiptPrinter';

const SalesTransactionHistory = ({ isOpen, onClose, onEditSale }) => {
  const { settings } = useSettings();
  const { canDelete } = useAuth();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 10;
  const [searchTerm, setSearchTerm] = useState('');
  const [deletingId, setDeletingId] = useState(null);
  const [showReceipt, setShowReceipt] = useState(false);
  const [isPrinting, setIsPrinting] = useState(false);
  const [receiptData, setReceiptData] = useState(null);
  const receiptPrinterRef = useRef(null);
  const selectedRowRef = useRef(null);
  const tableBodyRef = useRef(null);

  useEffect(() => {
    if (isOpen) {
      fetchTransactions();
    }
  }, [isOpen]);

  const fetchTransactions = async () => {
    try {
      setLoading(true);
      const [liveSales, dummySales] = await Promise.all([
        get('/sales?limit=100&fields=id,transactionId,createdAt,netAmount,paymentMethod,status,user,items'),
        get('/dummy-transactions')
      ]);

      let allTransactions = [];

      if (liveSales.success) {
        allTransactions = allTransactions.concat(
          liveSales.data.map(sale => ({
            id: sale.id,
            transactionId: sale.transactionId,
            type: 'LIVE',
            date: sale.createdAt,
            amount: sale.netAmount,
            paymentMethod: sale.paymentMethod,
            status: sale.status,
            cashier: sale.user ? `${sale.user.firstName} ${sale.user.lastName}` : 'Unknown',
            items: sale.items ? sale.items.length : 0,
            originalData: sale
          }))
        );
      }

      if (dummySales.success) {
        allTransactions = allTransactions.concat(
          dummySales.data.map(transaction => ({
            id: `dummy-${transaction.id}`,
            transactionId: transaction.transactionId,
            type: 'DUMMY',
            date: transaction.createdAt,
            amount: transaction.netTotal || transaction.totalAmount,
            paymentMethod: transaction.paymentMethod,
            status: 'completed',
            cashier: 'Dummy User',
            items: 1, // Dummy transactions don't have item details
            originalData: transaction
          }))
        );
      }

      allTransactions.sort((a, b) => new Date(b.date) - new Date(a.date));
      
      setTransactions(allTransactions);
      setSelectedIndex(allTransactions.length > 0 ? 0 : -1);
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredTransactions = transactions.filter(transaction =>
    transaction.transactionId.toLowerCase().includes(searchTerm.toLowerCase()) ||
    transaction.cashier.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalPages = Math.max(1, Math.ceil(filteredTransactions.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedTransactions = filteredTransactions.slice(startIndex, endIndex);

  useEffect(() => {
    // Reset to first page when search term changes or list shrinks
    setCurrentPage(1);
  }, [searchTerm, transactions.length]);

  // Keep selected row in range; when there are rows and none selected, select first
  useEffect(() => {
    const n = paginatedTransactions.length;
    if (n === 0) setSelectedIndex(-1);
    else if (selectedIndex >= n) setSelectedIndex(n - 1);
    else if (selectedIndex < 0) setSelectedIndex(0);
  }, [paginatedTransactions.length, selectedIndex]);

  // Scroll selected row into view when arrow keys change selection
  useEffect(() => {
    if (selectedIndex >= 0 && selectedRowRef.current) {
      selectedRowRef.current.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    }
  }, [selectedIndex]);

  const handleReprint = (transaction) => {
    if (!transaction) return;
    const data = transaction.originalData;
    setReceiptData(data);
    setShowReceipt(true);
    setIsPrinting(true);
  };

  const handleDelete = async (transaction) => {
    if (!transaction) return;
    if (!window.confirm('Delete this transaction?')) return;
    try {
      setDeletingId(transaction.id);
      let result;
      if (transaction.type === 'LIVE') {
        result = await del(`/sales/${transaction.originalData.id}`);
      } else {
        const rawId = String(transaction.id).replace('dummy-', '');
        result = await del(`/dummy-transactions/${rawId}`);
      }
      if (result && result.success) {
        setTransactions(prev => prev.filter(t => t.id !== transaction.id));
      } else if (result && !result.success && /not found|404/i.test(String(result.message || ''))) {
        setTransactions(prev => prev.filter(t => t.id !== transaction.id));
      } else {
        alert(result?.message || 'Failed to delete transaction');
      }
    } catch (err) {
      const msg = String(err?.message || err?.response?.data?.message || '');
      if (/not found|404/i.test(msg)) {
        setTransactions(prev => prev.filter(t => t.id !== transaction.id));
      } else {
        console.error('Delete failed', err);
        alert('Failed to delete transaction');
      }
    } finally {
      setDeletingId(null);
    }
  };

  // Arrow keys: select row. Letter shortcuts match Actions column: V View, E Edit, R/P Reprint, Del Delete
  useEffect(() => {
    if (!isOpen) return;
    const onKey = (e) => {
      const inInput = e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT' || e.target.isContentEditable;
      // Arrow keys: always handle in this modal so list selection works even when search input is focused
      if (e.key === 'ArrowDown' && paginatedTransactions.length > 0) {
        e.preventDefault();
        e.stopPropagation();
        setSelectedIndex(prev => (prev < 0 ? 0 : Math.min(prev + 1, paginatedTransactions.length - 1)));
        return;
      }
      if (e.key === 'ArrowUp' && paginatedTransactions.length > 0) {
        e.preventDefault();
        e.stopPropagation();
        setSelectedIndex(prev => Math.max(prev - 1, 0));
        return;
      }
      if (inInput) {
        if (e.key === 'Escape') {
          e.preventDefault();
          onClose();
        }
        return;
      }
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
        return;
      }
      // V or Enter: View (same as View button)
      if (e.key === 'Enter' || e.key.toLowerCase() === 'v') {
        e.preventDefault();
        const t = paginatedTransactions[selectedIndex];
        if (t && onEditSale) onEditSale(t.originalData);
        return;
      }
      // E: Edit (same as Edit button)
      if (e.key.toLowerCase() === 'e') {
        e.preventDefault();
        const t = paginatedTransactions[selectedIndex];
        if (t && onEditSale) onEditSale(t.originalData);
        return;
      }
      // Del: Delete (same as Delete button)
      if (e.key === 'Delete' && canDelete) {
        e.preventDefault();
        const t = paginatedTransactions[selectedIndex];
        if (t) handleDelete(t);
        return;
      }
      // R or P: Reprint (same as Reprint button)
      if (e.key.toLowerCase() === 'r' || e.key.toLowerCase() === 'p') {
        e.preventDefault();
        const t = paginatedTransactions[selectedIndex];
        if (t) handleReprint(t);
      }
    };
    window.addEventListener('keydown', onKey, { capture: true });
    return () => window.removeEventListener('keydown', onKey, { capture: true });
  }, [isOpen, paginatedTransactions, selectedIndex, onEditSale, onClose, canDelete, handleDelete, handleReprint]);

  // Reprint popup: Enter = print, Esc = close
  useEffect(() => {
    if (!showReceipt) return;
    const onKey = (e) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        setShowReceipt(false);
        return;
      }
      if (e.key === 'Enter') {
        e.preventDefault();
        receiptPrinterRef.current?.print?.();
      }
    };
    window.addEventListener('keydown', onKey, { capture: true });
    return () => window.removeEventListener('keydown', onKey, { capture: true });
  }, [showReceipt]);

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" style={{
      position: 'fixed',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      backgroundColor: 'rgba(0,0,0,0.5)',
      zIndex: 2000,
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center'
    }} onClick={onClose}>
      <div className="modal-content" style={{
        backgroundColor: 'white',
        borderRadius: '12px',
        boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
        width: '96%',
        maxWidth: '1100px',
        maxHeight: '92vh',
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column'
      }} onClick={(e) => e.stopPropagation()}>
        
        {/* Header */}
        <div style={{
          padding: '16px 20px',
          borderBottom: '1px solid #eee',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <h2 style={{ margin: 0, fontSize: '18px', fontWeight: '600' }}>
            Sales Transaction History
          </h2>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, color: '#6b7280', fontSize: 12, flexWrap: 'wrap' }}>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>↑</kbd><kbd style={{ padding: '2px 6px', marginLeft: 1, border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>↓</kbd> Select row</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>V</kbd>/<kbd style={{ padding: '2px 6px', marginLeft: 1, border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Enter</kbd> View</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>E</kbd> Edit</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>R</kbd>/<kbd style={{ padding: '2px 6px', marginLeft: 1, border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>P</kbd> Reprint</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Del</kbd> Delete</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Esc</kbd> Close</span>
          </div>
          <button
            onClick={onClose}
            style={{
              background: 'none',
              border: 'none',
              fontSize: '24px',
              cursor: 'pointer',
              color: '#999',
              padding: '0'
            }}
          >
            ×
          </button>
        </div>

        {/* Search */}
        <div style={{ padding: '16px 20px', borderBottom: '1px solid #eee' }}>
          <input
            type="text"
            placeholder="Search by Transaction ID or Cashier..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{
              width: '100%',
              padding: '8px 12px',
              border: '1px solid #ddd',
              borderRadius: '4px',
              fontSize: '14px'
            }}
          />
        </div>

        {/* Loading */}
        {loading && (
          <div style={{
            padding: '40px',
            textAlign: 'center',
            color: '#666'
          }}>
            Loading transactions...
          </div>
        )}

        {/* Transactions List */}
        {!loading && (
          <div ref={tableBodyRef} style={{
            flex: 1,
            overflowY: 'auto',
            minHeight: '300px'
          }}>
            {filteredTransactions.length === 0 ? (
              <div style={{
                padding: '40px',
                textAlign: 'center',
                color: '#999'
              }}>
                No transactions found
              </div>
            ) : (
              <table style={{
                width: '100%',
                borderCollapse: 'collapse'
              }}>
                <thead>
                  <tr style={{ backgroundColor: '#f8f9fa' }}>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>ID</th>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>Type</th>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>Date</th>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>Cashier</th>
                    <th style={{ padding: '12px', textAlign: 'right', borderBottom: '1px solid #eee' }}>Amount</th>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>Payment</th>
                    <th style={{ padding: '12px', textAlign: 'left', borderBottom: '1px solid #eee' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {paginatedTransactions.map((transaction, idx) => (
                    <tr
                      key={transaction.id}
                      ref={idx === selectedIndex ? selectedRowRef : null}
                      data-row-index={idx}
                      tabIndex={idx === selectedIndex ? 0 : -1}
                      onClick={() => setSelectedIndex(idx)}
                      style={{
                        borderBottom: '1px solid #f0f0f0',
                        backgroundColor: idx === selectedIndex ? '#eef2ff' : 'transparent',
                        borderLeft: idx === selectedIndex ? '4px solid #3b82f6' : '4px solid transparent',
                        cursor: 'pointer',
                        outline: 'none'
                      }}
                    >
                      <td style={{ padding: '12px' }}>
                        <div style={{ fontSize: '12px', color: '#666' }}>
                          {transaction.transactionId}
                        </div>
                      </td>
                      <td style={{ padding: '12px' }}>
                        <span style={{
                          padding: '4px 8px',
                          borderRadius: '4px',
                          fontSize: '12px',
                          fontWeight: '500',
                          backgroundColor: transaction.type === 'LIVE' ? '#dcfce7' : '#fef3c7',
                          color: transaction.type === 'LIVE' ? '#166534' : '#92400e'
                        }}>
                          {transaction.type}
                        </span>
                      </td>
                      <td style={{ padding: '12px' }}>
                        <div style={{ fontSize: '14px' }}>
                          {new Date(transaction.date).toLocaleDateString()}
                        </div>
                        <div style={{ fontSize: '12px', color: '#666' }}>
                          {new Date(transaction.date).toLocaleTimeString()}
                        </div>
                      </td>
                      <td style={{ padding: '12px' }}>{transaction.cashier}</td>
                      <td style={{ padding: '12px', textAlign: 'right', fontWeight: '500' }}>
                        {formatCurrency(transaction.amount, settings.currency)}
                      </td>
                      <td style={{ padding: '12px' }}>
                        <span style={{
                          textTransform: 'capitalize',
                          fontSize: '14px'
                        }}>
                          {transaction.paymentMethod}
                        </span>
                      </td>
                      <td style={{ padding: '12px' }}>
                        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                          <button
                            onClick={() => onEditSale && onEditSale(transaction.originalData)}
                            style={{
                              padding: '6px 10px',
                              backgroundColor: '#3b82f6',
                              color: 'white',
                              border: 'none',
                              borderRadius: '6px',
                              cursor: 'pointer',
                              fontSize: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: 6
                            }}
                          >
                            <span>View</span>
                            <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', color: '#111827' }}>V</kbd>
                          </button>
                          <button
                            onClick={() => onEditSale && onEditSale(transaction.originalData)}
                            style={{
                              padding: '6px 10px',
                              backgroundColor: '#10b981',
                              color: 'white',
                              border: 'none',
                              borderRadius: '6px',
                              cursor: 'pointer',
                              fontSize: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: 6
                            }}
                          >
                            <span>Edit</span>
                            <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', color: '#111827' }}>E</kbd>
                          </button>
                          <button
                            onClick={() => handleReprint(transaction)}
                            style={{
                              padding: '6px 10px',
                              backgroundColor: '#6b7280',
                              color: 'white',
                              border: 'none',
                              borderRadius: '6px',
                              cursor: 'pointer',
                              fontSize: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: 6
                            }}
                          >
                            <span>Reprint</span>
                            <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', color: '#111827' }}>R</kbd>/<kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', color: '#111827' }}>P</kbd>
                          </button>
                          {canDelete && (
                          <button
                            onClick={() => handleDelete(transaction)}
                            disabled={deletingId === transaction.id}
                            style={{
                              padding: '6px 10px',
                              backgroundColor: '#ef4444',
                              color: 'white',
                              border: 'none',
                              borderRadius: '6px',
                              cursor: deletingId === transaction.id ? 'not-allowed' : 'pointer',
                              opacity: deletingId === transaction.id ? 0.6 : 1,
                              fontSize: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: 6
                            }}
                          >
                            <span>Delete</span>
                            <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb', color: '#111827' }}>Del</kbd>
                          </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}

        {/* Footer */}
        <div style={{
          padding: '16px 20px',
          borderTop: '1px solid #eee',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <div style={{ fontSize: '14px', color: '#666' }}>
              Page {currentPage} / {totalPages}
            </div>
            <button
              onClick={() => setCurrentPage(Math.max(1, currentPage - 1))}
              disabled={currentPage === 1}
              style={{
                padding: '8px 12px',
                backgroundColor: currentPage === 1 ? '#e5e7eb' : '#6b7280',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: currentPage === 1 ? 'not-allowed' : 'pointer',
                fontSize: '14px'
              }}
            >
              Previous
            </button>
            <button
              onClick={() => setCurrentPage(Math.min(totalPages, currentPage + 1))}
              disabled={currentPage >= totalPages}
              style={{
                padding: '8px 12px',
                backgroundColor: currentPage >= totalPages ? '#e5e7eb' : '#6b7280',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: currentPage >= totalPages ? 'not-allowed' : 'pointer',
                fontSize: '14px'
              }}
            >
              Next
            </button>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ fontSize: '12px', color: '#666' }}>
              Showing {startIndex + 1}-{Math.min(endIndex, filteredTransactions.length)} of {filteredTransactions.length}
            </div>
            <button
              onClick={fetchTransactions}
              disabled={loading}
              style={{
                padding: '8px 16px',
                backgroundColor: '#10b981',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: loading ? 'not-allowed' : 'pointer',
                fontSize: '14px'
              }}
            >
              {loading ? 'Refreshing...' : 'Refresh'}
            </button>
          </div>
        </div>
      </div>
      {showReceipt && receiptData && (
        <div className="modal-overlay" style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 2100, display: 'flex', justifyContent: 'center', alignItems: 'center' }} onClick={() => setShowReceipt(false)}>
          <div className="receipt-modal" style={{ backgroundColor: 'white', padding: '20px', borderRadius: '8px', maxWidth: '400px', width: '90%' }} onClick={e => e.stopPropagation()}>
            <ReceiptPrinter
              ref={receiptPrinterRef}
              saleData={receiptData}
              businessInfo={{ name: settings.storeName, address: settings.storeAddress, phone: settings.storePhone }}
              currency={settings.currency}
              isPrinting={isPrinting}
              onPrintComplete={() => { setIsPrinting(false); setShowReceipt(false); }}
            />
            <div style={{ fontSize: '12px', color: '#6b7280', marginTop: '8px', textAlign: 'center' }}>
              <kbd style={{ padding: '2px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Enter</kbd> Print &nbsp; <kbd style={{ padding: '2px 5px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Esc</kbd> Close
            </div>
            <button onClick={() => setShowReceipt(false)} style={{ width: '100%', padding: '8px', marginTop: '10px' }}>Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default SalesTransactionHistory;
