import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { get, post } from '../utils/api';

const DEFAULT_COL_WIDTHS = { select: 52, name: 240, barcode: 200, price: 100, quantity: 72, discountPct: 80, discountVal: 95, costPrice: 95, minStock: 85, warehouse: 150, category: 150, createdDate: 120 };

const DATA_COL_KEYS = ['name', 'barcode', 'price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock', 'warehouse', 'category', 'createdDate'];
const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];
const COL_ORDER_STORAGE_KEY = 'dummyProducts.columnOrder';

const loadStoredColumnOrder = () => {
  try {
    const raw = localStorage.getItem(COL_ORDER_STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed) && parsed.length === DATA_COL_KEYS.length && DATA_COL_KEYS.every(k => parsed.includes(k))) return parsed;
  } catch (e) { /* ignore */ }
  return null;
};

const DummyProductsScreen = () => {
  const { t } = useTranslation();
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [warehouses, setWarehouses] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectAll, setSelectAll] = useState(false);
  const [colWidths, setColWidths] = useState(() => ({ ...DEFAULT_COL_WIDTHS }));
  const [visibleCols, setVisibleCols] = useState(() => [...DATA_COL_KEYS]);
  const [columnOrder, setColumnOrder] = useState(() => loadStoredColumnOrder() || [...DATA_COL_KEYS]);
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [showColDropdown, setShowColDropdown] = useState(false);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [focusedRowIndex, setFocusedRowIndex] = useState(-1);
  const resizeRef = useRef({ key: null, startX: 0, startW: 0 });
  const colDropdownRef = useRef(null);
  const tableBodyRef = useRef(null);

  useEffect(() => {
    try { localStorage.setItem(COL_ORDER_STORAGE_KEY, JSON.stringify(columnOrder)); } catch (e) { /* ignore */ }
  }, [columnOrder]);

  const totalPages = Math.max(1, Math.ceil(rows.length / pageSize));
  const currentPage = Math.min(page, totalPages);
  const startIdx = (currentPage - 1) * pageSize;
  const pageRows = rows.slice(startIdx, startIdx + pageSize);

  // Keep focusedRowIndex in range when page/data changes
  useEffect(() => {
    const n = pageRows.length;
    if (n === 0) {
      setFocusedRowIndex(-1);
      return;
    }
    setFocusedRowIndex(prev => (prev < 0 ? 0 : prev >= n ? n - 1 : prev));
  }, [currentPage, pageSize, pageRows.length]);

  const toggleColumn = (key) => {
    setVisibleCols(prev => {
      if (prev.includes(key)) {
        const next = prev.filter(k => k !== key);
        if (next.length === 0) return prev;
        return next;
      }
      return [...prev, key];
    });
  };

  const selectAllColumns = () => setVisibleCols([...DATA_COL_KEYS]);
  const clearAllColumns = () => setVisibleCols([DATA_COL_KEYS[0]]);

  const displayCols = columnOrder.filter(k => visibleCols.includes(k));

  const moveColumnUp = (key) => {
    setColumnOrder(prev => {
      const i = prev.indexOf(key);
      if (i <= 0) return prev;
      const next = [...prev];
      [next[i - 1], next[i]] = [next[i], next[i - 1]];
      return next;
    });
  };

  const moveColumnDown = (key) => {
    setColumnOrder(prev => {
      const i = prev.indexOf(key);
      if (i < 0 || i >= prev.length - 1) return prev;
      const next = [...prev];
      [next[i], next[i + 1]] = [next[i + 1], next[i]];
      return next;
    });
  };

  const resetColumnOrder = () => setColumnOrder([...DATA_COL_KEYS]);

  const colLabel = (key) => {
    const labels = { name: t('sales.productName') || 'Name', barcode: t('products.barcode') || 'Barcode', price: t('sales.price') || 'Price', quantity: t('sales.quantity') || 'Qty', discountPct: t('dummyProducts.discountPct') || 'Discount %', discountVal: t('dummyProducts.discountValue') || 'Discount value', costPrice: t('products.costPrice') || 'Cost price', minStock: t('products.minStock') || 'Min stock', warehouse: t('warehouse.warehouse') || 'Warehouse', category: t('products.category') || 'Category', createdDate: t('dummyProducts.createdDate') || 'Created date' };
    return labels[key] || key;
  };

  const formatCreatedDate = (val) => {
    if (!val) return '—';
    const d = new Date(val);
    return isNaN(d.getTime()) ? '—' : d.toLocaleDateString(undefined, { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  };

  const handleResizeStart = (e, key) => {
    e.preventDefault();
    resizeRef.current = { key, startX: e.clientX, startW: colWidths[key] };
    const onMove = (ev) => {
      const delta = ev.clientX - resizeRef.current.startX;
      const newW = Math.max(60, resizeRef.current.startW + delta);
      setColWidths(prev => ({ ...prev, [resizeRef.current.key]: newW }));
    };
    const onUp = () => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  };

  const ResizeHandle = ({ colKey }) => (
    <span
      role="separator"
      onMouseDown={(e) => handleResizeStart(e, colKey)}
      style={{ position: 'absolute', right: 0, top: 0, bottom: 0, width: 6, cursor: 'col-resize', zIndex: 1 }}
      title={t('dummyProducts.resizeColumn') || 'Drag to resize column'}
    />
  );

  const loadWarehouses = useCallback(async () => {
    try {
      const res = await get('/warehouses');
      if (res.success && res.data && res.data.length > 0) setWarehouses(res.data);
    } catch (e) {
      console.error(e);
    }
  }, []);

  const loadCategories = useCallback(async () => {
    try {
      const res = await get('/categories');
      if (res.success && res.data && Array.isArray(res.data)) setCategories(res.data);
    } catch (e) {
      console.error(e);
    }
  }, []);

  const loadDummyProducts = useCallback(async (override) => {
    try {
      setLoading(true);
      const from = override?.dateFrom !== undefined ? override.dateFrom : dateFrom;
      const to = override?.dateTo !== undefined ? override.dateTo : dateTo;
      const params = new URLSearchParams();
      if (from) params.set('fromDate', from);
      if (to) params.set('toDate', to);
      const qs = params.toString();
      const url = '/dummy-transactions/items/dummy-products' + (qs ? `?${qs}` : '');
      const res = await get(url);
      if (res.success && Array.isArray(res.data)) {
        setRows(res.data.map(r => ({
          ...r,
          selected: false,
          name: r.name || '',
          barcode: r.barcode || '',
          sellingPrice: r.sellingPrice != null ? String(r.sellingPrice) : '',
          quantity: r.quantity != null ? String(r.quantity) : '0',
          discountPercentage: r.discountPercentage != null && r.discountPercentage !== '' ? String(r.discountPercentage) : '',
          discountFixedPrice: r.discount != null ? String(r.discount) : '',
          costPrice: r.costPrice != null && r.costPrice !== '' ? String(r.costPrice) : '',
          minStockLevel: r.minStockLevel != null && r.minStockLevel !== '' ? String(r.minStockLevel) : '',
          categoryId: r.categoryId != null ? String(r.categoryId) : '',
          warehouseId: r.warehouseId != null ? String(r.warehouseId) : '',
          createdAt: r.createdAt || null
        })));
      } else {
        setRows([]);
      }
    } catch (e) {
      console.error(e);
      setRows([]);
    } finally {
      setLoading(false);
    }
  }, [dateFrom, dateTo]);

  useEffect(() => {
    loadDummyProducts();
    loadWarehouses();
    loadCategories();
  }, [loadDummyProducts, loadWarehouses, loadCategories]);

  useEffect(() => {
    const close = (e) => { if (showColDropdown && colDropdownRef.current && !colDropdownRef.current.contains(e.target)) setShowColDropdown(false); };
    document.addEventListener('mousedown', close);
    return () => document.removeEventListener('mousedown', close);
  }, [showColDropdown]);

  useEffect(() => {
    const onKey = (e) => { if (e.key === 'Escape') setShowColDropdown(false); };
    if (showColDropdown) {
      document.addEventListener('keydown', onKey);
      return () => document.removeEventListener('keydown', onKey);
    }
  }, [showColDropdown]);

  const toggleSelectAll = useCallback(() => {
    setSelectAll(prev => {
      const next = !prev;
      setRows(r => r.map(row => ({ ...row, selected: next })));
      return next;
    });
  }, []);

  const toggleRow = useCallback((id) => {
    setRows(prev => {
      const next = prev.map(r => r.id === id ? { ...r, selected: !r.selected } : r);
      const allSelected = next.length > 0 && next.every(r => r.selected);
      setSelectAll(allSelected);
      return next;
    });
  }, []);

  const updateRow = (id, field, value) => {
    setRows(prev => prev.map(r => r.id === id ? { ...r, [field]: value } : r));
  };

  const generateBarcodeForRow = (id) => {
    const num = Date.now().toString().slice(-8) + Math.floor(Math.random() * 10);
    const unique = `D${num}`;
    setRows(prev => prev.map(r => r.id === id ? { ...r, barcode: unique } : r));
  };

  const handleSave = async () => {
    const selected = rows.filter(r => r.selected);
    if (selected.length === 0) {
      alert(t('dummyProducts.selectAtLeastOne') || 'Select at least one row to save as product.');
      return;
    }
    setSaving(true);
    let ok = 0;
    let fail = 0;
    for (const row of selected) {
      const name = (row.name || '').trim();
      const sellingPrice = parseFloat(row.sellingPrice);
      if (!name || isNaN(sellingPrice) || sellingPrice < 0) {
        fail++;
        continue;
      }
      try {
        const qty = parseInt(row.quantity, 10);
        const quantity = !isNaN(qty) && qty >= 0 ? qty : 0;
        const discountPct = parseFloat(row.discountPercentage);
        const discountPercentage = !isNaN(discountPct) && discountPct >= 0 && discountPct <= 100 ? discountPct : undefined;
        const discountVal = parseFloat(row.discountFixedPrice);
        const discountFixedPrice = !isNaN(discountVal) && discountVal >= 0 ? discountVal : undefined;
        const costPriceVal = parseFloat(row.costPrice);
        const costPrice = !isNaN(costPriceVal) && costPriceVal >= 0 ? costPriceVal : undefined;
        const minStockVal = parseInt(row.minStockLevel, 10);
        const minStockLevel = !isNaN(minStockVal) && minStockVal >= 0 ? minStockVal : undefined;
        const rowCategoryId = row.categoryId && !isNaN(parseInt(row.categoryId)) ? parseInt(row.categoryId) : null;
        const rowWarehouseId = row.warehouseId && !isNaN(parseInt(row.warehouseId)) ? parseInt(row.warehouseId) : null;
        const payload = {
          name,
          sellingPrice,
          quantity,
          ...(row.barcode && row.barcode.trim() ? { barcode: row.barcode.trim() } : {}),
          ...(rowWarehouseId ? { warehouseId: rowWarehouseId } : {}),
          ...(rowCategoryId ? { categoryId: rowCategoryId } : {}),
          ...(costPrice !== undefined ? { costPrice } : {}),
          ...(minStockLevel !== undefined ? { minStockLevel } : {}),
          ...(discountPercentage !== undefined ? { discountPercentage } : {}),
          ...(discountFixedPrice !== undefined ? { discountFixedPrice } : {})
        };
        const result = await post('/products/create-with-barcode', payload);
        if (result && result.success) {
          ok++;
          setRows(prev => prev.filter(r => r.id !== row.id));
        } else {
          fail++;
        }
      } catch (e) {
        fail++;
      }
    }
    setSaving(false);
    setSelectAll(false);
    if (ok > 0) {
      alert(t('dummyProducts.savedCount', { count: ok }) || `${ok} product(s) created. They appear in the Products tab.`);
    }
    if (fail > 0) {
      alert(t('dummyProducts.failedCount', { count: fail }) || `${fail} row(s) could not be saved. Check name and price.`);
    }
  };

  return (
    <div data-screen="dummy-products" style={{ height: '100%', minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Single padded content area: header + table share same width */}
      <div style={{ flex: 1, minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: '0.5rem 1rem', boxSizing: 'border-box' }}>
        {/* Top section: compact spacing */}
        <header style={{ flexShrink: 0, width: '100%', marginBottom: '0.5rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', flexWrap: 'wrap', marginBottom: '0.35rem', padding: '6px 10px', borderRadius: 8, background: 'var(--bg-card)', border: '1px solid var(--border-light)', fontSize: '0.8125rem', color: 'var(--text-secondary)', minHeight: 32, boxSizing: 'border-box' }}>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Alt+R</kbd> {t('dummyProducts.shortcutRefresh') || 'Refresh'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Alt+S</kbd> {t('dummyProducts.shortcutSave') || 'Save selected'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>↑</kbd><kbd style={{ padding: '2px 6px', marginLeft: 2, border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>↓</kbd> {t('dummyProducts.shortcutMoveRow') || 'Move row'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Enter</kbd> {t('dummyProducts.shortcutToggleSelect') || 'Toggle select'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Ctrl+A</kbd> {t('dummyProducts.shortcutSelectAll') || 'Select all'}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '0.5rem', marginBottom: '0.35rem' }}>
            <h2 style={{ margin: 0, fontSize: '1.25rem', fontWeight: 700 }}>{t('dummyProducts.title') || 'Dummy Products'}</h2>
            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flexWrap: 'wrap' }}>
              <button
                type="button"
                data-action="dummy-save"
                onClick={handleSave}
                disabled={saving || rows.filter(r => r.selected).length === 0}
                className="btn btn-primary"
                title={t('dummyProducts.saveAsProductsTitle') || 'Save selected as products (Alt+S)'}
                style={{ padding: '4px 10px', fontSize: '0.8125rem', display: 'inline-flex', alignItems: 'center', gap: '6px' }}
              >
                {saving ? (t('common.saving') || 'Saving...') : (t('dummyProducts.saveAsProducts') || 'Save selected as products')}
                {!saving && <kbd style={{ padding: '2px 5px', fontSize: '0.7rem', border: '1px solid rgba(255,255,255,0.5)', borderRadius: 4, background: 'rgba(0,0,0,0.15)', fontWeight: 600 }}>Alt+S</kbd>}
              </button>
              <button type="button" onClick={loadDummyProducts} className="btn btn-outline-primary" title={t('dummyProducts.refreshTitle') || 'Refresh list (Alt+R)'} style={{ padding: '4px 10px', fontSize: '0.8125rem', display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                {t('common.refresh') || 'Refresh'}
                <kbd style={{ padding: '2px 5px', fontSize: '0.7rem', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Alt+R</kbd>
              </button>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 4, fontSize: '0.8125rem', fontWeight: 500, color: 'var(--text-secondary)' }}>
              {t('dummyProducts.dateFrom') || 'From'}: <input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} className="modern-input" style={{ padding: '4px 8px', width: '10rem', fontSize: '0.8125rem' }} />
            </label>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 4, fontSize: '0.8125rem', fontWeight: 500, color: 'var(--text-secondary)' }}>
              {t('dummyProducts.dateTo') || 'To'}: <input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} className="modern-input" style={{ padding: '4px 8px', width: '10rem', fontSize: '0.8125rem' }} />
            </label>
            <button type="button" onClick={() => { setPage(1); loadDummyProducts(); }} className="btn btn-primary" style={{ padding: '4px 10px', fontSize: '0.8125rem' }}>{t('dummyProducts.applyFilter') || 'Apply'}</button>
            <button type="button" onClick={() => { setDateFrom(''); setDateTo(''); setPage(1); loadDummyProducts({ dateFrom: '', dateTo: '' }); }} className="btn btn-outline-primary" style={{ padding: '4px 10px', fontSize: '0.8125rem' }}>{t('dummyProducts.clearFilter') || 'Clear'}</button>
            {(dateFrom || dateTo) && <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{t('dummyProducts.filteredByDate') || 'Filtered by date'}</span>}
          </div>
        </header>
      {loading ? (
        <p>{t('common.loading')}</p>
      ) : rows.length === 0 ? (
        <p style={{ color: 'var(--text-muted)' }}>{t('dummyProducts.noData') || 'No dummy product data. Add manual items on Sales Screen B to see them here.'}</p>
      ) : (
        <div style={{ flex: 1, minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={{ flexShrink: 0, display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.4rem', flexWrap: 'wrap' }}>
          <div ref={colDropdownRef} style={{ position: 'relative' }}>
            <button type="button" className="btn btn-outline-primary" style={{ padding: '4px 10px', fontSize: '0.8125rem' }} onClick={() => setShowColDropdown(v => !v)} aria-expanded={showColDropdown} aria-haspopup="true">
              {t('dummyProducts.selectColumns') || 'Select columns'} {visibleCols.length < DATA_COL_KEYS.length ? `(${visibleCols.length}/${DATA_COL_KEYS.length})` : ''}
            </button>
            {showColDropdown && (
              <div
                role="dialog"
                aria-label={t('dummyProducts.selectColumns') || 'Select columns'}
                onMouseDown={(e) => e.stopPropagation()}
                style={{ position: 'absolute', top: '100%', left: 0, marginTop: 2, background: 'var(--bg-card)', border: '1px solid var(--border-light)', borderRadius: 6, padding: '8px 10px', minWidth: 200, maxWidth: 260, zIndex: 1000, boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
              >
                <div style={{ fontSize: '0.7rem', fontWeight: 600, color: 'var(--text-muted)', marginBottom: 4, textTransform: 'uppercase' }}>
                  {t('dummyProducts.selectColumns') || 'Select columns'}
                </div>
                <div style={{ display: 'flex', gap: 4, marginBottom: 4 }}>
                  <button type="button" onClick={selectAllColumns} style={{ padding: '2px 6px', fontSize: 10, border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', cursor: 'pointer' }}>
                    {t('dummyProducts.showAllColumns') || 'All'}
                  </button>
                  <button type="button" onClick={clearAllColumns} style={{ padding: '2px 6px', fontSize: 10, border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', cursor: 'pointer' }}>
                    {t('dummyProducts.showMinColumns') || 'Minimal'}
                  </button>
                  <button type="button" onClick={resetColumnOrder} style={{ padding: '2px 6px', fontSize: 10, border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', cursor: 'pointer' }} title={t('dummyProducts.resetColumnOrder') || 'Reset column order'}>
                    {t('dummyProducts.resetOrder') || 'Reset order'}
                  </button>
                </div>
                <div style={{ fontSize: 10, color: 'var(--text-muted)', marginBottom: 4 }}>{t('dummyProducts.dragOrUseArrows') || 'Use arrows to reorder columns.'}</div>
                <div style={{ maxHeight: 220, overflowY: 'auto' }}>
                  {columnOrder.map((key, idx) => (
                    <div key={key} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '2px 0', fontSize: '0.8125rem' }}>
                      <input type="checkbox" id={`col-${key}`} checked={visibleCols.includes(key)} onChange={() => toggleColumn(key)} />
                      <label htmlFor={`col-${key}`} style={{ flex: 1, cursor: 'pointer' }}>{colLabel(key)}</label>
                      <span style={{ display: 'flex', gap: 1 }}>
                        <button type="button" onClick={() => moveColumnUp(key)} disabled={idx === 0} title={t('dummyProducts.moveColumnUp') || 'Move left'} style={{ padding: '1px 4px', fontSize: 10, border: '1px solid var(--border-light)', borderRadius: 3, background: 'var(--bg-main)', cursor: idx === 0 ? 'not-allowed' : 'pointer', opacity: idx === 0 ? 0.5 : 1 }} aria-label={t('dummyProducts.moveColumnUp') || 'Move left'}>↑</button>
                        <button type="button" onClick={() => moveColumnDown(key)} disabled={idx === columnOrder.length - 1} title={t('dummyProducts.moveColumnDown') || 'Move right'} style={{ padding: '1px 4px', fontSize: 10, border: '1px solid var(--border-light)', borderRadius: 3, background: 'var(--bg-main)', cursor: idx === columnOrder.length - 1 ? 'not-allowed' : 'pointer', opacity: idx === columnOrder.length - 1 ? 0.5 : 1 }} aria-label={t('dummyProducts.moveColumnDown') || 'Move right'}>↓</button>
                      </span>
                    </div>
                  ))}
                </div>
                <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 4 }}>Esc {t('common.close')}</div>
              </div>
            )}
          </div>
          <span style={{ fontSize: '0.8125rem', color: 'var(--text-muted)' }}>
            {t('dummyProducts.rowsPerPage') || 'Rows/page'}:{' '}
            <select value={pageSize} onChange={(e) => { setPageSize(Number(e.target.value)); setPage(1); }} className="modern-input" style={{ padding: '2px 6px', marginLeft: 2, fontSize: '0.8125rem' }}>
              {PAGE_SIZE_OPTIONS.map(n => (<option key={n} value={n}>{n}</option>))}
            </select>
          </span>
          <span style={{ fontSize: '0.8125rem', color: 'var(--text-muted)' }}>
            {startIdx + 1}-{Math.min(startIdx + pageSize, rows.length)} {t('dummyProducts.of') || 'of'} {rows.length}
          </span>
        </div>
        <div className="table-container" style={{ flex: 1, minHeight: 0, overflow: 'auto', overflowX: 'auto', overflowY: 'auto', border: '1px solid var(--border-light)', borderRadius: 'var(--radius-md)', isolation: 'isolate', width: '100%', minWidth: 0 }}>
          <table className="data-table" style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', minWidth: '100%' }}>
            <thead>
              <tr className="glass-panel" style={{ borderBottom: '2px solid var(--glass-border, var(--border-light))', position: 'sticky', top: 0, background: 'var(--glass-bg, var(--bg-card))', backdropFilter: 'blur(var(--blur-strength, 8px))', zIndex: 10, boxShadow: '0 2px 0 var(--glass-border, var(--border-light))' }}>
                <th style={{ padding: 6, width: colWidths.select, minWidth: 44, textAlign: 'center', position: 'sticky', left: 0, zIndex: 11, background: 'var(--glass-bg, var(--bg-card))', boxShadow: '2px 0 0 var(--glass-border, var(--border-light))', fontSize: '0.8125rem' }}>
                  <input type="checkbox" checked={selectAll} onChange={toggleSelectAll} title={t('dummyProducts.selectAll') || 'Select all'} />
                  <ResizeHandle colKey="select" />
                </th>
                {displayCols.map(key => {
                  const align = ['price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock'].includes(key) ? 'right' : 'left';
                  const minW = { name: 120, barcode: 100, price: 70, quantity: 56, discountPct: 56, discountVal: 70, costPrice: 70, minStock: 60, warehouse: 100, category: 100, createdDate: 100 }[key] || 70;
                  return (
                    <th key={key} style={{ padding: 6, width: colWidths[key], minWidth: minW, textAlign: align, position: 'relative', background: 'var(--glass-bg, var(--bg-card))', fontSize: '0.8125rem' }}>
                      {colLabel(key)}
                      <ResizeHandle colKey={key} />
                    </th>
                  );
                })}
              </tr>
            </thead>
            <tbody ref={tableBodyRef}>
              {pageRows.map((row, idx) => (
                <tr
                  key={row.id}
                  data-row-index={idx}
                  style={{
                    borderBottom: '1px solid var(--border-light)',
                    backgroundColor: idx === focusedRowIndex ? 'var(--primary-subtle)' : undefined,
                    borderLeft: idx === focusedRowIndex ? '4px solid var(--primary)' : '4px solid transparent'
                  }}
                >
                  <td style={{ padding: 6, width: colWidths.select, minWidth: 44, textAlign: 'center', position: 'sticky', left: 0, zIndex: 1, background: idx === focusedRowIndex ? 'var(--primary-subtle)' : 'var(--bg-main)', boxShadow: '2px 0 0 var(--border-light)' }}>
                    <input type="checkbox" checked={!!row.selected} onChange={() => toggleRow(row.id)} />
                  </td>
                  {displayCols.map(key => {
                    const align = ['price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock'].includes(key) ? 'right' : 'left';
                    const minW = { name: 120, barcode: 100, price: 70, quantity: 56, discountPct: 56, discountVal: 70, costPrice: 70, minStock: 60, warehouse: 100, category: 100, createdDate: 100 }[key] || 70;
                    const baseTd = { padding: 6, width: colWidths[key], minWidth: minW, textAlign: align, fontSize: '0.8125rem' };
                    if (key === 'name') return (<td key={key} style={{ ...baseTd, overflow: 'hidden' }}><input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, boxSizing: 'border-box' }} placeholder={t('sales.productName') || 'Name'} title={row.name || (t('sales.productName') || 'Name')} /></td>);
                    if (key === 'barcode') return (<td key={key} style={{ ...baseTd, overflow: 'hidden' }}><div style={{ display: 'flex', alignItems: 'center', gap: 4 }}><input type="text" value={row.barcode} onChange={(e) => updateRow(row.id, 'barcode', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, boxSizing: 'border-box' }} placeholder={t('dummyProducts.barcodeAutoPlaceholder') || 'Empty = auto-generated on save'} /><button type="button" onClick={() => generateBarcodeForRow(row.id)} className="btn btn-outline-primary" style={{ padding: '2px 6px', fontSize: '0.7rem', whiteSpace: 'nowrap' }} title={t('dummyProducts.generateBarcode') || 'Generate barcode'}>{t('dummyProducts.genBarcode') || 'Gen'}</button></div></td>);
                    if (key === 'price') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.sellingPrice} onChange={(e) => updateRow(row.id, 'sellingPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                    if (key === 'quantity') return (<td key={key} style={baseTd}><input type="number" min="0" value={row.quantity} onChange={(e) => updateRow(row.id, 'quantity', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                    if (key === 'discountPct') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" max="100" value={row.discountPercentage} onChange={(e) => updateRow(row.id, 'discountPercentage', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="%" /></td>);
                    if (key === 'discountVal') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.discountFixedPrice} onChange={(e) => updateRow(row.id, 'discountFixedPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                    if (key === 'costPrice') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.costPrice} onChange={(e) => updateRow(row.id, 'costPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                    if (key === 'minStock') return (<td key={key} style={baseTd}><input type="number" min="0" value={row.minStockLevel} onChange={(e) => updateRow(row.id, 'minStockLevel', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                    if (key === 'warehouse') return (<td key={key} style={baseTd}><select value={row.warehouseId || ''} onChange={(e) => updateRow(row.id, 'warehouseId', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, padding: '4px 6px', boxSizing: 'border-box', fontSize: '0.8125rem' }}><option value="">{t('common.select') || '—'}</option>{warehouses.map(w => (<option key={w.id} value={w.id}>{w.name}</option>))}</select></td>);
                    if (key === 'category') return (<td key={key} style={baseTd}><select value={row.categoryId || ''} onChange={(e) => updateRow(row.id, 'categoryId', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, padding: '4px 6px', boxSizing: 'border-box', fontSize: '0.8125rem' }}><option value="">{t('common.select') || '—'}</option>{categories.map(c => (<option key={c.id} value={c.id}>{c.name}</option>))}</select></td>);
                    if (key === 'createdDate') return (<td key={key} style={{ ...baseTd, fontSize: '0.8rem', color: 'var(--text-muted)' }} title={row.createdAt ? new Date(row.createdAt).toLocaleString() : ''}>{formatCreatedDate(row.createdAt)}</td>);
                    return <td key={key} style={baseTd}>—</td>;
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '0.4rem', marginTop: '0.4rem', padding: '4px 0' }}>
          <span style={{ fontSize: '0.8125rem', color: 'var(--text-muted)' }}>
            {t('dummyProducts.page') || 'Page'} {currentPage} {t('dummyProducts.of') || 'of'} {totalPages} ({rows.length} {t('dummyProducts.rows') || 'rows'})
          </span>
          <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <button type="button" className="btn btn-outline-primary" style={{ padding: '4px 8px', fontSize: '0.8125rem' }} disabled={currentPage <= 1} onClick={() => setPage(p => Math.max(1, p - 1))}>
              {t('dummyProducts.prev') || 'Prev'}
            </button>
            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
              let p;
              if (totalPages <= 5) p = i + 1;
              else if (currentPage <= 3) p = i + 1;
              else if (currentPage >= totalPages - 2) p = totalPages - 4 + i;
              else p = currentPage - 2 + i;
              return (
                <button key={p} type="button" className="btn btn-outline-primary" style={{ padding: '4px 8px', minWidth: 28, fontSize: '0.8125rem', fontWeight: p === currentPage ? 700 : 400 }} onClick={() => setPage(p)}>
                  {p}
                </button>
              );
            })}
            <button type="button" className="btn btn-outline-primary" style={{ padding: '4px 8px', fontSize: '0.8125rem' }} disabled={currentPage >= totalPages} onClick={() => setPage(p => Math.min(totalPages, p + 1))}>
              {t('dummyProducts.next') || 'Next'}
            </button>
          </div>
        </div>
        </div>
      )}
      </div>
    </div>
  );
};

export default DummyProductsScreen;
