import React, { useEffect } from 'react';
import { useTranslation } from 'react-i18next';

const HelpDemoModal = ({ isOpen, onClose }) => {
  const { t } = useTranslation();

  useEffect(() => {
    const onKey = (e) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) window.addEventListener('keydown', onKey, { capture: true });
    return () => window.removeEventListener('keydown', onKey, { capture: true });
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ background: 'white', width: '90%', maxWidth: 720, borderRadius: 12, overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}>
        <div style={{ padding: '16px 20px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>{t('helpDemo.title')}</h2>
          <button onClick={onClose} style={{ border: 'none', background: 'transparent', fontSize: 22, color: '#888', cursor: 'pointer' }}>×</button>
        </div>
        <div style={{ padding: 20 }}>
          <ol style={{ margin: 0, paddingLeft: 20, display: 'grid', rowGap: 12 }}>
            <li>
              <div style={{ fontWeight: 700 }}>{t('helpDemo.step1.title')}</div>
              <div style={{ color: '#555', fontSize: 14 }}>{t('helpDemo.step1.desc')}</div>
            </li>
            <li>
              <div style={{ fontWeight: 700 }}>{t('helpDemo.step2.title')}</div>
              <div style={{ color: '#555', fontSize: 14 }}>{t('helpDemo.step2.desc')}</div>
            </li>
            <li>
              <div style={{ fontWeight: 700 }}>{t('helpDemo.step3.title')}</div>
              <div style={{ color: '#555', fontSize: 14 }}>{t('helpDemo.step3.desc')}</div>
            </li>
            <li>
              <div style={{ fontWeight: 700 }}>{t('helpDemo.step4.title')}</div>
              <div style={{ color: '#555', fontSize: 14 }}>{t('helpDemo.step4.desc')}</div>
            </li>
          </ol>
          <div style={{ marginTop: 16, padding: 12, background: '#f9fafb', border: '1px solid #eee', borderRadius: 8 }}>
            <div style={{ fontSize: 12, color: '#6b7280', textTransform: 'uppercase', fontWeight: 800, marginBottom: 8 }}>{t('helpDemo.shortcuts')}</div>
            <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr', columnGap: 12, rowGap: 6, fontSize: 13 }}>
              <kbd>F2</kbd><span>{t('sales.shortcuts.search')}</span>
              <kbd>F8</kbd><span>{t('sales.shortcuts.quick')}</span>
              <kbd>F10</kbd><span>{t('sales.shortcuts.complete')}</span>
              <kbd>Alt+D</kbd><span>{t('helpDemo.open')}</span>
            </div>
          </div>
        </div>
        <div style={{ padding: '12px 20px', borderTop: '1px solid #eee', display: 'flex', justifyContent: 'flex-end' }}>
          <button onClick={onClose} className="modal-button primary">{t('common.close')}</button>
        </div>
      </div>
    </div>
  );
};

export default HelpDemoModal;

