import React, { useState, useEffect, useRef } from 'react';
import { get } from '../utils/api';
import { formatCurrency } from '../utils/currency';
import { useSettings } from '../context/SettingsContext';
import GlassCard from './common/GlassCard';
import '../styles/antigravity.css';

const ProductSearchModal = ({ isOpen, onClose, onAddProduct, quantity = 1 }) => {
  const { settings } = useSettings();
  const [searchTerm, setSearchTerm] = useState('');
  const [products, setProducts] = useState([]);
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [loading, setLoading] = useState(false);
  const searchInputRef = useRef(null);

  // Load products when modal opens
  useEffect(() => {
    if (isOpen) {
      // Focus search input when modal opens
      searchInputRef.current?.focus();

      // Load all products
      loadProducts();
    }
  }, [isOpen]);

  // Load products from API
  const loadProducts = async () => {
    setLoading(true);
    try {
      const result = await get('/products');
      if (result.success) {
        setProducts(result.data || []);
        setFilteredProducts(result.data || []);
      } else {
        console.error('Error loading products:', result.message);
        setProducts([]);
        setFilteredProducts([]);
      }
    } catch (error) {
      console.error('Error loading products:', error);
      setProducts([]);
      setFilteredProducts([]);
    } finally {
      setLoading(false);
    }
  };

  // Filter products based on search term (name, barcode, SKU)
  useEffect(() => {
    if (searchTerm.trim() === '') {
      setFilteredProducts(products);
    } else {
      const term = searchTerm.toLowerCase();
      const filtered = products.filter(product =>
        product.name?.toLowerCase().includes(term) ||
        (product.barcode && product.barcode.toLowerCase().includes(term)) ||
        (product.sku && product.sku.toLowerCase().includes(term))
      );
      setFilteredProducts(filtered);
    }
  }, [searchTerm, products]);

  // Reset selected index when products change
  useEffect(() => {
    if (filteredProducts.length > 0) {
      setSelectedIndex(0);
      setSelectedProduct(filteredProducts[0]);
    } else {
      setSelectedIndex(-1);
      setSelectedProduct(null);
    }
  }, [filteredProducts]);

  // Handle keyboard events in modal
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        onClose();
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex(prev => (prev + 1) % filteredProducts.length);
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex(prev => (prev - 1 + filteredProducts.length) % filteredProducts.length);
      } else if (e.key === 'Enter') {
        e.preventDefault();
        if (selectedIndex >= 0 && filteredProducts[selectedIndex]) {
          onAddProduct(filteredProducts[selectedIndex], quantity);
          onClose();
        } else if (searchTerm.trim() !== '') {
          // If no selection but there's a search term, maybe trigger manual reload?
          // But search is already reactive. Let's just select the first one if available.
          if (filteredProducts.length > 0) {
            onAddProduct(filteredProducts[0], quantity);
            onClose();
          }
        }
      }
    };

    // Update selectedProduct when selectedIndex changes
    if (selectedIndex >= 0 && selectedIndex < filteredProducts.length) {
      setSelectedProduct(filteredProducts[selectedIndex]);
    }

    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [isOpen, onClose, onAddProduct, filteredProducts, selectedIndex, quantity, searchTerm]);

  if (!isOpen) return null;

  return (
    <div className="modal-overlay">
      <div className="modal-container" style={{ maxWidth: '800px', width: '100%', height: '80vh', display: 'flex', flexDirection: 'column' }}>
        <div className="modal-header" style={{ padding: '1.5rem 2rem', borderBottom: '1px solid var(--border-light)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div className="modal-title" style={{ fontSize: '1.25rem', fontWeight: '800', color: 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <svg style={{ width: '24px', height: '24px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            SEARCH PRODUCTS
          </div>
          <button onClick={onClose} className="modal-close-button" style={{ background: 'transparent', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', padding: '0.5rem', borderRadius: 'var(--radius-md)' }}>
            <svg style={{ width: '24px', height: '24px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="modal-body" style={{ flex: 1, padding: '2rem', overflowY: 'hidden', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px', border: '1px solid #ddd', borderRadius: '8px', backgroundColor: 'white' }}>
            <svg style={{ width: '24px', height: '24px', color: '#999', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input
              ref={searchInputRef}
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Start typing name or scan barcode..."
              style={{
                flex: 1,
                border: 'none',
                outline: 'none',
                fontSize: '1.125rem',
                padding: '0',
                background: 'transparent'
              }}
              autoFocus
            />
          </div>

          {loading ? (
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <div style={{ width: '40px', height: '40px', border: '3px solid var(--primary-light)', borderTopColor: 'var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
            </div>
          ) : (
            <div style={{ flex: 1, overflowY: 'auto' }} className="animate-fade-in">
              {filteredProducts.length === 0 ? (
                <div style={{ height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', gap: '1rem' }}>
                  <svg style={{ width: '64px', height: '64px', opacity: 0.3 }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <div style={{ fontWeight: '700' }}>No products found</div>
                </div>
              ) : (
                <GlassCard style={{ padding: 0, overflow: 'hidden' }}>
                  <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                      <thead>
                        <tr className="glass-panel" style={{ borderBottom: '1px solid var(--glass-border)', background: 'var(--glass-bg)', color: 'var(--text-muted)', fontWeight: 'bold' }}>
                          <th style={{ textAlign: 'left', padding: '12px' }}>Product</th>
                          <th style={{ textAlign: 'left', padding: '12px' }}>SKU</th>
                          <th style={{ textAlign: 'left', padding: '12px' }}>Barcode</th>
                          <th style={{ textAlign: 'right', padding: '12px' }}>Price</th>
                          <th style={{ textAlign: 'center', padding: '12px' }}>Stock</th>
                          <th style={{ textAlign: 'center', padding: '12px' }}>Action</th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredProducts.map((product, index) => (
                          <tr
                            key={product.id}
                            className="inventory-row"
                            style={{
                              cursor: 'pointer',
                              backgroundColor: selectedIndex === index ? 'var(--primary-subtle)' : 'transparent',
                              borderBottom: '1px solid rgba(255,255,255,0.03)',
                              transition: 'background 0.2s'
                            }}
                            onClick={() => setSelectedIndex(index)}
                            onDoubleClick={() => { onAddProduct(product, quantity); onClose(); }}
                          >
                            <td style={{ padding: '12px' }}>
                              <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                <div style={{ width: '40px', height: '40px', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-sm)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--border-light)', flexShrink: 0 }}>
                                  {product.image ? (
                                    <img
                                      src={product.image.startsWith('http') ? product.image : `/uploads/${product.image}`}
                                      alt={product.name}
                                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                      onError={(e) => { e.target.style.display = 'none'; if (e.target.nextSibling) e.target.nextSibling.style.display = 'block'; }}
                                    />
                                  ) : null}
                                  <svg style={{ width: '18px', height: '18px', color: 'var(--text-muted)', display: product.image ? 'none' : 'block' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>
                                </div>
                                <span style={{ fontWeight: '600', color: 'var(--text-main)' }}>{product.name}</span>
                              </div>
                            </td>
                            <td style={{ padding: '12px', fontSize: '0.9rem', color: 'var(--text-muted)' }}>{product.sku || '–'}</td>
                            <td style={{ padding: '12px', fontFamily: 'monospace', fontSize: '0.9rem', color: 'var(--text-muted)' }}>{product.barcode || '–'}</td>
                            <td style={{ padding: '12px', textAlign: 'right', fontWeight: '700', color: 'var(--primary)' }}>{formatCurrency(Number(product.sellingPrice || product.selling_price || 0), settings?.currency || 'USD')}</td>
                            <td style={{ padding: '12px', textAlign: 'center', fontWeight: '600', color: (product.inventory?.quantity || 0) <= (product.minStockLevel || 0) ? 'var(--danger)' : 'var(--success)' }}>
                              {product.inventory?.quantity ?? '0'}
                            </td>
                            <td style={{ padding: '12px', textAlign: 'center' }}>
                              <button
                                type="button"
                                onClick={(e) => { e.stopPropagation(); onAddProduct(product, quantity); onClose(); }}
                                style={{ padding: '0.5rem 1rem', borderRadius: 'var(--radius-md)', border: 'none', background: 'var(--primary)', color: 'white', fontWeight: '700', cursor: 'pointer', fontSize: '0.875rem' }}
                              >
                                SELECT
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </GlassCard>
              )}
            </div>
          )}
        </div>

        <div className="modal-footer" style={{ padding: '1.5rem 2rem', borderTop: '1px solid var(--border-light)', display: 'flex', justifyContent: 'flex-end', gap: '1rem', backgroundColor: 'var(--bg-card)' }}>
          <button onClick={onClose} className="modal-button secondary">
            CANCEL (ESC)
          </button>
          <button
            onClick={() => { if (selectedProduct) { onAddProduct(selectedProduct, quantity); onClose(); } }}
            disabled={!selectedProduct}
            className={`modal-button primary ${!selectedProduct ? 'disabled' : ''}`}
            style={{ minWidth: '180px' }}
          >
            ADD SELECTED (ENTER)
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductSearchModal;