import React, { useState, useEffect, useRef } from 'react';
import { get, post, put, del } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import ProductSearchModal from './ProductSearchModal';
import QuickProductModal from './QuickProductModal';
import ProductEditModal from './ProductEditModal';
import GlobalSearchBar from './common/GlobalSearchBar';
import DataActionsShortcutsBar from './common/DataActionsShortcutsBar';
import GlassCard from './common/GlassCard';
import '../styles/antigravity.css';
import useProductKeyboard from '../hooks/useProductKeyboard';
import { useSettings } from '../context/SettingsContext';
import { formatCurrency } from '../utils/currency';
import { useTranslation } from 'react-i18next';

/** Single product row in the product list table (meaningful name for the former product row reference). */
function ProductListCard({ product, index, isFocused, isSelected, canDelete, settings, t, onRowClick, onView, onEdit, onPrintBarcode, onDuplicate, onDelete }) {
  return (
    <tr
      tabIndex={index === 0 ? 0 : -1}
      data-row-index={index}
      onClick={() => onRowClick(product, index)}
      className="inventory-row"
      style={{
        borderBottom: '1px solid rgba(255,255,255,0.03)',
        backgroundColor: isSelected ? 'var(--primary-subtle)' : isFocused ? 'var(--glass-highlight)' : 'transparent',
        borderLeft: isFocused ? '4px solid var(--primary)' : '4px solid transparent',
        cursor: 'pointer',
        transition: 'background 0.2s',
        color: 'var(--text-main)'
      }}
    >
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit', position: 'sticky', left: 0, zIndex: 1, background: 'inherit', minWidth: 160, boxShadow: '2px 0 0 rgba(255,255,255,0.03)' }}>
        <span style={{ fontWeight: '600' }}>{product.name}</span>
      </td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>{product.barcode || '-'}</td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>{product.sku || '-'}</td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'right', color: 'inherit', fontWeight: '500' }}>{formatCurrency(Number(product.costPrice || 0), settings.currency || 'USD')}</td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'right', color: 'var(--primary)', fontWeight: '700' }}>{formatCurrency(Number(product.sellingPrice || 0), settings.currency || 'USD')}</td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'center', color: 'inherit' }}>
        {product.discountPercentage > 0 ? (
          <span style={{ color: 'var(--success)', fontWeight: '600' }}>{Number(product.discountPercentage)}%</span>
        ) : product.discountFixedPrice > 0 ? (
          <span style={{ color: 'var(--success)', fontWeight: '600' }}>-{settings.currency || '$'}{Number(product.discountFixedPrice)}</span>
        ) : '-'}
      </td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>
        {product.warehouse?.name ?? product.defaultWarehouse?.name ?? '-'}
      </td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'center', color: 'inherit' }}>
        <span style={{
          fontWeight: '700',
          color: (product.inventory?.quantity || 0) <= (product.minStockLevel || 0) ? 'var(--danger)' : 'var(--success)'
        }}>
          {product.inventory ? product.inventory.quantity : '0'}
        </span>
      </td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'center' }}>
        <span style={{
          padding: '4px 8px',
          borderRadius: 'var(--radius-sm)',
          backgroundColor: product.isActive ? 'var(--primary-subtle)' : 'var(--secondary-dark)',
          color: product.isActive ? 'var(--primary)' : 'var(--text-muted)',
          fontSize: '11px',
          fontWeight: '800',
          textTransform: 'uppercase'
        }}>
          {product.isActive ? t('products.active') : t('products.inactive')}
        </span>
      </td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'center' }}>
        <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', justifyContent: 'center' }}>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onView(product); }} title={t('common.view') + ' (V)'}>{t('common.view')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>V</kbd></button>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onEdit(product); }} title={t('common.edit') + ' (E)'}>{t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd></button>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onPrintBarcode(product); }} title={t('products.printBarcode') || 'Print Barcode'}>{t('common.print') || 'Print'}</button>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onDuplicate(product); }} title={t('products.copy') + ' (Alt+C)'} style={{ color: '#8b5cf6', borderColor: '#8b5cf6' }}>{t('products.copy') || 'Copy'} <kbd style={{ fontSize: 10, padding: '2px 5px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Alt+C</kbd></button>
          {canDelete && <button className="btn btn-sm btn-outline-danger" onClick={(e) => { e.stopPropagation(); onDelete(product.id); }} title={t('common.delete') + ' (Del)'}>{t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd></button>}
        </div>
      </td>
    </tr>
  );
}

/** Product detail view modal (meaningful name for the product view overlay). */
function ProductDetailModal({ product, onClose, onEdit, formatCurrency, settings, t }) {
  if (!product) return null;
  return (
    <div className="modal-overlay" onClick={onClose} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
      <div className="modal-container" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px', width: '90%', background: 'white', borderRadius: '12px', padding: '24px', boxShadow: '0 8px 32px rgba(0,0,0,0.2)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', borderBottom: '1px solid #eee', paddingBottom: '12px' }}>
          <h3 style={{ margin: 0 }}>{t('common.view')} - {product.name}</h3>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#666' }}>×</button>
        </div>
        <div style={{ display: 'grid', gap: '12px', fontSize: '14px' }}>
          <div><strong>{t('products.productName')}:</strong> {product.name}</div>
          <div><strong>{t('products.barcode')}:</strong> {product.barcode || '-'}</div>
          <div><strong>{t('products.sku')}:</strong> {product.sku || '-'}</div>
          <div><strong>{t('products.category')}:</strong> {product.category?.name || '-'}</div>
          <div><strong>{t('products.costPrice')}:</strong> {formatCurrency(Number(product.costPrice || 0), settings.currency || 'USD')}</div>
          <div><strong>{t('products.sellingPrice')}:</strong> {formatCurrency(Number(product.sellingPrice || 0), settings.currency || 'USD')}</div>
          <div><strong>{t('products.unit')}:</strong> {product.unit || product.baseUnit?.shortName || 'pcs'}</div>
          <div><strong>{t('products.stock')}:</strong> {product.inventory?.quantity ?? 0}</div>
          <div><strong>{t('products.status')}:</strong> {product.isActive ? t('products.active') : t('products.inactive')}</div>
        </div>
        <div style={{ marginTop: '20px', display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
          <button className="btn btn-primary" onClick={() => { onClose(); onEdit(product); }}>{t('common.edit')}</button>
          <button className="btn btn-secondary" onClick={onClose}>{t('common.close')}</button>
        </div>
      </div>
    </div>
  );
}

const ProductManagement = () => {
  const { settings: settingsFromContext } = useSettings();
  const settings = settingsFromContext ?? {};
  const { canDelete } = useAuth();
  const { t } = useTranslation();
  const [products, setProducts] = useState([]);
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('name');
  const [sortOrder, setSortOrder] = useState('asc');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(10);
  const [showSearchModal, setShowSearchModal] = useState(false);
  const [showQuickProductModal, setShowQuickProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [viewingProduct, setViewingProduct] = useState(null);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [focusedRow, setFocusedRow] = useState(-1);
  const [showInactive, setShowInactive] = useState(false);
  const [duplicateProduct, setDuplicateProduct] = useState(null);

  const tableBodyRef = useRef(null);
  const searchInputRef = useRef(null);

  // Load products on component mount
  useEffect(() => {
    loadProducts();
  }, [showInactive]);

  // Filter and sort products
  useEffect(() => {
    let filtered = [...products];

    // Apply search filter
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      filtered = filtered.filter(product =>
        product.name.toLowerCase().includes(term) ||
        (product.barcode && product.barcode.toLowerCase().includes(term)) ||
        (product.sku && product.sku.toLowerCase().includes(term))
      );
    }

    // Apply sorting
    filtered.sort((a, b) => {
      let aValue = a[sortBy];
      let bValue = b[sortBy];

      // Handle null/undefined values
      if (aValue == null) aValue = '';
      if (bValue == null) bValue = '';

      // Convert to string for comparison
      aValue = String(aValue);
      bValue = String(bValue);

      if (sortOrder === 'asc') {
        return aValue.localeCompare(bValue);
      } else {
        return bValue.localeCompare(aValue);
      }
    });

    setFilteredProducts(filtered);
    // Reset to first page when filtering changes, but ensure current page is valid
    if (filtered.length > 0) {
      const totalPages = Math.ceil(filtered.length / itemsPerPage);
      setCurrentPage(prevPage => Math.min(prevPage, totalPages > 0 ? totalPages : 1));
    } else {
      setCurrentPage(1);
    }
  }, [products, searchTerm, sortBy, sortOrder, showInactive]);

  // Pagination
  const totalPages = Math.ceil(filteredProducts.length / itemsPerPage);
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredProducts.slice(indexOfFirstItem, indexOfLastItem);

  const loadProducts = async () => {
    try {
      setLoading(true);
      // If showInactive is true, we want ALL products (don't filter by active)
      // If showInactive is false, we want ONLY active products (active=true)
      const url = showInactive ? '/products' : '/products?active=true';
      const result = await get(url);
      if (result.success) {
        setProducts(result.data);
      } else {
        setError('Failed to load products');
      }
    } catch (err) {
      setError('Network error occurred');
      console.error('Error loading products:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleSort = (column) => {
    if (sortBy === column) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(column);
      setSortOrder('asc');
    }
  };

  const handleSearchChange = (value) => {
    setSearchTerm(value);
  };

  const focusTableResults = () => {
    const firstRow = tableBodyRef.current?.querySelector('tr[tabindex="0"], tr[data-row-index]');
    if (firstRow) firstRow.focus?.();
    else tableBodyRef.current?.focus?.();
  };

  const handleRowClick = (product, index) => {
    setSelectedProduct(product);
    setFocusedRow(index);
  };

  const handleViewProduct = (product) => {
    setViewingProduct(product);
  };

  const handleEditProduct = (product) => {
    setEditingProduct(product);
  };

  const handleDeleteProduct = async (productId) => {
    if (window.confirm(t('products.confirmDelete'))) {
      try {
        const result = await del(`/products/${productId}`);

        if (result.success) {
          // Remove the deleted product from the current state instead of reloading all products
          const updatedProducts = products.filter(product => product.id !== productId);
          const updatedFilteredProducts = filteredProducts.filter(product => product.id !== productId);

          setProducts(updatedProducts);
          setFilteredProducts(updatedFilteredProducts);

          // Adjust current page if needed
          const totalPages = Math.ceil(updatedFilteredProducts.length / itemsPerPage);
          if (currentPage > totalPages && totalPages > 0) {
            setCurrentPage(totalPages);
          } else if (totalPages === 0) {
            setCurrentPage(1);
          }

          setSelectedProduct(null);
          setFocusedRow(-1);
        } else {
          alert(t('products.errors.deleteFailed'));
        }
      } catch (error) {
        console.error('Error deleting product:', error);
        alert(error?.message?.toLowerCase().includes('network') ? t('messages.networkError') : t('products.errors.deleteFailed'));
      }
    }
  };

  function handlePrintBarcode(product) {
    if (!product?.barcode) {
      alert(t('products.noBarcode') || 'This product does not have a barcode.');
      return;
    }
    const name = (product.name || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    const price = Number(product.sellingPrice || 0).toFixed(2);
    const barcode = product.barcode;
    const storeName = (settings.storeName || '').replace(/</g, '&lt;').replace(/>/g, '&gt;') || 'Store';
    const barcodeImgUrl = `https://barcode.tec-it.com/barcode.ashx?data=${encodeURIComponent(barcode)}&code=Code128&dpi=96`;
    const printHtml = `<!DOCTYPE html><html><head><title>Barcode - ${name}</title><style>@page{margin:0}body{margin:20px;font-family:Inter,sans-serif;text-align:center;-webkit-print-color-adjust:exact;print-color-adjust:exact}</style></head><body>
      <h2 style="margin:0 0 8px 0;font-size:18px;">${name}</h2>
      <p style="margin:0 0 16px 0;font-size:24px;font-weight:bold;">${price}</p>
      <img src="${barcodeImgUrl}" alt="Barcode" style="max-width:100%;height:auto;" onload="try{var w=window.parent;if(w.__barcodePrintReady){w.__barcodePrintReady();w.__barcodePrintReady=null;}}catch(e){}" onerror="try{var w=window.parent;if(w.__barcodePrintReady){w.__barcodePrintReady();w.__barcodePrintReady=null;}}catch(e){}" />
      <p style="margin:12px 0 0 0;font-family:monospace;font-size:14px;">${barcode}</p>
      <p style="margin:20px 0 0 0;font-size:11px;color:#333;">${storeName}</p>
      </body></html>`;

    let printed = false;
    const doPrint = () => {
      if (printed) return;
      printed = true;
      try {
        if (iframe.contentWindow) {
          iframe.contentWindow.focus();
          iframe.contentWindow.print();
        }
      } catch (e) {
        console.warn('Barcode print failed:', e);
      }
      window.__barcodePrintReady = null;
      setTimeout(() => {
        if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
      }, 500);
    };

    window.__barcodePrintReady = doPrint;

    const iframe = document.createElement('iframe');
    iframe.setAttribute('style', 'position:absolute;width:0;height:0;border:0;visibility:hidden;');
    document.body.appendChild(iframe);
    const doc = iframe.contentWindow.document;
    doc.open();
    doc.write(printHtml);
    doc.close();

    iframe.addEventListener('load', () => {
      const img = iframe.contentDocument?.querySelector('img');
      if (img && img.complete && img.naturalWidth > 0) {
        doPrint();
        return;
      }
      if (img) {
        img.addEventListener('load', () => doPrint(), { once: true });
        img.addEventListener('error', () => setTimeout(doPrint, 300), { once: true });
      }
    });
    setTimeout(() => { if (!printed) doPrint(); }, 6000);
  }

  const handleDuplicateProduct = (product) => {
    // Prepare product data for duplication (exclude id, createdAt, updatedAt)
    const productData = {
      name: `${product.name} (Copy)`,
      sellingPrice: product.sellingPrice,
      costPrice: product.costPrice,
      barcode: product.barcode,
      sku: product.sku,
      categoryId: product.categoryId,
      description: product.description,
      taxRate: product.taxRate,
      discountPercentage: product.discountPercentage,
      discountFixedPrice: product.discountFixedPrice,
      unit: product.unit,
      minStockLevel: product.minStockLevel,
      isActive: product.isActive,
      image: product.image
    };

    setDuplicateProduct(productData);
    setShowQuickProductModal(true);
  };

  const handleSaveProduct = async (productData) => {
    try {
      let result;
      if (editingProduct) {
        result = await put(`/products/${editingProduct.id}`, productData);

        if (result.success) {
          loadProducts();
          setEditingProduct(null);
        } else {
          alert(t('products.errors.updateFailed'));
        }
      } else {
        result = await post('/products', productData);

        if (result.success) {
          loadProducts();
          setEditingProduct(null);
        } else {
          const msg = (result.message || '').toLowerCase();
          const friendly = msg.includes('barcode') && (msg.includes('unique') || msg.includes('exists') || msg.includes('duplicate')) ? t('products.errors.barcodeExists') : t('products.errors.createFailed');
          alert(friendly);
        }
      }
      return result;
    } catch (error) {
      console.error('Error saving product:', error);
      const friendly = error?.message?.toLowerCase().includes('network') ? t('messages.networkError') : t('products.errors.saveFailed');
      alert(friendly);
      throw error;
    }
  };

  const handleQuickAdd = async (productData) => {
    try {
      // If productData already has an id, the modal created it itself.
      if (productData && productData.id) {
        await loadProducts();
        setShowQuickProductModal(false);
        setSelectedProduct(productData);
        return;
      }

      // Map the product data from the modal form to API expectations
      const productPayload = {
        name: productData.name,
        barcode: productData.barcode || null,
        sellingPrice: productData.sellingPrice,
        costPrice: productData.costPrice || null,
        discountPercentage: productData.discountPercentage || null,
        discountFixedPrice: productData.discountFixedPrice || null,
        isActive: true,
        image: productData.image || null
      };

      const result = await post('/products', productPayload);

      if (result.success) {
        await loadProducts();
        setShowQuickProductModal(false);
      } else {
        const msg = (result.message || '').toLowerCase();
        const friendly = msg.includes('barcode') && (msg.includes('unique') || msg.includes('exists') || msg.includes('duplicate')) ? t('products.errors.barcodeExists') : t('products.errors.createFailed');
        alert(friendly);
      }
    } catch (error) {
      console.error('Error adding product:', error);
      alert(error?.message?.toLowerCase().includes('network') ? t('messages.networkError') : t('products.errors.createFailed'));
    }
  };

  // Use the keyboard hook
  const { reEnableKeyboard } = useProductKeyboard({
    selectedProduct,
    focusedRow,
    filteredProducts,
    currentItems,
    handleDeleteProduct: canDelete ? handleDeleteProduct : () => {},
    handleViewProduct,
    handleEditProduct,
    handleDuplicateProduct,
    handlePrintBarcode,
    loadProducts,
    setShowSearchModal,
    setShowQuickProductModal,
    setFocusedRow,
    setSelectedProduct
  });

  // Restore focus to product management when modals close
  useEffect(() => {
    if (!editingProduct && !viewingProduct && !showSearchModal && !showQuickProductModal) {
      // Small delay to ensure DOM is updated
      const timer = setTimeout(() => {
        // Re-enable keyboard shortcuts
        console.log('Restoring keyboard focus for product management');
        reEnableKeyboard();
      }, 100);

      return () => clearTimeout(timer);
    }
  }, [editingProduct, viewingProduct, showSearchModal, showQuickProductModal, reEnableKeyboard]);

  return (
    <div className="product-management-root" data-screen="product-management" style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0, backgroundColor: 'var(--bg-main)', flex: 1, overflow: 'hidden' }}>
      <div style={{ flex: 1, padding: '20px', minHeight: 0, display: 'flex', flexDirection: 'column' }}>
        <div style={{ width: '100%', maxWidth: '1200px', margin: '0 auto', flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column' }}>
          {/* Screen header: title left, actions right; shortcuts moved here from footer */}
          <div style={{ marginBottom: '12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
            <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '700', color: 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '10px' }}>
              <svg style={{ width: '28px', height: '28px', color: 'var(--primary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8 4-8-4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
              </svg>
              {t('products.title')}
            </h2>
            <div className="product-management-shortcuts" style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem 1rem', alignItems: 'center', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>F2</kbd> {t('products.shortcutF2')}</span>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>F8</kbd> {t('products.shortcutF8')}</span>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>Ctrl+E</kbd> {t('products.shortcutCtrlE')}</span>
              <span><kbd style={{ padding: '2px 5px', background: 'var(--bg-main)', border: '1px solid var(--border-light)', borderRadius: '4px' }}>Del</kbd> {t('products.shortcutDel')}</span>
            </div>
            <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexWrap: 'wrap' }}>
              <GlobalSearchBar
                value={searchTerm}
                onChange={handleSearchChange}
                onClear={() => setSearchTerm('')}
                onArrowDown={focusTableResults}
                inputRef={searchInputRef}
                placeholder={t('search.placeholder')}
              />
              <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '14px', cursor: 'pointer', userSelect: 'none', color: 'var(--text-main)' }}>
                <input
                  type="checkbox"
                  checked={showInactive}
                  onChange={() => setShowInactive(!showInactive)}
                  style={{ width: '16px', height: '16px', cursor: 'pointer' }}
                />
                {t('products.showInactive')}
              </label>
              <button
                onClick={() => setShowSearchModal(true)}
                className="btn btn-outline-primary"
                style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 14px' }}
              >
                <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
                {t('common.search')} (F2)
              </button>
              <button
                onClick={loadProducts}
                className="btn btn-outline-primary"
                style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 14px' }}
                title={t('common.refresh') || 'Refresh'}
              >
                <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                </svg>
                {t('common.refresh') || 'Refresh'}
              </button>
              <button
                data-pos-action="add-new"
                onClick={() => setShowQuickProductModal(true)}
                className="btn btn-primary"
                style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 16px' }}
              >
                <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                </svg>
                {t('products.addProduct')} <kbd>F8</kbd>
              </button>
            </div>
          </div>

          <DataActionsShortcutsBar showDelete={canDelete} showCopy />
          {/* Products Table - Stock table style */}
          <GlassCard style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 0 }}>
            <div className="glass-panel" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1rem', borderBottom: '1px solid var(--glass-border)', borderRadius: '16px 16px 0 0', fontWeight: 'bold', color: 'var(--text-muted)' }}>
              <h3 style={{ margin: 0 }}>{t('products.productList')} ({filteredProducts.length})</h3>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                {selectedProduct && (
                  <>
                    <button
                      onClick={() => handleDuplicateProduct(selectedProduct)}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: '#8b5cf6',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '14px'
                      }}
                    >
                      {t('products.copy') || 'Copy'} <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 4, background: 'rgba(0,0,0,0.2)', fontWeight: 600 }}>Alt+C</kbd>
                    </button>
                    <button
                      onClick={() => handleEditProduct(selectedProduct)}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: '#f59e0b',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '14px'
                      }}
                    >
                      {t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 4, background: 'rgba(0,0,0,0.2)', fontWeight: 600 }}>Ctrl+E</kbd>
                    </button>
                    {canDelete && (
                    <button
                      onClick={() => handleDeleteProduct(selectedProduct.id)}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: '#ef4444',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '14px'
                      }}
                    >
                      {t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 5px', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 4, background: 'rgba(0,0,0,0.2)', fontWeight: 600 }}>Del</kbd>
                    </button>
                    )}
                  </>
                )}
              </div>
            </div>

            {loading ? (
              <div style={{ textAlign: 'center', padding: '40px' }}>
                <p>{t('common.loading')}</p>
              </div>
            ) : error ? (
              <div style={{ textAlign: 'center', padding: '40px', color: '#ef4444' }}>
                <p>{t('common.error')}: {error}</p>
                <button
                  onClick={loadProducts}
                  style={{
                    padding: '8px 16px',
                    backgroundColor: '#4f46e5',
                    color: 'white',
                    border: 'none',
                    borderRadius: '4px',
                    cursor: 'pointer',
                    marginTop: '12px'
                  }}
                >
                  Try Again
                </button>
              </div>
            ) : filteredProducts.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-muted)' }}>
                <p>{t('products.noProducts')}</p>
                <p style={{ fontSize: '14px' }}>Try adjusting your search criteria</p>
              </div>
            ) : (
              <div className="animate-fade-in product-list-container" style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0 }}>
                <div className="product-list-scroll" style={{ overflow: 'auto', overflowX: 'auto', overflowY: 'auto', flex: 1, minHeight: 0, maxHeight: 'calc(100vh - 280px)', isolation: 'isolate' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 900 }}>
                    <thead>
                      <tr className="glass-panel" style={{ borderBottom: '1px solid var(--glass-border)', position: 'sticky', top: 0, background: 'var(--glass-bg)', backdropFilter: 'blur(var(--blur-strength))', zIndex: 10, color: 'var(--text-muted)', boxShadow: '0 1px 0 var(--glass-border)' }}>
                        <th
                          onClick={() => handleSort('name')}
                          style={{
                            textAlign: 'left',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none',
                            position: 'sticky',
                            left: 0,
                            zIndex: 11,
                            background: 'var(--glass-bg)',
                            minWidth: 160,
                            boxShadow: '2px 0 0 var(--glass-border)'
                          }}
                        >
                          {t('products.productName')} {sortBy === 'name' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th
                          onClick={() => handleSort('barcode')}
                          style={{
                            textAlign: 'left',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none'
                          }}
                        >
                          {t('products.barcode')} {sortBy === 'barcode' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th
                          onClick={() => handleSort('sku')}
                          style={{
                            textAlign: 'left',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none'
                          }}
                        >
                          {t('products.sku')} {sortBy === 'sku' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th
                          onClick={() => handleSort('costPrice')}
                          style={{
                            textAlign: 'right',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none'
                          }}
                        >
                          {t('products.costPrice')} {sortBy === 'costPrice' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th
                          onClick={() => handleSort('sellingPrice')}
                          style={{
                            textAlign: 'right',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none'
                          }}
                        >
                          {t('products.sellingPrice')} {sortBy === 'sellingPrice' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th style={{ textAlign: 'center', padding: '12px', fontSize: '14px', fontWeight: '600' }}>{t('products.discount')}</th>
                        <th style={{ textAlign: 'left', padding: '12px', fontSize: '14px', fontWeight: '600' }}>{t('warehouse.warehouses') || t('warehouse.title') || 'Warehouse'}</th>
                        <th style={{ textAlign: 'center', padding: '12px', fontSize: '14px', fontWeight: '600' }}>{t('products.stock')}</th>
                        <th
                          onClick={() => handleSort('isActive')}
                          style={{
                            textAlign: 'center',
                            padding: '12px',
                            fontSize: '14px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            userSelect: 'none'
                          }}
                        >
                          {t('products.status')} {sortBy === 'isActive' && (sortOrder === 'asc' ? '↑' : '↓')}
                        </th>
                        <th style={{ textAlign: 'center', padding: '12px', fontSize: '14px', fontWeight: '600' }}>
                          {t('products.actions')}
                        </th>
                      </tr>
                    </thead>
                    <tbody ref={tableBodyRef}>
                      {currentItems.map((product, index) => (
                        <ProductListCard
                          key={`product-${product.id}-${index}`}
                          product={product}
                          index={index}
                          isFocused={focusedRow === index}
                          isSelected={selectedProduct?.id === product.id}
                          canDelete={canDelete}
                          settings={settings}
                          t={t}
                          onRowClick={handleRowClick}
                          onView={handleViewProduct}
                          onEdit={handleEditProduct}
                          onPrintBarcode={handlePrintBarcode}
                          onDuplicate={handleDuplicateProduct}
                          onDelete={handleDeleteProduct}
                        />
                      ))}
                    </tbody>
                  </table>
                </div>

                {/* Pagination - always show when there are products */}
                {filteredProducts.length > 0 && (
                  <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '1rem', marginTop: '2rem', padding: '1rem', borderTop: '1px solid var(--border-light)' }}>
                    <button
                      onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                      disabled={currentPage === 1}
                      className="modal-button secondary"
                      style={{ padding: '0.5rem 1.5rem', fontWeight: '800' }}
                    >
                      PREVIOUS
                    </button>

                    <div style={{ fontSize: '0.875rem', fontWeight: '800', color: 'var(--text-main)', padding: '0.625rem 1.25rem', borderRadius: 'var(--radius-md)', backgroundColor: 'var(--bg-main)', border: '1px solid var(--border-light)' }}>
                      PAGE {currentPage} <span style={{ color: 'var(--text-muted)', margin: '0 0.5rem' }}>/</span> {totalPages}
                    </div>

                    <button
                      onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                      disabled={currentPage === totalPages}
                      className="modal-button secondary"
                      style={{ padding: '0.5rem 1.5rem', fontWeight: '800' }}
                    >
                      NEXT
                    </button>
                  </div>
                )}
              </div>
            )}
          </GlassCard>
        </div>
      </div>

      {/* Modals */}
      <ProductSearchModal
        isOpen={showSearchModal}
        onClose={() => setShowSearchModal(false)}
        onAddProduct={(product) => {
          setSelectedProduct(product);
          setShowSearchModal(false);
        }}
      />

      <QuickProductModal
        isOpen={showQuickProductModal}
        onClose={() => {
          setShowQuickProductModal(false);
          setDuplicateProduct(null);
        }}
        onAddProduct={handleQuickAdd}
        quantity={1}
        initialData={duplicateProduct}
      />

      {viewingProduct && (
        <div className="modal-overlay" onClick={() => setViewingProduct(null)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div className="modal-container" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px', width: '90%', background: 'white', borderRadius: '12px', padding: '24px', boxShadow: '0 8px 32px rgba(0,0,0,0.2)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', borderBottom: '1px solid #eee', paddingBottom: '12px' }}>
              <h3 style={{ margin: 0 }}>{t('common.view')} - {viewingProduct.name}</h3>
              <button onClick={() => setViewingProduct(null)} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#666' }}>×</button>
            </div>
            <div style={{ display: 'grid', gap: '12px', fontSize: '14px' }}>
              <div><strong>{t('products.productName')}:</strong> {viewingProduct.name}</div>
              <div><strong>{t('products.barcode')}:</strong> {viewingProduct.barcode || '-'}</div>
              <div><strong>{t('products.sku')}:</strong> {viewingProduct.sku || '-'}</div>
              <div><strong>{t('products.category')}:</strong> {viewingProduct.category?.name || '-'}</div>
              <div><strong>{t('products.costPrice')}:</strong> {formatCurrency(Number(viewingProduct.costPrice || 0), settings.currency || 'USD')}</div>
              <div><strong>{t('products.sellingPrice')}:</strong> {formatCurrency(Number(viewingProduct.sellingPrice || 0), settings.currency || 'USD')}</div>
              <div><strong>{t('products.unit')}:</strong> {viewingProduct.unit || viewingProduct.baseUnit?.shortName || 'pcs'}</div>
              <div><strong>{t('products.stock')}:</strong> {viewingProduct.inventory?.quantity ?? 0}</div>
              <div><strong>{t('products.status')}:</strong> {viewingProduct.isActive ? t('products.active') : t('products.inactive')}</div>
            </div>
            <div style={{ marginTop: '20px', display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
              <button className="btn btn-primary" onClick={() => { setViewingProduct(null); handleEditProduct(viewingProduct); }}>{t('common.edit')}</button>
              <button className="btn btn-secondary" onClick={() => setViewingProduct(null)}>{t('common.close')}</button>
            </div>
          </div>
        </div>
      )}

      <ProductEditModal
        isOpen={!!editingProduct}
        product={editingProduct}
        onClose={() => setEditingProduct(null)}
        onSave={handleSaveProduct}
      />
    </div >
  );
};

export default ProductManagement;
