import React, { useState, useEffect } from 'react';
import ProductManagement from './ProductManagement';
import CategoryManagement from './CategoryManagement';
import UnitsManagement from './UnitsManagement';
import PaymentMethodManagement from './PaymentMethodManagement';
import DummyProductsScreen from './DummyProductsScreen';
import BulkAddProductsScreen from './BulkAddProductsScreen';
import { useTranslation } from 'react-i18next';

const TABS = [
  { id: 'products', labelKey: 'products.tabProducts', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
  { id: 'dummyProducts', labelKey: 'dummyProducts.tab', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4' },
  { id: 'bulkAdd', labelKey: 'bulkAdd.tab', icon: 'M12 6v6m0 0v6m0-6h6m-6 0H6' },
  { id: 'category', labelKey: 'categories.tabCategories', icon: 'M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10' },
  { id: 'units', labelKey: 'products.unit', icon: 'M3 6l3 1m0 0l-3 9a5.002 5.002 0 006.001 0M6 7l3 9M6 7l6-2m6 2l3-1m-3 1l-3 9a5.002 5.002 0 006.001 0M18 7l3 9m-3-9l-6-2m0-2v2m0 16V5m0 16H9m3 0h3' },
  { id: 'paymentMethods', labelKey: 'sales.paymentMethod', icon: 'M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z' }
];

const ProductCategoryScreen = () => {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('products');

    useEffect(() => {
        const handleShortcuts = (e) => {
            if (e.altKey) {
                const k = e.key.toLowerCase();
                if (['1','2','3','4','5','6'].includes(k)) {
                    const idx = parseInt(k, 10) - 1;
                    if (TABS[idx]) {
                        e.preventDefault();
                        setActiveTab(TABS[idx].id);
                    }
                }
            }
        };
        window.addEventListener('keydown', handleShortcuts);
        return () => window.removeEventListener('keydown', handleShortcuts);
    }, []);

    return (
        <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
            {/* Sidebar Tabs - Stock Management style */}
            <div style={{ width: '280px', backgroundColor: 'var(--bg-card)', borderRight: '1px solid var(--border-light)', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: '800', marginBottom: '1.5rem', color: 'var(--text-main)', paddingLeft: '0.5rem' }}>{t('navigation.productManagement')}</h2>
                {TABS.map((tab, idx) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.75rem',
                            padding: '0.875rem 1rem',
                            borderRadius: 'var(--radius-md)',
                            border: 'none',
                            backgroundColor: activeTab === tab.id ? 'var(--primary-subtle)' : 'transparent',
                            color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
                            cursor: 'pointer',
                            fontWeight: '600',
                            textAlign: 'left',
                            transition: 'all var(--transition-fast)'
                        }}
                    >
                        <svg style={{ width: '20px', height: '20px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={tab.icon} /></svg>
                        {t(tab.labelKey)}
                        <kbd style={{ marginLeft: 'auto', padding: '2px 4px', backgroundColor: 'var(--border-light)', borderRadius: '4px', fontSize: '0.7rem', opacity: 0.8 }}>Alt+{idx + 1}</kbd>
                    </button>
                ))}

                <div style={{ marginTop: 'auto', padding: '1rem', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-lg)', border: '1px dashed var(--border-light)' }}>
                    <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', margin: 0 }}>
                        {t('products.title')} • Alt+1–6
                    </p>
                </div>
            </div>

            {/* Main Panel - no page scroll; only table area scrolls inside each tab */}
            <div style={{ flex: 1, minHeight: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                <div style={{ flexShrink: 0, padding: '1rem 2.5rem', backgroundColor: 'var(--bg-card)', borderBottom: '1px solid var(--border-light)', display: 'flex', gap: '0.5rem', alignItems: 'center', fontSize: '0.875rem', color: 'var(--text-muted)' }}>
                    <span>{t('navigation.productManagement')}</span>
                    <span>/</span>
                    <span style={{ color: 'var(--primary)', fontWeight: '600' }}>{t(TABS.find(t => t.id === activeTab)?.labelKey || 'products.title')}</span>
                </div>

                <div style={{ flex: 1, minHeight: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                    {activeTab === 'products' && <ProductManagement />}
                    {activeTab === 'dummyProducts' && <DummyProductsScreen />}
                    {activeTab === 'bulkAdd' && <BulkAddProductsScreen />}
                    {activeTab === 'category' && <CategoryManagement />}
                    {activeTab === 'units' && <UnitsManagement />}
                    {activeTab === 'paymentMethods' && <PaymentMethodManagement />}
                </div>
            </div>
        </div>
    );
};

export default ProductCategoryScreen;
