import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { get, post, put, del } from '../utils/api';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../context/AuthContext';
import GlobalSearchBar from './common/GlobalSearchBar';
import DataActionsShortcutsBar from './common/DataActionsShortcutsBar';

const CategoryManagement = () => {
    const { t } = useTranslation();
    const { canDelete } = useAuth();
    const [categories, setCategories] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingCategory, setEditingCategory] = useState(null);
    const [formData, setFormData] = useState({ name: '', description: '', parentId: '' });
    const [formErrors, setFormErrors] = useState({});
    const [saving, setSaving] = useState(false);
    const [selectedIndex, setSelectedIndex] = useState(-1);
    const nameInputRef = useRef(null);
    const searchInputRef = useRef(null);
    const tableContainerRef = useRef(null);

    useEffect(() => {
        loadCategories();
    }, []);

    const loadCategories = async () => {
        try {
            setLoading(true);
            const result = await get('/categories');
            if (result.success) {
                setCategories(result.data);
            } else {
                setError('Failed to load categories');
            }
        } catch (err) {
            setError('Network error occurred');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    // Build category tree and flattened list with indentation
    const categoryTree = useMemo(() => {
        const byId = new Map(categories.map(c => [c.id, { ...c, children: [] }]));
        const roots = [];
        byId.forEach((node) => {
            if (node.parentId && byId.has(node.parentId)) {
                byId.get(node.parentId).children.push(node);
            } else {
                roots.push(node);
            }
        });
        // sort children by name
        const sortTree = (nodes) => {
            nodes.sort((a, b) => a.name.localeCompare(b.name));
            nodes.forEach(n => sortTree(n.children));
        };
        sortTree(roots);
        return roots;
    }, [categories]);

    const flattenedCategories = useMemo(() => {
        const result = [];
        const traverse = (nodes, depth = 0, prefix = []) => {
            nodes.forEach(node => {
                const labelPath = [...prefix, node.name].join(' > ');
                result.push({ ...node, depth, labelPath });
                if (node.children && node.children.length) {
                    traverse(node.children, depth + 1, [...prefix, node.name]);
                }
            });
        };
        traverse(categoryTree);
        return result;
    }, [categoryTree]);

    // Search: Category Name, Parent Category (via labelPath)
    const filteredCategories = useMemo(() => {
        const term = searchTerm.trim().toLowerCase();
        if (!term) return flattenedCategories;
        return flattenedCategories.filter(c =>
            c.name.toLowerCase().includes(term) ||
            (c.description && c.description.toLowerCase().includes(term)) ||
            (c.labelPath && c.labelPath.toLowerCase().includes(term))
        );
    }, [flattenedCategories, searchTerm]);

    const focusTableResults = useCallback(() => {
        const firstRow = tableContainerRef.current?.querySelector('tbody tr');
        if (firstRow) firstRow.setAttribute?.('tabindex', '0') && firstRow.focus?.();
    }, []);

    const selectedCategory = selectedIndex >= 0 && selectedIndex < filteredCategories.length ? filteredCategories[selectedIndex] : null;

    const handleOpenModal = (category = null) => {
        if (category) {
            setEditingCategory(category);
            setFormData({
                name: category.name,
                description: category.description || '',
                parentId: category.parentId ?? ''
            });
        } else {
            setEditingCategory(null);
            setFormData({ name: '', description: '', parentId: '' });
        }
        setFormErrors({});
        setShowModal(true);
    };

    const handleSave = async (e) => {
        if (e && typeof e.preventDefault === 'function') e.preventDefault();
        if (saving) return;
        const errors = {};
        if (!formData.name || !formData.name.trim()) {
            errors.name = t('messages.requiredField');
        }
        if (editingCategory && formData.parentId && parseInt(formData.parentId) === editingCategory.id) {
            errors.parentId = t('categories.parentCategory') + ' - invalid selection';
        }
        const parentIdVal = formData.parentId !== '' && !isNaN(parseInt(formData.parentId)) ? parseInt(formData.parentId) : null;
        const duplicate = categories.find(c =>
            (c.name || '').trim().toLowerCase() === (formData.name || '').trim().toLowerCase() &&
            (c.parentId == null ? null : c.parentId) === parentIdVal &&
            (!editingCategory || c.id !== editingCategory.id)
        );
        if (duplicate) {
            errors.name = t('categories.duplicateCategory') || 'A category with this name already exists under the same parent.';
        }
        setFormErrors(errors);
        if (Object.keys(errors).length > 0) return;

        setSaving(true);
        // Prepare payload
        const payload = {
            name: formData.name.trim(),
            description: formData.description ? formData.description.trim() : ''
        };
        if (formData.parentId !== '' && !isNaN(parseInt(formData.parentId))) {
            payload.parentId = parseInt(formData.parentId);
        } else {
            payload.parentId = null;
        }
        try {
            if (editingCategory) {
                const result = await put(`/categories/${editingCategory.id}`, payload);
                if (result.success) loadCategories();
                else alert(result.message || (result.errors && result.errors[0]?.msg) || t('messages.saveError'));
            } else {
                const result = await post('/categories', payload);
                if (result.success) loadCategories();
                else alert(result.message || (result.errors && result.errors[0]?.msg) || t('messages.saveError'));
            }
            setShowModal(false);
        } catch (err) {
            alert(t('messages.saveError'));
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm(t('categories.confirmDelete'))) {
            try {
                const result = await del(`/categories/${id}`);
                if (result.success) loadCategories();
                else alert(result.message || t('messages.deleteError'));
            } catch (err) {
                alert(t('messages.deleteError'));
            }
        }
    };

    // Keyboard shortcuts for Categories
    const handleKeyDown = useCallback((e) => {
        const isInputElement = e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable;
        const isModalOpen = showModal;

        // Modal-specific shortcuts
        if (isModalOpen) {
            // F10, Ctrl+S or Enter to Save
            if (e.key === 'F10' || (e.ctrlKey && e.key.toLowerCase() === 's') || (e.key === 'Enter' && e.target.tagName !== 'TEXTAREA')) {
                e.preventDefault();
                handleSave();
                return;
            }
            // Escape to Cancel
            if (e.key === 'Escape') {
                e.preventDefault();
                setShowModal(false);
                return;
            }
            return;
        }

        // Screen-level shortcuts (ignore if typing)
        if (isInputElement) return;

        // Ctrl+N: New category
        if (e.ctrlKey && e.key.toLowerCase() === 'n') {
            e.preventDefault();
            handleOpenModal(null);
            return;
        }
        // Ctrl+E, Enter, V or E: View/Edit selected
        if ((e.ctrlKey && e.key.toLowerCase() === 'e') || e.key === 'Enter' || (e.key.toLowerCase() === 'v') || (e.key.toLowerCase() === 'e')) {
            if (selectedCategory) {
                e.preventDefault();
                handleOpenModal(selectedCategory);
            }
            return;
        }
        // Delete: Delete selected (requires canDelete)
        if (e.key === 'Delete' && canDelete) {
            if (selectedCategory) {
                e.preventDefault();
                handleDelete(selectedCategory.id);
            }
            return;
        }
        // Arrow navigation
        if (e.key === 'ArrowDown' && filteredCategories.length > 0) {
            e.preventDefault();
            setSelectedIndex(prev => Math.min((prev < 0 ? 0 : prev + 1), filteredCategories.length - 1));
            return;
        }
        if (e.key === 'ArrowUp' && filteredCategories.length > 0) {
            e.preventDefault();
            setSelectedIndex(prev => Math.max((prev < 0 ? 0 : prev - 1), 0));
            return;
        }
    }, [showModal, filteredCategories, selectedCategory, formData, canDelete]);

    useEffect(() => {
        window.addEventListener('keydown', handleKeyDown, { capture: true });
        return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
    }, [handleKeyDown]);

    // Reset selection when list changes
    useEffect(() => {
        if (filteredCategories.length === 0) setSelectedIndex(-1);
        else if (selectedIndex >= filteredCategories.length) setSelectedIndex(filteredCategories.length - 1);
    }, [filteredCategories, selectedIndex]);

    // Auto-focus first input when modal opens
    useEffect(() => {
        if (showModal) nameInputRef.current?.focus();
    }, [showModal]);

    return (
        <div style={{ display: 'flex', flexDirection: 'column', minHeight: 'calc(100vh - 80px)', backgroundColor: 'var(--bg-main)' }}>
            <div style={{ flex: 1, padding: '20px', overflow: 'auto' }}>
                <div style={{ marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '10px' }}>
                    <h2 style={{ margin: 0 }}>{t('categories.title')}</h2>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexWrap: 'wrap' }}>
                        <GlobalSearchBar
                            value={searchTerm}
                            onChange={setSearchTerm}
                            onClear={() => setSearchTerm('')}
                            onArrowDown={focusTableResults}
                            inputRef={searchInputRef}
                            placeholder={t('search.placeholder')}
                        />
                        <button
                            data-pos-action="add-new"
                            className="btn btn-primary"
                            onClick={() => handleOpenModal()}
                        >
                            + {t('categories.newCategory')} <kbd>F8</kbd>
                        </button>
                    </div>
                </div>

                <DataActionsShortcutsBar showDelete={canDelete} />
                <div className="table-container" ref={tableContainerRef}>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>{t('categories.categoryName')}</th>
                                <th>{t('categories.description')}</th>
                                <th>{t('common.actions')}</th>
                            </tr>
                        </thead>
                        <tbody>
                            {loading ? (
                                <tr><td colSpan="3" style={{ textAlign: 'center', padding: '40px', color: '#666' }}>{t('common.loading')}</td></tr>
                            ) : filteredCategories.length === 0 ? (
                                <tr><td colSpan="3" style={{ textAlign: 'center', padding: '40px', color: '#666' }}>{t('messages.noData')}</td></tr>
                            ) : (
                                filteredCategories.map(cat => {
                                    const indent = { paddingLeft: `${(cat.depth || 0) * 24}px` };
                                    const index = filteredCategories.findIndex(c => c.id === cat.id);
                                    const isSelected = index === selectedIndex;
                                    return (
                                        <tr
                                            key={cat.id}
                                            tabIndex={index === 0 ? 0 : -1}
                                            data-row-index={index}
                                            onClick={() => setSelectedIndex(index)}
                                            onDoubleClick={() => handleOpenModal(cat)}
                                            style={{
                                                backgroundColor: isSelected ? 'rgba(59,130,246,0.1)' : 'transparent',
                                                cursor: 'pointer'
                                            }}
                                        >
                                            <td><span style={indent}>{cat.name}</span></td>
                                            <td style={{ color: '#666' }}>{cat.description || t('categories.noDescription')}</td>
                                            <td>
                                                <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', alignItems: 'center' }}>
                                                    <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); handleOpenModal(cat); }} title="Enter/V/E">{t('common.view')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>V</kbd></button>
                                                    <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); handleOpenModal(cat); }} title="E">{t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd></button>
                                                    {canDelete && <button className="btn btn-sm btn-outline-danger" onClick={(e) => { e.stopPropagation(); handleDelete(cat.id); }} title="Del">{t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd></button>}
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-container" style={{ width: '450px', maxWidth: '450px' }} onClick={(e) => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2 style={{ margin: 0 }}>{editingCategory ? t('categories.editCategory') : t('categories.newCategory')}</h2>
                            <button type="button" className="modal-close" onClick={() => setShowModal(false)} aria-label="Close">
                                ×
                            </button>
                        </div>
                        <form onSubmit={handleSave}>
                            <div className="modal-body" style={{ padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                                <div className="form-group">
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '800', fontSize: '0.75rem', color: 'var(--text-muted)' }}>{t('categories.categoryName').toUpperCase()} *</label>
                                        <input
                                        ref={nameInputRef}
                                        type="text"
                                        value={formData.name}
                                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        className="form-input"
                                        placeholder="e.g. Beverages"
                                    />
                                    {formErrors.name && <p style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{formErrors.name}</p>}
                                </div>
                                <div className="form-group">
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '800', fontSize: '0.75rem', color: 'var(--text-muted)' }}>{t('categories.parentCategory')}</label>
                                    <select
                                        value={formData.parentId}
                                        onChange={(e) => setFormData({ ...formData, parentId: e.target.value })}
                                        className="form-input"
                                    >
                                        <option value="">{t('categories.selectParent')}</option>
                                        {flattenedCategories
                                            .filter(c => !editingCategory || c.id !== editingCategory.id)
                                            .map(c => (
                                                <option key={c.id} value={c.id}>
                                                    {c.labelPath}
                                                </option>
                                            ))}
                                    </select>
                                    {formErrors.parentId && <p style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{formErrors.parentId}</p>}
                                </div>
                                <div className="form-group">
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '800', fontSize: '0.75rem', color: 'var(--text-muted)' }}>{t('categories.description').toUpperCase()}</label>
                                    <textarea
                                        value={formData.description}
                                        onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                        className="form-input"
                                        style={{ minHeight: '120px', resize: 'vertical' }}
                                        placeholder="Optional category description..."
                                    />
                                </div>
                            </div>
                            <div className="modal-footer" style={{ padding: '1.5rem 2rem', borderTop: '1px solid var(--border-light)', display: 'flex', justifyContent: 'flex-end', gap: '1rem', backgroundColor: 'var(--bg-card)' }}>
                                <button type="button" data-pos-action="cancel" onClick={() => setShowModal(false)} className="modal-button secondary">{t('categories.cancel').toUpperCase()} <kbd>Esc</kbd></button>
                                <button type="submit" data-pos-action="save" className="modal-button primary" style={{ fontWeight: '800' }} disabled={saving}>{saving ? t('common.loading') : t('categories.saveCategory').toUpperCase()} <kbd>F10</kbd></button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CategoryManagement;
