import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { get } from '../utils/api';
import GlassCard from './common/GlassCard';
import { formatCurrency } from '../utils/currency';
import TransactionDashboard from './TransactionDashboard';
import { useTranslation } from 'react-i18next';

const ABCDashboard = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState('overview');
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [grnData, setGrnData] = useState([]);

  const [grnLoading, setGrnLoading] = useState(false);

  // Fetch dashboard data
  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const response = await get('/dashboard?mode=FULL');
        if (response.success) {
          setDashboardData(response.data);
        } else {
          setError('Failed to load dashboard data');
        }
      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Error loading dashboard data');
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  // Transaction fetching logic removed - handled by TransactionDashboard component

  // Fetch GRN data when GRN tab is active
  useEffect(() => {
    if (activeTab === 'grn') {
      const fetchGrnData = async () => {
        try {
          setGrnLoading(true);
          const response = await get('/grns');
          if (response.success) {
            setGrnData(response.data);
          }
        } catch (err) {
          console.error('Error fetching GRN data:', err);
        } finally {
          setGrnLoading(false);
        }
      };
      fetchGrnData();
    }
  }, [activeTab]);

  const tabs = [
    { id: 'overview', labelKey: 'dashboard.overview', icon: 'M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z' },
    { id: 'sales', labelKey: 'dashboard.salesAnalytics', icon: 'M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z' },
    { id: 'inventory', labelKey: 'dashboard.inventory', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
    { id: 'transactions', labelKey: 'dashboard.transactions', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01' },
    { id: 'grn', labelKey: 'dashboard.grnReports', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
    { id: 'performance', labelKey: 'dashboard.performance', icon: 'M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z' },
  ];

  // Alt+1–9 shortcuts for tabs (like Stock screen)
  useEffect(() => {
    const handleShortcuts = (e) => {
      if (e.altKey) {
        const k = e.key.toLowerCase();
        if (['1','2','3','4','5','6','7','8','9'].includes(k)) {
          const idx = parseInt(k) - 1;
          if (tabs[idx]) {
            e.preventDefault();
            setActiveTab(tabs[idx].id);
          }
        }
      }
    };
    window.addEventListener('keydown', handleShortcuts);
    return () => window.removeEventListener('keydown', handleShortcuts);
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ width: '48px', height: '48px', border: '4px solid var(--border-light)', borderTop: '4px solid var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }}></div>
            <p style={{ color: 'var(--text-muted)', fontSize: '1.1rem' }}>Loading ABC Dashboard...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ textAlign: 'center', padding: '2rem', backgroundColor: 'var(--bg-card)', borderRadius: 'var(--radius-lg)', border: '1px solid var(--border-light)', maxWidth: '500px' }}>
            <div style={{ width: '64px', height: '64px', backgroundColor: 'var(--danger-subtle)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1.5rem' }}>
              <svg style={{ width: '32px', height: '32px', color: 'var(--danger)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <h3 style={{ color: 'var(--text-main)', margin: '0 0 1rem 0' }}>Error Loading Data</h3>
            <p style={{ color: 'var(--text-muted)', margin: '0 0 1.5rem 0' }}>{error}</p>
            <button
              onClick={() => window.location.reload()}
              style={{ padding: '0.75rem 1.5rem', backgroundColor: 'var(--primary)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontWeight: '600' }}
            >
              Retry
            </button>
          </div>
        </div>
      </div>
    );
  }

  const data = dashboardData || {};
  const summary = data.summary || {};
  const topProducts = data.topProducts || [];

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
      {/* Sidebar Tabs */}
      <div style={{ width: '280px', backgroundColor: 'var(--bg-card)', borderRight: '1px solid var(--border-light)', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        <h2 style={{ fontSize: '1.25rem', fontWeight: '800', marginBottom: '1.5rem', color: 'var(--text-main)', paddingLeft: '0.5rem' }}>{t('navigation.dashboard')}</h2>
        {tabs.map((tab, idx) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              padding: '0.875rem 1rem',
              borderRadius: 'var(--radius-md)',
              border: 'none',
              backgroundColor: activeTab === tab.id ? 'var(--primary-subtle)' : 'transparent',
              color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
              cursor: 'pointer',
              fontWeight: '600',
              textAlign: 'left',
              transition: 'all var(--transition-fast)'
            }}
          >
            <svg style={{ width: '20px', height: '20px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={tab.icon} /></svg>
            {t(tab.labelKey)}
            <kbd style={{ marginLeft: 'auto', padding: '2px 4px', backgroundColor: 'var(--border-light)', borderRadius: '4px', fontSize: '0.7rem', opacity: 0.8 }}>Alt+{idx + 1}</kbd>
          </button>
        ))}

        <div style={{ marginTop: 'auto', padding: '1rem', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-lg)', border: '1px dashed var(--border-light)' }}>
          <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', margin: '0 0 0.25rem 0' }}>{t('dashboard.shortcutsHint')} Alt+1–{tabs.length} {t('common.page')}</p>
          <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', margin: 0 }}>{t('dashboard.refreshNote')}</p>
        </div>
      </div>

      {/* Main Panel */}
      <div style={{ flex: 1, padding: '2.5rem', overflowY: 'auto' }}>
        <div style={{ maxWidth: '1200px' }}>

          {activeTab === 'overview' && (
            <div className="animate-fade-in">
              <div style={{ marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '2.5rem', fontWeight: '800', margin: '0 0 0.5rem 0', background: 'linear-gradient(135deg, var(--primary) 0%, var(--accent-secondary) 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                  Dashboard Overview
                </h1>
                <p style={{ color: 'var(--text-muted)', margin: 0, fontSize: '1.1rem' }}>Comprehensive business analytics at a glance</p>
              </div>

              {/* KPI Cards */}
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>Total Revenue</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: 'var(--success)' }}>
                        {formatCurrency(summary.todaySales || 0)}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        Today's sales
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: 'var(--success-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: 'var(--success)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    </div>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>Products in Stock</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: 'var(--primary)' }}>
                        {summary.totalProducts || 0}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: summary.lowStockItems > 0 ? 'var(--warning)' : 'var(--text-muted)', fontSize: '0.85rem' }}>
                        {summary.lowStockItems > 0 ? `${summary.lowStockItems} low stock items` : 'All items well stocked'}
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: 'var(--primary-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: 'var(--primary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                    </div>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>Active Suppliers</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: 'var(--accent-secondary)' }}>
                        {summary.totalUsers || 0}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        Active users
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: 'var(--accent-secondary-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: 'var(--accent-secondary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                    </div>
                  </div>
                </GlassCard>
              </div>

              {/* Charts Section */}
              <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <h3 style={{ margin: '0 0 1.5rem 0', fontSize: '1.25rem', fontWeight: '700' }}>Weekly Sales Trend</h3>
                  <div style={{ height: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-md)', border: '1px dashed var(--border-light)' }}>
                    <p style={{ color: 'var(--text-muted)', textAlign: 'center' }}>
                      Sales trend chart would be rendered here<br />
                      <span style={{ fontSize: '0.9rem' }}>Using Chart.js or similar library</span>
                    </p>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h3 style={{ margin: '0 0 1.5rem 0', fontSize: '1.25rem', fontWeight: '700' }}>Top Categories</h3>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    {topProducts.slice(0, 5).map((product, index) => (
                      <div key={index} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                          <div style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: `hsl(${index * 60}, 70%, 60%)` }}></div>
                          <span style={{ fontSize: '0.9rem', fontWeight: '500' }}>{product.name}</span>
                        </div>
                        <span style={{ fontSize: '0.9rem', fontWeight: '600', color: 'var(--text-main)' }}>
                          {formatCurrency(product.revenue)}
                        </span>
                      </div>
                    ))}
                  </div>
                </GlassCard>
              </div>
            </div>
          )}

          {activeTab === 'sales' && (
            <div className="animate-fade-in">
              <h3 style={{ fontSize: '1.5rem', marginBottom: '2rem' }}>Sales Analytics</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Daily Sales</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--primary)', margin: '0 0 0.5rem 0' }}>
                    {formatCurrency(summary.todaySales || 0)}
                  </p>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', margin: 0 }}>
                    Today's sales
                  </p>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Weekly Average</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--success)', margin: '0 0 0.5rem 0' }}>
                    {formatCurrency((summary.todaySales || 0) * 7)}
                  </p>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', margin: 0 }}>
                    7-day estimate
                  </p>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Monthly Total</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--accent-secondary)', margin: '0 0 0.5rem 0' }}>
                    {formatCurrency((summary.todaySales || 0) * 30)}
                  </p>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', margin: 0 }}>
                    30-day estimate
                  </p>
                </GlassCard>
              </div>
            </div>
          )}

          {activeTab === 'inventory' && (
            <div className="animate-fade-in">
              <h3 style={{ fontSize: '1.5rem', marginBottom: '2rem' }}>Inventory Overview</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Total Items</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--primary)', margin: '0 0 0.5rem 0' }}>
                    {summary.totalProducts || 0}
                  </p>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Low Stock</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: summary.lowStockItems > 0 ? 'var(--warning)' : 'var(--success)', margin: '0 0 0.5rem 0' }}>
                    {summary.lowStockItems || 0}
                  </p>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Out of Stock</h4>
                  <p style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--danger)', margin: '0 0 0.5rem 0' }}>
                    0
                  </p>
                </GlassCard>
              </div>
            </div>
          )}

          {activeTab === 'transactions' && (
            <div className="animate-fade-in">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
                <h3 style={{ fontSize: '1.5rem', margin: 0 }}>{t('dashboard.transactions')}</h3>
                <Link
                  to="/transaction-report"
                  style={{
                    padding: '0.5rem 1rem',
                    backgroundColor: 'var(--primary)',
                    color: 'white',
                    border: 'none',
                    borderRadius: 'var(--radius-md)',
                    cursor: 'pointer',
                    fontSize: '0.9rem',
                    textDecoration: 'none',
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: '0.5rem',
                    fontWeight: '600'
                  }}
                >
                  <svg style={{ width: 16, height: 16 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
                  {t('transactionReport.title')}
                </Link>
              </div>
              <TransactionDashboard />
            </div>
          )}

          {activeTab === 'grn' && (
            <div className="animate-fade-in">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h3 style={{ fontSize: '1.5rem', margin: 0 }}>GRN Reports</h3>
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                  <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                    {grnData.length} GRNs
                  </span>
                  <button
                    onClick={() => {
                      const fetchGrnData = async () => {
                        setGrnLoading(true);
                        const response = await get('/grns');
                        if (response.success) setGrnData(response.data);
                        setGrnLoading(false);
                      };
                      fetchGrnData();
                    }}
                    style={{ padding: '0.5rem 1rem', backgroundColor: 'var(--bg-card)', color: 'var(--text-main)', border: '1px solid var(--border-light)', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontSize: '0.9rem' }}
                  >
                    Refresh
                  </button>
                  <Link
                    to="/grn-management"
                    style={{
                      padding: '0.5rem 1rem',
                      backgroundColor: 'var(--primary)',
                      color: 'white',
                      border: 'none',
                      borderRadius: 'var(--radius-md)',
                      cursor: 'pointer',
                      fontSize: '0.9rem',
                      textDecoration: 'none',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '0.5rem'
                    }}
                  >
                    <svg style={{ width: '16px', height: '16px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                    Open GRN Manager
                  </Link>
                </div>
              </div>

              {grnLoading ? (
                <div style={{ textAlign: 'center', padding: '3rem' }}>
                  <div style={{ width: '48px', height: '48px', border: '4px solid var(--border-light)', borderTop: '4px solid var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }}></div>
                  <p>Loading GRN data...</p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '1.5rem' }}>
                  {grnData.slice(0, 12).map((grn, index) => (
                    <GlassCard key={grn.id} style={{ padding: '1.25rem' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                        <div>
                          <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '1.1rem', fontWeight: '700' }}>{grn.grnNumber || `GRN-000${index + 1}`}</h4>
                          <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            {new Date(grn.receivedDate).toLocaleDateString()} • {grn.supplier?.name || 'Unknown Supplier'}
                          </p>
                        </div>
                        <span style={{
                          padding: '0.25rem 0.75rem',
                          borderRadius: 'var(--radius-full)',
                          fontSize: '0.8rem',
                          fontWeight: '600',
                          backgroundColor: grn.status === 'completed' ? 'var(--success-subtle)' : 'var(--warning-subtle)',
                          color: grn.status === 'completed' ? 'var(--success)' : 'var(--warning)'
                        }}>
                          {grn.status?.toUpperCase() || 'PENDING'}
                        </span>
                      </div>

                      <div style={{ marginBottom: '1rem' }}>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>Items: {grn.items?.length || 0}</p>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>Total Qty: {grn.totalQuantity || 0}</p>
                      </div>

                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <span style={{ fontSize: '1.25rem', fontWeight: '800', color: 'var(--primary)' }}>
                          {formatCurrency(grn.totalCost || 0)}
                        </span>
                        <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                          {grn.invoiceNumber || 'No Invoice'}
                        </span>
                      </div>
                    </GlassCard>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'performance' && (
            <div className="animate-fade-in">
              <h3 style={{ fontSize: '1.5rem', marginBottom: '2rem' }}>Performance Metrics</h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>System Health</h4>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <div style={{ width: '12px', height: '12px', backgroundColor: 'var(--success)', borderRadius: '50%' }}></div>
                    <span style={{ fontWeight: '600' }}>All Systems Operational</span>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '1.1rem', fontWeight: '700' }}>Data Sync</h4>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <div style={{ width: '12px', height: '12px', backgroundColor: 'var(--success)', borderRadius: '50%' }}></div>
                    <span style={{ fontWeight: '600' }}>Real-time Sync Active</span>
                  </div>
                </GlassCard>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default ABCDashboard;