import React, { useState, useEffect } from 'react';
import { get, post, put, del } from '../utils/api';

import { useAuth } from '../context/AuthContext';

const SUB_TABS = [{ id: 'users', label: 'Users' }, { id: 'privileges', label: 'User Privileges' }];

const UserManagement = () => {
  const { currentUser, canDelete } = useAuth();
  const [users, setUsers] = useState([]);
  const [showUserForm, setShowUserForm] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeSubTab, setActiveSubTab] = useState('users');

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    try {
      setLoading(true);
      const response = await get('/users');
      if (response.success) {
        setUsers(response.data);
      } else {
        setError(response.message || 'Failed to load users');
      }
    } catch (err) {
      setError('Network error occurred while loading users');
      console.error('Error loading users:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateUser = () => {
    setEditingUser(null);
    setShowUserForm(true);
  };

  const handleEditUser = (user) => {
    setEditingUser(user);
    setShowUserForm(true);
  };

  const handleDeleteUser = async (userId) => {
    if (window.confirm('Are you sure you want to delete this user? This action cannot be undone.')) {
      try {
        const response = await del(`/users/${userId}`);
        if (response.success) {
          loadUsers();
          alert('User deleted successfully');
        } else {
          alert(response.message || 'Failed to delete user');
        }
      } catch (error) {
        console.error('Error deleting user:', error);
        alert('Error deleting user');
      }
    }
  };

  const toggleUserStatus = async (user, newStatus) => {
    try {
      const response = await put(`/users/${user.id}/status`, {
        isActive: newStatus
      });
      if (response.success) {
        loadUsers(); // Refresh the user list
        alert(`User ${newStatus ? 'activated' : 'suspended'} successfully`);
      } else {
        alert(response.message || 'Failed to update user status');
      }
    } catch (error) {
      console.error('Error updating user status:', error);
      alert('Error updating user status');
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    try {
      const response = await put(`/users/${userId}`, {
        role: newRole
      });
      if (response.success) {
        loadUsers(); // Refresh the user list
        alert('User role updated successfully');
      } else {
        alert(response.message || 'Failed to update user role');
      }
    } catch (error) {
      console.error('Error updating user role:', error);
      alert('Error updating user role');
    }
  };

  const handleUpdatePrivileges = async (userId, privileges) => {
    try {
      const response = await put(`/users/${userId}`, { privileges });
      if (response.success) {
        setUsers(prev => prev.map(u => u.id === userId ? { ...u, privileges: { ...(u.privileges || {}), ...privileges } } : u));
      } else {
        alert(response.message || 'Failed to update privileges');
      }
    } catch (err) {
      console.error('Error updating privileges:', err);
      alert('Failed to update privileges');
    }
  };

  if (loading) {
    return (
      <div style={{ textAlign: 'center', padding: '2rem' }}>
        <div style={{ fontSize: '1.5rem', color: 'var(--text-muted)' }}>Loading users...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ padding: '2rem' }}>
        <div style={{
          padding: '1rem',
          backgroundColor: 'var(--danger-light)',
          border: '1px solid var(--danger)',
          borderRadius: 'var(--radius-md)',
          color: 'var(--danger)'
        }}>
          Error: {error}
          <button
            onClick={loadUsers}
            style={{
              marginLeft: '1rem',
              padding: '0.25rem 0.5rem',
              backgroundColor: 'var(--danger)',
              color: 'white',
              border: 'none',
              borderRadius: 'var(--radius-sm)',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (currentUser?.role !== 'admin') {
    return (
      <div style={{ padding: '2rem' }}>
        <div style={{
          padding: '1rem',
          backgroundColor: 'var(--warning-light)',
          border: '1px solid var(--warning)',
          borderRadius: 'var(--radius-md)',
          color: 'var(--warning-dark)'
        }}>
          Access Denied: Only administrators can manage users.
        </div>
      </div>
    );
  }

  return (
    <div className="user-management" style={{ width: '100%' }}>
      <div className="management-header" style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '1rem',
        padding: '1rem 0'
      }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '600' }}>User Management</h2>
        <button
          className="btn-primary"
          onClick={handleCreateUser}
          style={{
            padding: '0.75rem 1.5rem',
            backgroundColor: 'var(--primary)',
            color: 'white',
            border: 'none',
            borderRadius: 'var(--radius-md)',
            cursor: 'pointer',
            fontWeight: '600',
            fontSize: '0.875rem'
          }}
        >
          Add New User
        </button>
      </div>

      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1.5rem', borderBottom: '1px solid var(--border-light)', paddingBottom: '0.5rem' }}>
        {SUB_TABS.map(t => (
          <button
            key={t.id}
            type="button"
            onClick={() => setActiveSubTab(t.id)}
            style={{
              padding: '0.5rem 1rem',
              border: 'none',
              borderRadius: 'var(--radius-md)',
              background: activeSubTab === t.id ? 'var(--primary)' : 'var(--bg-main)',
              color: activeSubTab === t.id ? 'white' : 'var(--text-muted)',
              cursor: 'pointer',
              fontWeight: 600,
              fontSize: '0.875rem'
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'privileges' && (
        <div style={{ marginBottom: '2rem' }}>
          <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)', marginBottom: '1rem' }}>
            Assign privileges per user. Cashiers can be given &quot;Can delete&quot; (e.g. delete transactions, products). Admin and Manager have delete by default.
          </p>
          <div className="user-list" style={{ overflowX: 'auto' }}>
            <table className="user-table" style={{ width: '100%', borderCollapse: 'collapse', backgroundColor: 'var(--bg-card)', borderRadius: 'var(--radius-md)', overflow: 'hidden' }}>
              <thead style={{ backgroundColor: 'var(--bg-main)' }}>
                <tr>
                  <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Username</th>
                  <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Role</th>
                  <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Can delete</th>
                </tr>
              </thead>
              <tbody>
                {users.map(user => {
                  const role = (user.role || '').toLowerCase();
                  const isAdminOrManager = role === 'admin' || role === 'manager';
                  const canDeletePriv = user.privileges?.canDelete === true;
                  const effectiveCanDelete = isAdminOrManager || canDeletePriv;
                  return (
                    <tr key={user.id} style={{ borderBottom: '1px solid var(--border-light)' }}>
                      <td style={{ padding: '1rem', verticalAlign: 'middle' }}>{user.username}</td>
                      <td style={{ padding: '1rem', verticalAlign: 'middle', textTransform: 'capitalize' }}>{user.role}</td>
                      <td style={{ padding: '1rem', verticalAlign: 'middle' }}>
                        {isAdminOrManager ? (
                          <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>Yes (by role)</span>
                        ) : (
                          <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer' }}>
                            <input
                              type="checkbox"
                              checked={canDeletePriv}
                              onChange={(e) => handleUpdatePrivileges(user.id, { canDelete: e.target.checked })}
                            />
                            <span>{canDeletePriv ? 'Yes' : 'No'}</span>
                          </label>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeSubTab === 'users' && <div className="user-list" style={{ overflowX: 'auto' }}>
        <table className="user-table" style={{
          width: '100%',
          borderCollapse: 'collapse',
          backgroundColor: 'var(--bg-card)',
          borderRadius: 'var(--radius-md)',
          overflow: 'hidden'
        }}>
          <thead style={{ backgroundColor: 'var(--bg-main)' }}>
            <tr>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>UID</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Username</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Email</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Role</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Status</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Last Login</th>
              <th style={{ padding: '1rem', textAlign: 'left', borderBottom: '2px solid var(--border-light)' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {users.map(user => (
              <tr key={user.id} style={{
                ':hover': { backgroundColor: 'var(--bg-hover)' },
                borderBottom: '1px solid var(--border-light)'
              }}>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>{user.uid}</td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>{user.username}</td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>{user.email}</td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>
                  <select
                    value={user.role}
                    onChange={(e) => handleRoleChange(user.id, e.target.value)}
                    className="role-select"
                    style={{
                      padding: '0.5rem',
                      border: '1px solid var(--border-light)',
                      borderRadius: 'var(--radius-sm)',
                      backgroundColor: 'var(--bg-main)',
                      minWidth: '100px'
                    }}
                  >
                    <option value="cashier">Cashier</option>
                    <option value="manager">Manager</option>
                    <option value="admin">Admin</option>
                  </select>
                </td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>
                  <span className={`status-badge ${user.isActive ? 'active' : 'inactive'}`} style={{
                    padding: '0.25rem 0.5rem',
                    borderRadius: 'var(--radius-sm)',
                    fontSize: '0.75rem',
                    fontWeight: '600',
                    backgroundColor: user.isActive ? 'var(--success-light)' : 'var(--danger-light)',
                    color: user.isActive ? 'var(--success-dark)' : 'var(--danger-dark)',
                    border: `1px solid ${user.isActive ? 'var(--success)' : 'var(--danger)'}`
                  }}>
                    {user.isActive ? 'Active' : 'Suspended'}
                  </span>
                </td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>
                  {user.lastLogin ? new Date(user.lastLogin).toLocaleString() : 'Never'}
                </td>
                <td style={{ padding: '1rem', verticalAlign: 'middle' }}>
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button
                      className="btn-edit"
                      onClick={() => handleEditUser(user)}
                      style={{
                        padding: '0.5rem 0.75rem',
                        backgroundColor: 'var(--secondary)',
                        color: 'white',
                        border: 'none',
                        borderRadius: 'var(--radius-sm)',
                        cursor: 'pointer',
                        fontSize: '0.75rem'
                      }}
                    >
                      Edit
                    </button>
                    <button
                      className="btn-status"
                      onClick={() => toggleUserStatus(user, !user.isActive)}
                      disabled={user.id === currentUser?.id}
                      style={{
                        padding: '0.5rem 0.75rem',
                        backgroundColor: user.isActive ? 'var(--warning)' : 'var(--success)',
                        color: 'white',
                        border: 'none',
                        borderRadius: 'var(--radius-sm)',
                        cursor: user.id === currentUser?.id ? 'not-allowed' : 'pointer',
                        fontSize: '0.75rem',
                        opacity: user.id === currentUser?.id ? 0.5 : 1
                      }}
                    >
                      {user.isActive ? 'Suspend' : 'Activate'}
                    </button>
                    {canDelete && (
                    <button
                      className="btn-delete"
                      onClick={() => handleDeleteUser(user.id)}
                      disabled={user.id === currentUser?.id}
                      style={{
                        padding: '0.5rem 0.75rem',
                        backgroundColor: 'var(--danger)',
                        color: 'white',
                        border: 'none',
                        borderRadius: 'var(--radius-sm)',
                        cursor: user.id === currentUser?.id ? 'not-allowed' : 'pointer',
                        fontSize: '0.75rem',
                        opacity: user.id === currentUser?.id ? 0.5 : 1
                      }}
                    >
                      Delete
                    </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>}

      {showUserForm && (
        <UserForm
          user={editingUser}
          onClose={() => {
            setShowUserForm(false);
            setEditingUser(null);
          }}
          onSave={loadUsers}
        />
      )}

      {users.length === 0 && (
        <div style={{
          textAlign: 'center',
          padding: '3rem',
          color: 'var(--text-muted)',
          backgroundColor: 'var(--bg-card)',
          borderRadius: 'var(--radius-md)',
          marginTop: '1rem'
        }}>
          <div style={{ fontSize: '1.5rem', marginBottom: '1rem' }}>👥</div>
          <h3>No Users Found</h3>
          <p>Get started by adding your first user account.</p>
          <button
            onClick={handleCreateUser}
            style={{
              marginTop: '1rem',
              padding: '0.75rem 1.5rem',
              backgroundColor: 'var(--primary)',
              color: 'white',
              border: 'none',
              borderRadius: 'var(--radius-md)',
              cursor: 'pointer',
              fontWeight: '600'
            }}
          >
            Add User
          </button>
        </div>
      )}
    </div>
  );
}

// User Form Component
const UserForm = ({ user, onClose, onSave }) => {
  const [formData, setFormData] = useState({
    uid: '',
    username: '',
    email: '',
    password: '',
    confirmPassword: '',
    role: 'cashier',
    firstName: '',
    lastName: '',
    phone: ''
  });

  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user) {
      setFormData({
        uid: user.uid || '',
        username: user.username || '',
        email: user.email || '',
        password: '',
        confirmPassword: '',
        role: user.role || 'cashier',
        firstName: user.firstName || '',
        lastName: user.lastName || '',
        phone: user.phone || ''
      });
    } else {
      setFormData({
        uid: '',
        username: '',
        email: '',
        password: '',
        confirmPassword: '',
        role: 'cashier',
        firstName: '',
        lastName: '',
        phone: ''
      });
    }
  }, [user]);

  const validateForm = () => {
    const newErrors = {};

    if (!formData.uid.trim()) newErrors.uid = 'UID is required';
    if (formData.uid.length < 6) newErrors.uid = 'UID must be at least 6 characters';
    if (!/^[a-zA-Z0-9]+$/.test(formData.uid)) newErrors.uid = 'UID can only contain letters and numbers';

    if (!formData.username.trim()) newErrors.username = 'Username is required';
    if (formData.username.length < 3) newErrors.username = 'Username must be at least 3 characters';

    if (!formData.firstName.trim()) newErrors.firstName = 'First Name is required';
    if (!formData.lastName.trim()) newErrors.lastName = 'Last Name is required';

    if (!formData.email.trim()) newErrors.email = 'Email is required';
    if (!/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = 'Email is invalid';

    if (!user && !formData.password) newErrors.password = 'Password is required';
    if (!user && formData.password && formData.password.length < 8) newErrors.password = 'Password must be at least 8 characters';
    if (!user && formData.password && formData.password !== formData.confirmPassword) newErrors.confirmPassword = 'Passwords do not match';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) return;

    setLoading(true);
    try {
      let response;
      if (user) {
        // Update existing user
        const updateData = {
          uid: formData.uid,
          username: formData.username,
          email: formData.email,
          role: formData.role,
          firstName: formData.firstName,
          lastName: formData.lastName,
          phone: formData.phone
        };

        if (formData.password) {
          updateData.password = formData.password;
        }

        response = await put(`/users/${user.id}`, updateData);
      } else {
        // Create new user
        response = await post('/users/register', {
          uid: formData.uid,
          username: formData.username,
          email: formData.email,
          password: formData.password,
          role: formData.role,
          firstName: formData.firstName,
          lastName: formData.lastName,
          phone: formData.phone
        });
      }

      if (response.success) {
        alert(user ? 'User updated successfully' : 'User created successfully');
        onSave();
        onClose();
      } else {
        alert(response.message || (user ? 'Failed to update user' : 'Failed to create user'));
      }
    } catch (error) {
      console.error(user ? 'Error updating user:' : 'Error creating user:', error);
      alert(user ? 'Error updating user' : 'Error creating user');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Clear error when user types
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    }}>
      <div style={{
        backgroundColor: 'var(--bg-card)',
        borderRadius: 'var(--radius-lg)',
        padding: '2rem',
        width: '90%',
        maxWidth: '600px',
        maxHeight: '90vh',
        overflowY: 'auto'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
          <h3 style={{ margin: 0, fontSize: '1.25rem' }}>
            {user ? 'Edit User' : 'Add New User'}
          </h3>
          <button
            onClick={onClose}
            style={{
              background: 'transparent',
              border: 'none',
              cursor: 'pointer',
              color: 'var(--text-muted)',
              padding: '4px',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
            onMouseOver={(e) => e.currentTarget.style.backgroundColor = 'var(--bg-hover)'}
            onMouseOut={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
          >
            <svg style={{ width: '24px', height: '24px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>UID *</label>
              <input
                type="text"
                name="uid"
                value={formData.uid}
                onChange={handleChange}
                disabled={!!user}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: errors.uid ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)',
                  backgroundColor: user ? 'var(--bg-main)' : 'var(--bg-card)'
                }}
              />
              {errors.uid && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.uid}</div>}
            </div>

            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Username *</label>
              <input
                type="text"
                name="username"
                value={formData.username}
                onChange={handleChange}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: errors.username ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)'
                }}
              />
              {errors.username && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.username}</div>}
            </div>
          </div>

          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Email *</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              style={{
                width: '100%',
                padding: '0.75rem',
                border: errors.email ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                borderRadius: 'var(--radius-md)'
              }}
            />
            {errors.email && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.email}</div>}
          </div>

          {!user && (
            <>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                <div>
                  <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Password *</label>
                  <input
                    type="password"
                    name="password"
                    value={formData.password}
                    onChange={handleChange}
                    style={{
                      width: '100%',
                      padding: '0.75rem',
                      border: errors.password ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                      borderRadius: 'var(--radius-md)'
                    }}
                  />
                  {errors.password && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.password}</div>}
                </div>

                <div>
                  <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Confirm Password *</label>
                  <input
                    type="password"
                    name="confirmPassword"
                    value={formData.confirmPassword}
                    onChange={handleChange}
                    style={{
                      width: '100%',
                      padding: '0.75rem',
                      border: errors.confirmPassword ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                      borderRadius: 'var(--radius-md)'
                    }}
                  />
                  {errors.confirmPassword && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.confirmPassword}</div>}
                </div>
              </div>
            </>
          )}

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>First Name *</label>
              <input
                type="text"
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: errors.firstName ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)'
                }}
              />
              {errors.firstName && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.firstName}</div>}
            </div>

            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Last Name *</label>
              <input
                type="text"
                name="lastName"
                value={formData.lastName}
                onChange={handleChange}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: errors.lastName ? '1px solid var(--danger)' : '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)'
                }}
              />
              {errors.lastName && <div style={{ color: 'var(--danger)', fontSize: '0.75rem', marginTop: '0.25rem' }}>{errors.lastName}</div>}
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Phone</label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)'
                }}
              />
            </div>

            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600' }}>Role</label>
              <select
                name="role"
                value={formData.role}
                onChange={handleChange}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: '1px solid var(--border-light)',
                  borderRadius: 'var(--radius-md)',
                  backgroundColor: 'var(--bg-main)'
                }}
              >
                <option value="cashier">Cashier</option>
                <option value="manager">Manager</option>
                <option value="admin">Admin</option>
              </select>
            </div>
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '2rem' }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: '0.75rem 1.5rem',
                backgroundColor: 'var(--secondary)',
                color: 'white',
                border: 'none',
                borderRadius: 'var(--radius-md)',
                cursor: 'pointer'
              }}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              style={{
                padding: '0.75rem 1.5rem',
                backgroundColor: 'var(--primary)',
                color: 'white',
                border: 'none',
                borderRadius: 'var(--radius-md)',
                cursor: loading ? 'not-allowed' : 'pointer'
              }}
            >
              {loading ? 'Saving...' : (user ? 'Update User' : 'Create User')}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default UserManagement;