import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { useSettings } from './SettingsContext';
import {
  applyTheme,
  getStoredTheme,
  setStoredTheme,
  resolveEffectiveTheme,
  onSystemPreferenceChange,
  setStoredPrimaryColor
} from '../utils/themeUtils';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const { settings, updateSetting } = useSettings();
  const [customColor, setCustomColor] = useState(settings?.customBrandColor || '#6366f1');
  const [themeMode, setThemeModeState] = useState(() => {
    // Prefer localStorage for immediate apply before API loads
    const stored = getStoredTheme();
    if (stored) return stored;
    // Fallback: map legacy darkMode to themeMode
    if (settings?.darkMode === true) return 'dark';
    if (settings?.themeMode && ['light', 'dark', 'system'].includes(settings.themeMode)) return settings.themeMode;
    return 'light';
  });

  // Apply theme to document (data-theme on html)
  const applyThemeToDocument = useCallback((mode) => {
    const effective = applyTheme(mode);
    return effective;
  }, []);

  // Sync themeMode from settings when they load
  useEffect(() => {
    if (!settings || Object.keys(settings).length === 0) return;
    const fromSettings = settings.themeMode || (settings.darkMode ? 'dark' : 'light');
    if (['light', 'dark', 'system'].includes(fromSettings) && fromSettings !== themeMode) {
      setThemeModeState(fromSettings);
      setStoredTheme(fromSettings);
      applyThemeToDocument(fromSettings);
    }
  }, [settings?.themeMode, settings?.darkMode]);

  // Apply theme whenever themeMode changes
  useEffect(() => {
    applyThemeToDocument(themeMode);
    setStoredTheme(themeMode);
  }, [themeMode, applyThemeToDocument]);

  // Listen for system preference changes when mode is 'system'
  useEffect(() => {
    if (themeMode !== 'system') return;
    return onSystemPreferenceChange(() => {
      applyThemeToDocument('system');
    });
  }, [themeMode, applyThemeToDocument]);

  // Apply primary color (hue) and custom brand color
  useEffect(() => {
    const root = document.documentElement;
    if (settings?.themeMode === 'custom' && (settings.customBrandColor || customColor)) {
      const color = settings.customBrandColor || customColor;
      const hsl = hexToHSL(color);
      if (hsl) {
        root.style.setProperty('--primary-h', hsl.h);
        root.style.setProperty('--primary-s', `${hsl.s}%`);
        root.style.setProperty('--primary-l', `${hsl.l}%`);
      }
    } else if (settings?.themeColor) {
      root.style.setProperty('--primary-h', String(settings.themeColor));
      root.style.setProperty('--primary-s', '75%');
      root.style.setProperty('--primary-l', '60%');
    }
  }, [settings?.themeColor, settings?.themeMode, settings?.customBrandColor, customColor]);

  const hexToHSL = (hex) => {
    hex = String(hex).replace('#', '');
    if (hex.length !== 6) return null;
    const r = parseInt(hex.substring(0, 2), 16) / 255;
    const g = parseInt(hex.substring(2, 4), 16) / 255;
    const b = parseInt(hex.substring(4, 6), 16) / 255;
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    let h, s, l = (max + min) / 2;
    if (max === min) {
      h = s = 0;
    } else {
      const d = max - min;
      s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
      switch (max) {
        case r: h = ((g - b) / d + (g < b ? 6 : 0)) / 6; break;
        case g: h = ((b - r) / d + 2) / 6; break;
        case b: h = ((r - g) / d + 4) / 6; break;
        default: h = 0;
      }
    }
    return { h: Math.round(h * 360), s: Math.round(s * 100), l: Math.round(l * 100) };
  };

  const setThemeMode = (mode) => {
    if (!['light', 'dark', 'system'].includes(mode)) return;
    setThemeModeState(mode);
    setStoredTheme(mode);
    updateSetting('themeMode', mode);
    updateSetting('darkMode', mode === 'dark');
  };

  const setDarkMode = (isDark) => {
    const mode = isDark ? 'dark' : 'light';
    setThemeMode(mode);
  };

  const setThemeColor = (hue) => {
    updateSetting('themeColor', hue);
    updateSetting('themeMode', 'light');
    setStoredPrimaryColor(hue);
    const root = document.documentElement;
    root.style.setProperty('--primary-h', String(hue));
    root.style.setProperty('--primary-s', '75%');
    root.style.setProperty('--primary-l', '60%');
  };

  const setCustomBrandColor = (color) => {
    setCustomColor(color);
    updateSetting('customBrandColor', color);
    updateSetting('themeMode', 'custom');
    setStoredPrimaryColor(color);
    const hsl = hexToHSL(color);
    if (hsl) {
      const root = document.documentElement;
      root.style.setProperty('--primary-h', hsl.h);
      root.style.setProperty('--primary-s', `${hsl.s}%`);
      root.style.setProperty('--primary-l', `${hsl.l}%`);
    }
  };

  const effectiveTheme = resolveEffectiveTheme(themeMode);

  const value = {
    themeMode: themeMode || settings?.themeMode || 'light',
    darkMode: effectiveTheme === 'dark',
    themeColor: settings?.themeColor || '245',
    customBrandColor: customColor || settings?.customBrandColor || '#6366f1',
    setThemeMode,
    setDarkMode,
    setThemeColor,
    setCustomBrandColor,
    applyTheme: applyThemeToDocument
  };

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

export default ThemeContext;
