import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { get } from '../utils/api';
import GlassCard from './common/GlassCard';
import GlobalSearchBar from './common/GlobalSearchBar';
import { formatCurrency } from '../utils/currency';
import StockAdjustment from './StockAdjustment';
import { useTranslation } from 'react-i18next';

const Stock1Screen = ({ embedMode = false, activeTab: controlledTab }) => {
  const { t } = useTranslation();
  const [internalTab, setInternalTab] = useState('overview');
  const activeTab = embedMode && controlledTab != null ? controlledTab : internalTab;
  const setActiveTab = embedMode && controlledTab != null ? () => {} : setInternalTab;
  const [inventoryData, setInventoryData] = useState([]);
  const [stockAdjustments, setStockAdjustments] = useState([]);
  const [lowStockItems, setLowStockItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [inventoryLoading, setInventoryLoading] = useState(false);
  const [adjustmentLoading, setAdjustmentLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const searchInputRef = useRef(null);
  const contentRef = useRef(null);

  // Search: Product Name, Barcode, Category
  const term = searchTerm.trim().toLowerCase();
  const filteredInventory = useMemo(() => {
    if (!term) return inventoryData;
    return inventoryData.filter(item =>
      (item.product?.name && item.product.name.toLowerCase().includes(term)) ||
      (item.product?.barcode && item.product.barcode.toLowerCase().includes(term)) ||
      (item.product?.category?.name && item.product.category.name.toLowerCase().includes(term))
    );
  }, [inventoryData, term]);

  const filteredLowStock = useMemo(() => {
    if (!term) return lowStockItems;
    return lowStockItems.filter(item =>
      (item.product?.name && item.product.name.toLowerCase().includes(term)) ||
      (item.product?.barcode && item.product.barcode.toLowerCase().includes(term))
    );
  }, [lowStockItems, term]);

  const filteredAdjustments = useMemo(() => {
    if (!term) return stockAdjustments;
    return stockAdjustments.filter(a =>
      (a.product?.name && a.product.name.toLowerCase().includes(term)) ||
      (a.product?.barcode && a.product.barcode.toLowerCase().includes(term))
    );
  }, [stockAdjustments, term]);

  const focusResults = useCallback(() => {
    const firstCard = contentRef.current?.querySelector('[data-searchable="true"]');
    if (firstCard) firstCard.focus?.();
  }, []);

  // Fetch initial inventory data
  useEffect(() => {
    const fetchInventoryData = async () => {
      try {
        setLoading(true);
        const response = await get('/inventory');
        if (response.success) {
          setInventoryData(response.data);

          // Filter low stock items
          const lowStock = response.data.filter(item =>
            item.quantity <= (item.product?.minStockLevel || 10)
          );
          setLowStockItems(lowStock);
        }
      } catch (err) {
        console.error('Error fetching inventory data:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchInventoryData();
  }, []);

  // Fetch inventory when inventory tab is active
  useEffect(() => {
    if (activeTab === 'inventory') {
      const fetchInventory = async () => {
        try {
          setInventoryLoading(true);
          const response = await get('/inventory');
          if (response.success) {
            setInventoryData(response.data);

            // Filter low stock items
            const lowStock = response.data.filter(item =>
              item.quantity <= (item.product?.minStockLevel || 10)
            );
            setLowStockItems(lowStock);
          }
        } catch (err) {
          console.error('Error fetching inventory:', err);
        } finally {
          setInventoryLoading(false);
        }
      };
      fetchInventory();
    }
  }, [activeTab]);

  // Fetch stock adjustments when adjustments tab is active
  useEffect(() => {
    if (activeTab === 'adjustments') {
      const fetchAdjustments = async () => {
        try {
          setAdjustmentLoading(true);
          const response = await get('/stock-adjustments');
          if (response.success) {
            setStockAdjustments(response.data);
          }
        } catch (err) {
          console.error('Error fetching stock adjustments:', err);
        } finally {
          setAdjustmentLoading(false);
        }
      };
      fetchAdjustments();
    }
  }, [activeTab]);

  const tabs = [
    { id: 'overview', label: t('stock.overview'), icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
    { id: 'inventory', label: t('stock.inventoryLevels'), icon: 'M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z' },
    { id: 'low-stock', label: t('stock.lowStockAlerts'), icon: 'M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z' },
    { id: 'adjustments', label: t('stock.adjustments'), icon: 'M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15' },
  ];

  if (loading && !embedMode) {
    return (
      <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ width: '48px', height: '48px', border: '4px solid var(--border-light)', borderTop: '4px solid var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }}></div>
            <p style={{ color: 'var(--text-muted)', fontSize: '1.1rem' }}>{t('common.loading')}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: embedMode ? 'auto' : 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
      {!embedMode && (
      /* Sidebar Tabs */
      <div style={{ width: '280px', backgroundColor: 'var(--bg-card)', borderRight: '1px solid var(--border-light)', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        <h2 style={{ fontSize: '1.25rem', fontWeight: '800', marginBottom: '1.5rem', color: 'var(--text-main)', paddingLeft: '0.5rem' }}>{t('stock.title')}</h2>
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              padding: '0.875rem 1rem',
              borderRadius: 'var(--radius-md)',
              border: 'none',
              backgroundColor: activeTab === tab.id ? 'var(--primary-subtle)' : 'transparent',
              color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
              cursor: 'pointer',
              fontWeight: '600',
              textAlign: 'left',
              transition: 'all var(--transition-fast)'
            }}
          >
            <svg style={{ width: '20px', height: '20px' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={tab.icon} /></svg>
            {tab.label}
          </button>
        ))}

        <div style={{ marginTop: 'auto', padding: '1rem', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-lg)', border: '1px dashed var(--border-light)' }}>
          <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', margin: 0 }}>Real-time inventory tracking</p>
        </div>
      </div>
      )}

      {/* Main Panel */}
      <div style={{ flex: 1, padding: embedMode ? '0 1rem 1rem' : '2.5rem', overflowY: 'auto' }}>
        <div ref={contentRef} style={{ maxWidth: '1200px' }}>
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '1rem' }}>
            <GlobalSearchBar
              value={searchTerm}
              onChange={setSearchTerm}
              onClear={() => setSearchTerm('')}
              onArrowDown={focusResults}
              inputRef={searchInputRef}
              placeholder={t('search.placeholder')}
            />
          </div>

          {activeTab === 'overview' && (
            <div className="animate-fade-in">
              <div style={{ marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '2.5rem', fontWeight: '800', margin: '0 0 0.5rem 0', background: 'linear-gradient(135deg, var(--primary) 0%, var(--accent-secondary) 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                  {t('stock.overviewTitle')}
                </h1>
                <p style={{ color: 'var(--text-muted)', margin: 0, fontSize: '1.1rem' }}>Comprehensive inventory and stock control dashboard</p>
              </div>

              {/* KPI Cards */}
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t('stock.totalItems')}</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: 'var(--primary)' }}>
                        {inventoryData.length}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        Active products in stock
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: 'var(--primary-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: 'var(--primary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                    </div>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t('stock.lowStockAlerts')}</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: lowStockItems.length > 0 ? 'var(--warning)' : 'var(--success)' }}>
                        {lowStockItems.length}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        {lowStockItems.length > 0 ? 'Require immediate attention' : 'All items well stocked'}
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: lowStockItems.length > 0 ? 'var(--warning-subtle)' : 'var(--success-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: lowStockItems.length > 0 ? 'var(--warning)' : 'var(--success)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                    </div>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <p style={{ margin: '0 0 0.5rem 0', color: 'var(--text-muted)', fontSize: '0.9rem' }}>{t('stock.adjustments')}</p>
                      <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: 'var(--accent-secondary)' }}>
                        {filteredAdjustments.length}
                      </h2>
                      <p style={{ margin: '0.5rem 0 0 0', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        Recent inventory adjustments
                      </p>
                    </div>
                    <div style={{ width: '48px', height: '48px', backgroundColor: 'var(--accent-secondary-subtle)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <svg style={{ width: '24px', height: '24px', color: 'var(--accent-secondary)' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                    </div>
                  </div>
                </GlassCard>
              </div>

              {/* Stock Summary */}
              <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
                <GlassCard style={{ padding: '1.5rem' }}>
                  <h3 style={{ margin: '0 0 1.5rem 0', fontSize: '1.25rem', fontWeight: '700' }}>{t('stock.distribution')}</h3>
                  <div style={{ height: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-md)', border: '1px dashed var(--border-light)' }}>
                    <p style={{ color: 'var(--text-muted)', textAlign: 'center' }}>
                      Inventory distribution chart would be rendered here<br />
                      <span style={{ fontSize: '0.9rem' }}>Using Chart.js or similar library</span>
                    </p>
                  </div>
                </GlassCard>

                <GlassCard style={{ padding: '1.5rem' }}>
                  <h3 style={{ margin: '0 0 1.5rem 0', fontSize: '1.25rem', fontWeight: '700' }}>{t('stock.stockCategories')}</h3>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    {Object.entries(
                      inventoryData
                        .filter(item => item.product?.category)
                        .reduce((acc, item) => {
                          const category = item.product.category.name;
                          if (!acc[category]) {
                            acc[category] = 0;
                          }
                          acc[category] += item.quantity;
                          return acc;
                        }, {})
                    )
                      .slice(0, 5)
                      .map(([category, total], index) => (
                        <div key={category} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <div style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: `hsl(${index * 60}, 70%, 60%)` }}></div>
                            <span style={{ fontSize: '0.9rem', fontWeight: '500' }}>{category}</span>
                          </div>
                          <span style={{ fontSize: '0.9rem', fontWeight: '600', color: 'var(--text-main)' }}>
                            {total} items
                          </span>
                        </div>
                      ))}
                  </div>
                </GlassCard>
              </div>
            </div>
          )}

          {activeTab === 'inventory' && (
            <div className="animate-fade-in">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h3 style={{ fontSize: '1.5rem', margin: 0 }}>{t('stock.inventoryLevels')}</h3>
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                  <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                    {filteredInventory.length} items
                  </span>
                  <button
                    onClick={() => {
                      const fetchInventory = async () => {
                        setInventoryLoading(true);
                        const response = await get('/inventory');
                        if (response.success) setInventoryData(response.data);
                        setInventoryLoading(false);
                      };
                      fetchInventory();
                    }}
                    style={{ padding: '0.5rem 1rem', backgroundColor: 'var(--primary)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontSize: '0.9rem' }}
                  >
                    {t('common.loading')} (F5)
                  </button>
                </div>
              </div>

              {inventoryLoading ? (
                <div style={{ textAlign: 'center', padding: '3rem' }}>
                  <div style={{ width: '48px', height: '48px', border: '4px solid var(--border-light)', borderTop: '4px solid var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }}></div>
                  <p>{t('common.loading')}</p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '1.5rem' }}>
                  {filteredInventory.slice(0, 12).map((item, index) => (
                    <GlassCard key={item.id || index} style={{ padding: '1.25rem' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                        <div>
                          <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '1.1rem', fontWeight: '700' }}>{item.product?.name || 'Unknown Product'}</h4>
                          <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            {item.product?.barcode || 'No Barcode'}
                          </p>
                        </div>
                        <span style={{
                          padding: '0.25rem 0.75rem',
                          borderRadius: 'var(--radius-full)',
                          fontSize: '0.8rem',
                          fontWeight: '600',
                          backgroundColor: item.quantity <= (item.product?.minStockLevel || 10) ? 'var(--danger-subtle)' : 'var(--success-subtle)',
                          color: item.quantity <= (item.product?.minStockLevel || 10) ? 'var(--danger)' : 'var(--success)'
                        }}>
                          {item.quantity <= (item.product?.minStockLevel || 10) ? t('products.lowStock') : t('products.inStock')}
                        </span>
                      </div>

                      <div style={{ marginBottom: '1rem' }}>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>Current: {item.quantity} units</p>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>Min Level: {item.product?.minStockLevel || 10} units</p>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                          Value: {formatCurrency(item.quantity * (item.product?.costPrice || 0))}
                        </p>
                      </div>

                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <span style={{ fontSize: '1rem', fontWeight: '700', color: 'var(--primary)' }}>
                          {formatCurrency(item.product?.sellingPrice || 0)}
                        </span>
                        <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                          {item.product?.category?.name || 'Uncategorized'}
                        </span>
                      </div>
                    </GlassCard>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'low-stock' && (
            <div className="animate-fade-in">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h3 style={{ fontSize: '1.5rem', margin: 0 }}>{t('stock.lowStockAlerts')}</h3>
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                  <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                    {filteredLowStock.length} items need attention
                  </span>
                </div>
              </div>

                  {filteredLowStock.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '3rem', backgroundColor: 'var(--success-subtle)', borderRadius: 'var(--radius-lg)', border: '1px solid var(--success)' }}>
                  <div style={{ width: '64px', height: '64px', backgroundColor: 'var(--success)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1.5rem' }}>
                    <svg style={{ width: '32px', height: '32px', color: 'white' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg>
                  </div>
                  <h3 style={{ color: 'var(--success)', margin: '0 0 1rem 0' }}>All Stock Levels Healthy</h3>
                  <p style={{ color: 'var(--text-muted)', margin: 0 }}>No items are currently below minimum stock levels.</p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '1.5rem' }}>
                  {filteredLowStock.map((item, index) => (
                    <GlassCard key={item.id || index} style={{ padding: '1.25rem', border: '2px solid var(--danger)' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                        <div>
                          <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '1.1rem', fontWeight: '700', color: 'var(--danger)' }}>{item.product?.name || 'Unknown Product'}</h4>
                          <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            {item.product?.barcode || 'No Barcode'}
                          </p>
                        </div>
                        <div style={{ width: '24px', height: '24px', backgroundColor: 'var(--danger)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                          <svg style={{ width: '16px', height: '16px', color: 'white' }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                        </div>
                      </div>

                      <div style={{ marginBottom: '1rem' }}>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--danger)', fontWeight: '600' }}>Current: {item.quantity} units</p>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>Minimum: {item.product?.minStockLevel || 10} units</p>
                        <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                          Value: {formatCurrency(item.quantity * (item.product?.costPrice || 0))}
                        </p>
                      </div>

                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <span style={{ fontSize: '1rem', fontWeight: '700', color: 'var(--danger)' }}>
                          {t('products.lowStock')}
                        </span>
                        <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                          {item.product?.category?.name || 'Uncategorized'}
                        </span>
                      </div>
                    </GlassCard>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'adjustments' && (
            <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', gap: '2.5rem' }}>
              <StockAdjustment onAdjustmentSuccess={() => {
                const fetchAdjustments = async () => {
                  setAdjustmentLoading(true);
                  const response = await get('/stock-adjustments');
                  if (response.success) setStockAdjustments(response.data);
                  setAdjustmentLoading(false);
                };
                fetchAdjustments();
              }} />

              <div style={{ borderTop: '1px solid var(--border-light)', paddingTop: '2.5rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                  <h3 style={{ fontSize: '1.5rem', margin: 0 }}>{t('stock.adjustmentHistory')}</h3>
                  <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                    <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                      {filteredAdjustments.length} adjustments
                    </span>
                    <button
                      onClick={() => {
                        const fetchAdjustments = async () => {
                          setAdjustmentLoading(true);
                          const response = await get('/stock-adjustments');
                          if (response.success) setStockAdjustments(response.data);
                          setAdjustmentLoading(false);
                        };
                        fetchAdjustments();
                      }}
                      style={{ padding: '0.5rem 1rem', backgroundColor: 'var(--primary)', color: 'white', border: 'none', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontSize: '0.9rem' }}
                    >
                      {t('common.loading')}
                    </button>
                  </div>
                </div>

                {adjustmentLoading ? (
                  <div style={{ textAlign: 'center', padding: '3rem' }}>
                    <div style={{ width: '48px', height: '48px', border: '4px solid var(--border-light)', borderTop: '4px solid var(--primary)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }}></div>
                    <p>{t('common.loading')}</p>
                  </div>
                ) : (
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '1.5rem' }}>
                    {filteredAdjustments.slice(0, 12).map((adjustment, index) => (
                      <GlassCard key={adjustment.id || index} style={{ padding: '1.25rem' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                          <div>
                            <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '1.1rem', fontWeight: '700' }}>{adjustment.product?.name || 'Unknown Product'}</h4>
                            <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                              {new Date(adjustment.adjustmentDate || adjustment.createdAt).toLocaleDateString()}
                            </p>
                          </div>
                          <span style={{
                            padding: '0.25rem 0.75rem',
                            borderRadius: 'var(--radius-full)',
                            fontSize: '0.8rem',
                            fontWeight: '600',
                            backgroundColor: adjustment.isApproved ? 'var(--success-subtle)' : 'var(--warning-subtle)',
                            color: adjustment.isApproved ? 'var(--success)' : 'var(--warning)'
                          }}>
                            {adjustment.isApproved ? t('stock.approved') : t('stock.pending')}
                          </span>
                        </div>

                        <div style={{ marginBottom: '1rem' }}>
                          <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            <strong>{t('stock.type')}:</strong> {adjustment.adjustmentType === 'addition' ? t('common.add') : t('common.delete')}
                          </p>
                          <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            <strong>{t('grn.quantity')}:</strong> {adjustment.quantity} {t('products.unit')}
                          </p>
                          <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                            <strong>{t('stock.reason')}:</strong> <span style={{ textTransform: 'capitalize' }}>{adjustment.reason.replace('_', ' ')}</span>
                          </p>
                          {adjustment.notes && (
                            <p style={{ margin: '0.5rem 0 0 0', fontSize: '0.85rem', color: 'var(--text-muted)', fontStyle: 'italic' }}>
                              "{adjustment.notes}"
                            </p>
                          )}
                        </div>

                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <span style={{ fontSize: '1rem', fontWeight: '700', color: 'var(--primary)' }}>
                            {formatCurrency(adjustment.quantity * (adjustment.product?.costPrice || 0))}
                          </span>
                          <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                            {t('stock.by')}: {adjustment.adjustedBy?.username || 'System'}
                          </span>
                        </div>
                      </GlassCard>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default Stock1Screen;