import React, { useState, useEffect, useRef } from 'react';
import { get, post, put, del } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import GlassCard from './common/GlassCard';
import { useTranslation } from 'react-i18next';
import '../styles/antigravity.css';

function CustomerRow({ customer, index, isFocused, isSelected, canDelete, t, onRowClick, onView, onEdit, onDelete }) {
  return (
    <tr
      key={customer.id}
      tabIndex={index === 0 ? 0 : -1}
      data-row-index={index}
      onClick={() => onRowClick(customer, index)}
      className="inventory-row"
      style={{
        borderBottom: '1px solid rgba(255,255,255,0.03)',
        backgroundColor: isSelected ? 'var(--primary-subtle)' : isFocused ? 'var(--glass-highlight)' : 'transparent',
        borderLeft: isFocused ? '4px solid var(--primary)' : '4px solid transparent',
        cursor: 'pointer',
        transition: 'background 0.2s',
        color: 'var(--text-main)'
      }}
    >
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>
        <span style={{ fontWeight: '600' }}>{customer.name}</span>
      </td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>{customer.phone || '-'}</td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit' }}>{customer.email || '-'}</td>
      <td style={{ padding: '12px', fontSize: '14px', color: 'inherit', maxWidth: 200, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={customer.address || ''}>{customer.address || '-'}</td>
      <td style={{ padding: '12px', fontSize: '14px', textAlign: 'center' }}>
        <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', justifyContent: 'center' }}>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onView(customer); }} title={t('common.view') + ' (V)'}>{t('common.view')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>V</kbd></button>
          <button className="btn btn-sm btn-outline-primary" onClick={(e) => { e.stopPropagation(); onEdit(customer); }} title={t('common.edit') + ' (E)'}>{t('common.edit')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>E</kbd></button>
          {canDelete && <button className="btn btn-sm btn-outline-danger" onClick={(e) => { e.stopPropagation(); onDelete(customer.id); }} title={t('common.delete') + ' (Del)'}>{t('common.delete')} <kbd style={{ fontSize: 10, padding: '1px 4px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600 }}>Del</kbd></button>}
        </div>
      </td>
    </tr>
  );
}

const CustomerManagement = () => {
  const { canDelete } = useAuth();
  const { t } = useTranslation();
  const [customers, setCustomers] = useState([]);
  const [filteredCustomers, setFilteredCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('name');
  const [sortOrder, setSortOrder] = useState('asc');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(10);
  const [editingCustomer, setEditingCustomer] = useState(null);
  const [viewingCustomer, setViewingCustomer] = useState(null);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [focusedRow, setFocusedRow] = useState(-1);
  const [showFormModal, setShowFormModal] = useState(false);
  const [formData, setFormData] = useState({ name: '', phone: '', email: '', address: '' });
  const tableBodyRef = useRef(null);

  useEffect(() => { loadCustomers(); }, []);

  // Shortcuts: F8 Add, V View, E Edit, Del Delete (when list has focus / no modal open)
  useEffect(() => {
    const handleKey = (e) => {
      if (showFormModal || viewingCustomer) return;
      const tag = (e.target && e.target.tagName) || '';
      if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
      if (e.key === 'F8') {
        e.preventDefault();
        openAdd();
      }
      if (e.key === 'v' || e.key === 'V') {
        if (selectedCustomer) {
          e.preventDefault();
          handleView(selectedCustomer);
        }
      }
      if (e.key === 'e' || e.key === 'E') {
        if (selectedCustomer) {
          e.preventDefault();
          handleEdit(selectedCustomer);
        }
      }
      if (e.key === 'Delete' || e.key === 'Backspace') {
        if (selectedCustomer && canDelete) {
          e.preventDefault();
          handleDelete(selectedCustomer.id);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [showFormModal, viewingCustomer, selectedCustomer, canDelete]);

  useEffect(() => {
    let filtered = [...customers];
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      filtered = filtered.filter(c =>
        (c.name && c.name.toLowerCase().includes(term)) ||
        (c.phone && c.phone.toLowerCase().includes(term)) ||
        (c.email && c.email.toLowerCase().includes(term)) ||
        (c.address && c.address.toLowerCase().includes(term))
      );
    }
    filtered.sort((a, b) => {
      let aVal = a[sortBy] == null ? '' : String(a[sortBy]);
      let bVal = b[sortBy] == null ? '' : String(b[sortBy]);
      return sortOrder === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
    });
    setFilteredCustomers(filtered);
    setCurrentPage(p => Math.min(p, Math.max(1, Math.ceil(filtered.length / itemsPerPage)) || 1));
  }, [customers, searchTerm, sortBy, sortOrder]);

  const loadCustomers = async () => {
    try {
      setLoading(true);
      setError('');
      const res = await get('/customers');
      if (res && res.success === true && Array.isArray(res.data)) {
        setCustomers(res.data);
      } else {
        setCustomers([]);
        if (res && res.success === false) setError(res.message || 'Failed to load customers');
      }
    } catch (e) {
      setError(e.message || 'Failed to load customers');
      setCustomers([]);
    } finally {
      setLoading(false);
    }
  };

  const totalPages = Math.max(1, Math.ceil(filteredCustomers.length / itemsPerPage));
  const indexOfFirstItem = (currentPage - 1) * itemsPerPage;
  const currentItems = filteredCustomers.slice(indexOfFirstItem, indexOfFirstItem + itemsPerPage);

  const handleSort = (col) => {
    setSortBy(col);
    setSortOrder(prev => (prev === 'asc' ? 'desc' : 'asc'));
  };

  const handleRowClick = (customer, index) => {
    setSelectedCustomer(customer);
    setFocusedRow(index);
  };

  const openAdd = () => {
    setFormData({ name: '', phone: '', email: '', address: '' });
    setEditingCustomer(null);
    setShowFormModal(true);
  };

  const handleEdit = (customer) => {
    setFormData({
      name: customer.name || '',
      phone: customer.phone || '',
      email: customer.email || '',
      address: customer.address || ''
    });
    setEditingCustomer(customer);
    setShowFormModal(true);
  };

  const handleView = (customer) => setViewingCustomer(customer);

  const handleSave = async () => {
    if (!formData.name.trim()) {
      alert(t('customers.name') + ' ' + (t('messages.requiredField') || 'is required'));
      return;
    }
    try {
      const result = editingCustomer
        ? await put(`/customers/${editingCustomer.id}`, formData)
        : await post('/customers', formData);
      if (result && result.success === false) {
        alert(result.message || 'Failed to save customer');
        return;
      }
      setShowFormModal(false);
      setEditingCustomer(null);
      setFormData({ name: '', phone: '', email: '', address: '' });
      await loadCustomers();
    } catch (e) {
      alert(e.message || 'Failed to save customer');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(t('common.confirmDelete') || 'Delete this customer?')) return;
    try {
      await del(`/customers/${id}`);
      if (selectedCustomer?.id === id) setSelectedCustomer(null);
      loadCustomers();
    } catch (e) {
      alert(e.message || 'Failed to delete customer');
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', height: '100%' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <h3 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '800' }}>{t('customers.title') || 'Customers'}</h3>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <input
            type="text"
            placeholder={t('common.search') || 'Search...'}
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            style={{ padding: '8px 12px', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-light)', minWidth: 200 }}
          />
          <button onClick={loadCustomers} className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            {t('common.refresh') || 'Refresh'}
          </button>
          <button onClick={openAdd} className="btn btn-primary" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            + {t('customers.addCustomer')} <kbd style={{ fontSize: 10, padding: '2px 5px', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 4, background: 'rgba(0,0,0,0.2)', fontWeight: 600 }}>F8</kbd>
          </button>
        </div>
      </div>

      <GlassCard style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 0 }}>
        <div className="glass-panel" style={{ padding: '1rem', borderBottom: '1px solid var(--glass-border)', borderRadius: '16px 16px 0 0', fontWeight: 'bold', color: 'var(--text-muted)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
          <h3 style={{ margin: 0 }}>{t('customers.list')} ({filteredCustomers.length})</h3>
          <span style={{ fontSize: 12, fontWeight: 'normal' }}>
            <kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', marginRight: 4 }}>F8</kbd> {t('customers.addCustomer')}
            <span style={{ marginLeft: 8 }}>·</span>
            <kbd style={{ marginLeft: 8, padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', marginRight: 4 }}>V</kbd> {t('common.view')}
            <span style={{ marginLeft: 8 }}>·</span>
            <kbd style={{ marginLeft: 8, padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', marginRight: 4 }}>E</kbd> {t('common.edit')}
            <span style={{ marginLeft: 8 }}>·</span>
            <kbd style={{ marginLeft: 8, padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)' }}>Del</kbd> {t('common.delete')}
          </span>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>{t('common.loading')}</div>
        ) : error ? (
          <div style={{ textAlign: 'center', padding: 40, color: 'var(--danger)' }}>
            <p>{error}</p>
            <button onClick={loadCustomers} className="btn btn-primary" style={{ marginTop: 12 }}>{t('common.tryAgain') || 'Try Again'}</button>
          </div>
        ) : filteredCustomers.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>
            <p>{t('customers.noCustomers') || 'No customers yet.'}</p>
            <button onClick={openAdd} className="btn btn-primary" style={{ marginTop: 12 }}>{t('customers.addCustomer') || 'Add Customer'}</button>
          </div>
        ) : (
          <>
            <div style={{ overflow: 'auto', flex: 1, minHeight: 0 }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr className="glass-panel" style={{ borderBottom: '1px solid var(--glass-border)', position: 'sticky', top: 0, background: 'var(--glass-bg)', zIndex: 10, color: 'var(--text-muted)' }}>
                    <th onClick={() => handleSort('name')} style={{ textAlign: 'left', padding: 12, fontSize: 14, fontWeight: 600, cursor: 'pointer', userSelect: 'none' }}>
                      {t('customers.name') || 'Name'} {sortBy === 'name' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th onClick={() => handleSort('phone')} style={{ textAlign: 'left', padding: 12, fontSize: 14, fontWeight: 600, cursor: 'pointer', userSelect: 'none' }}>
                      {t('customers.phone') || 'Phone'} {sortBy === 'phone' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th onClick={() => handleSort('email')} style={{ textAlign: 'left', padding: 12, fontSize: 14, fontWeight: 600, cursor: 'pointer', userSelect: 'none' }}>
                      {t('customers.email') || 'Email'} {sortBy === 'email' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th style={{ textAlign: 'left', padding: 12, fontSize: 14, fontWeight: 600 }}>{t('customers.address') || 'Address'}</th>
                    <th style={{ textAlign: 'center', padding: 12, fontSize: 14, fontWeight: 600 }}>{t('products.actions') || 'Actions'}</th>
                  </tr>
                </thead>
                <tbody ref={tableBodyRef}>
                  {currentItems.map((customer, index) => (
                    <CustomerRow
                      key={customer.id}
                      customer={customer}
                      index={index}
                      isFocused={focusedRow === index}
                      isSelected={selectedCustomer?.id === customer.id}
                      canDelete={canDelete}
                      t={t}
                      onRowClick={handleRowClick}
                      onView={handleView}
                      onEdit={handleEdit}
                      onDelete={handleDelete}
                    />
                  ))}
                </tbody>
              </table>
            </div>

            {filteredCustomers.length > itemsPerPage && (
              <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '1rem', padding: '1rem', borderTop: '1px solid var(--border-light)' }}>
                <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="modal-button secondary" style={{ padding: '0.5rem 1.5rem', fontWeight: 800 }}>PREVIOUS</button>
                <span style={{ fontSize: '0.875rem', fontWeight: 800, padding: '0.625rem 1.25rem', borderRadius: 'var(--radius-md)', backgroundColor: 'var(--bg-main)', border: '1px solid var(--border-light)' }}>
                  PAGE {currentPage} / {totalPages}
                </span>
                <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="modal-button secondary" style={{ padding: '0.5rem 1.5rem', fontWeight: 800 }}>NEXT</button>
              </div>
            )}
          </>
        )}
      </GlassCard>

      {/* View modal */}
      {viewingCustomer && (
        <div className="modal-overlay" onClick={() => setViewingCustomer(null)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div className="modal-container" onClick={e => e.stopPropagation()} style={{ maxWidth: 500, width: '90%', background: 'white', borderRadius: 12, padding: 24, boxShadow: '0 8px 32px rgba(0,0,0,0.2)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16, borderBottom: '1px solid #eee', paddingBottom: 12 }}>
              <h3 style={{ margin: 0 }}>{t('common.view')} - {viewingCustomer.name}</h3>
              <button onClick={() => setViewingCustomer(null)} style={{ background: 'none', border: 'none', fontSize: 24, cursor: 'pointer', color: '#666' }}>×</button>
            </div>
            <div style={{ display: 'grid', gap: 12, fontSize: 14 }}>
              <div><strong>{t('customers.name')}:</strong> {viewingCustomer.name}</div>
              <div><strong>{t('customers.phone')}:</strong> {viewingCustomer.phone || '-'}</div>
              <div><strong>{t('customers.email')}:</strong> {viewingCustomer.email || '-'}</div>
              <div><strong>{t('customers.address')}:</strong> {viewingCustomer.address || '-'}</div>
            </div>
            <div style={{ marginTop: 20, display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button className="btn btn-primary" onClick={() => { setViewingCustomer(null); handleEdit(viewingCustomer); }}>{t('common.edit')}</button>
              <button className="btn btn-secondary" onClick={() => setViewingCustomer(null)}>{t('common.close')}</button>
            </div>
          </div>
        </div>
      )}

      {/* Add/Edit form modal */}
      {showFormModal && (
        <div className="modal-overlay" onClick={() => setShowFormModal(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div className="modal-container" onClick={e => e.stopPropagation()} style={{ maxWidth: 480, width: '90%', background: 'white', borderRadius: 12, padding: 24, boxShadow: '0 8px 32px rgba(0,0,0,0.2)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20, borderBottom: '1px solid #eee', paddingBottom: 12 }}>
              <h3 style={{ margin: 0 }}>{editingCustomer ? t('customers.editCustomer') : t('customers.addCustomer')}</h3>
              <button onClick={() => setShowFormModal(false)} style={{ background: 'none', border: 'none', fontSize: 24, cursor: 'pointer', color: '#666' }}>×</button>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 12, fontWeight: 600 }}>{t('customers.name') || 'Name'} *</label>
                <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} style={{ width: '100%', padding: '8px 12px', border: '1px solid #e5e7eb', borderRadius: 8, boxSizing: 'border-box' }} />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 12, fontWeight: 600 }}>{t('customers.phone') || 'Phone'}</label>
                <input type="text" value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} style={{ width: '100%', padding: '8px 12px', border: '1px solid #e5e7eb', borderRadius: 8, boxSizing: 'border-box' }} />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 12, fontWeight: 600 }}>{t('customers.email') || 'Email'}</label>
                <input type="email" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} style={{ width: '100%', padding: '8px 12px', border: '1px solid #e5e7eb', borderRadius: 8, boxSizing: 'border-box' }} />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: 4, fontSize: 12, fontWeight: 600 }}>{t('customers.address') || 'Address'}</label>
                <textarea rows={3} value={formData.address} onChange={e => setFormData({ ...formData, address: e.target.value })} style={{ width: '100%', padding: '8px 12px', border: '1px solid #e5e7eb', borderRadius: 8, boxSizing: 'border-box', resize: 'vertical' }} />
              </div>
            </div>
            <div style={{ marginTop: 20, display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button className="btn btn-secondary" onClick={() => setShowFormModal(false)}>{t('common.cancel')}</button>
              <button className="btn btn-primary" onClick={handleSave}>{editingCustomer ? t('common.save') : (t('customers.addCustomer') || 'Add Customer')}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomerManagement;
