import React, { useState, useRef, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { post } from '../utils/api';

/**
 * ManagerAuthorizationModal - Reusable modal for manager override (warehouse change, high discount, etc.)
 * F8/F10: Submit, Esc: Cancel
 */
const ManagerAuthorizationModal = ({
  isOpen,
  onClose,
  onAuthorized,
  title,
  message,
}) => {
  const { t } = useTranslation();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const passwordRef = useRef(null);

  const titleText = title ?? t('rbac.authorizationRequired');
  const messageText = message ?? t('rbac.managerAuthMessage');

  useEffect(() => {
    if (isOpen) {
      setUsername('');
      setPassword('');
      setError('');
      passwordRef.current?.focus();
    }
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
      if (e.key === 'F8' || e.key === 'F10') {
        e.preventDefault();
        handleSubmit();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [isOpen, username, password]);

  const handleSubmit = async () => {
    if (!username.trim() || !password.trim()) {
      setError(t('rbac.enterCredentials'));
      return;
    }
    setError('');
    setLoading(true);
    try {
      const data = await post('/users/login', { username: username.trim(), password });
      if (data.success && data.user) {
        const role = data.user.role || 'ADMIN';
        if (role === 'ADMIN' || role === 'MANAGER') {
          onAuthorized();
          onClose();
        } else {
          setError(t('rbac.accessDenied'));
        }
      } else {
        setError(t('rbac.invalidCredentials'));
      }
    } catch (err) {
      setError(t('rbac.networkError'));
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-container" style={{ width: '400px', maxWidth: '95vw' }} onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2 style={{ margin: 0 }}>{titleText}</h2>
          <button type="button" className="modal-close" onClick={onClose} aria-label="Close">×</button>
        </div>
        <div className="modal-body">
          <p style={{ margin: '0 0 1rem 0', color: 'var(--text-muted)' }}>{messageText}</p>
          <div className="form-group" style={{ marginBottom: '1rem' }}>
            <label>{t('rbac.managerUsername')}</label>
            <input
              type="text"
              value={username}
              onChange={(e) => { setUsername(e.target.value); setError(''); }}
              onKeyDown={(e) => e.key === 'Enter' && passwordRef.current?.focus()}
              placeholder={t('rbac.usernamePlaceholder')}
              className="form-input"
              autoComplete="username"
            />
          </div>
          <div className="form-group" style={{ marginBottom: '1rem' }}>
            <label>{t('rbac.managerPassword')}</label>
            <input
              ref={passwordRef}
              type="password"
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
              placeholder={t('rbac.passwordPlaceholder')}
              className="form-input"
              autoComplete="current-password"
            />
          </div>
          {error && <p style={{ color: 'var(--danger)', fontSize: '0.9rem', margin: '0 0 1rem 0' }}>{error}</p>}
        </div>
        <div className="modal-footer">
          <button type="button" data-pos-action="cancel" onClick={onClose} className="btn btn-secondary">
            {t('common.cancel')} <kbd>Esc</kbd>
          </button>
          <button type="button" data-pos-action="save" onClick={handleSubmit} disabled={loading} className="btn btn-primary">
            {loading ? t('common.loading') : t('rbac.authorize')} <kbd>F8</kbd>/<kbd>F10</kbd>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ManagerAuthorizationModal;
