// Keyboard event handler for POS system
class POSKeyboardHandler {
  constructor() {
    this.handlers = new Map();
    this.isActive = false;
    this.boundHandleKeyDown = this.handleKeyDown.bind(this);
  }

  // Initialize keyboard event listeners
  init() {
    if (this.isActive) return;
    window.addEventListener('keydown', this.boundHandleKeyDown, { capture: true });
    this.isActive = true;
  }

  // Clean up keyboard event listeners
  destroy() {
    if (!this.isActive) return;
    window.removeEventListener('keydown', this.boundHandleKeyDown, { capture: true });
    this.isActive = false;
  }

  // Register a handler for a specific key
  registerKey(key, callback, options = {}) {
    const keyConfig = {
      callback,
      preventDefault: options.preventDefault !== false, // Default to true
      condition: options.condition || (() => true), // Default to always execute
      description: options.description || ''
    };

    this.handlers.set(key ? key.toLowerCase() : key, keyConfig);
  }

  // Unregister a handler for a specific key
  unregisterKey(key) {
    this.handlers.delete(key ? key.toLowerCase() : key);
  }

  // Handle keydown events
  handleKeyDown(event) {
    // Convert key to lowercase for consistent matching
    const key = event.key ? event.key.toLowerCase() : null;
    if (!key) return;

    // First check for Ctrl+Letter combinations
    if (event.ctrlKey && !event.shiftKey && !event.altKey && key.length === 1 && /[a-z]/.test(key)) {
      const ctrlKey = `ctrl+${key}`;
      const handler = this.handlers.get(ctrlKey);
      if (handler) {
        console.log(`[KeyboardHandler] Detected ${ctrlKey} press`);
        // Check condition - if it exists, use it; otherwise default to true
        try {
          const conditionMet = handler.condition ? handler.condition(event) : true;
          if (conditionMet) {
            if (handler.preventDefault) {
              event.preventDefault();
              event.stopPropagation();
            }
            handler.callback(event);
            return; // Don't check regular key handlers if Ctrl+Letter matched
          }
        } catch (error) {
          console.error('Error in keyboard handler condition:', error);
        }
      }
    }

    // Alt+Letter: match by event.code so Alt+H works in all keyboard layouts
    if (event.altKey && event.code && event.code.startsWith('Key')) {
      const letterKey = event.code.replace('Key', '').toLowerCase();
      const altHandler = this.handlers.get(letterKey);
      if (altHandler && altHandler.condition && altHandler.condition(event)) {
        if (altHandler.preventDefault) event.preventDefault();
        altHandler.callback(event);
        return;
      }
    }

    // Check if we have a handler for this key
    const handler = this.handlers.get(key);
    if (!handler) {
      if (event.altKey || event.ctrlKey) {
        console.log(`[KeyboardHandler] No handler for key: ${key} (Alt: ${event.altKey}, Ctrl: ${event.ctrlKey})`);
      }
      return;
    }

    // Check if the condition is met
    try {
      const conditionMet = handler.condition ? handler.condition(event) : true;
      if (conditionMet) {
        console.log(`[KeyboardHandler] Triggering handler for key: ${key} (Alt: ${event.altKey})`);
        if (handler.preventDefault) {
          event.preventDefault();
        }

        // Execute the callback
        handler.callback(event);
      }
    } catch (error) {
      console.error('Error in keyboard handler:', error);
    }
  }

  // Register a handler for Ctrl+Letter combination
  registerCtrlKey(letter, callback, options = {}) {
    const letterLower = letter.toLowerCase();
    const keyConfig = {
      callback,
      preventDefault: options.preventDefault !== false,
      // The condition only needs to check custom conditions since handleKeyDown
      // already verifies it's a Ctrl+Letter combination before calling this
      condition: options.condition || (() => true),
      description: options.description || `Ctrl+${letter.toUpperCase()}`
    };

    this.handlers.set(`ctrl+${letterLower}`, keyConfig);
    console.log(`Registered Ctrl+${letter.toUpperCase()} shortcut: ${options.description || 'No description'}`);
  }

  // Unregister a Ctrl+Letter handler
  unregisterCtrlKey(letter) {
    const letterLower = letter.toLowerCase();
    this.handlers.delete(`ctrl+${letterLower}`);
  }

  // Get all registered shortcuts for display in help
  getShortcuts() {
    const shortcuts = [];
    for (const [key, config] of this.handlers) {
      if (config.description) {
        shortcuts.push({
          key: key.toUpperCase(),
          description: config.description
        });
      }
    }
    return shortcuts;
  }
}

// Create a singleton instance
const posKeyboardHandler = new POSKeyboardHandler();

// Predefined POS shortcuts
export const registerPOSShortcuts = (callbacks = {}) => {
  // F2: Search product by name
  if (callbacks.searchProduct) {
    posKeyboardHandler.registerKey('F2', callbacks.searchProduct, {
      description: 'Search product by name'
    });
  }

  // F4: Edit selected row
  if (callbacks.editRow) {
    posKeyboardHandler.registerKey('F4', callbacks.editRow, {
      description: 'Edit selected row'
    });
  }

  // F8: Add "Quick Product"
  if (callbacks.addQuickProduct) {
    posKeyboardHandler.registerKey('F8', callbacks.addQuickProduct, {
      description: 'Add quick product'
    });
  }

  // F10: Complete Sale and Print Receipt / Save Settings
  const f10Callback = callbacks.completeSale || callbacks.saveSettings;
  if (f10Callback) {
    posKeyboardHandler.registerKey('F10', f10Callback, {
      description: callbacks.completeSale ? 'Complete sale and print receipt' : 'Save settings'
    });
  }

  // ESC: Cancel/Clear transaction
  if (callbacks.clearTransaction || callbacks.cancelChanges) {
    posKeyboardHandler.registerKey('Escape', callbacks.clearTransaction || callbacks.cancelChanges, {
      description: callbacks.clearTransaction ? 'Cancel/clear transaction' : 'Cancel changes'
    });
  }

  // Arrow Up: Navigate up in list (skip when modal open so e.g. transaction history can use arrows)
  if (callbacks.navigateUp) {
    posKeyboardHandler.registerKey('ArrowUp', callbacks.navigateUp, {
      condition: (e) => !document.querySelector('.modal-overlay'),
      description: 'Navigate up in list'
    });
  }

  // Arrow Down: Navigate down in list (skip when modal open so e.g. transaction history can use arrows)
  if (callbacks.navigateDown) {
    posKeyboardHandler.registerKey('ArrowDown', callbacks.navigateDown, {
      condition: (e) => !document.querySelector('.modal-overlay'),
      description: 'Navigate down in list'
    });
  }

  // Enter: Confirm selection (skip when any modal is open so payment modal can use Enter to confirm)
  if (callbacks.confirmSelection) {
    posKeyboardHandler.registerKey('Enter', callbacks.confirmSelection, {
      condition: (e) => !document.querySelector('.modal-overlay'),
      description: 'Confirm selection'
    });
  }

  // Delete: Remove selected item
  if (callbacks.deleteRow) {
    posKeyboardHandler.registerKey('Delete', callbacks.deleteRow, {
      description: 'Remove selected item'
    });
  }

  // '+' key: Increase quantity
  if (callbacks.increaseQuantity) {
    posKeyboardHandler.registerKey('+', callbacks.increaseQuantity, {
      description: 'Increase quantity'
    });
  }

  // '-' key: Decrease quantity
  if (callbacks.decreaseQuantity) {
    posKeyboardHandler.registerKey('-', callbacks.decreaseQuantity, {
      description: 'Decrease quantity'
    });
  }

  // Alt + G: Digital payment method (Tabs shortcuts removed)
  if (callbacks.setDigitalPayment) {
    posKeyboardHandler.registerKey('g', callbacks.setDigitalPayment, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Set digital payment method'
    });
  }

  // Alt + K: Card payment method (moved from Alt + D to avoid conflict with Help Demo)
  if (callbacks.setCardPayment) {
    posKeyboardHandler.registerKey('k', callbacks.setCardPayment, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Set card payment method'
    });
  }

  // Alt + P: (Removed tab navigation shortcut)

  // Alt + S: Focus scanner (Tabs shortcuts removed)
  if (callbacks.focusScanner) {
    posKeyboardHandler.registerKey('s', callbacks.focusScanner, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Focus barcode scanner'
    });
  }

  // Alt + C: Cash payment (Tabs shortcuts removed)
  if (callbacks.setCashPayment) {
    posKeyboardHandler.registerKey('c', callbacks.setCashPayment, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Set cash payment method'
    });
  }

  // Alt + T: Focus Transaction Discount
  if (callbacks.focusTransactionDiscount) {
    posKeyboardHandler.registerKey('t', callbacks.focusTransactionDiscount, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Focus transaction discount'
    });
  }

  // Alt + H: Open History
  if (callbacks.openHistory) {
    posKeyboardHandler.registerKey('h', callbacks.openHistory, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Open transaction history'
    });
  }

  // Alt + D: Open Payment Method selection
  if (callbacks.openPaymentMethod) {
    posKeyboardHandler.registerKey('d', callbacks.openPaymentMethod, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Open payment method selection'
    });
  }

  // Alt + A: Focus AI Assistant (Sales screen)
  if (callbacks.focusAIAssistant) {
    posKeyboardHandler.registerKey('a', callbacks.focusAIAssistant, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Focus AI Assistant'
    });
  } else if (callbacks.setAccountPayment) {
  // Alt + A: Account payment method (fallback)
    posKeyboardHandler.registerKey('a', callbacks.setAccountPayment, {
      condition: (event) => {
        if (!event.altKey) return false;
        // Don't trigger if user is typing in an input field
        const target = event.target;
        const tagName = target.tagName;
        if (tagName === 'INPUT' || tagName === 'TEXTAREA' || target.isContentEditable) {
          return false;
        }
        return true;
      },
      preventDefault: true,
      description: 'Set account payment method'
    });
  }

  // Alt + W: Open warehouse selection (same as Alt+D for Payment Method - works even when focused on input)
  if (callbacks.focusWarehouse) {
    posKeyboardHandler.registerKey('w', callbacks.focusWarehouse, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Open warehouse selection'
    });
  }

  // Alt + N: Focus product name (Screen B manual entry)
  if (callbacks.focusProductName) {
    posKeyboardHandler.registerKey('n', callbacks.focusProductName, {
      condition: (event) => event.altKey,
      preventDefault: true,
      description: 'Focus product name (Screen B)'
    });
  }

  // Alt + B: Bank payment method
  if (callbacks.setBankPayment) {
    posKeyboardHandler.registerKey('b', callbacks.setBankPayment, {
      condition: (event) => {
        if (!event.altKey) return false;
        // Don't trigger if user is typing in an input field
        const target = event.target;
        const tagName = target.tagName;
        if (tagName === 'INPUT' || tagName === 'TEXTAREA' || target.isContentEditable) {
          return false;
        }
        return true;
      },
      preventDefault: true,
      description: 'Set bank payment method'
    });
  }
};

// Initialize the keyboard handler
export const initPOSKeyboardHandler = () => {
  posKeyboardHandler.init();
  return posKeyboardHandler;
};

// Destroy the keyboard handler
export const destroyPOSKeyboardHandler = () => {
  posKeyboardHandler.destroy();
};

// Get the keyboard handler instance
export const getPOSKeyboardHandler = () => {
  return posKeyboardHandler;
};

// Export the class for direct use if needed
export default POSKeyboardHandler;
