import React from 'react';
import { useTranslation } from 'react-i18next';

const WarehouseSelectionModal = ({ isOpen, onClose, onSelect, warehouses = [], current }) => {
  const { t } = useTranslation();
  React.useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e) => {
      const num = parseInt(e.key, 10);
      if (num >= 1 && num <= 9 && num <= warehouses.length) {
        e.preventDefault();
        const wh = warehouses[num - 1];
        if (wh) { onSelect(String(wh.id)); onClose(); }
      }
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
    };
    window.addEventListener('keydown', handleKey, true);
    return () => window.removeEventListener('keydown', handleKey, true);
  }, [isOpen, onClose, onSelect, warehouses]);

  if (!isOpen) return null;
  return (
    <div className="modal-overlay" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ background: 'white', width: 400, maxHeight: '80vh', borderRadius: 12, overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}>
        <div style={{ padding: '14px 16px', borderBottom: '1px solid #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <h3 style={{ margin: 0 }}>{t('warehouse.selectWarehouse')}</h3>
          <button onClick={onClose} style={{ border: 'none', background: 'transparent', fontSize: 22, color: '#888', cursor: 'pointer' }} aria-label="Close">×</button>
        </div>
        <div style={{ padding: 16, maxHeight: 400, overflowY: 'auto', display: 'grid', gap: 10 }}>
          {warehouses.length === 0 ? (
            <p style={{ color: '#666', margin: 0 }}>{t('warehouse.noWarehouses') || 'No warehouses'}</p>
          ) : (
            warehouses.map((wh, idx) => {
              const num = idx + 1;
              const isSelected = String(current) === String(wh.id);
              return (
                <button
                  key={wh.id}
                  onClick={() => { onSelect(String(wh.id)); onClose(); }}
                  className={`sales-button ${isSelected ? 'sales-button-success' : 'sales-button-secondary'}`}
                  style={{ justifyContent: 'space-between', display: 'flex', alignItems: 'center', textAlign: 'left' }}
                >
                  <span>
                    {num <= 9 && <kbd style={{ marginRight: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>{num}</kbd>}
                    {wh.parentWarehouse ? '↳ ' : ''}{wh.name || wh.code || wh.id}{wh.location ? ` (${wh.location})` : ''}
                  </span>
                  {isSelected && <span style={{ fontWeight: 800 }}>✓</span>}
                </button>
              );
            })
          )}
          <div style={{ fontSize: 12, color: '#666', marginTop: 8 }}>
            <span>{t('warehouse.selectWarehouse')}:</span>
            {warehouses.slice(0, 9).map((_, i) => (
              <kbd key={i} style={{ marginLeft: 6, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>{i + 1}</kbd>
            ))}
            <span style={{ marginLeft: 8 }}>·</span>
            <kbd style={{ marginLeft: 8, fontSize: 11, padding: '2px 6px', border: '1px solid #e5e7eb', borderRadius: 4, background: '#f9fafb' }}>Esc</kbd>
            <span style={{ marginLeft: 4 }}>{t('common.close') || 'Close'}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WarehouseSelectionModal;
