import React, { useState, useEffect } from 'react';
import EnhancedGRNManagement from './EnhancedGRNManagement';
import Stock1Screen from './Stock1Screen';
import { useTranslation } from 'react-i18next';
import { getPOSKeyboardHandler } from '../utils/keyboardHandler';

const GRN_TABS = [
  { id: 'grn_list', labelKey: 'grn.grnData', icon: 'M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z' },
  { id: 'suppliers', labelKey: 'suppliers.title', icon: 'M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z' },
  { id: 'warehouses', labelKey: 'warehouse.warehouses', icon: 'M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4' },
  { id: 'stock', labelKey: 'stock.title', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
  { id: 'transfers', labelKey: 'warehouse.transferStock', icon: 'M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4' }
];

const STOCK_TABS = [
  { id: 'overview', labelKey: 'stock.overview', icon: 'M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z' },
  { id: 'inventory', labelKey: 'stock.inventoryLevels', icon: 'M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z' },
  { id: 'low-stock', labelKey: 'stock.lowStockAlerts', icon: 'M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z' },
  { id: 'adjustments', labelKey: 'stock.adjustments', icon: 'M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15' }
];

const ALL_TABS = [...GRN_TABS, ...STOCK_TABS];

const StockManagementScreen = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState('grn_list');
  const visibleTabs = ALL_TABS;

  const keyboardHandler = getPOSKeyboardHandler();

  useEffect(() => {
    const handleShortcuts = (e) => {
      if (e.altKey) {
        const k = e.key.toLowerCase();
        if (['1','2','3','4','5','6','7','8','9'].includes(k)) {
          const idx = parseInt(k) - 1;
          if (visibleTabs[idx]) {
            e.preventDefault();
            setActiveTab(visibleTabs[idx].id);
          }
        }
      }
    };
    window.addEventListener('keydown', handleShortcuts);
    return () => window.removeEventListener('keydown', handleShortcuts);
  }, [visibleTabs]);

  const isGRNTab = GRN_TABS.some(tab => tab.id === activeTab);
  const isStockTab = STOCK_TABS.some(tab => tab.id === activeTab);

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 64px)', backgroundColor: 'var(--bg-main)', overflow: 'hidden' }}>
      {/* Sidebar Tabs - Product Management style */}
      <div style={{ width: '280px', backgroundColor: 'var(--bg-card)', borderRight: '1px solid var(--border-light)', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        <h2 style={{ fontSize: '1.25rem', fontWeight: '800', marginBottom: '1.5rem', color: 'var(--text-main)', paddingLeft: '0.5rem' }}>{t('navigation.stockManagement')}</h2>
        {visibleTabs.map((tab, idx) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              padding: '0.875rem 1rem',
              borderRadius: 'var(--radius-md)',
              border: 'none',
              backgroundColor: activeTab === tab.id ? 'var(--primary-subtle)' : 'transparent',
              color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
              cursor: 'pointer',
              fontWeight: '600',
              textAlign: 'left',
              transition: 'all var(--transition-fast)'
            }}
          >
            <svg style={{ width: '20px', height: '20px', flexShrink: 0 }} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={tab.icon} /></svg>
            {t(tab.labelKey)}
            <kbd style={{ marginLeft: 'auto', padding: '2px 4px', backgroundColor: 'var(--border-light)', borderRadius: '4px', fontSize: '0.7rem', opacity: 0.8 }}>Alt+{idx + 1}</kbd>
          </button>
        ))}

        <div style={{ marginTop: 'auto', padding: '1rem', backgroundColor: 'var(--bg-main)', borderRadius: 'var(--radius-lg)', border: '1px dashed var(--border-light)' }}>
          <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', margin: 0 }}>
            {t('stock.title')} • Alt+1–9 {t('common.page')}
          </p>
        </div>
      </div>

      {/* Main Panel */}
      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '1rem 2.5rem', backgroundColor: 'var(--bg-card)', borderBottom: '1px solid var(--border-light)', display: 'flex', gap: '0.5rem', alignItems: 'center', fontSize: '0.875rem', color: 'var(--text-muted)' }}>
          <span>{t('navigation.stockManagement')}</span>
          <span>/</span>
          <span style={{ color: 'var(--primary)', fontWeight: '600' }}>{t(visibleTabs.find(tab => tab.id === activeTab)?.labelKey || 'grn.title')}</span>
        </div>

        <div style={{ flex: 1, overflowY: 'auto' }}>
          {isGRNTab && (
            <EnhancedGRNManagement embedMode activeTab={activeTab} />
          )}
          {isStockTab && (
            <Stock1Screen embedMode activeTab={activeTab} />
          )}
        </div>
      </div>
    </div>
  );
};

export default StockManagementScreen;
