/**
 * Theme Management Utilities
 * Handles applying themes and persisting preference to localStorage
 */

const THEME_STORAGE_KEY = 'pos-theme-preference';
const PRIMARY_COLOR_STORAGE_KEY = 'pos-primary-color';

/**
 * Resolve effective theme: 'light' | 'dark'
 * For 'system', uses prefers-color-scheme media query
 */
export function resolveEffectiveTheme(themeMode) {
  if (themeMode === 'dark') return 'dark';
  if (themeMode === 'light') return 'light';
  if (themeMode === 'system') {
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
  return 'light';
}

/**
 * Apply the selected theme by setting data-theme on document root
 * @param {'light' | 'dark' | 'system'} themeMode - User preference
 */
export function applyTheme(themeMode) {
  const root = document.documentElement;
  const effective = resolveEffectiveTheme(themeMode);
  root.setAttribute('data-theme', effective);
  root.setAttribute('data-ambient-mode', effective === 'dark' ? 'true' : 'false');
  return effective;
}

/**
 * Get stored theme from localStorage
 * @returns {'light' | 'dark' | 'system'}
 */
export function getStoredTheme() {
  try {
    const stored = localStorage.getItem(THEME_STORAGE_KEY);
    if (['light', 'dark', 'system'].includes(stored)) return stored;
  } catch (e) {
    console.warn('Theme storage read failed:', e);
  }
  return 'light';
}

/**
 * Save theme preference to localStorage
 */
export function setStoredTheme(themeMode) {
  try {
    localStorage.setItem(THEME_STORAGE_KEY, themeMode);
  } catch (e) {
    console.warn('Theme storage write failed:', e);
  }
}

/**
 * Get stored primary color (hex or hue string)
 */
export function getStoredPrimaryColor() {
  try {
    return localStorage.getItem(PRIMARY_COLOR_STORAGE_KEY) || null;
  } catch (e) {
    return null;
  }
}

/**
 * Save primary color to localStorage
 */
export function setStoredPrimaryColor(value) {
  try {
    if (value) localStorage.setItem(PRIMARY_COLOR_STORAGE_KEY, value);
    else localStorage.removeItem(PRIMARY_COLOR_STORAGE_KEY);
  } catch (e) {
    console.warn('Primary color storage failed:', e);
  }
}

/**
 * Listen for system preference changes (for 'system' mode)
 * @param {function} callback - Called with 'light' | 'dark' when preference changes
 * @returns {function} Unsubscribe function
 */
export function onSystemPreferenceChange(callback) {
  if (!window.matchMedia) return () => {};
  const mq = window.matchMedia('(prefers-color-scheme: dark)');
  const handler = () => callback(mq.matches ? 'dark' : 'light');
  mq.addEventListener('change', handler);
  return () => mq.removeEventListener('change', handler);
}
