import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { get, post } from '../utils/api';

const DEFAULT_COL_WIDTHS = { select: 52, name: 240, barcode: 200, price: 100, quantity: 72, discountPct: 80, discountVal: 95, costPrice: 95, minStock: 85, warehouse: 150, category: 150 };
const BULK_COL_KEYS = ['name', 'barcode', 'price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock', 'warehouse', 'category'];
const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];

const createEmptyRow = () => ({
  id: `bulk-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
  name: '',
  barcode: '',
  sellingPrice: '',
  quantity: '0',
  discountPercentage: '',
  discountFixedPrice: '',
  costPrice: '',
  minStockLevel: '',
  warehouseId: '',
  categoryId: '',
  selected: true
});

const BulkAddProductsScreen = () => {
  const { t } = useTranslation();
  const [rows, setRows] = useState([]);
  const [saving, setSaving] = useState(false);
  const [warehouses, setWarehouses] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectAll, setSelectAll] = useState(false);
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [focusedRowIndex, setFocusedRowIndex] = useState(-1);
  const tableBodyRef = useRef(null);

  const totalPages = Math.max(1, Math.ceil(rows.length / pageSize));
  const currentPage = Math.min(page, totalPages);
  const startIdx = (currentPage - 1) * pageSize;
  const pageRows = rows.slice(startIdx, startIdx + pageSize);

  useEffect(() => {
    const n = pageRows.length;
    if (n === 0) setFocusedRowIndex(-1);
    else setFocusedRowIndex(prev => (prev < 0 ? 0 : prev >= n ? n - 1 : prev));
  }, [currentPage, pageSize, pageRows.length]);

  const loadWarehouses = useCallback(async () => {
    try {
      const res = await get('/warehouses');
      if (res.success && res.data && res.data.length > 0) setWarehouses(res.data);
    } catch (e) {
      console.error(e);
    }
  }, []);

  const loadCategories = useCallback(async () => {
    try {
      const res = await get('/categories');
      if (res.success && res.data && Array.isArray(res.data)) setCategories(res.data);
    } catch (e) {
      console.error(e);
    }
  }, []);

  useEffect(() => {
    loadWarehouses();
    loadCategories();
  }, [loadWarehouses, loadCategories]);

  const addRow = useCallback(() => {
    setRows(prev => [...prev, createEmptyRow()]);
    setPage(Math.max(1, Math.ceil((rows.length + 1) / pageSize)));
  }, [rows.length, pageSize]);

  const removeRow = useCallback((id) => {
    setRows(prev => prev.filter(r => r.id !== id));
  }, []);

  const updateRow = (id, field, value) => {
    setRows(prev => prev.map(r => r.id === id ? { ...r, [field]: value } : r));
  };

  const toggleRow = (id) => {
    setRows(prev => {
      const next = prev.map(r => r.id === id ? { ...r, selected: !r.selected } : r);
      const allSelected = next.length > 0 && next.every(r => r.selected);
      setSelectAll(allSelected);
      return next;
    });
  };

  const toggleSelectAll = useCallback(() => {
    setSelectAll(prev => {
      const next = !prev;
      setRows(r => r.map(row => ({ ...row, selected: next })));
      return next;
    });
  }, []);

  const generateBarcodeForRow = (id) => {
    const num = Date.now().toString().slice(-8) + Math.floor(Math.random() * 10);
    const unique = `B${num}`;
    setRows(prev => prev.map(r => r.id === id ? { ...r, barcode: unique } : r));
  };

  const handleSave = async () => {
    const selected = rows.filter(r => r.selected);
    if (selected.length === 0) {
      alert(t('bulkAdd.selectAtLeastOne') || 'Select at least one row to add as product.');
      return;
    }
    setSaving(true);
    let ok = 0;
    let fail = 0;
    for (const row of selected) {
      const name = (row.name || '').trim();
      const sellingPrice = parseFloat(row.sellingPrice);
      if (!name || isNaN(sellingPrice) || sellingPrice < 0) {
        fail++;
        continue;
      }
      try {
        const qty = parseInt(row.quantity, 10);
        const quantity = !isNaN(qty) && qty >= 0 ? qty : 0;
        const discountPct = parseFloat(row.discountPercentage);
        const discountPercentage = !isNaN(discountPct) && discountPct >= 0 && discountPct <= 100 ? discountPct : undefined;
        const discountVal = parseFloat(row.discountFixedPrice);
        const discountFixedPrice = !isNaN(discountVal) && discountVal >= 0 ? discountVal : undefined;
        const costPriceVal = parseFloat(row.costPrice);
        const costPrice = !isNaN(costPriceVal) && costPriceVal >= 0 ? costPriceVal : undefined;
        const minStockVal = parseInt(row.minStockLevel, 10);
        const minStockLevel = !isNaN(minStockVal) && minStockVal >= 0 ? minStockVal : undefined;
        const rowCategoryId = row.categoryId && !isNaN(parseInt(row.categoryId)) ? parseInt(row.categoryId) : null;
        const rowWarehouseId = row.warehouseId && !isNaN(parseInt(row.warehouseId)) ? parseInt(row.warehouseId) : null;
        const payload = {
          name,
          sellingPrice,
          quantity,
          ...(row.barcode && row.barcode.trim() ? { barcode: row.barcode.trim() } : {}),
          ...(rowWarehouseId ? { warehouseId: rowWarehouseId } : {}),
          ...(rowCategoryId ? { categoryId: rowCategoryId } : {}),
          ...(costPrice !== undefined ? { costPrice } : {}),
          ...(minStockLevel !== undefined ? { minStockLevel } : {}),
          ...(discountPercentage !== undefined ? { discountPercentage } : {}),
          ...(discountFixedPrice !== undefined ? { discountFixedPrice } : {})
        };
        const result = await post('/products/create-with-barcode', payload);
        if (result && result.success) {
          ok++;
          setRows(prev => prev.filter(r => r.id !== row.id));
        } else {
          fail++;
        }
      } catch (e) {
        fail++;
      }
    }
    setSaving(false);
    setSelectAll(false);
    if (ok > 0) {
      alert(t('bulkAdd.savedCount', { count: ok }) || `${ok} product(s) created. They appear in the Products tab.`);
    }
    if (fail > 0) {
      alert(t('bulkAdd.failedCount', { count: fail }) || `${fail} row(s) could not be saved. Check name and price.`);
    }
  };

  const colLabel = (key) => {
    const labels = {
      name: t('sales.productName') || 'Name',
      barcode: t('products.barcode') || 'Barcode',
      price: t('sales.price') || 'Price',
      quantity: t('sales.quantity') || 'Qty',
      discountPct: t('dummyProducts.discountPct') || 'Discount %',
      discountVal: t('dummyProducts.discountValue') || 'Discount value',
      costPrice: t('products.costPrice') || 'Cost price',
      minStock: t('products.minStock') || 'Min stock',
      warehouse: t('warehouse.warehouse') || 'Warehouse',
      category: t('products.category') || 'Category'
    };
    return labels[key] || key;
  };

  useEffect(() => {
    if (focusedRowIndex < 0 || !tableBodyRef.current) return;
    const row = tableBodyRef.current.querySelector(`tr[data-row-index="${focusedRowIndex}"]`);
    if (row) row.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  }, [focusedRowIndex]);

  useEffect(() => {
    const onKey = (e) => {
      if (e.target?.tagName === 'INPUT' || e.target?.tagName === 'SELECT' || e.target?.tagName === 'TEXTAREA') return;
      if (e.altKey && e.key.toLowerCase() === 'n') {
        e.preventDefault();
        document.querySelector('[data-action="bulk-add-row"]')?.click();
        return;
      }
      if (e.altKey && e.key.toLowerCase() === 's') {
        e.preventDefault();
        document.querySelector('[data-action="bulk-save"]')?.click();
        return;
      }
      if (e.ctrlKey && e.key.toLowerCase() === 'a') {
        e.preventDefault();
        toggleSelectAll();
        return;
      }
      if (pageRows.length > 0 && (e.key === 'ArrowDown' || e.key === 'ArrowUp')) {
        e.preventDefault();
        if (e.key === 'ArrowDown') setFocusedRowIndex(prev => (prev < 0 ? 0 : Math.min(prev + 1, pageRows.length - 1)));
        else setFocusedRowIndex(prev => Math.max(prev - 1, 0));
        return;
      }
      if (e.key === 'Enter' && focusedRowIndex >= 0 && pageRows[focusedRowIndex]) {
        e.preventDefault();
        toggleRow(pageRows[focusedRowIndex].id);
      }
    };
    window.addEventListener('keydown', onKey, { capture: true });
    return () => window.removeEventListener('keydown', onKey, { capture: true });
  }, [toggleSelectAll, pageRows, focusedRowIndex, toggleRow]);

  return (
    <div data-screen="bulk-add-products" style={{ height: '100%', minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <div style={{ flex: 1, minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: '1rem 1.5rem', boxSizing: 'border-box' }}>
        <header style={{ flexShrink: 0, width: '100%', marginBottom: '1rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', flexWrap: 'wrap', marginBottom: '0.5rem', padding: '6px 10px', borderRadius: 8, background: 'var(--bg-card)', border: '1px solid var(--border-light)', fontSize: '0.8125rem', color: 'var(--text-secondary)', minHeight: 32, boxSizing: 'border-box' }}>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Alt+N</kbd> {t('bulkAdd.addRow') || 'Add row'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Alt+S</kbd> {t('dummyProducts.shortcutSave') || 'Save selected'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>↑</kbd><kbd style={{ marginLeft: 2, padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>↓</kbd> {t('bulkAdd.moveRow') || 'Move row'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Enter</kbd> {t('bulkAdd.toggleSelect') || 'Toggle select'}</span>
            <span><kbd style={{ padding: '2px 6px', border: '1px solid var(--border-light)', borderRadius: 4, background: 'var(--bg-main)', fontWeight: 600, color: 'var(--text-main)' }}>Ctrl+A</kbd> {t('dummyProducts.shortcutSelectAll') || 'Select all'}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '0.75rem', marginBottom: '0.5rem' }}>
            <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 700 }}>{t('bulkAdd.title') || 'Bulk Add Products'}</h2>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
              <button type="button" data-action="bulk-add-row" onClick={addRow} className="btn btn-primary" title={t('bulkAdd.addRow') || 'Add row (Alt+N)'} style={{ padding: '6px 14px', display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                + {t('bulkAdd.addRow') || 'Add row'}
                <kbd style={{ padding: '2px 5px', fontSize: '0.7rem', border: '1px solid rgba(255,255,255,0.5)', borderRadius: 4, background: 'rgba(0,0,0,0.15)', fontWeight: 600 }}>Alt+N</kbd>
              </button>
              <button
                type="button"
                data-action="bulk-save"
                onClick={handleSave}
                disabled={saving || rows.filter(r => r.selected).length === 0}
                className="btn btn-primary"
                title={t('bulkAdd.saveSelectedAsProducts') || 'Save selected as products (Alt+S)'}
                style={{ padding: '6px 14px', display: 'inline-flex', alignItems: 'center', gap: '6px' }}
              >
                {saving ? (t('common.saving') || 'Saving...') : (t('bulkAdd.saveAsProducts') || 'Save selected as products')}
                {!saving && <kbd style={{ padding: '2px 6px', fontSize: '0.7rem', border: '1px solid rgba(255,255,255,0.5)', borderRadius: 4, background: 'rgba(0,0,0,0.15)', fontWeight: 600 }}>Alt+S</kbd>}
              </button>
            </div>
          </div>
          <p style={{ margin: 0, fontSize: '0.875rem', color: 'var(--text-muted)' }}>
            {t('bulkAdd.hint') || 'Start with an empty table. Click "Add row" to add lines, fill name and price (required), then save selected rows as products in bulk.'}
          </p>
        </header>

        {rows.length === 0 ? (
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1rem', border: '2px dashed var(--border-light)', borderRadius: 'var(--radius-md)', background: 'var(--bg-main)', color: 'var(--text-muted)' }}>
            <p style={{ margin: 0, fontSize: '1rem' }}>{t('bulkAdd.noRows') || 'No rows yet. Click "Add row" to start.'}</p>
            <button type="button" data-action="bulk-add-row" onClick={addRow} className="btn btn-primary" title={t('bulkAdd.addRow') || 'Add row (Alt+N)'} style={{ padding: '10px 20px', display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
              + {t('bulkAdd.addRow') || 'Add row'} <kbd style={{ padding: '2px 5px', fontSize: '0.7rem', border: '1px solid rgba(255,255,255,0.5)', borderRadius: 4, background: 'rgba(0,0,0,0.15)', fontWeight: 600 }}>Alt+N</kbd>
            </button>
          </div>
        ) : (
          <div style={{ flex: 1, minHeight: 0, width: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
            <div style={{ flexShrink: 0, display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.75rem', flexWrap: 'wrap' }}>
              <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>
                {t('dummyProducts.rowsPerPage') || 'Rows per page'}:{' '}
                <select value={pageSize} onChange={(e) => { setPageSize(Number(e.target.value)); setPage(1); }} className="modern-input" style={{ padding: '4px 8px', marginLeft: 4 }}>
                  {PAGE_SIZE_OPTIONS.map(n => (<option key={n} value={n}>{n}</option>))}
                </select>
              </span>
              <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>
                {startIdx + 1}-{Math.min(startIdx + pageSize, rows.length)} {t('dummyProducts.of') || 'of'} {rows.length}
              </span>
            </div>
            <div className="table-container" style={{ flex: 1, minHeight: 0, overflow: 'auto', border: '1px solid var(--border-light)', borderRadius: 'var(--radius-md)', width: '100%', minWidth: 0 }}>
              <table className="data-table" style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', minWidth: '100%' }}>
                <thead>
                  <tr className="glass-panel" style={{ borderBottom: '2px solid var(--glass-border, var(--border-light))', position: 'sticky', top: 0, background: 'var(--glass-bg, var(--bg-card))', zIndex: 10 }}>
                    <th style={{ padding: 12, width: DEFAULT_COL_WIDTHS.select, minWidth: 48, textAlign: 'center', position: 'sticky', left: 0, zIndex: 11, background: 'var(--glass-bg, var(--bg-card))' }}>
                      <input type="checkbox" checked={selectAll} onChange={toggleSelectAll} title={t('dummyProducts.selectAll') || 'Select all'} />
                    </th>
                    <th style={{ padding: 12, width: 40, minWidth: 40, textAlign: 'center', position: 'sticky', left: 52, zIndex: 11, background: 'var(--glass-bg, var(--bg-card))' }} title={t('bulkAdd.removeRow') || 'Remove row'}>—</th>
                    {BULK_COL_KEYS.map(key => {
                      const align = ['price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock'].includes(key) ? 'right' : 'left';
                      const minW = { name: 120, barcode: 100, price: 70, quantity: 56, discountPct: 56, discountVal: 70, costPrice: 70, minStock: 60, warehouse: 100, category: 100 }[key] || 70;
                      return (
                        <th key={key} style={{ padding: 12, width: DEFAULT_COL_WIDTHS[key] || 100, minWidth: minW, textAlign: align, background: 'var(--glass-bg, var(--bg-card))' }}>
                          {colLabel(key)}
                        </th>
                      );
                    })}
                  </tr>
                </thead>
                <tbody ref={tableBodyRef}>
                  {pageRows.map((row, idx) => (
                    <tr
                      key={row.id}
                      data-row-index={idx}
                      style={{
                        borderBottom: '1px solid var(--border-light)',
                        backgroundColor: idx === focusedRowIndex ? 'var(--primary-subtle)' : undefined,
                        borderLeft: idx === focusedRowIndex ? '4px solid var(--primary)' : '4px solid transparent'
                      }}
                    >
                      <td style={{ padding: 12, width: DEFAULT_COL_WIDTHS.select, minWidth: 48, textAlign: 'center', position: 'sticky', left: 0, zIndex: 1, background: idx === focusedRowIndex ? 'var(--primary-subtle)' : 'var(--bg-main)', boxShadow: '2px 0 0 var(--border-light)' }}>
                        <input type="checkbox" checked={!!row.selected} onChange={() => toggleRow(row.id)} />
                      </td>
                      <td style={{ padding: 8, width: 40, minWidth: 40, textAlign: 'center', position: 'sticky', left: 52, zIndex: 1, background: idx === focusedRowIndex ? 'var(--primary-subtle)' : 'var(--bg-main)', boxShadow: '2px 0 0 var(--border-light)' }}>
                        <button type="button" onClick={() => removeRow(row.id)} className="btn btn-outline-primary" style={{ padding: '4px 8px', fontSize: '0.75rem' }} title={t('bulkAdd.removeRow') || 'Remove row'}>×</button>
                      </td>
                      {BULK_COL_KEYS.map(key => {
                        const align = ['price', 'quantity', 'discountPct', 'discountVal', 'costPrice', 'minStock'].includes(key) ? 'right' : 'left';
                        const minW = { name: 120, barcode: 100, price: 70, quantity: 56, discountPct: 56, discountVal: 70, costPrice: 70, minStock: 60, warehouse: 100, category: 100 }[key] || 70;
                        const baseTd = { padding: 12, width: DEFAULT_COL_WIDTHS[key] || 100, minWidth: minW, textAlign: align };
                        if (key === 'name') return (<td key={key} style={{ ...baseTd, overflow: 'hidden' }}><input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, boxSizing: 'border-box' }} placeholder={t('sales.productName') || 'Name'} /></td>);
                        if (key === 'barcode') return (<td key={key} style={{ ...baseTd, overflow: 'hidden' }}><div style={{ display: 'flex', alignItems: 'center', gap: 6 }}><input type="text" value={row.barcode} onChange={(e) => updateRow(row.id, 'barcode', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, boxSizing: 'border-box' }} placeholder={t('dummyProducts.barcodeAutoPlaceholder') || 'Empty = auto'} /><button type="button" onClick={() => generateBarcodeForRow(row.id)} className="btn btn-outline-primary" style={{ padding: '6px 10px', fontSize: '0.75rem', whiteSpace: 'nowrap' }}>{t('dummyProducts.genBarcode') || 'Gen'}</button></div></td>);
                        if (key === 'price') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.sellingPrice} onChange={(e) => updateRow(row.id, 'sellingPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                        if (key === 'quantity') return (<td key={key} style={baseTd}><input type="number" min="0" value={row.quantity} onChange={(e) => updateRow(row.id, 'quantity', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                        if (key === 'discountPct') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" max="100" value={row.discountPercentage} onChange={(e) => updateRow(row.id, 'discountPercentage', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="%" /></td>);
                        if (key === 'discountVal') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.discountFixedPrice} onChange={(e) => updateRow(row.id, 'discountFixedPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                        if (key === 'costPrice') return (<td key={key} style={baseTd}><input type="number" step="0.01" min="0" value={row.costPrice} onChange={(e) => updateRow(row.id, 'costPrice', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                        if (key === 'minStock') return (<td key={key} style={baseTd}><input type="number" min="0" value={row.minStockLevel} onChange={(e) => updateRow(row.id, 'minStockLevel', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, textAlign: 'right', boxSizing: 'border-box' }} placeholder="0" /></td>);
                        if (key === 'warehouse') return (<td key={key} style={baseTd}><select value={row.warehouseId || ''} onChange={(e) => updateRow(row.id, 'warehouseId', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, padding: '6px 8px', boxSizing: 'border-box' }}><option value="">{t('common.select') || '—'}</option>{warehouses.map(w => (<option key={w.id} value={w.id}>{w.name}</option>))}</select></td>);
                        if (key === 'category') return (<td key={key} style={baseTd}><select value={row.categoryId || ''} onChange={(e) => updateRow(row.id, 'categoryId', e.target.value)} className="modern-input" style={{ width: '100%', minWidth: 0, padding: '6px 8px', boxSizing: 'border-box' }}><option value="">{t('common.select') || '—'}</option>{categories.map(c => (<option key={c.id} value={c.id}>{c.name}</option>))}</select></td>);
                        return <td key={key} style={baseTd}>—</td>;
                      })}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div style={{ flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '0.75rem', marginTop: '0.75rem', padding: '8px 0' }}>
              <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>
                {t('dummyProducts.page') || 'Page'} {currentPage} {t('dummyProducts.of') || 'of'} {totalPages} ({rows.length} {t('dummyProducts.rows') || 'rows'})
              </span>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <button type="button" className="btn btn-outline-primary" style={{ padding: '6px 12px' }} disabled={currentPage <= 1} onClick={() => setPage(p => Math.max(1, p - 1))}>{t('dummyProducts.prev') || 'Prev'}</button>
                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                  let p = totalPages <= 5 ? i + 1 : currentPage <= 3 ? i + 1 : currentPage >= totalPages - 2 ? totalPages - 4 + i : currentPage - 2 + i;
                  return (
                    <button key={p} type="button" className="btn btn-outline-primary" style={{ padding: '6px 10px', minWidth: 36, fontWeight: p === currentPage ? 700 : 400 }} onClick={() => setPage(p)}>{p}</button>
                  );
                })}
                <button type="button" className="btn btn-outline-primary" style={{ padding: '6px 12px' }} disabled={currentPage >= totalPages} onClick={() => setPage(p => Math.min(totalPages, p + 1))}>{t('dummyProducts.next') || 'Next'}</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default BulkAddProductsScreen;
