import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const isAuthenticated = !!currentUser;

  // Check if user is logged in on initial load & setup session listener
  useEffect(() => {
    const token = localStorage.getItem('token');
    const user = localStorage.getItem('user');

    if (token && user) {
      setCurrentUser(JSON.parse(user));
    }
    setLoading(false);

    // Inactivity listener
    let logoutTimer;
    const resetTimer = () => {
      if (logoutTimer) clearTimeout(logoutTimer);
      logoutTimer = setTimeout(() => {
        console.log('Session timed out');
        logout();
      }, 30 * 60 * 1000); // 30 minutes
    };

    if (token) {
      window.addEventListener('mousemove', resetTimer);
      window.addEventListener('keydown', resetTimer);
      resetTimer();
    }

    return () => {
      window.removeEventListener('mousemove', resetTimer);
      window.removeEventListener('keydown', resetTimer);
      if (logoutTimer) clearTimeout(logoutTimer);
    };
  }, [isAuthenticated]);

  const login = async (username, password) => {
    try {
      const response = await fetch('/api/users/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ username, password }),
      });

      const data = await response.json();

      if (data.success) {
        const { token, user } = data;

        // Store token and user in localStorage
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));

        setCurrentUser(user);
        return { success: true, user };
      } else {
        return { success: false, message: data.message || 'Login failed' };
      }
    } catch (error) {
      console.error('Login error:', error);
      return { success: false, message: 'Network error occurred' };
    }
  };

  const logout = async () => {
    try {
      // Call logout API endpoint
      await fetch('/api/users/logout', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
      });

      // Clear localStorage
      localStorage.removeItem('token');
      localStorage.removeItem('user');

      setCurrentUser(null);
    } catch (error) {
      console.error('Logout error:', error);
      // Even if API call fails, still clear local storage
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      setCurrentUser(null);
    }
  };

  // Role helpers: ADMIN, MANAGER, CASHIER (case-insensitive)
  const userRole = (currentUser?.role || 'ADMIN').toString().toUpperCase();
  const isAdmin = userRole === 'ADMIN';
  const isManager = userRole === 'MANAGER';
  const isCashier = userRole === 'CASHIER';
  const canChangeWarehouse = isAdmin || isManager;
  const canAccessWarehouseMgmt = isAdmin || isManager;
  const canAccessStockTransfer = isAdmin || isManager;
  const canAccessSettings = isAdmin;
  const canAccessAdmin = isAdmin;
  // Delete: admin/manager always; cashier only if privilege canDelete is set
  const canDelete = isAdmin || isManager || currentUser?.privileges?.canDelete === true;

  const value = {
    currentUser,
    login,
    logout,
    isAuthenticated,
    userRole,
    isAdmin,
    isManager,
    isCashier,
    canChangeWarehouse,
    canAccessWarehouseMgmt,
    canAccessStockTransfer,
    canAccessSettings,
    canAccessAdmin,
    canDelete,
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};